const kelimeListesi = [{"word":"abolish","level":"C1","type":"v.","turkish":"Kaldırmak, feshetmek, yürürlükten kaldırmak.","definition":"To formally put an end to a system, practice, or institution.","examples":["Many people campaigned to abolish slavery during the 19th century.","The government decided to abolish the unpopular tax."]},{"word":"abortion","level":"C1","type":"n.","turkish":"Kürtaj,çocuk düşürme.","definition":"The deliberate termination of a human pregnancy, most often performed during the first 28 weeks.","examples":["The debate over the legality of abortion continues in many countries.","She made the difficult decision to have an abortion."]},{"word":"absence","level":"C1","type":"n.","turkish":"Yokluk, bulunmama, devamsızlık.","definition":"The state of being away from a place or person; the non -existence or lack of something.","examples":["His frequent absence from meetings was noted by his supervisor.","In the absence of clear evidence, the case was dismissed."]},{"word":"absent","level":"C1","type":"adj.","turkish":"Yok, mevcut olmayan, devamsız.","definition":"Not present in a place, at an occasion, or as part of something.","examples":["Several students were absent due to the flu.","He was absent from work for two weeks."]},{"word":"absorb","level":"B2","type":"v.","turkish":"Emmek, soğurmak, içineçekmek; (mecazi) anlamak,özümsemek.","definition":"To take in or soak up (energy, or a liquid or other substance) by chemical or physical action; to understand facts or information fully.","examples":["Plants absorb carbon dioxide from the atmosphere.","It took him a while to absorb all the new information."]},{"word":"abstract","level":"B2","type":"adj.","turkish":"Soyut.","definition":"Existing in thought or as an idea but not having a physical or concrete existence.","examples":["Truth and beauty are abstract concepts.","The artist is known for her abstract paintings."]},{"word":"absurd","level":"C1","type":"adj.","turkish":"Saçma, anlamsız, abes.","definition":"Wildly unreasonable, illogical, or inappropriate.","examples":["The idea that the earth is flat is absurd.","He laughed at the absurdity of the situation."]},{"word":"abuse","level":"C1","type":"n.","turkish":"(n) Kötüye kullanma, istismar, suistimal; (v) Kötüye kullanmak, istismar etmek, suistimal etmek, köt","definition":"(n) The improper use of something; cruel and violent treatment of a person or animal. (v) To use something to bad effect or for a bad purpose; misuse; treat (a person or animal) with cruelty or violence.","examples":["Drug abuse is a serious problem in many communities. (noun) He was accused of abusing his power. (verb)"]},{"word":"academy","level":"C1","type":"n.","turkish":"Akademi, yüksekokul.","definition":"A place of study or training in a special field; a society or institution founded for the promotion of art, science, or literature.","examples":["She trained at a prestigious music academy.","The police academy provides rigorous training for new recruits."]},{"word":"accelerate","level":"C1","type":"v.","turkish":"Hızlandırmak, ivme kazandırmak.","definition":"To begin to move more quickly; increase in rate, amount, or extent.","examples":["The car accelerated smoothly away from the traffic lights.","The government plans to accelerate economic growth."]},{"word":"accent","level":"B2","type":"n.","turkish":"Aksan,şive; vurgu.","definition":"A distinctive mode of pronunciation of a language, especially one associated with a particular nation, locality, or social class.","examples":["He spoke English with a strong French accent.","She has a slight regional accent."]},{"word":"acceptance","level":"C1","type":"n.","turkish":"Kabul, kabullenme, onaylama.","definition":"The action of consenting to receive or undertake something offered; agreement with or belief in an idea, opinion, or explanation.","examples":["Her acceptance into the university was a dream come true.","There is growing acceptance of alternative medicine."]},{"word":"accessible","level":"C1","type":"adj.","turkish":"Erişilebilir, ulaşılabilir, (kolay) anlaşılır.","definition":"Able to be reached or entered; easily understood or appreciated.","examples":["The museum is easily accessible by public transport.","The professor made complex theories accessible to everyone."]},{"word":"accidentally","level":"B2","type":"adv.","turkish":"Kazara, tesadüfen, yanlışlıkla.","definition":"By chance; inadvertently.","examples":["I accidentally deleted the important file.","She accidentally bumped into an old friend at the supermarket."]},{"word":"accommodate","level":"B2","type":"v.","turkish":"Yerleştirmek, kalacak yer sağlamak; uyum sağlamak, ihtiyacını karşılamak.","definition":"To provide lodging or sufficient space for; fit in with the wishes or needs of.","examples":["The hotel can accommodate up to 500 guests.","We need to accommodate the needs of disabled students."]},{"word":"accommodation","level":"B2","type":"n.","turkish":"Konaklama, kalacak yer.","definition":"A room, group of rooms, or building in which someone may live or stay.","examples":["Hotel accommodation is included in the price of the tour.","They found temporary accommodation with friends."]},{"word":"accomplish","level":"B2","type":"v.","turkish":"Başarmak, tamamlamak,üstesinden gelmek.","definition":"To achieve or complete successfully.","examples":["It's amazing what you can accomplish when you work together.","She accomplished her goal of running a marathon."]},{"word":"accomplishment","level":"C1","type":"n.","turkish":"Başarı, beceri, marifet.","definition":"Something that has been achieved successfully; a skill or special ability.","examples":["Graduating from university was a major accomplishment for him.","Playing the piano is just one of her many accomplishments."]},{"word":"accordingly","level":"C1","type":"adv.","turkish":"Buna göre, ona göre, bu doğrultuda.","definition":"In a way that is appropriate to the particular circumstances; therefore.","examples":["We have received your instructions and will act accordingly.","The weather forecast predicted rain, so we dressed accordingly."]},{"word":"accountability","level":"C1","type":"n.","turkish":"Hesap verebilirlik, sorumluluk.","definition":"The fact or condition of being accountable; responsibility.","examples":["There is a need for greater accountability in public office.","The company emphasizes accountability among its employees."]},{"word":"accountable","level":"C1","type":"adj.","turkish":"Sorumlu, hesap vermekle yükümlü.","definition":"Required or expected to justify actions or decisions; responsible.","examples":["Politicians are accountable to the voters.","Managers should be accountable for their decisions."]},{"word":"accountant","level":"B2","type":"n.","turkish":"Muhasebeci.","definition":"A person whose job is to keep or inspect financial accounts.","examples":["We hired an accountant to handle the company's finances.","My accountant helps me with my tax returns every year."]},{"word":"accumulate","level":"C1","type":"v.","turkish":"Biriktirmek, toplamak, yığmak.","definition":"To gather together or acquire an increasing number or quantity of.","examples":["Dust had accumulated on the furniture.","Over the years, he accumulated a vast collection of rare books."]},{"word":"accumulation","level":"C1","type":"n.","turkish":"Birikim, yığılma, toplama.","definition":"The acquisition or gradual gathering of something.","examples":["The accumulation of wealth was his main goal.","The accumulation of snow caused traffic problems."]},{"word":"accuracy","level":"B2","type":"n.","turkish":"Doğruluk, kesinlik, hassasiyet.","definition":"The quality or state of being correct or precise.","examples":["The accuracy of the report was questioned.","GPS systems offer high accuracy in navigation."]},{"word":"accurately","level":"B2","type":"adv.","turkish":"Doğru birşekilde, tam olarak, kesin olarak.","definition":"In a way that is correct in all details; exactly.","examples":["The witness described the event accurately.","It is important to measure the ingredients accurately."]},{"word":"accusation","level":"C1","type":"n.","turkish":"Suçlama, itham.","definition":"A charge or claim that someone has done something illegal or wrong.","examples":["He denied the accusations against him.","The politician faced serious accusations of corruption."]},{"word":"accused","level":"C1","type":"n.","turkish":"Sanık, suçlanan kişi.","definition":"A person or group of people who are charged with or on trial for a crime.","examples":["The accused pleaded not guilty in court.","The lawyer presented evidence to defend the accused."]},{"word":"acid","level":"B2","type":"n.","turkish":"(n) Asit; (adj) Asidik, ekşi.","definition":"(n) A chemical substance, usually a liquid, which contains hydrogen and can react with other substances to form salts. (adj) Containing acid or having the properties of an acid; having a pH of less than 7; sharp-tasting or sour.","examples":["Lemon juice contains citric acid. (noun) The soil in this region is too acid for some plants. (adjective)"]},{"word":"acquisition","level":"C1","type":"n.","turkish":"Edinme, kazanma, satın alma (genellikleşirket vb.).","definition":"An asset or object bought or obtained; the learning or developing of a skill, habit, or quality; the buying of one company by another.","examples":["The museum's latest acquisition is a 17th -century painting.","The company announced the acquisition of its main competitor."]},{"word":"acre","level":"B2","type":"n.","turkish":"Dönüm (yaklaşık 4047 metrekarelik araziölçü birimi).","definition":"A unit of land area equal to 4,840 square yards (0.405 hectare).","examples":["They bought a house with ten acres of land.","The farmer cultivates wheat on his 50 -acre farm."]},{"word":"activate","level":"B2","type":"v.","turkish":"Etkinleştirmek,çalıştırmak, faaliyete geçirmek.","definition":"To make (something) active or operative.","examples":["You need to enter a code to activate the software.","The smoke detector was activated by the steam."]},{"word":"activation","level":"C1","type":"n.","turkish":"Etkinleştirme, aktivasyon, faaliyete geçirme.","definition":"The action or process of making something active or operative.","examples":["Account activation requires email verification.","The activation of the alarm system scared the burglars away."]},{"word":"activist","level":"C1","type":"n.","turkish":"Aktivist, eylemci.","definition":"A person who campaigns to bring about political or social change.","examples":["Environmental activists protested against the new factory.","She has been a human rights activist for many years."]},{"word":"acute","level":"C1","type":"adj.","turkish":"Şiddetli, keskin (ağrı, duygu vb.); dar (açı); (hastalık) akut.","definition":"(of a bad, difficult, or unwelcome situation or phenomenon) Present or experienced to a severe or intense degree ; (of an angle) less than 90 degrees; (of a disease or its symptoms) of short duration but typically severe.","examples":["He suffered from acute back pain.","There is an acute shortage of doctors in the region."]},{"word":"adaptation","level":"C1","type":"n.","turkish":"Adaptasyon, uyarlama, uyum sağlama.","definition":"The action or process of adapting or being adapted; a movie, television drama, or stage play that has been adapted from a written work.","examples":["Adaptation to a new environment can be challenging.","The film is a successful adaptation of the novel."]},{"word":"addiction","level":"B2","type":"n.","turkish":"Bağımlılık.","definition":"The fact or condition of being addicted to a particular substance, thing, or activity.","examples":["He sought help for his gambling addiction.","Drug addiction affects people from all walks of life."]},{"word":"additionally","level":"B2","type":"adv.","turkish":"Ek olarak, ayrıca, bunun yanı sıra.","definition":"As an extra factor or circumstance; furthermore.","examples":["The hotel offers free breakfast.","Additionally, guests can use the gym."]},{"word":"adequate","level":"B2","type":"adj.","turkish":"Yeterli, kafi, uygun.","definition":"Satisfactory or acceptable in quality or quantity.","examples":["The food supplies were not adequate for the long journey.","Ensure you have adequate insurance coverage before traveling."]},{"word":"adequately","level":"B2","type":"adv.","turkish":"Yeterli birşekilde, layıkıyla.","definition":"To a satisfactory or acceptable extent.","examples":["Are the students adequately prepared for the exam?","The issue was not adequately addressed in the meeting."]},{"word":"adhere","level":"C1","type":"v.","turkish":"Yapışmak; bağlı kalmak (kural, inanç vb.).","definition":"To stick fast to (a surface or substance); believe in and follow the practices of.","examples":["The sticker didn't adhere to the wet surface.","All members must adhere to the club's rules."]},{"word":"adjacent","level":"C1","type":"adj.","turkish":"Bitişik, komşu, yan yana.","definition":"Next to or adjoining something else.","examples":["They live in the house adjacent to ours.","The park is adjacent to the river."]},{"word":"adjust","level":"B2","type":"v.","turkish":"Ayarlamak, uyarlamak, alıştırmak.","definition":"To alter or move (something) slightly in order to achieve the desired fit, appearance, or result; adapt or become used to new conditions.","examples":["You may need to adjust the settings on your camera.","It took her a while to adjust to living in a big city."]},{"word":"adjustment","level":"C1","type":"n.","turkish":"Ayarlama, ayarlama, uyum, intibak.","definition":"A small alteration or movement made to achieve a desired fit, appearance, or result; the process of adapting or becoming used to new conditions.","examples":["I made a slight adjustment to the mirror.","The adjustment to the new school was difficult for the child."]},{"word":"administer","level":"C1","type":"v.","turkish":"Yönetmek, idare etmek; (ilaç vb.) vermek, uygulamak.","definition":"To manage and be responsible for the running of (a business, organization, etc.) ; dispense or apply (a remedy or drug).","examples":["The agency is responsible for administering the funds.","The nurse will administer the medication."]},{"word":"administrative","level":"C1","type":"adj.","turkish":"İdari, yönetimsel.","definition":"Relating to the running of a business, organization, etc.; relating to management or administration.","examples":["She works in an administrative role at the university.","The job involves a lot of administrative tasks."]},{"word":"administrator","level":"C1","type":"n.","turkish":"Yönetici, idareci.","definition":"A person responsible for running a business, organization, etc.","examples":["The hospital administrator manages the day -to-day operations.","He worked as a network administrator for a tech company."]},{"word":"admission","level":"C1","type":"n.","turkish":"Kabul (okul, kulüp vb.); giriş izni, giriş ücreti; itiraf.","definition":"The process or fact of entering or being allowed to enter a place, organization, or institution; a statement acknowledging the truth of something.","examples":["Admission to the museum is free on Sundays.","His silence was taken as an admission of guilt."]},{"word":"adolescent","level":"C1","type":"n.","turkish":"Ergen, genç (genellikle 10 -19 yaş arası).","definition":"A young person who is developing into an adult.","examples":["The book is aimed at adolescents and young adults.","Navigating the challenges of being an adolescent can be tough."]},{"word":"adoption","level":"C1","type":"n.","turkish":"Evlat edinme; benimseme (fikir, yöntem vb.).","definition":"The action or fact of legally taking another's child and bringing it up as one's own; the action or fact of choosing to take up, follow, or use something.","examples":["They decided to go through the process of adoption.","The adoption of new technology has increased efficiency."]},{"word":"adverse","level":"C1","type":"adj.","turkish":"Olumsuz, ters, aksi, zıt.","definition":"Preventing success or development; harmful; unfavorable.","examples":["The project was cancelled due to adverse weather conditions.","Some patients experience adverse side effects from the medication."]},{"word":"advocate","level":"C1","type":"n.","turkish":"(n) Savunucu, destekçi, avukat; (v) Savunmak, desteklemek.","definition":"(n) A person who publicly supports or recommends a particular cause or policy; a person who pleads on someone else's behalf. (v) To publicly recommend or support.","examples":["She is a strong advocate for women's rights. (noun) Doctors advocate regular exercise for good health. (verb)"]},{"word":"aesthetic","level":"C1","type":"adj.","turkish":"Estetik, güzellikle ilgili.","definition":"Concerned with beauty or the appreciation of beauty.","examples":["The new building has a pleasing aesthetic design.","The furniture was chosen more for its aesthetic value than its comfort."]},{"word":"affection","level":"C1","type":"n.","turkish":"Sevgi,şefkat, düşkünlük.","definition":"A gentle feeling of fondness or liking.","examples":["He shows great affection for his children.","The dog greeted its owner with obvious affection."]},{"word":"affordable","level":"B2","type":"adj.","turkish":"Satın alınabilir, uygun fiyatlı, bütçeye uygun.","definition":"Inexpensive; reasonably priced.","examples":["They are looking for affordable housing in the city center.","The company offers high -quality products at affordable prices."]},{"word":"aftermath","level":"C1","type":"n.","turkish":"Sonuç, akıbet (genellikle olumsuz bir olay sonrası).","definition":"The consequences or aftereffects of a significant unpleasant event.","examples":["In the aftermath of the earthquake, thousands were left homeless.","The country is still dealing with the aftermath of the war."]},{"word":"aged","level":"B2","type":"adj.","turkish":"Yaşlı; yaşlanmış, yıllanmış (şarap, peynir vb.).","definition":"Old; (of things like wine or cheese) having been allowed to mature or ripen.","examples":["The charity provides support for aged people living alone.","This cheese has been aged for two years."]},{"word":"aggression","level":"C1","type":"n.","turkish":"Saldırganlık, tecavüz.","definition":"Hostile or violent behavior or attitudes toward another; readiness to attack or confront.","examples":["The dog showed signs of aggression towards strangers.","Acts of aggression will not be tolerated."]},{"word":"agricultural","level":"C1","type":"adj.","turkish":"Tarımsal, zirai.","definition":"Relating to agriculture (farming).","examples":["The country's economy is heavily dependent on agricultural exports.","New agricultural techniques have increased crop yields."]},{"word":"agriculture","level":"B2","type":"n.","turkish":"Tarım, ziraat.","definition":"The science or practice of farming, including cultivation of the soil for the growing of crops and the rearing of animals to provide food, wool, and other products.","examples":["Agriculture is a vital industry in this region.","Advances in technology have transformed modern agriculture."]},{"word":"aide","level":"C1","type":"n.","turkish":"Yardımcı, asistan (genellikle politikacı veyaüst düzey yönetici için).","definition":"An assistant to an important person, especially a political leader.","examples":["The senator arrived with her chief aide.","A White House aide briefed the reporters."]},{"word":"alert","level":"C1","type":"v.","turkish":"(v) Uyarmak, alarma geçirmek; (n) Uyarı, alarm; (adj) Teyakkuzda, uyanık, dikkatli.","definition":"(v) To warn (someone) of a danger, threat, or problem; (n) The state of being watchful for possible danger; an alarm or warning; (adj) Quick to notice any unusual circumstances; watchful.","examples":["The system will alert you if there is a security breach. (verb) Security forces were on high alert following the incident. (noun) You need to stay alert while driving at night. (adjective)"]},{"word":"alien","level":"B2","type":"n.","turkish":"(n) Yabancı (başkaülkeden veya gezegenden gelen), uzaylı; (adj) Yabancı, ait olmayan, uzaylı.","definition":"(n) A foreigner, especially one who is not a naturalized citizen of the country where they are living; a hypothetical or fictional being from another world; (adj) Belonging to a foreign country or nation; unfamiliar and disturbing or distasteful.","examples":["The movie features an encounter with friendly aliens. (noun) The feeling of being in a completely alien culture was overwhelming at first. (adjective)"]},{"word":"align","level":"C1","type":"v.","turkish":"Hizalamak, aynı hizaya getirmek; (mecazi) aynıçizgiye getirmek, uyumlu hale getirmek.","definition":"To place or arrange (things) in a straight line; give support to (a party, cause, or person).","examples":["Make sure to align the edges of the paper before cutting.","The company needs to align its goals with its resources."]},{"word":"alignment","level":"C1","type":"n.","turkish":"Hizalama, sıra; (mecazi) uyum, iş birliği.","definition":"Arrangement in a straight line, or in correct relative positions; a position of agreement or alliance.","examples":["The wheels of the car need alignment.","There is a strong alignment between the two political parties on this issue."]},{"word":"alike","level":"C1","type":"adv.","turkish":"(adv) Benzerşekilde; (adj) Benzer, farksız.","definition":"(adv) In a similar way; (adj) (of two or more people or things) Similar to each other.","examples":["Great minds think alike. (adverb) The twins look very alike. (adjective)"]},{"word":"allegation","level":"C1","type":"n.","turkish":"İddia, suçlama (genellikle kanıtsız).","definition":"A claim or assertion that someone has done something illegal or wrong, typically one made without proof.","examples":["He strongly denied the allegations of fraud.","The newspaper published serious allegations against the minister."]},{"word":"allege","level":"C1","type":"v.","turkish":"İddia etmek, ileri sürmek (genellikle kanıtsız).","definition":"To claim or assert that someone has done something illegal or wrong, typically without proof.","examples":["The prosecution alleges that he stole the money.","It was alleged that the company had ignored safety regulations."]},{"word":"allegedly","level":"C1","type":"adv.","turkish":"İddiaya göre, söylendiğine göre.","definition":"Used to convey that something is claimed to be the case or have taken place, although there is no proof.","examples":["He was allegedly involved in the robbery.","The documents were allegedly stolen from his office."]},{"word":"alliance","level":"C1","type":"n.","turkish":"İttifak, birlik, anlaşma.","definition":"A union or association formed for mutual benefit, especially between countries or organizations.","examples":["The two countries formed a military alliance.","The company entered into a strategic alliance with a competitor."]},{"word":"allocate","level":"C1","type":"v.","turkish":"Tahsis etmek, ayırmak, paylaştırmak (kaynak, görev vb.).","definition":"To distribute (resources or duties) for a particular purpose.","examples":["The government must allocate more funding for education.","The manager will allocate tasks to each team member."]},{"word":"allocation","level":"C1","type":"n.","turkish":"Tahsis, ayırma, paylaştırma.","definition":"The action or process of allocating or distributing something.","examples":["The allocation of resources was carefully planned.","We need to review the budget allocation for the next fiscal year."]},{"word":"allowance","level":"C1","type":"n.","turkish":"Harçlık;ödenek, tahsisat; izin verilen miktar, pay; hoşgörü, müsamaha.","definition":"The amount of something that is permitted, especially within a set of regulations or for a specified purpose; a sum of money paid regularly to a person, often a child; tolerance.","examples":["My parents gave me a weekly allowance when I was a kid.","The baggage allowance on this flight is 20 kilograms."]},{"word":"ally","level":"C1","type":"n.","turkish":"Müttefik, dost (ülke, kişi vb.).","definition":"A state formally cooperating with another for a military or other purpose; a person or organization that cooperates with or helps another in a particular activity.","examples":["During the war, France and Britain were allies.","She found a strong ally in her fight for equal rights."]},{"word":"alongside","level":"B2","type":"prep.","turkish":"Yanına, yanında, yanı sıra, birlikte.","definition":"Close beside, next to, or touching; together or in cooperation with.","examples":["A police car pulled up alongside us.","She worked alongside her colleagues on the project."]},{"word":"altogether","level":"B2","type":"adv.","turkish":"Tamamen, bütünüyle; toplamda, hepsi birden.","definition":"Completely; totally; on the whole.","examples":["I'm not altogether sure that's the best idea.","That will be $50 altogether. aluminum (n."]},{"word":"amateur","level":"C1","type":"adj.","turkish":"(adj) Amatör, meraklı, acemi; (n) Amatör, hevesli.","definition":"(adj) Engaging or engaged in without payment; nonprofessional; (n) One who engages in an activity as a pastime rather than a profession.","examples":["He is an amateur photographer. (adjective) The play was performed by a group of local amateurs. (noun)"]},{"word":"ambassador","level":"C1","type":"n.","turkish":"Büyükelçi, elçi.","definition":"An accredited diplomat sent by a country as its official representative to a foreign country.","examples":["The Turkish ambassador to the United States attended the meeting.","She served as the French ambassador in London."]},{"word":"ambitious","level":"B2","type":"adj.","turkish":"Hırslı, iddialı, tutkulu.","definition":"Having or showing a strong desire and determination to succeed.","examples":["She is a very ambitious young lawyer.","The company has ambitious plans for expansion."]},{"word":"ambulance","level":"B2","type":"n.","turkish":"Ambulans, cankurtaran.","definition":"A vehicle specially equipped for taking sick or injured people to and from the hospital.","examples":["Call an ambulance immediately!","The injured cyclist was taken to the hospital by ambulance."]},{"word":"amend","level":"C1","type":"v.","turkish":"Değiştirmek, düzeltmek (yasa, belge vb.).","definition":"To make minor changes in (a text) in order to make it fairer, more accurate, or more up to-date.","examples":["Parliament voted to amend the law.","The contract needs to be amended to include the new terms."]},{"word":"amendment","level":"C1","type":"n.","turkish":"Değişiklik, düzeltme (yasa, belge vb.).","definition":"A minor change or addition designed to improve a text, piece of legislation, etc.","examples":["Several amendments were made to the constitution.","The committee proposed an amendment to the bill. amid (prep."]},{"word":"amusing","level":"B2","type":"adj.","turkish":"Eğlenceli, komik, güldürücü.","definition":"Causing laughter and providing entertainment.","examples":["He told us an amusing story about his childhood.","I found the comedian's performance quite amusing."]},{"word":"analogy","level":"C1","type":"n.","turkish":"Analoji, benzetme, karşılaştırma.","definition":"A comparison between two things, typically for the purpose of explanation or clarification.","examples":["He drew an analogy between the human heart and a pump.","The teacher used a simple analogy to explain the complex concept."]},{"word":"analyst","level":"B2","type":"n.","turkish":"Analist,çözümleyici, tahlilci.","definition":"A person who conducts analysis.","examples":["Financial analysts predict a rise in stock prices.","The data analyst presented her findings to the team."]},{"word":"ancestor","level":"B2","type":"n.","turkish":"Ata, soy, cet.","definition":"A person, typically one more remote than a grandparent, from whom one is descended.","examples":["My ancestors came from Ireland.","Archaeologists discovered the remains of our early human ancestors."]},{"word":"anchor","level":"C1","type":"n.","turkish":"Çapa, demir; (TV/radyo) sunucu, spiker; (mecazi) dayanak noktası, güvence.","definition":"A heavy object attached to a rope or chain and used to moor a vessel to the seabed; a person who presents and coordinates a television or radio program; a source of stability or security.","examples":["The ship dropped anchor in the bay.","She is the main news anchor for the evening broadcast."]},{"word":"angel","level":"C1","type":"n.","turkish":"Melek.","definition":"A spiritual being believed to act as an attendant, agent, or messenger of God, conventionally represented in human form with wings.","examples":["Children often draw pictures of angels with wings and halos.","She was described as a guardian angel for her kindness."]},{"word":"animation","level":"B2","type":"n.","turkish":"Animasyon, canlandırma; canlılık, coşku.","definition":"The technique of photographing successive drawings or positions of puppets or models to create an illusion of movement when the movie is shown as a sequence; the state of being full of life or vigor; liveliness.","examples":["Computer animation is used extensively in modern films.","She spoke with great animation about her trip."]},{"word":"annually","level":"B2","type":"adv.","turkish":"Yılda bir, yıllık olarak.","definition":"Once a year; every year.","examples":["The festival takes place annually in July.","Salaries are reviewed annually."]},{"word":"anonymous","level":"C1","type":"adj.","turkish":"Anonim, ismi bilinmeyen, kimliği belirsiz.","definition":"(of a person) Not identified by name; of unknown name.","examples":["An anonymous donor contributed a large sum to the charity.","The author wished to remain anonymous."]},{"word":"anticipate","level":"B2","type":"v.","turkish":"Beklemek, ummak, tahmin etmek, öngörmek.","definition":"To regard as probable; expect or predict; look forward to.","examples":["We anticipate that sales will increase next quarter.","She eagerly anticipated her vacation."]},{"word":"anxiety","level":"B2","type":"n.","turkish":"Endişe, kaygı, anksiyete.","definition":"A feeling of worry, nervousness, or unease, typically about an imminent event or something with an uncertain outcome.","examples":["Exam anxiety is common among students.","He suffers from chronic anxiety."]},{"word":"apology","level":"B2","type":"n.","turkish":"Özür, af dileme.","definition":"A regretful acknowledgment of an offense or failure.","examples":["Please accept my sincere apology for the mistake.","He made a public apology for his remarks."]},{"word":"apparatus","level":"C1","type":"n.","turkish":"Aygıt, cihaz, aparat; düzenek, sistem (organizasyon vb.).","definition":"The technical equipment or machinery needed for a particular activity or purpose; a complex structure within an organization or system.","examples":["The laboratory is equipped with sophisticated scientific apparatus.","The complex apparatus of government bureaucracy can be slow. apparel (n."]},{"word":"appealing","level":"C1","type":"adj.","turkish":"Çekici, cazip, hoş.","definition":"Attractive or interesting.","examples":["The idea of working from home is very appealing to many people.","The brightly colored packaging makes the product visually appealing."]},{"word":"appetite","level":"C1","type":"n.","turkish":"İştah; (mecazi) arzu, istek.","definition":"A natural desire to satisfy a bodily need, especially for food; a strong desire or liking for something.","examples":["Exercise can increase your appetite.","He has an insatiable appetite for knowledge."]},{"word":"applaud","level":"C1","type":"v.","turkish":"Alkışlamak; (mecazi) takdir etmek, övmek.","definition":"To show approval or praise by clapping; show approval of (an action or idea).","examples":["The audience applauded loudly at the end of the performance.","We applaud the decision to invest in renewable energy."]},{"word":"applicable","level":"C1","type":"adj.","turkish":"Uygulanabilir, ilgili, geçerli.","definition":"Relevant or appropriate.","examples":["Please fill out the applicable sections of the form.","The discount is only applicable to students."]},{"word":"applicant","level":"B2","type":"n.","turkish":"Başvuru sahibi, aday, talip.","definition":"A person who makes a formal application for something, especially a job.","examples":["There were over 100 applicants for the position.","Successful applicants will be notified by email."]},{"word":"appoint","level":"C1","type":"v.","turkish":"Atamak, tayin etmek; kararlaştırmak (zaman, yer).","definition":"To assign a job or role to (someone); decide on and arrange (a time or place).","examples":["The company decided to appoint a new CEO.","They appointed a time for the next meeting."]},{"word":"appreciation","level":"C1","type":"n.","turkish":"Takdir, minnettarlık; değerini anlama; (değer) artışı.","definition":"Recognition and enjoyment of the good qualities of someone or something; gratitude; an increase in value.","examples":["She expressed her appreciation for all the help she received.","We have a deep appreciation for classical music."]},{"word":"appropriately","level":"B2","type":"adv.","turkish":"Uygun birşekilde, yerinde olarak.","definition":"In a manner that is suitable or proper in the circumstances.","examples":["Please dress appropriately for the formal event.","The situation was handled appropriately by the staff."]},{"word":"arbitrary","level":"C1","type":"adj.","turkish":"Keyfi, rastgele, nedensiz; (matematik) isteğe bağlı.","definition":"Based on random choice or personal whim, rather than any reason or system.","examples":["The selection process seemed completely arbitrary.","The dictator made arbitrary decisions without consulting anyone."]},{"word":"architectural","level":"C1","type":"adj.","turkish":"Mimari.","definition":"Relating to architecture (the art and practice of designing and constructing buildings).","examples":["The city is famous for its stunning architectural heritage.","He studied architectural design at university."]},{"word":"archive","level":"C1","type":"n.","turkish":"Arşiv, belge deposu.","definition":"A collection of historical documents or records providing information about a place, institution, or group of people.","examples":["Researchers often consult the national archive for historical data.","The library maintains an extensive archive of local newspapers."]},{"word":"arena","level":"C1","type":"n.","turkish":"Arena, alan, saha (spor, gösteri vb.); (mecazi) mücadele alanı, sahne.","definition":"A level area surrounded by seating, in which sports, entertainments, and other public events are held; a place or scene of activity, debate, or conflict.","examples":["The concert took place in a large indoor arena.","He entered the political arena with high hopes."]},{"word":"arm","level":"C1","type":"v.","turkish":"Silahlandırmak.","definition":"To supply or provide with weapons.","examples":["The rebels were heavily armed.","Police decided to arm themselves before entering the building."]},{"word":"array","level":"C1","type":"n.","turkish":"Dizi, sıra; (etkileyici) topluluk, gösteriş.","definition":"An impressive display or range of a particular type of thing; an ordered series or arrangement.","examples":["The store offers a wide array of electronic goods.","A vast array of solar panels covered the field."]},{"word":"arrow","level":"B2","type":"n.","turkish":"Ok; ok işareti.","definition":"A shaft sharpened at the front and flighted with feathers at the back, shot from a bow as a weapon or for sport; a mark or sign resembling an arrow, used to show direction or position.","examples":["Robin Hood was famous for his skill with a bow and arrow.","Follow the arrows to find the exit."]},{"word":"articulate","level":"C1","type":"v.","turkish":"Açık ve net ifade etmek, dile getirmek; (sesleri) telaffuz etmek.","definition":"To express (an idea or feeling) fluently and coherently; pronounce (something) clearly and distinctly.","examples":["She found it difficult to articulate her feelings.","He needs to articulate his words more clearly when speaking publicly."]},{"word":"artwork","level":"B2","type":"n.","turkish":"Sanat eseri, sanatçalışması.","definition":"Illustrations, photographs, or other nontextual material prepared for inclusion in a publication; works of art collectively.","examples":["The museum displayed impressive artwork from local artists.","The book includes beautiful color artwork."]},{"word":"ash","level":"C1","type":"n.","turkish":"Kül.","definition":"The powdery residue left after the burning of a substance.","examples":["Volcanic ash covered the town after the eruption.","He flicked the cigarette ash into the ashtray."]},{"word":"aspiration","level":"C1","type":"n.","turkish":"Güçlü arzu, emel, hedef,özlem.","definition":"A hope or ambition of achieving something.","examples":["His main aspiration was to become a successful writer.","She has political aspirations and plans to run for office."]},{"word":"aspire","level":"C1","type":"v.","turkish":"Şiddetle arzu etmek, hedeflemek, talip olmak.","definition":"To direct one's hopes or ambitions toward achieving something.","examples":["Many young athletes aspire to compete in the Olympics.","He aspires to a career in medicine."]},{"word":"assassination","level":"C1","type":"n.","turkish":"Suikast.","definition":"The action of assassinating (murdering an important person for political or religious reasons).","examples":["The assassination of the president shocked the world.","There was a failed assassination attempt on the prime minister."]},{"word":"assault","level":"C1","type":"n.","turkish":"(n) Saldırı, hücum; darp; (v) Saldırmak, hücum etmek; darp etmek.","definition":"(n) A physical attack; (v) To make a physical attack on.","examples":["He was charged with assault after the fight. (noun) The soldiers assaulted the enemy fortress at dawn. (verb)"]},{"word":"assemble","level":"C1","type":"v.","turkish":"Toplamak, bir araya getirmek; (parçaları) birleştirmek, monte etmek.","definition":"To gather together in one place for a common purpose; fit together the component parts of (a machine or other object).","examples":["The students were asked to assemble in the main hall.","It took several hours to assemble the new furniture."]},{"word":"assembly","level":"C1","type":"n.","turkish":"Montaj; toplantı, kurul; bir araya gelme.","definition":"The action of fitting together the component parts of a machine or other object; a group of people gathered together in one place for a common purpose.","examples":["The final assembly of the car takes place at this factory.","All students are required to attend the school assembly on Friday mornings."]},{"word":"assert","level":"C1","type":"v.","turkish":"İddia etmek,öne sürmek, (hakkını/yetkisini) savunmak.","definition":"To state a fact or belief confidently and forcefully; cause others to recognize (one's authority or a right) by confident and forceful behavior.","examples":["He continued to assert his innocence despite the evidence against him.","You need to assert yourself more in meetings."]},{"word":"assertion","level":"C1","type":"n.","turkish":"İddia, beyan, sav.","definition":"A confident and forceful statement of fact or belief.","examples":["The lawyer challenged the assertion made by the witness.","Her assertion that she was the best candidate for the job was bold."]},{"word":"asset","level":"B2","type":"n.","turkish":"Varlık, mal varlığı; değerlişey, avantaj.","definition":"A useful or valuable thing, person, or quality; property owned by a person or company, regarded as having value.","examples":["Her language skills are a real asset to the team.","The company's total assets are listed in the annual report."]},{"word":"assign","level":"B2","type":"v.","turkish":"Atamak, görevlendirmek, tahsis etmek; (ödev vb.) vermek.","definition":"To allocate (a job or duty); designate or set (something) aside for a specific purpose.","examples":["The teacher will assign homework at the end of the class.","Each team member was assigned a specific role in the project."]},{"word":"assistance","level":"B2","type":"n.","turkish":"Yardım, destek.","definition":"The action of helping someone with a job or task.","examples":["Can I be of any assistance?","They requested financial assistance from the government."]},{"word":"assumption","level":"B2","type":"n.","turkish":"Varsayım, farz etme, tahmin.","definition":"A thing that is accepted as true or as certain to happen, without proof.","examples":["We are working on the assumption that the project will be completed by Friday.","It's dangerous to make assumptions about people you don't know."]},{"word":"assurance","level":"C1","type":"n.","turkish":"Güvence, teminat; kendine güven, emin olma.","definition":"A positive declaration intended to give confidence; a promise; confidence or certainty in one's own abilities.","examples":["He gave me his assurance that the work would be finished on time.","She spoke with quiet assurance about her plans for the future."]},{"word":"assure","level":"B2","type":"v.","turkish":"Güvence vermek, temin etmek, garanti etmek.","definition":"To tell someone confidently that something is true, especially so that they do not worry; make (something) certain to happen.","examples":["I can assure you that you will be satisfied with the results.","The captain assured the passengers that the turbulence was normal."]},{"word":"astonishing","level":"B2","type":"adj.","turkish":"Şaşırtıcı, hayret verici.","definition":"Extremely surprising or impressive; amazing.","examples":["The magician performed some astonishing tricks.","It is astonishing how quickly technology has advanced."]},{"word":"asylum","level":"C1","type":"n.","turkish":"Sığınma, iltica; akıl hastanesi (eski kullanım).","definition":"The protection granted by a nation to someone who has left their native country as a political refugee; an institution offering shelter and support to people who are mentally ill (dated term).","examples":["Many people seek political asylum in other countries due to persecution.","He applied for asylum after fleeing the war -torn region."]},{"word":"athletic","level":"B2","type":"adj.","turkish":"Atletik, sporla ilgili, sportmen.","definition":"Physically strong, fit, and active; relating to or characteristic of athletes or athletics.","examples":["She comes from a very athletic family.","The school has excellent athletic facilities."]},{"word":"atrocity","level":"C1","type":"n.","turkish":"Vahşet, mezalim, gaddarlık.","definition":"An extremely wicked or cruel act, typically one involving physical violence or injury.","examples":["The dictator was responsible for numerous atrocities against his own people.","War atrocities were documented by international observers."]},{"word":"attachment","level":"B2","type":"n.","turkish":"Ek (e-posta vb.); bağlılık, sevgi; takılan parça, aksesuar.","definition":"An extra part or extension that is or can be attached to something; affection, fondness, or sympathy for someone or something; a file sent with an email.","examples":["Please find the report as an attachment to this email.","He has a strong emotional attachment to his childhood home."]},{"word":"attain","level":"C1","type":"v.","turkish":"Ulaşmak, elde etmek, erişmek (hedef, seviye vb.).","definition":"To succeed in achieving (something that one desires and has worked for).","examples":["She worked hard to attain her goal of becoming a doctor.","He hopes to attain a high level of proficiency in English."]},{"word":"attendance","level":"C1","type":"n.","turkish":"Katılım, devam, hazır bulunma; katılanların sayısı.","definition":"The action or state of going regularly to or being present at a place or event; the number of people present at a particular place or event.","examples":["Regular attendance at school is mandatory.","Attendance at the concert exceeded expectations."]},{"word":"attribute","level":"C1","type":"v.","turkish":"(v) Atfetmek, -e yormak, bağlamak; (n) Nitelik,özellik, sıfat.","definition":"(v) To regard something as being caused by (someone or something); (n) A quality or feature regarded as a characteristic or inherent part of someone or something.","examples":["He attributes his success to hard work and determination. (verb) Patience is an important attribute for a teacher. (noun)"]},{"word":"auction","level":"C1","type":"n.","turkish":"Açık artırma, müzayede.","definition":"A public sale in which goods or property are sold to the highest bidder.","examples":["The painting was sold at auction for over a million dollars.","They bought their new house at a property auction."]},{"word":"audio","level":"B2","type":"adj.","turkish":"Sesle ilgili, işitsel.","definition":"Relating to sound or its recording and reproduction.","examples":["The presentation included both visual and audio elements.","Please check your audio settings before the online meeting."]},{"word":"audit","level":"C1","type":"n.","turkish":"Denetim, hesap denetimi, teftiş.","definition":"An official inspection of an organization's accounts, typically by an independent body.","examples":["The company undergoes an external audit every year.","An internal audit revealed some inconsistencies in the records."]},{"word":"authentic","level":"C1","type":"adj.","turkish":"Otantik, gerçek, asıl, hakiki.","definition":"Of undisputed origin; genuine.","examples":["The restaurant serves authentic Italian cuisine.","Experts confirmed that the signature was authentic."]},{"word":"authorize","level":"C1","type":"v.","turkish":"Yetki vermek, izin vermek, onaylamak.","definition":"To give official permission for or approval to (an action or agent).","examples":["Only managers can authorize expenditures over $1000.","The government authorized the use of the new vaccine. auto (n."]},{"word":"autonomy","level":"C1","type":"n.","turkish":"Özerklik, otonomi, bağımsızlık.","definition":"The right or condition of self government; freedom from external control or influence; independence.","examples":["The region was granted greater autonomy after the referendum.","Teachers are given considerable autonomy in how they structure their lessons. autumn (n."]},{"word":"availability","level":"C1","type":"n.","turkish":"Mevcudiyet, bulunabilirlik, uygunluk (zaman açısından).","definition":"The quality of being able to be used or obtained; the state of being free to do something.","examples":["Please check the availability of rooms before booking the hotel.","Can you confirm your availability for a meeting next week? await (v."]},{"word":"awareness","level":"B2","type":"n.","turkish":"Farkındalık, bilinç.","definition":"Knowledge or perception of a situation or fact.","examples":["The campaign aims to raise public awareness about environmental issues.","There is a growing awareness of the importance of mental health."]},{"word":"awkward","level":"B2","type":"adj.","turkish":"Garip, tuhaf, biçimsiz; sıkıntılı, utanç verici (durum); sakar.","definition":"Causing difficulty; hard to do or deal with; causing or feeling embarrassment or inconvenience; clumsy.","examples":["There was an awkward silence after he asked the question.","He felt awkward asking for money."]},{"word":"backdrop","level":"C1","type":"n.","turkish":"Fon, arka plan (sahne, olay vb.).","definition":"The setting or background for a scene, event, or situation.","examples":["The mountains provided a stunning backdrop for the wedding photos.","Against the backdrop of economic recession,"]},{"word":"backing","level":"C1","type":"n.","turkish":"Destek (mali, manevi vb.), arkaçıkma.","definition":"Help or support; financial support.","examples":["The project received financial backing from several investors.","She couldn't have succeeded without the backing of her family."]},{"word":"backup","level":"C1","type":"n.","turkish":"Yedek, yedekleme (veri vb.); destek (kişi, plan).","definition":"Help or support; a copy of a file or other item of data made in case the original is lost or damaged; a person or thing that can be used or prepared for use as a substitute.","examples":["It's crucial to make regular backups of your important files.","The police called for backup when the situation escalated."]},{"word":"badge","level":"B2","type":"n.","turkish":"Rozet, yaka kartı, kimlik kartı.","definition":"A small piece of metal, plastic, or cloth bearing a design or words, typically worn to identify a person or indicate membership or support.","examples":["All employees must wear their identification badges at all times.","He proudly wore the conference badge around his neck."]},{"word":"bail","level":"C1","type":"n.","turkish":"Kefalet (mahkeme).","definition":"The temporary release of an accused person awaiting trial, sometimes on condition that a sum of money be lodged to guarantee their appearance in court.","examples":["The judge set bail at $10,000.","He was released on bail pending trial."]},{"word":"balanced","level":"B2","type":"adj.","turkish":"Dengeli,ölçülü.","definition":"Keeping or showing a balance; arranged in good proportions; taking everything into account; fairly judged or presented.","examples":["It's important to eat a balanced diet.","The news report provided a balanced view of the situation."]},{"word":"ballet","level":"B2","type":"n.","turkish":"Bale.","definition":"An artistic dance form performed to music using precise and highly formalized set steps and gestures.","examples":["She has been taking ballet lessons since she was five.","We went to see a performance of the Swan Lake ballet."]},{"word":"balloon","level":"B2","type":"n.","turkish":"Balon.","definition":"A flexible bag inflated with a gas, such as air or helium, typically used as a toy or a decoration.","examples":["Colorful balloons decorated the room for the party.","The hot air balloon floated gently across the sky."]},{"word":"ballot","level":"C1","type":"n.","turkish":"Oy pusulası; oylama, seçim.","definition":"A process of voting, in writing and typically in secret; the piece of paper used in voting.","examples":["Voters cast their ballots at the polling station.","The winner was decided by secret ballot."]},{"word":"bankruptcy","level":"C1","type":"n.","turkish":"İflas.","definition":"The state of being bankrupt (declared in law unable to pay outstanding debts).","examples":["The company was forced to file for bankruptcy.","Poor financial management led to the bankruptcy of the business."]},{"word":"banner","level":"C1","type":"n.","turkish":"Pankart, afiş, bayrak.","definition":"A long strip of cloth bearing a slogan or design, hung in a public place or carried in a demonstration or procession.","examples":["Protesters carried banners demanding change.","A large banner welcoming the team hung across the stadium entrance."]},{"word":"bare","level":"C1","type":"adj.","turkish":"Çıplak, yalın, boş; temel, asgari.","definition":"Not clothed or covered; basic or essential; without addition; basic and simple.","examples":["He walked on the beach with bare feet.","The room was bare, with only a bed and a chair."]},{"word":"barely","level":"B2","type":"adv.","turkish":"Zar zor, ancak, güçlükle.","definition":"Only just; almost not.","examples":["He was so tired he could barely keep his eyes open.","There was barely enough food for everyone."]},{"word":"bargain","level":"B2","type":"n.","turkish":"Pazarlık; kelepir, ucuz eşya.","definition":"An agreement between two or more people or groups as to what each will do for the other; a thing bought or offered for sale much more cheaply than is usual or expected.","examples":["After some negotiation, they struck a bargain.","This coat was a real bargain at half price."]},{"word":"barrel","level":"C1","type":"n.","turkish":"Varil, fıçı; namlu (silah).","definition":"A cylindrical container bulging out in the middle, traditionally made of wooden staves with metal hoops; a tube forming part of a gun.","examples":["Oil is often stored and transported in large barrels.","He cleaned the barrel of his rifle."]},{"word":"basement","level":"B2","type":"n.","turkish":"Bodrum katı, bodrum.","definition":"The floor of a building partly or entirely below ground level.","examples":["We store our old furniture in the basement.","The house has a finished basement with a game room."]},{"word":"basket","level":"B2","type":"n.","turkish":"Sepet; pota (basketbol).","definition":"A container used to hold or carry things, typically made from interwoven strips of cane or wire; (in basketball) a net fixed on a hoop used as the goal.","examples":["She carried a basket full of fresh fruit.","He scored the winning basket just before the buzzer. bass¹ (n."]},{"word":"bat","level":"B2","type":"n.","turkish":"(n) Yarasa; sopa (beyzbol, kriket vb.); (v) Sopayla vurmak (topa).","definition":"(n) A nocturnal mouselike mammal with wings; an implement with a handle and a solid surface, typically of wood, used for hitting the ball in games such as baseball, cricket, and table tennis; (v) To strike (a ball) with a bat.","examples":["We saw several bats flying around at dusk. (noun - animal) It's your turn to bat. (verb - sports)"]},{"word":"battlefield","level":"C1","type":"n.","turkish":"Savaş alanı, muharebe meydanı.","definition":"The piece of ground on which a battle is or was fought.","examples":["Many soldiers lost their lives on the battlefield.","The historians visited the ancient battlefield."]},{"word":"bay","level":"C1","type":"n.","turkish":"Koy, körfez; bölme, bölüm (park yeri, pencere vb.).","definition":"A broad inlet of the sea where the land curves inward; a recessed area or space.","examples":["The ship anchored in a secluded bay.","Please park your car in the designated bay."]},{"word":"beam","level":"C1","type":"n.","turkish":"Işın, hüzme (ışık); kiriş, direk (yapı); (geniş) gülümseme.","definition":"A ray or shaft of light; a long, sturdy piece of squared timber or metal spanning an opening or part of a building; a wide smile.","examples":["A beam of sunlight shone through the clouds. (light) The old house had exposed wooden beams in the ceiling. (structure)"]},{"word":"beast","level":"C1","type":"n.","turkish":"Canavar, hayvan (özellikle büyük veya vahşi).","definition":"An animal, especially a large or dangerous four-footed one.","examples":["The lion is often called the king of beasts.","Legends tell of a mythical beast living in the forest. behalf (n."]},{"word":"behavioral","level":"C1","type":"adj.","turkish":"Davranışsal.","definition":"Involving, relating to, or emphasizing behavior.","examples":["The study focused on the behavioral patterns of chimpanzees.","He is receiving behavioral therapy to manage his anger issues."]},{"word":"beloved","level":"C1","type":"adj.","turkish":"Sevgili, sevilen, aziz.","definition":"Dearly loved.","examples":["He lost his beloved wife last year.","The town gathered to remember their beloved former mayor."]},{"word":"bench","level":"C1","type":"n.","turkish":"Sıra, bank; tezgah (çalışma); (mahkeme) yargıç kürsüsü, yargıçlar; (spor) yedek kulübesi.","definition":"A long seat for several people, typically made of wood or metal; a workbench; the seat where a judge sits in court; (in sports) the reserve players.","examples":["They sat on a park bench enjoying the sunshine. (seat) The judge addressed the court from the bench. (court)"]},{"word":"benchmark","level":"C1","type":"n.","turkish":"Kıyaslama noktası,ölçüt, standart, referans noktası.","definition":"A standard or point of reference against which things may be compared or assessed.","examples":["The new software set a benchmark for performance in the industry.","We use customer satisfaction ratings as a key benchmark."]},{"word":"beneath","level":"C1","type":"prep.","turkish":"Altında, alt tarafında.","definition":"In or to a lower position than (something else); directly under it.","examples":["The keys were hidden beneath a pile of papers.","They found an old tunnel running beneath the city."]},{"word":"beneficial","level":"B2","type":"adj.","turkish":"Faydalı, yararlı, hayırlı.","definition":"Favorable or advantageous; resulting in good.","examples":["Regular exercise is beneficial for your health.","The new policy is expected to be beneficial to small businesses."]},{"word":"beneficiary","level":"C1","type":"n.","turkish":"Lehdar, hak sahibi, yararlanan kişi (miras, sigorta vb.).","definition":"A person who derives advantage from something, especially a trust, will, or life insurance policy.","examples":["He was the sole beneficiary of his uncle's will.","The charity provides support to its beneficiaries."]},{"word":"beside","level":"B2","type":"prep.","turkish":"Yanında, yanına.","definition":"At the side of; next to.","examples":["He sat beside her on the sofa.","There is a small table beside the bed."]},{"word":"besides","level":"B2","type":"prep.","turkish":"(prep) -den başka, haricinde; (adv) Ayrıca, bununla birlikte, hem de.","definition":"(prep) In addition to; apart from. (adv) In addition; as well.","examples":["What other sports do you play besides football? (preposition) I don't really want to go.","Besides, it's too late now. (adverb)"]},{"word":"betray","level":"C1","type":"v.","turkish":"İhanet etmek, aldatmak; (sır vb.) açığa vurmak, ele vermek.","definition":"To be disloyal to (a person, country, organization, or set of principles); unintentionally reveal; be evidence of.","examples":["He felt that she had betrayed his trust.","His nervous smile betrayed his anxiety. beverage (n."]},{"word":"bias","level":"B2","type":"n.","turkish":"Ön yargı, eğilim, taraf tutma.","definition":"Prejudice in favor of or against one thing, person, or group compared with another, usually in a way considered to be unfair.","examples":["The news channel was accused of political bias.","It's important to avoid bias in scientific research."]},{"word":"bid","level":"B2","type":"n.","turkish":"(n) Teklif (özellikle açık artırmada veya ihalede), girişim; (v) Teklif vermek, fiyat vermek; (mecaz","definition":"(n) An offer of a particular price for something, especially at an auction; an attempt or effort to achieve something. (v) To offer (a particular price) for something, especially at an auction; make an effort or attempt to achieve.","examples":["She made the highest bid for the painting at the auction. (noun) Several companies are expected to bid for the contract. (verb)"]},{"word":"bind","level":"C1","type":"v.","turkish":"Bağlamak (iple vb.); ciltlemek (kitap); (mecazi) birleştirmek, zorunlu kılmak.","definition":"To tie or fasten (something) tightly; impose a legal or moral obligation on; cause (people) to feel united.","examples":["They bound his hands together with rope.","Both parties are legally bound by the terms of the contract."]},{"word":"biography","level":"C1","type":"n.","turkish":"Biyografi, yaşamöyküsü.","definition":"An account of someone's life written by someone else.","examples":["He wrote a detailed biography of Winston Churchill.","I enjoy reading historical biographies."]},{"word":"biological","level":"B2","type":"adj.","turkish":"Biyolojik, yaşamsal.","definition":"Relating to biology or living organisms.","examples":["She decided to search for her biological parents.","All living things are governed by biological processes."]},{"word":"bishop","level":"C1","type":"n.","turkish":"Piskopos (Hristiyanlıkta); fil (satrançta).","definition":"A senior member of the Christian clergy, typically in charge of a diocese and empowered to confer holy orders; a chess piece, typically with a cleft mitre-shaped top, that can move any number of unoccupied squares diagonally.","examples":["The Bishop of Canterbury is the head of the Church of England.","In chess, the bishop moves diagonally across the board."]},{"word":"bizarre","level":"C1","type":"adj.","turkish":"Garip, tuhaf, acayip.","definition":"Very strange or unusual, especially so as to cause interest or amusement.","examples":["He told us a bizarre story about aliens landing in his garden.","The costumes for the play were quite bizarre."]},{"word":"blade","level":"C1","type":"n.","turkish":"Bıçak ağzı, kesici kısım (kılıç, makas, pervane vb.); (uzun, yassı) yaprak (ot vb.).","definition":"The flat cutting edge of a knife, sword, or other tool or weapon; a long, narrow leaf of grass or a similar plant.","examples":["Be careful, the blade of this knife is very sharp.","The helicopter's rotor blades started to turn."]},{"word":"blanket","level":"B2","type":"n.","turkish":"Battaniye; (mecazi)örtü, tabaka.","definition":"A covering made of wool or other fabric, used to keep a person warm in bed; a thick covering or layer of something.","examples":["It was cold, so I put an extra blanket on the bed.","A thick blanket of snow covered the ground."]},{"word":"blast","level":"C1","type":"n.","turkish":"(n) Patlama, infilak;şiddetli rüzgar; (müzik, ses) yüksek ses; (v) Patlatmak, havaya uçurmak; (ses)ç","definition":"(n) An explosion; a strong gust of wind; a sudden loud noise. (v) To blow up or break apart (something solid) with explosives; make a loud noise.","examples":["The bomb blast shattered windows nearby. (noun) Music was blasting from the speakers. (verb)"]},{"word":"bleed","level":"C1","type":"v.","turkish":"Kanamak; (renk) akmak, karışmak; (mecazi) sızdırmak (para vb.).","definition":"To lose blood from the body as a result of injury or illness; (of dye or color) seep into an adjacent color or area; draw off fluid or gas from (something).","examples":["His nose started to bleed after he fell.","The bright red color bled into the white fabric when it was washed."]},{"word":"blend","level":"C1","type":"v.","turkish":"(v) Karıştırmak, harmanlamak; uyum sağlamak, birbirine yakışmak; (n) Karışım, harman.","definition":"(v) To mix (a substance) with another substance so that they combine together; combine harmoniously. (n) A mixture of different substances or qualities.","examples":["Blend the ingredients together until smooth. (verb) The curtains blend perfectly with the carpet. (verb) This coffee is a blend of beans from Colombia and Brazil. (noun)"]},{"word":"bless","level":"C1","type":"v.","turkish":"Kutsamak, takdis etmek; hayır dua etmek; (Tanrı'dan) lütfetmek.","definition":"To pronounce words in a religious rite, invoking divine favor upon; confer prosperity or happiness upon.","examples":["The priest blessed the congregation.","May God bless you and keep you safe."]},{"word":"blessing","level":"C1","type":"n.","turkish":"Nimet, lütuf, Tanrı'nın lütfu; hayır dua; onay, rıza.","definition":"God's favor and protection; a prayer asking for divine favor and protection; something for which one is grateful; approval or permission.","examples":["Having good health is a true blessing.","They got married with their parents' blessing."]},{"word":"blow","level":"B2","type":"n.","turkish":"Darbe, vuruş; (mecazi)şok, kötü olay.","definition":"A powerful stroke with a hand, weapon, or hard object; a sudden shock or disappointment.","examples":["He received a heavy blow to the head.","Losing his job was a terrible blow to him."]},{"word":"boast","level":"C1","type":"v.","turkish":"Övünmek, böbürlenmek.","definition":"To talk with excessive pride and self-satisfaction about one's achievements, possessions, or abilities.","examples":["He's always boasting about how much money he earns.","She boasted that her son was a genius."]},{"word":"bold","level":"B2","type":"adj.","turkish":"Cesur, gözü pek; (yazı tipi) kalın; (renk, desen)çarpıcı, belirgin.","definition":"(of a person, action, or idea) Showing a willingness to take risks; confident and courageous; (of a color or design) Strong or vivid; (of type) Having thick strokes.","examples":["It was a bold decision to start her own business.","Please print the headings in bold type."]},{"word":"bombing","level":"B2","type":"n.","turkish":"Bombalama, bombalama eylemi.","definition":"An attack using one or more bombs.","examples":["The city suffered heavy bombing during the war.","Several people were injured in the terrorist bombing."]},{"word":"bonus","level":"C1","type":"n.","turkish":"İkramiye, prim; ekstradan verilenşey, avantaj.","definition":"A sum of money added to a person's wages as a reward for good performance; an extra benefit or advantage.","examples":["Employees received a Christmas bonus this year.","The free parking is an added bonus of working here."]},{"word":"booking","level":"C1","type":"n.","turkish":"Rezervasyon, yer ayırtma.","definition":"An act of reserving accommodation, a ticket, etc., in advance.","examples":["I need to make a hotel booking for my trip next week.","Online booking is available for flights."]},{"word":"boom","level":"C1","type":"n.","turkish":"(Ekonomik) patlama, hızlı artış; gümbürtü, patlama sesi.","definition":"A period of rapid economic growth; a loud, deep, resonant sound.","examples":["The country experienced an economic boom in the 1990s.","We heard the distant boom of thunder."]},{"word":"boost","level":"B2","type":"v.","turkish":"(v) Artırmak, yükseltmek, desteklemek; (n) Artış, destek, teşvik.","definition":"(v) To help or encourage (something) to increase or improve. (n) A source of help or encouragement leading to increase or improvement.","examples":["The new advertising campaign aims to boost sales. (verb) Winning the award gave her confidence a much needed boost. (noun)"]},{"word":"bounce","level":"C1","type":"v.","turkish":"Zıplamak, sekmek (top vb.); (e-posta) geri dönmek; (mecazi) fikir alışverişinde bulunmak.","definition":"(of an object, especially a ball) Move quickly up, back, or away from a surface after hitting it; (of an email) Be returned to the sender; informally discuss ideas.","examples":["The children were bouncing a ball against the wall.","My email to him kept bouncing back."]},{"word":"bound","level":"B2","type":"adj.","turkish":"-e doğru giden, -e yönelik; bağlı, ilişkili; zorunlu, kaçınılmaz.","definition":"Heading toward somewhere; certain or destined to happen; legally or morally obliged to do something.","examples":["The train is bound for London.","With so much rain, floods are bound to happen."]},{"word":"boundary","level":"C1","type":"n.","turkish":"Sınır, hudut; (mecazi) limit, kısıtlama.","definition":"A line that marks the limits of an area; a dividing line; a limit of something abstract, especially a subject or sphere of activity.","examples":["The river forms the boundary between the two countries.","It's important to set clear boundaries in relationships. bow¹ (v., n."]},{"word":"breach","level":"C1","type":"n.","turkish":"(n) İhlal (yasa, kural, anlaşma vb.), uymama; gedik, yarık; (v) İhlal etmek, uymamak; gedik açmak.","definition":"(n) An act of breaking or failing to observe a law, agreement, or code of conduct; a gap in a wall, barrier, or defense. (v) To make a gap in and break through (a wall, barrier, or defense); break or fail to observe (a law, agreement, or code of cond","examples":["This was a clear breach of the contract terms. (noun) The company was sued for breaching the agreement. (verb)"]},{"word":"breakdown","level":"C1","type":"n.","turkish":"Arıza (makine, araç vb.);çöküş (sinirsel, duygusal); analiz, ayrıntılı döküm.","definition":"A mechanical failure; a failure of a relationship or system; a collapse of physical or mental health; a detailed analysis.","examples":["We had a breakdown on the motorway.","She suffered a nervous breakdown due to stress."]},{"word":"breakthrough","level":"C1","type":"n.","turkish":"Büyük buluş,önemli gelişme, atılım.","definition":"A sudden, dramatic, and important discovery or development.","examples":["Scientists have made a major breakthrough in cancer research.","This invention represents a significant breakthrough in technology."]},{"word":"breed","level":"C1","type":"v.","turkish":"(v) (Hayvan) doğurmak, yavrulamak; yetiştirmek (hayvan, bitki); (mecazi) yol açmak, neden olmak; (n)","definition":"(v) (of animals) Mate and then produce offspring; cause (an animal) to produce offspring, typically in a controlled environment; cause (something) to happen, typically something bad. (n) A stock of animals or plants within a species having a distinct","examples":["Rabbits breed very quickly. (verb) Poor hygiene can breed disease. (verb) What breed of dog is it? (noun)"]},{"word":"brick","level":"B2","type":"n.","turkish":"Tuğla.","definition":"A small rectangular block typically made of fired or sun -dried clay, used in building.","examples":["The house was built with red bricks.","He threw a brick through the window."]},{"word":"briefly","level":"B2","type":"adv.","turkish":"Kısaca, kısa bir süre için.","definition":"For a short time; concisely.","examples":["We stopped briefly for lunch.","Could you explain the situation briefly?"]},{"word":"broadband","level":"C1","type":"n.","turkish":"Geniş bant (internet bağlantısı).","definition":"A high -capacity transmission technique using a wide range of frequencies, which enables a large number of messages to be communicated simultaneously.","examples":["High-speed broadband access is essential for many businesses.","Do you have broadband internet at home?"]},{"word":"broadcaster","level":"B2","type":"n.","turkish":"Yayıncı (TV, radyo); sunucu, spiker.","definition":"An organization that transmits a program or information by radio or television; a person who presents a radio or television programme.","examples":["The BBC is a major public service broadcaster.","He is a well-known sports broadcaster."]},{"word":"broadly","level":"B2","type":"adv.","turkish":"Genel olarak, genel anlamda; genişçe, açıkça.","definition":"In general and without considering minor details; widely.","examples":["Broadly speaking, the project was a success.","He smiled broadly when he heard the good news."]},{"word":"browser","level":"C1","type":"n.","turkish":"İnternet tarayıcısı (Chrome, Firefox vb.).","definition":"A computer program with a graphical user interface for displaying HTML files, used to navigate the World Wide Web.","examples":["Which web browser do you prefer to use?","You may need to update your browser to view this website correctly."]},{"word":"brutal","level":"C1","type":"adj.","turkish":"Vahşi, acımasız, gaddar; (mecazi) kaba, sert.","definition":"Savagely violent; cruel; harsh and direct.","examples":["The dictator was known for his brutal treatment of opponents.","She gave a brutal assessment of the company's performance. buck (n."]},{"word":"buffer","level":"C1","type":"n.","turkish":"Tampon (bölge, kimyasal, bilgisayar vb.); (tren) tampon.","definition":"A person or thing that prevents incompatible or antagonistic people or things from coming into contact with or harming each other; (Chemistry) a solution which resists changes in pH; (Computing) a temporary memory area.","examples":["The park acts as a buffer between the houses and the busy road.","The video stopped playing because it needed to buffer."]},{"word":"bug","level":"B2","type":"n.","turkish":"Böcek; (bilgisayar programında) hata, sorun; gizli mikrofon.","definition":"A small insect; an error in a computer program or system; a concealed microphone.","examples":["There's a strange bug crawling on the window.","The programmers are working to fix a bug in the software."]},{"word":"bulk","level":"C1","type":"n.","turkish":"Büyük kısım,çoğunluk; hacim, kütle; toptan (satış).","definition":"The mass or size of something large; the greater part of something; (in bulk) in large quantities.","examples":["The vast bulk of the work has already been done.","It's cheaper to buy goods in bulk."]},{"word":"burden","level":"C1","type":"n.","turkish":"Yük, ağırlık (hem gerçek hem mecazi).","definition":"A load, typically a heavy one; the main responsibility for achieving a specified aim or task.","examples":["He carried a heavy burden of firewood on his back.","Caring for elderly parents can be a significant financial burden."]},{"word":"bureaucracy","level":"C1","type":"n.","turkish":"Bürokrasi, kırtasiyecilik.","definition":"A system of government in which most of the important decisions are taken by state officials rather than by elected representatives; excessively complicated administrative procedure.","examples":["People often complain about government bureaucracy.","We had to deal with a lot of bureaucracy to get the permit."]},{"word":"burial","level":"C1","type":"n.","turkish":"Gömme, defin, cenaze töreni.","definition":"The action or practice of interring a dead body.","examples":["The burial took place at the local cemetery.","Ancient burial sites can provide valuable historical information."]},{"word":"burst","level":"C1","type":"v.","turkish":"Patlamak, yarılmak; aniden (gülmeye, ağlamaya vb.) başlamak; hızla girmek/çıkmak.","definition":"To break open or apart suddenly and violently, especially as a result of an impact or internal pressure; suddenly begin doing or producing something; move suddenly and violently.","examples":["The balloon burst with a loud bang.","She burst into tears when she heard the news."]},{"word":"cabin","level":"B2","type":"n.","turkish":"Kabin (uçak, gemi vb.); kulübe (ahşap, dağ vb.).","definition":"A private room or compartment on a ship or aircraft; a small wooden shelter or house in a wild or remote area.","examples":["We booked a cabin on the cruise ship.","They spent their vacation in a log cabin in the mountains."]},{"word":"cabinet","level":"C1","type":"n.","turkish":"Dolap (mutfak, banyo vb.); kabine, bakanlar kurulu.","definition":"A cupboard with shelves or drawers for storing or displaying articles; (Cabinet) a body of advisers to the president or head of state, typically composed of the heads of the executive departments.","examples":["Put the glasses back in the kitchen cabinet.","The Prime Minister held a meeting with the Cabinet this morning."]},{"word":"calculation","level":"C1","type":"n.","turkish":"Hesaplama, hesap; tahmin,öngörü.","definition":"A mathematical determination of the size or number of something; an assessment of the risks, possibilities, or effects of a situation or course of action.","examples":["According to my calculations, we should arrive by noon.","Careful calculation is required before making such a large investment."]},{"word":"canal","level":"B2","type":"n.","turkish":"Kanal (su yolu).","definition":"An artificial waterway constructed to allow the passage of boats or ships inland or to convey water for irrigation.","examples":["Venice is famous for its beautiful canals.","The Panama Canal connects the Atlantic and Pacific Oceans."]},{"word":"candle","level":"B2","type":"n.","turkish":"Mum.","definition":"A cylinder or block of wax or tallow with a central wick that is lit to produce light as it burns.","examples":["The power went out, so we lit some candles.","She blew out the candles on her birthday cake."]},{"word":"canvas","level":"C1","type":"n.","turkish":"Kanvas, branda bezi; tuval (resim).","definition":"A strong, coarse unbleached cloth made from hemp, flax, cotton, or a similar yarn, used to make sails and tents and as a surface for oil painting.","examples":["The tent is made of waterproof canvas.","The artist stretched the canvas tightly over the frame before painting."]},{"word":"capability","level":"C1","type":"n.","turkish":"Yetenek, kabiliyet, kapasite.","definition":"The power or ability to do something.","examples":["The company has the capability to handle large projects.","He demonstrated his capabilities as a leader."]},{"word":"capitalism","level":"C1","type":"n.","turkish":"Kapitalizm, sermayecilik.","definition":"An economic and political system in which a country's trade and industry are controlled by private owners for profit, rather than by the state.","examples":["Capitalism encourages competition between businesses.","The rise of capitalism led to major social changes."]},{"word":"capitalist","level":"C1","type":"adj.","turkish":"Kapitalist, sermayeci.","definition":"Practicing or based on capitalism; relating to capitalists or capitalism.","examples":["The United States has a predominantly capitalist economy.","He holds strong capitalist beliefs."]},{"word":"carbon","level":"B2","type":"n.","turkish":"Karbon (element); karbon kağıdı.","definition":"The chemical element of atomic number 6, a nonmetal that has two main forms (diamond and graphite); carbon paper.","examples":["All living organisms are based on carbon.","Reducing carbon emissions is crucial for combating climate change."]},{"word":"cargo","level":"C1","type":"n.","turkish":"Kargo, yük (gemi, uçak vb. ile taşınan).","definition":"Goods carried on a ship, aircraft, or motor vehicle.","examples":["The ship was carrying a large cargo of oil.","Cargo planes transport goods around the world."]},{"word":"carriage","level":"C1","type":"n.","turkish":"Vagon (tren); at arabası; taşıma, nakliye; duruş, tavır.","definition":"Any of the separate sections of a train that carry passengers; a four -wheeled passenger vehicle pulled by two or more horses; the transporting of goods from one place to another; a person's bearing or deportment.","examples":["We found seats in the last carriage of the train.","Cinderella traveled to the ball in a magical carriage."]},{"word":"carve","level":"C1","type":"v.","turkish":"Oymak (ahşap, taş vb.); (et) dilimlemek.","definition":"To cut (a hard material) in order to produce an object, design, or inscription; cut (cooked meat) into slices for eating.","examples":["He carved a beautiful statue out of wood.","Would you like to carve the roast chicken?"]},{"word":"casino","level":"C1","type":"n.","turkish":"Gazino, kumarhane.","definition":"A public room or building where gambling games are played.","examples":["They spent the evening playing roulette at the casino.","Las Vegas is famous for its large casinos."]},{"word":"castle","level":"B2","type":"n.","turkish":"Kale,şato.","definition":"A large building, typically of the medieval period, fortified against attack with thick walls, battlements, towers, and often a moat.","examples":["We visited an ancient castle overlooking the river.","Many fairy tales feature princesses living in castles."]},{"word":"casual","level":"B2","type":"adj.","turkish":"Gündelik, spor (kıyafet); gelişigüzel, teklifsiz, samimi; geçici, düzenli olmayan.","definition":"Relaxed and unconcerned; not formal or festive; occurring by chance or irregularly.","examples":["You can wear casual clothes to the party; it's not formal.","We had a casual conversation about our weekend plans."]},{"word":"casualty","level":"C1","type":"n.","turkish":"Kazazede, yaralı, zayiat (savaş, kaza vb.); (mecazi) kurban.","definition":"A person killed or injured in a war or accident; a person or thing badly affected by an event or situation.","examples":["There were several casualties in the train crash.","Small businesses have been major casualties of the economic recession. catalog (n."]},{"word":"cater","level":"C1","type":"v.","turkish":"Yiyecek içecek sağlamak (parti, toplantı vb.); ihtiyacını karşılamak, hizmet etmek, hitap etmek.","definition":"To provide food and drink, typically at social events and in a professional capacity; provide with what is needed or required.","examples":["Which company will be catering the wedding reception?","The hotel tries to cater to the needs of all its guests. cattle (n."]},{"word":"caution","level":"C1","type":"n.","turkish":"Dikkat, tedbir, ihtiyat; uyarı, ikaz.","definition":"Care taken to avoid danger or mistakes; a warning or admonition.","examples":["Proceed with caution when driving in foggy conditions.","The label includes a caution about using the product near open flames."]},{"word":"cautious","level":"C1","type":"adj.","turkish":"Dikkatli, tedbirli, ihtiyatlı.","definition":"(of a person) Careful to avoid potential problems or dangers.","examples":["He is a cautious driver and always obeys the speed limit.","Investors are being cautious due to the uncertain economic climate."]},{"word":"cave","level":"B2","type":"n.","turkish":"Mağara.","definition":"A large underground chamber, typically of natural origin, in a hillside or cliff.","examples":["Early humans sometimes lived in caves.","Exploring the dark cave was an adventure. cease (v."]},{"word":"cemetery","level":"C1","type":"n.","turkish":"Mezarlık, kabristan.","definition":"A large burial ground, especially one not in a churchyard.","examples":["They visited their grandparents' graves in the cemetery.","The old cemetery is located on the hill outside the town."]},{"word":"certainty","level":"B2","type":"n.","turkish":"Kesinlik, katiyet; kesin olanşey.","definition":"Firm conviction that something is the case; something that is certain to happen.","examples":["I can't say with any certainty what will happen next.","Death and taxes are often cited as life's only certainties."]},{"word":"certificate","level":"B2","type":"n.","turkish":"Sertifika, belge, diploma.","definition":"An official document attesting a certain fact, in particular one testifying to the holder's qualifications or achievements.","examples":["She received a certificate for completing the course.","You need to show your birth certificate as proof of age."]},{"word":"challenging","level":"B2","type":"adj.","turkish":"Zorlu, mücadele gerektiren, iddialı.","definition":"Testing one's abilities; demanding.","examples":["Climbing Mount Everest is"]},{"word":"carve","level":"C1","type":"v.","turkish":"Oymak (ahşap, taş vb.); (et) dilimlemek.","definition":"To cut (a hard material) in order to produce an object, design, or inscription; cut (cooked meat) into slices for eating.","examples":["He carved a beautiful statue out of wood.","Would you like to carve the roast chicken?"]},{"word":"casino","level":"C1","type":"n.","turkish":"Gazino, kumarhane.","definition":"A public room or building where gambling games are played.","examples":["They spent the evening playing roulette at the casino.","Las Vegas is famous for its large casinos."]},{"word":"castle","level":"B2","type":"n.","turkish":"Kale,şato.","definition":"A large building, typically of the medieval period, fortified against attack with thick walls, battlements, towers, and often a moat.","examples":["We visited an ancient castle overlooking the river.","Many fairy tales feature princesses living in castles."]},{"word":"casual","level":"B2","type":"adj.","turkish":"Gündelik, spor (kıyafet); gelişigüzel, teklifsiz, samimi; geçici, düzenli olmayan.","definition":"Relaxed and unconcerned; not formal or festive; occurring by chance or irregularly.","examples":["You can wear casual clothes to the party; it's not formal.","We had a casual conversation about our weekend plans."]},{"word":"casualty","level":"C1","type":"n.","turkish":"Kazazede, yaralı, zayiat (savaş, kaza vb.); (mecazi) kurban.","definition":"A person killed or injured in a war or accident; a person or thing badly affected by an event or situation.","examples":["There were several casualties in the train crash.","Small businesses have been major casualties of the economic recession. catalog (n."]},{"word":"cater","level":"C1","type":"v.","turkish":"Yiyecek içecek sağlamak (parti, toplantı vb.); ihtiyacını karşılamak, hizmet etmek, hitap etmek.","definition":"To provide food and drink, typically at social events and in a professional capacity; provide with what is needed or required.","examples":["Which company will be catering the wedding reception?","The magazine aims to cater to young professionals. cattle (n."]},{"word":"caution","level":"C1","type":"n.","turkish":"Dikkat, tedbir, ihtiyat; uyarı, ikaz.","definition":"Care taken to avoid danger or mistakes; a warning or admonition.","examples":["Proceed with caution when driving in foggy conditions.","The label includes a caution about using the product near open flames."]},{"word":"cautious","level":"C1","type":"adj.","turkish":"Dikkatli, tedbirli, ihtiyatlı.","definition":"(of a person) Careful to avoid potential problems or dangers.","examples":["He is a cautious driver and always obeys the speed limit.","Investors are being cautious due to the uncertain economic climate."]},{"word":"cave","level":"B2","type":"n.","turkish":"Mağara.","definition":"A large underground chamber, typically of natural origin, in a hillside or cliff.","examples":["Early humans sometimes lived in caves.","Exploring the dark cave was an adventure. cease (v."]},{"word":"cemetery","level":"C1","type":"n.","turkish":"Mezarlık, kabristan.","definition":"A large burial ground, especially one not in a churchyard.","examples":["They visited their grandparents' graves in the cemetery.","The old cemetery is located on the hill outside the town."]},{"word":"certainty","level":"B2","type":"n.","turkish":"Kesinlik, katiyet; kesin olanşey.","definition":"Firm conviction that something is the case; something that is certain to happen.","examples":["I can't say with any certainty what will happen next.","Death and taxes are often cited as life's only certainties."]},{"word":"certificate","level":"B2","type":"n.","turkish":"Sertifika, belge, diploma.","definition":"An official document attesting a certain fact, in particular one testifying to the holder's qualifications or achievements.","examples":["She received a certificate for completing the course.","You need to show your birth certificate as proof of age."]},{"word":"challenging","level":"B2","type":"adj.","turkish":"Zorlu, mücadele gerektiren, iddialı.","definition":"Testing one's abilities; demanding.","examples":["Climbing Mount Everest is a challenging task.","She finds her new job very challenging but rewarding."]},{"word":"chamber","level":"C1","type":"n.","turkish":"Oda (genellikle resmi,özel veya yasal amaçlı); meclis, kurul odası; (silah) hazne.","definition":"A large room used for formal or public events; a private room, typically a bedroom; one of the houses of a legislature; the part of a gun bore that contains the charge.","examples":["The king received guests in the royal chamber.","The decision was debated in the council chamber."]},{"word":"championship","level":"B2","type":"n.","turkish":"Şampiyonluk;şampiyona, turnuva.","definition":"A contest for the position of champion in a sport or game; the position of being a champion.","examples":["Their team won the national championship last year.","She competed in the world chess championship."]},{"word":"chaos","level":"C1","type":"n.","turkish":"Kaos, kargaşa, keşmekeş.","definition":"Complete disorder and confusion.","examples":["The classroom was in complete chaos after the party.","Heavy snow caused chaos on the roads. characterize (v."]},{"word":"charm","level":"C1","type":"n.","turkish":"Çekicilik, cazibe, albeni; tılsım, muska.","definition":"The power or quality of delighting, attracting, or fascinating others; an object worn on a chain or bracelet, believed to bring good luck.","examples":["He possesses great personal charm.","She wears a lucky charm on her necklace."]},{"word":"charming","level":"B2","type":"adj.","turkish":"Çekici, cazibeli, hoş, alımlı.","definition":"Pleasant or attractive.","examples":["We had dinner with a charming young couple.","The cottage looked charming covered in snow."]},{"word":"charter","level":"C1","type":"n.","turkish":"Berat, ferman, kuruluş belgesi; kiralama (uçak, gemi vb.).","definition":"A written grant by a country's legislative or sovereign power, by which an institution such as a company, college, or city is created and its rights and privileges defined; the reservation of an aircraft, boat, or bus for private use.","examples":["The city was granted a royal charter in 1604.","They booked a charter flight for their group holiday."]},{"word":"chase","level":"B2","type":"v.","turkish":"(v) Kovalamak, peşinden koşmak; (n) Kovalamaca, takip.","definition":"(v) To pursue in order to catch or catch up with. (n) The act of pursuing someone or something.","examples":["The police car chased the stolen vehicle through the city streets. (verb) The dog enjoyed the chase after the ball. (noun)"]},{"word":"cheek","level":"B2","type":"n.","turkish":"Yanak.","definition":"Either side of the face below the eye.","examples":["She kissed him on the cheek.","The baby has rosy cheeks."]},{"word":"cheer","level":"B2","type":"v.","turkish":"(v) Tezahürat yapmak, alkışlamak; neşelendirmek; (n) Tezahürat, alkış; neşe.","definition":"(v) To shout for joy or in praise or encouragement; give comfort or support to. (n) A shout of joy or encouragement; cheerfulness.","examples":["The crowd cheered when their team scored a goal. (verb) Let's give a big cheer for the winners! (noun)"]},{"word":"choir","level":"C1","type":"n.","turkish":"Koro.","definition":"An organized group of singers, typically one that takes part in church services or performs in public.","examples":["She sings in the church choir.","The school choir performed at the Christmas concert."]},{"word":"chop","level":"B2","type":"v.","turkish":"Doğramak, kıymak (balta, bıçak vb. ile).","definition":"To cut (something) into small pieces with repeated sharp blows using an axe or knife.","examples":["He was chopping wood for the fire.","Chop the onions finely before adding them to the pan."]},{"word":"chronic","level":"C1","type":"adj.","turkish":"Kronik, müzmin (hastalık vb.); sürekli, devamlı (sorun vb.).","definition":"(of an illness) Persisting for a long time or constantly recurring; (of a problem) long lasting and difficult to eradicate.","examples":["He suffers from chronic back pain.","There is a chronic shortage of housing in the city."]},{"word":"chunk","level":"C1","type":"n.","turkish":"Parça, yığın, küme (kalın/büyük).","definition":"A thick, solid piece of something.","examples":["Add a large chunk of butter to the potatoes.","A significant chunk of the budget was allocated to marketing."]},{"word":"circuit","level":"B2","type":"n.","turkish":"Devre (elektrik); pist (yarış); tur, dolaşma.","definition":"A complete and closed path around which a circulating electric current can flow; a track used for motor racing; a regular journey or route around a particular area.","examples":["An electrician fixed the faulty circuit.","The cars raced around the circuit ten times."]},{"word":"circulate","level":"C1","type":"v.","turkish":"Dolaşmak (kan, hava vb.); (haber, bilgi) yayılmak, dolaşmak; dolaştırmak.","definition":"To move continuously or freely through a closed system or area; pass from place to place or person to person.","examples":["Fans help to circulate air in the room.","Rumors began to circulate about his resignation."]},{"word":"circulation","level":"C1","type":"n.","turkish":"Dolaşım (kan vb.); (gazete, dergi) tiraj; (para, bilgi) dolaşım.","definition":"Movement to and fro or around something, especially that of fluid in a closed system; the public availability or knowledge of something; the number of copies issued of a newspaper or magazine.","examples":["Exercise improves blood circulation.","The newspaper has a daily circulation of over 1 million."]},{"word":"citizenship","level":"C1","type":"n.","turkish":"Vatandaşlık, yurttaşlık.","definition":"The position or status of being a citizen of a particular country.","examples":["He applied for Canadian citizenship after living there for five years.","Having citizenship grants you certain rights and responsibilities."]},{"word":"civic","level":"C1","type":"adj.","turkish":"Şehirle ilgili, kentsel; vatandaşlık(la ilgili), sivil.","definition":"Relating to a city or town, especially its administration; relating to the duties or activities of people in relation to their town, city, or local area.","examples":["Voting is considered a civic duty.","The mayor attended the civic reception."]},{"word":"civilian","level":"C1","type":"n.","turkish":"(n) Sivil (asker veya polis olmayan); (adj) Sivil.","definition":"(n) A person not in the armed services or the police force. (adj) Relating to civilians.","examples":["Many innocent civilians were killed during the conflict. (noun) He returned to civilian life after ten years in the army. (adjective) civilization (n.","B2) ( İngiliz İngilizcesi: civilisation) Türkçe Anlamı: Uygarlık, medeniyet."]},{"word":"clarify","level":"B2","type":"v.","turkish":"Açıklamak, açıklığa kavuşturmak, netleştirmek.","definition":"To make (a statement or situation) less confused and more clearly comprehensible.","examples":["Could you please clarify what you mean by that?","The report aims to clarify the causes of the accident."]},{"word":"clarity","level":"C1","type":"n.","turkish":"Açıklık, netlik, berraklık.","definition":"The quality of being clear, in particular the quality of being easy to see, hear, or understand; the quality of being coherent and intelligible.","examples":["She explained the complex issue with great clarity.","The clarity of the water allowed us to see the fish below."]},{"word":"clash","level":"C1","type":"n.","turkish":"Çatışma,çarpışma (fikir, grup, renk vb.); gürültülüçarpma sesi.","definition":"A violent confrontation; a mismatch of colours; a loud jarring sound.","examples":["There were violent clashes between protesters and police.","The bright orange shirt clashes with the purple trousers."]},{"word":"classification","level":"C1","type":"n.","turkish":"Sınıflandırma, tasnif.","definition":"The action or process of classifying something according to shared qualities or characteristics.","examples":["The library uses a standard system for book classification.","The classification of species helps biologists understand evolution."]},{"word":"classify","level":"B2","type":"v.","turkish":"Sınıflandırmak, tasnif etmek; (bilgiyi) gizli olarak sınıflandırmak.","definition":"To arrange (a group of people or things) in classes or categories according to shared qualities or characteristics; designate (documents or information) as officially secret.","examples":["Scientists classify animals based on their characteristics.","These documents have been classified as top secret."]},{"word":"cliff","level":"B2","type":"n.","turkish":"Uçurum, yar, falez.","definition":"A steep rock face, especially at the edge of the sea.","examples":["Be careful not to walk too close to the edge of the cliff.","Seabirds nested on the high cliffs. cling (v."]},{"word":"clinic","level":"B2","type":"n.","turkish":"Klinik, poliklinik, sağlık ocağı.","definition":"An establishment or hospital department where outpatients are given medical treatment or advice, especially of a specialist nature.","examples":["She goes to the physiotherapy clinic twice a week.","There is a free dental clinic for low-income families."]},{"word":"clinical","level":"C1","type":"adj.","turkish":"Klinik, tıbbi; (mecazi) soğuk, duygusuz, objektif.","definition":"Relating to the observation and treatment of actual patients rather than theoretical or laboratory studies; efficient and unemotional; coldly detached.","examples":["The new drug is undergoing clinical trials.","He described the events with cold, clinical precision."]},{"word":"clip","level":"B2","type":"n.","turkish":"Klips, mandal, ataş; (film, video) kısa bölüm, klip; kırpma.","definition":"A flexible or spring-loaded device for holding an object or objects together or in place; a short sequence taken from a movie or broadcast; an act of cutting something short.","examples":["Use a paper clip to hold the documents together.","We watched a short clip from the new movie."]},{"word":"closure","level":"C1","type":"n.","turkish":"Kapanma, kapatma (işletme, yol vb.); sona erme; (duygusal) kapanış, kabullenme.","definition":"An act or process of closing something, especially an institution, thoroughfare, or frontier; a feeling that an emotional or traumatic experience has been resolved.","examples":["The factory closure resulted in hundreds of job losses.","Visiting the place helped her find closure after the accident."]},{"word":"cluster","level":"C1","type":"n.","turkish":"Küme, grup, salkım.","definition":"A group of similar things or people positioned or occurring closely together.","examples":["A cluster of stars shone brightly in the night sky.","There was a small cluster of houses around the church."]},{"word":"coalition","level":"C1","type":"n.","turkish":"Koalisyon, birleşme (genellikle siyasi).","definition":"A temporary alliance for combined action, especially of political parties forming a government.","examples":["The parties formed a coalition government after the election.","A coalition of environmental groups protested the development."]},{"word":"coastal","level":"C1","type":"adj.","turkish":"Kıyı, sahil (ile ilgili).","definition":"Relating to or bordering on the coast.","examples":["We drove along the scenic coastal road.","Many coastal towns rely on tourism."]},{"word":"cocktail","level":"C1","type":"n.","turkish":"Kokteyl (içecek); karışım.","definition":"An alcoholic drink consisting of a spirit or several spirits mixed with other ingredients, such as fruit juice, lemonade, or cream; a mixture of substances or factors.","examples":["They served cocktails before dinner.","The report described a dangerous cocktail of pollutants in the river."]},{"word":"cognitive","level":"C1","type":"adj.","turkish":"Bilişsel, idrak ile ilgili.","definition":"Relating to cognition (the mental action or process of acquiring knowledge and understanding through thought, experience, and the senses).","examples":["Aging can affect cognitive abilities such as memory.","The study focuses on children's cognitive development."]},{"word":"coincide","level":"C1","type":"v.","turkish":"Rastlamak, aynı zamana denk gelmek; çakışmak, uyuşmak (fikir vb.).","definition":"To occur at or during the same time; correspond in nature; tally.","examples":["My vacation coincides with the school holidays.","His views coincide with mine on this matter."]},{"word":"coincidence","level":"B2","type":"n.","turkish":"Tesadüf, rastlantı.","definition":"A remarkable concurrence of events or circumstances without apparent causal connection.","examples":["What a coincidence!","I wasn't expecting to see you here."]},{"word":"collaborate","level":"C1","type":"v.","turkish":"İş birliği yapmak, birlikteçalışmak.","definition":"To work jointly on an activity, especially to produce or create something.","examples":["The two scientists collaborated on the research project.","We need to collaborate effectively to meet the deadline."]},{"word":"collaboration","level":"C1","type":"n.","turkish":"İş birliği.","definition":"The action of working with someone to produce or create something.","examples":["The project was a successful collaboration between several departments.","International collaboration is essential for scientific progress."]},{"word":"collective","level":"C1","type":"adj.","turkish":"Kolektif, ortak, toplu.","definition":"Done by people acting as a group; belonging or relating to all the members of a group.","examples":["The decision was made by collective agreement.","We made a collective effort to clean up the park."]},{"word":"collector","level":"B2","type":"n.","turkish":"Koleksiyoncu, koleksiyoner; tahsildar, toplayıcı.","definition":"A person who collects things of a specified type, professionally or as a hobby; a person employed to collect payments, taxes, or debts.","examples":["He is an avid stamp collector.","The art collector bought several paintings at the auction."]},{"word":"collision","level":"C1","type":"n.","turkish":"Çarpışma (araç, nesne vb.); (mecazi) çatışma, anlaşmazlık.","definition":"An instance of one moving object or person striking violently against another; a conflict of opposing ideas or interests.","examples":["Both drivers were injured in the head -on collision.","There was a collision of interests between the two departments."]},{"word":"colonial","level":"C1","type":"adj.","turkish":"Sömürge(cilikle ilgili), kolonyal.","definition":"Relating to or characteristic of a colony or colonialism.","examples":["India was part of the British colonial empire.","The museum displays artifacts from the colonial era."]},{"word":"colony","level":"B2","type":"n.","turkish":"Sömürge, koloni; (hayvan, bitki) koloni.","definition":"A country or area under the full or partial political control of another country, typically a distant one, and occupied by settlers from that country; a group of people or animals of one kind living together.","examples":["Australia was originally a British penal colony.","A large colony of ants lived under the stone. colorful (adj."]},{"word":"columnist","level":"C1","type":"n.","turkish":"Köşe yazarı.","definition":"A journalist contributing regularly to a newspaper or magazine, usually giving views on a particular subject.","examples":["She is a popular political columnist for a national newspaper.","The columnist expressed strong opinions in his latest article. combat (n., v."]},{"word":"comic","level":"B2","type":"adj.","turkish":"(adj) Komik, güldürücü; (n) Komedyen; çizgi roman.","definition":"(adj) Causing or meant to cause laughter. (n) A comedian; a periodical containing comic strips.","examples":["The play had some very comic moments. (adjective) He reads superhero comics every week. (noun)"]},{"word":"commander","level":"B2","type":"n.","turkish":"Komutan.","definition":"A person in authority, especially over a body of troops or a military operation; an officer who is in charge of a military operation.","examples":["The commander gave orders to his troops.","She was appointed commander of the naval base. commence (v."]},{"word":"commentary","level":"C1","type":"n.","turkish":"Yorum, anlatım (maç, olay vb.); tefsir, açıklama.","definition":"An expression of opinions or offering of explanations about an event or situation; a descriptive spoken account (especially on a broadcast) of an event or performance as it happens.","examples":["The book includes a detailed commentary on the historical context.","He provided live commentary during the football match."]},{"word":"commentator","level":"C1","type":"n.","turkish":"Yorumcu, spiker (maç, olay vb.).","definition":"A person who comments on events or on a text; a person who provides a commentary on a broadcast program or sporting event.","examples":["Political commentators discussed the election results.","The sports commentator described the action excitedly."]},{"word":"commerce","level":"C1","type":"n.","turkish":"Ticaret (özellikle büyükölçekli).","definition":"The activity of buying and selling, especially on a large scale.","examples":["The city is a major center for industry and commerce.","E-commerce has changed the way people shop."]},{"word":"commissioner","level":"C1","type":"n.","turkish":"Komiser (polis, yetkili kurulüyesi vb.).","definition":"A person appointed to a role on or by a commission; the head of a particular government department or agency (e.g., police, fire).","examples":["The Police Commissioner gave a press conference.","She was appointed European Commissioner for Trade."]},{"word":"commodity","level":"C1","type":"n.","turkish":"Ticari mal, emtia (özellikle ham madde veya tarımürünü).","definition":"A raw material or primary agricultural product that can be bought and sold, such as copper or coffee.","examples":["Oil is a vital global commodity.","Prices for agricultural commodities fluctuate depending on the harvest."]},{"word":"communist","level":"C1","type":"adj.","turkish":"Komünist.","definition":"Relating to or based on the principles of communism (a political theory advocating class war and leading to a society in which all property is publicly owned and each person works and is paid according to their abilities and needs).","examples":["The country was ruled by a communist government for decades.","He held strong communist ideals."]},{"word":"companion","level":"C1","type":"n.","turkish":"Arkadaş, yoldaş, refakatçi.","definition":"A person or animal with whom one spends a lot of time or with whom one travels.","examples":["His dog has been his faithful companion for many years.","She travelled to Italy with a travelling companion."]},{"word":"comparable","level":"C1","type":"adj.","turkish":"Karşılaştırılabilir, kıyaslanabilir, benzer.","definition":"Able to be likened to another; similar; of equivalent quality; worthy of comparison.","examples":["The two houses are comparable in size.","The quality of their products is comparable to the best on the market."]},{"word":"comparative","level":"B2","type":"adj.","turkish":"Karşılaştırmalı; (dilbilgisi) karşılaştırma derecesi (-den daha).","definition":"Perceived or measured by comparison with something else; relative; relating to or denoting the degree of comparison expressing a higher degree of a quality (e.g. braver).","examples":["The study offers a comparative analysis of the two systems. \"Taller\" is the comparative form of the adjective \"tall\"."]},{"word":"compassion","level":"C1","type":"n.","turkish":"Şefkat, merhamet, acıma duygusu.","definition":"Sympathetic pity and concern for the sufferings or misfortunes of others.","examples":["She showed great compassion towards the refugees.","Nurses need to have compassion for their patients."]},{"word":"compel","level":"C1","type":"v.","turkish":"Zorlamak, mecbur etmek.","definition":"To force or oblige (someone) to do something.","examples":["The law will compel companies to reduce pollution.","Illness compelled him to stay at home."]},{"word":"compelling","level":"C1","type":"adj.","turkish":"İkna edici, zorlayıcı; (ilgi)çekici, sürükleyici.","definition":"Evoking interest, attention, or admiration in a powerfully irresistible way; not able to be refuted; inspiring conviction.","examples":["The novel tells a compelling story of love and loss.","There is compelling evidence that he committed the crime."]},{"word":"compensate","level":"C1","type":"v.","turkish":"Telafi etmek, karşılamak (zararı vb.); tazminatödemek.","definition":"To pay (someone) for loss, suffering, or injury; reduce or counteract (something undesirable) by exerting an opposite force or effect.","examples":["The company had to compensate workers for injuries suffered at work.","Nothing can compensate for the loss of a loved one."]},{"word":"compensation","level":"C1","type":"n.","turkish":"Tazminat, telafi.","definition":"Something, typically money, awarded to someone as a recompense for loss, injury, or suffering.","examples":["He received financial compensation for his injuries.","The court ordered the company to pay compensation to the victims."]},{"word":"competence","level":"C1","type":"n.","turkish":"Yetkinlik, yeterlilik, ustalık.","definition":"The ability to do something successfully or efficiently.","examples":["He demonstrated high competence in his field.","The job requires a high level of technical competence."]},{"word":"competent","level":"C1","type":"adj.","turkish":"Yetkin, yeterli, ehil, usta.","definition":"Having the necessary ability, knowledge, or skill to do something successfully.","examples":["She is a highly competent surgeon.","Make sure you hire a competent lawyer."]},{"word":"compile","level":"C1","type":"v.","turkish":"Derlemek, toplamak (bilgi, liste vb.).","definition":"To produce (something, especially a list, report, or book) by assembling information collected from other sources.","examples":["The researchers compiled a list of potential side effects.","We need to compile all the data for the presentation."]},{"word":"complement","level":"C1","type":"v.","turkish":"Tamamlamak, bütünlemek, uyum sağlamak.","definition":"To add to (something) in a way that enhances or improves it; make perfect.","examples":["The wine perfectly complements the spicy food.","His skills complement hers, making them a great team."]},{"word":"completion","level":"B2","type":"n.","turkish":"Tamamlama, bitirme.","definition":"The action or process of finishing something.","examples":["The project is nearing completion.","Upon completion of the course, you will receive a certificate."]},{"word":"complexity","level":"C1","type":"n.","turkish":"Karmaşıklık, komplekslik.","definition":"The state or quality of being intricate or complicated.","examples":["The complexity of the problem made it difficult to solve.","He was impressed by the complexity of the machine's design."]},{"word":"compliance","level":"C1","type":"n.","turkish":"Uyma, itaat, uygunluk (kural, yasa vb.).","definition":"The action or fact of complying with a wish or command; the state or fact of according with or meeting rules or standards.","examples":["The company was fined for non-compliance with safety regulations.","All procedures must be carried out in compliance with the law."]},{"word":"complication","level":"C1","type":"n.","turkish":"Komplikasyon, işleri zorlaştıran durum; (tıbbi) komplikasyon.","definition":"A circumstance that complicates something; a difficulty; a secondary disease or condition aggravating an already existing one.","examples":["Unexpected complications delayed the project.","The surgery went well, but there were some minor complications afterwards."]},{"word":"comply","level":"C1","type":"v.","turkish":"Uymak, itaat etmek, yerine getirmek (kural, istek vb.).","definition":"To act in accordance with a wish or command; meet specified standards.","examples":["All businesses must comply with the new regulations.","Failure to comply may result in a fine."]},{"word":"compose","level":"B2","type":"v.","turkish":"Oluşturmak, meydana getirmek; bestelemek (müzik); yazmak (metin).","definition":"To write or create (a work of art, especially music or poetry); constitute or make up (a whole).","examples":["Mozart composed his first symphony at a very young age.","Water is composed of hydrogen and oxygen."]},{"word":"composer","level":"B2","type":"n.","turkish":"Besteci, bestekar.","definition":"A person who writes music, especially as a professional occupation.","examples":["Beethoven is one of the most famous classical composers.","The film composer won an award for the soundtrack."]},{"word":"composition","level":"C1","type":"n.","turkish":"Kompozisyon, beste, yapıt; bileşim, yapı; yazmaödevi.","definition":"A work of music, literature, or art; the nature of something's ingredients or constituents; the way in which a whole or mixture is made up; a short essay written as a school exercise.","examples":["The orchestra performed a beautiful musical composition.","We studied the chemical composition of the rock."]},{"word":"compound","level":"B2","type":"n.","turkish":"Bileşik (kimyasal); yerleşke, etrafı çevrili alan.","definition":"A thing that is composed of two or more separate elements; a mixture; an area enclosed by a fence or wall, containing buildings.","examples":["Water is a compound of hydrogen and oxygen.","The embassy compound was heavily guarded."]},{"word":"comprehensive","level":"B2","type":"adj.","turkish":"Kapsamlı, etraflı, detaylı.","definition":"Including or dealing with all or nearly all elements or aspects of something.","examples":["The report provides a comprehensive overview of the situation.","We offer a comprehensive range of services. comprise (v."]},{"word":"compromise","level":"C1","type":"n.","turkish":"(n) Uzlaşma, taviz; (v) Uzlaşmak, anlaşmaya varmak; tehlikeye atmak, zedelemek.","definition":"(n) An agreement or settlement of a dispute that is reached by each side making concessions. (v) To settle a dispute by mutual concession; accept standards that are lower than is desirable; weaken or harm by risky behaviour.","examples":["After long negotiations, they finally reached a compromise. (noun) We must not compromise safety standards. (verb)"]},{"word":"compulsory","level":"B2","type":"adj.","turkish":"Zorunlu, mecburi.","definition":"Required by law or a rule; obligatory.","examples":["Education is compulsory for children between the ages of 6 and 16.","Wearing a seatbelt is compulsory in most countries."]},{"word":"compute","level":"C1","type":"v.","turkish":"Hesaplamak (genellikle bilgisayarla).","definition":"To calculate (a figure or amount) using mathematical formulas or a computer.","examples":["The software can compute complex statistical data quickly.","We need to compute the total cost of the project."]},{"word":"conceal","level":"C1","type":"v.","turkish":"Gizlemek, saklamak.","definition":"To keep from sight; hide.","examples":["He tried to conceal the weapon under his coat.","She could barely conceal her excitement."]},{"word":"concede","level":"C1","type":"v.","turkish":"Kabul etmek (yenilgiyi, doğruluğu vb.); ödün vermek, taviz vermek.","definition":"To admit that something is true or valid after first denying or resisting it; surrender or yield (something that one possesses).","examples":["The candidate conceded defeat after the election results were announced.","I had to concede that his argument was logical."]},{"word":"conceive","level":"C1","type":"v.","turkish":"Tasarlamak, düşünmek, aklına getirmek; (çocuğa) gebe kalmak.","definition":"To form or devise (a plan or idea) in the mind; become pregnant with (a child).","examples":["It's difficult to conceive of a world without the internet.","They were unable to conceive a child naturally."]},{"word":"conception","level":"C1","type":"n.","turkish":"Kavram, fikir, anlayış; gebe kalma, döllenme.","definition":"The action of conceiving a child or of one being conceived; the forming or devising of a plan or idea.","examples":["He has no conception of the difficulties involved.","The project was brilliant in its initial conception."]},{"word":"concession","level":"C1","type":"n.","turkish":"Taviz,ödün; imtiyaz, ruhsat (işletme vb.).","definition":"A thing that is granted, especially in response to demands; a thing conceded; the right to use land or other property for a specified purpose, granted by a government, company, or other controlling body.","examples":["Both sides had to make concessions to reach an agreement.","The government granted a mining concession to the company."]},{"word":"concrete","level":"B2","type":"adj.","turkish":"(adj) Somut, elle tutulur; (n) Beton.","definition":"(adj) Existing in a material or physical form; real or solid; not abstract. (n) A heavy, rough building material made from a mixture of broken stone or gravel, sand, cement, and water.","examples":["We need concrete evidence, not just theories. (adjective) The walls are made of reinforced concrete. (noun)"]},{"word":"condemn","level":"C1","type":"v.","turkish":"Kınamak, ayıplamak; (mahkum vb.) cezayaçarptırmak.","definition":"To express complete disapproval of, typically in public; censure; sentence (someone) to a particular punishment, especially death.","examples":["Leaders around the world condemned the terrorist attack.","He was condemned to life imprisonment."]},{"word":"confer","level":"C1","type":"v.","turkish":"Vermek, bahşetmek (unvan, derece vb.); görüşmek, danışmak.","definition":"To grant or bestow (a title, degree, benefit, or right); have discussions; exchange opinions.","examples":["The university conferred an honorary degree upon the visiting dignitary.","The lawyers needed to confer privately before proceeding."]},{"word":"confess","level":"B2","type":"v.","turkish":"İtiraf etmek, günahçıkarmak.","definition":"To admit or acknowledge that one has committed a crime or is at fault in some way; (in the Christian Church) declare one's sins formally to a priest.","examples":["After hours of questioning, he finally confessed to the robbery.","She confessed that she had lied about her age."]},{"word":"confession","level":"C1","type":"n.","turkish":"İtiraf, günahçıkarma.","definition":"A formal statement admitting that one is guilty of a crime; (in the Christian Church) a declaration of one's sins.","examples":["The police obtained a signed confession from the suspect.","He made a full confession to the priest."]},{"word":"configuration","level":"C1","type":"n.","turkish":"Yapılandırma, konfigürasyon, düzenleme biçimi.","definition":"An arrangement of elements in a particular form, figure, or combination.","examples":["You can change the computer's default configuration settings.","The seating configuration can be altered to suit different events."]},{"word":"confine","level":"C1","type":"v.","turkish":"Sınırlamak, hapsetmek, -e kapatmak.","definition":"To keep or restrict someone or something within certain limits of space, scope, quantity, or time.","examples":["The prisoners were confined to their cells for 23 hours a day.","Please confine your remarks to the topic under discussion."]},{"word":"confirmation","level":"C1","type":"n.","turkish":"Doğrulama, teyit, onay.","definition":"The action of confirming something or the state of being confirmed.","examples":["We are still waiting for confirmation of the flight details.","Please send an email confirmation of your booking."]},{"word":"confront","level":"C1","type":"v.","turkish":"Yüzleşmek, yüzleştirmek; karşı karşıya gelmek/getirmek.","definition":"To meet (someone) face to face with hostile or argumentative intent; face up to and deal with (a problem or difficult situation).","examples":["She decided to confront her boss about the unfair treatment.","We must confront the reality of climate change."]},{"word":"confrontation","level":"C1","type":"n.","turkish":"Yüzleşme, karşılaşma,çatışma.","definition":"A hostile or argumentative meeting or situation between opposing parties.","examples":["There was a violent confrontation between the rival gangs.","She tried to avoid a direct confrontation with her colleague."]},{"word":"confusion","level":"B2","type":"n.","turkish":"Kafa karışıklığı,şaşkınlık; kargaşa.","definition":"Uncertainty about what is happening, intended, or required; the state of being bewildered or unclear in one’s mind about something; disorder.","examples":["The complex instructions led to widespread confusion.","There was some confusion about who should attend the meeting."]},{"word":"congratulate","level":"C1","type":"v.","turkish":"Tebrik etmek, kutlamak.","definition":"To give (someone) one's good wishes when something special or pleasant has happened to them.","examples":["I congratulated her on her promotion.","We called to congratulate them on their new baby."]},{"word":"congregation","level":"C1","type":"n.","turkish":"Cemaat (kilise vb.).","definition":"A group of people assembled for religious worship.","examples":["The priest addressed the congregation.","The church has a large and active congregation."]},{"word":"congressional","level":"C1","type":"adj.","turkish":"Kongre(ye ait), meclis(le ilgili) (Özellikle ABD Kongresi).","definition":"Relating to the US Congress or the congress of another country.","examples":["A congressional committee investigated the matter.","She is running for a congressional seat in the next election."]},{"word":"conquer","level":"C1","type":"v.","turkish":"Fethetmek, ele geçirmek; yenmek, üstesinden gelmek (zorluk vb.).","definition":"To overcome and take control of (a place or people) by use of military force; successfully overcome (a problem or weakness).","examples":["The Normans conquered England in 1066.","He is determined to conquer his fear of flying."]},{"word":"conscience","level":"C1","type":"n.","turkish":"Vicdan.","definition":"A person's moral sense of right and wrong, viewed as acting as a guide to one's behaviour.","examples":["My conscience wouldn't let me keep the money I found.","He has a guilty conscience about what he did."]},{"word":"consciousness","level":"C1","type":"n.","turkish":"Bilinç,şuur; farkındalık.","definition":"The state of being awake and aware of one's surroundings; the awareness or perception of something by a person.","examples":["He lost consciousness after hitting his head.","There is a growing consciousness of environmental issues."]},{"word":"consecutive","level":"C1","type":"adj.","turkish":"Ardışık, art arda gelen, birbirini izleyen.","definition":"Following continuously; in unbroken or logical sequence.","examples":["The team won five consecutive games.","She was absent for three consecutive days."]},{"word":"consensus","level":"C1","type":"n.","turkish":"Fikir birliği, uzlaşma, mutabakat.","definition":"General agreement.","examples":["The committee failed to reach a consensus.","There is a growing consensus that climate change is a serious threat."]},{"word":"consent","level":"C1","type":"n.","turkish":"(n) Rıza, onay, muvafakat; (v) Rıza göstermek, onaylamak, izin vermek.","definition":"(n) Permission for something to happen or agreement to do something. (v) To give permission for something to happen.","examples":["You need written consent from your parents to go on the trip. (noun) He reluctantly consented to the proposal. (verb)"]},{"word":"consequently","level":"B2","type":"adv.","turkish":"Sonuç olarak, bu nedenle, bunun sonucunda.","definition":"As a result; therefore.","examples":["He overslept and, consequently, was late for work.","The company invested heavily in marketing; consequently, sales increased significantly."]},{"word":"conservation","level":"B2","type":"n.","turkish":"Koruma, muhafaza (doğa,çevre, tarihi eser vb.).","definition":"The action of conserving something, in particular the preservation, protection, or restoration of the natural environment, natural resources, or historical sites.","examples":["Wildlife conservation is crucial for biodiversity.","The old building is undergoing conservation work."]},{"word":"conserve","level":"C1","type":"v.","turkish":"Korumak, muhafaza etmek (enerji, su, doğa vb.).","definition":"To protect (something, especially an environmentally or culturally important place or thing) from harm or destruction; prevent the wasteful overuse of (a resource).","examples":["We need to conserve water during the drought.","Efforts are being made to conserve endangered species."]},{"word":"considerable","level":"B2","type":"adj.","turkish":"Önemli (ölçüde), hatırı sayılır, kayda değer.","definition":"Notably large in size, amount, or extent.","examples":["The project required a considerable amount of time and effort.","She has made considerable progress in her studies."]},{"word":"considerably","level":"B2","type":"adv.","turkish":"Önemliölçüde, bir hayli, oldukça.","definition":"By a notably large amount or to a notably large extent; greatly.","examples":["Prices have increased considerably over the past year.","He is considerably older than his wife."]},{"word":"consistency","level":"C1","type":"n.","turkish":"Tutarlılık, uyum; kıvam, yoğunluk.","definition":"Consistent behaviour or treatment; the quality of achieving a level of performance which does not vary greatly in quality over time; the viscosity of a liquid.","examples":["Consistency is important if you want to achieve your goals.","The sauce should have the consistency of thick cream."]},{"word":"consistently","level":"B2","type":"adv.","turkish":"Sürekli olarak, tutarlı birşekilde.","definition":"In every case or on every occasion; invariably; in a way that does not vary.","examples":["She consistently arrives late for meetings.","The team has performed consistently well throughout the season."]},{"word":"consolidate","level":"C1","type":"v.","turkish":"Sağlamlaştırmak, pekiştirmek; birleştirmek (şirket, borç vb.).","definition":"To combine (a number of things) into a single more effective or coherent whole; make (something) physically stronger or more solid.","examples":["The company plans to consolidate its operations at a single site.","Victory helped to consolidate his position as leader."]},{"word":"conspiracy","level":"B2","type":"n.","turkish":"Komplo, suikast planı, gizli anlaşma.","definition":"A secret plan by a group to do something unlawful or harmful.","examples":["They were accused of conspiracy to overthrow the government.","He believes there was a conspiracy behind the assassination."]},{"word":"constitute","level":"C1","type":"v.","turkish":"Oluşturmak, teşkil etmek, meydana getirmek.","definition":"To be (a part) of a whole; be or be equivalent to (something).","examples":["Women constitute more than half of the workforce.","These actions constitute a serious breach of contract."]},{"word":"constitution","level":"C1","type":"n.","turkish":"Anayasa; bünye, yapı (vücut vb.).","definition":"A body of fundamental principles or established precedents according to which a state or other organization is acknowledged to be governed; a person's physical state regarding health and strength.","examples":["Freedom of speech is guaranteed by the constitution.","He has a strong constitution and rarely gets ill."]},{"word":"constitutional","level":"C1","type":"adj.","turkish":"Anayasal.","definition":"Relating to an established set of principles governing a state; in accordance with a political constitution.","examples":["The Supreme Court ruled that the law was constitutional.","Every citizen has constitutional rights."]},{"word":"constraint","level":"C1","type":"n.","turkish":"Kısıtlama, sınırlama; baskı.","definition":"A limitation or restriction; stiffness of manner and inhibition in relations between people.","examples":["Budget constraints forced them to delay the project.","She felt weighed down by the constraints of her job."]},{"word":"consult","level":"B2","type":"v.","turkish":"Danışmak, başvurmak (uzmana, kaynağa vb.).","definition":"To seek information or advice from (someone with expertise in a particular area); refer to (a source of information) in order to ascertain something.","examples":["You should consult your doctor if the symptoms persist.","I need to consult the manual before using the machine."]},{"word":"consultant","level":"B2","type":"n.","turkish":"Danışman, uzman.","definition":"A person who provides expert advice professionally.","examples":["The company hired a management consultant to improve efficiency.","She works as an independent IT consultant."]},{"word":"consultation","level":"C1","type":"n.","turkish":"Danışma, görüşme; konsültasyon (doktorlar arası vb.).","definition":"The action or process of formally consulting or discussing; a meeting with an expert, such as a medical doctor, in order to seek advice.","examples":["You may need a consultation with a specialist.","The decision was made after extensive consultation with stakeholders."]},{"word":"consumption","level":"B2","type":"n.","turkish":"Tüketim (enerji, gıda vb.).","definition":"The action of using up a resource; the eating, drinking, or ingesting of something.","examples":["Energy consumption increases significantly during winter.","The government is trying to reduce tobacco consumption."]},{"word":"contemplate","level":"C1","type":"v.","turkish":"Derin düşünmek, düşünceye dalmak; niyet etmek, düşünmek.","definition":"To look thoughtfully for a long time at; think profoundly and at length; meditate; think about (doing something).","examples":["He sat by the window and contemplated the view.","She is contemplating changing her job."]},{"word":"contempt","level":"C1","type":"n.","turkish":"Aşağılama, hor görme, küçümseme; (mahkemeye) itaatsizlik.","definition":"The feeling that a person or a thing is beneath consideration, worthless, or deserving scorn; disregard for something that should be taken into account; (contempt of court) the offence of being disobedient to or disrespectful towards a court of law.","examples":["She looked at him with utter contempt.","He was held in contempt of court for refusing to answer questions."]},{"word":"contend","level":"C1","type":"v.","turkish":"Mücadele etmek, yarışmak; iddia etmek, savunmak.","definition":"To struggle to surmount (a difficulty or danger); engage in a competition or campaign in order to win or achieve (something); assert something as a position in an argument.","examples":["Three teams are contending for the championship.","The lawyer contended that her client was innocent."]},{"word":"contender","level":"C1","type":"n.","turkish":"Yarışmacı, rakip (şampiyonluk,ödül vb. için).","definition":"A person or group competing with others to achieve something.","examples":["He is a serious contender for the presidential nomination.","Several strong contenders are participating in the race. content² (adj."]},{"word":"contention","level":"C1","type":"n.","turkish":"İddia, sav;çekişme, anlaşmazlık.","definition":"An assertion, especially one maintained in argument; heated disagreement.","examples":["It is my contention that the plan will not work.","The main point of contention was the proposed budget cuts."]},{"word":"continually","level":"C1","type":"adv.","turkish":"Sürekli olarak, devamlı (genellikle aralıklarla tekrarlanan).","definition":"Repeated frequently in the same way; regularly. (Often implies repetition with interruptions, unlike 'continuously').","examples":["The phone has been ringing continually all morning.","He continually interrupted the speaker."]},{"word":"contractor","level":"C1","type":"n.","turkish":"Müteahhit, yüklenici; (bağımsız) sözleşmeliçalışan.","definition":"A person or company that undertakes a contract to provide materials or labor to perform a service or do a job.","examples":["We hired a building contractor to renovate the house.","Many IT professionals work as independent contractors."]},{"word":"contradiction","level":"C1","type":"n.","turkish":"Çelişki, tutarsızlık, aykırılık.","definition":"A combination of statements, ideas, or features of a situation that are opposed to one another; inconsistency.","examples":["There is a direct contradiction between his words and actions.","His testimony was full of contradictions."]},{"word":"contrary","level":"C1","type":"adj.","turkish":"(adj) Ters, aksi, zıt; (n) Aksine, tersi ('on the contrary').","definition":"(adj) Opposite in nature, direction, or meaning. (n) The opposite.","examples":["Contrary to popular belief, bats are not blind. (adjective) I thought it would be difficult, but on the contrary, it was quite easy. (noun phrase)"]},{"word":"contributor","level":"C1","type":"n.","turkish":"Katkıda bulunan, katkı sağlayan (kişi, faktör); (yazı vb.) gönderen yazar.","definition":"A person or thing that contributes something; a person who writes articles for a newspaper, magazine, or book.","examples":["He was a major contributor to the charity fund.","Lack of sleep is a key contributor to stress."]},{"word":"controversial","level":"B2","type":"adj.","turkish":"Tartışmalı,çekişmeli, ihtilaflı.","definition":"Giving rise or likely to give rise to public disagreement.","examples":["The government's new policy is highly controversial.","He is a controversial figure in politics."]},{"word":"controversy","level":"B2","type":"n.","turkish":"Tartışma, anlaşmazlık, ihtilaf (genellikle kamuoyuönünde).","definition":"Prolonged public disagreement or heated discussion.","examples":["The decision sparked a major controversy.","The book caused considerable controversy when it was published."]},{"word":"convenience","level":"B2","type":"n.","turkish":"Kolaylık, rahatlık, uygunluk; (tuvalet anlamında 'public convenience').","definition":"The state of being able to proceed with something with little effort or difficulty; a thing that contributes to ease or comfort.","examples":["For your convenience, the store is open 24 hours.","Online banking offers great convenience to customers."]},{"word":"convention","level":"B2","type":"n.","turkish":"Kongre, toplantı; gelenek, adet; anlaşma, sözleşme (uluslararası).","definition":"A large meeting or conference; a way in which something is usually done; an agreement between countries covering particular matters.","examples":["The annual teachers' convention will be held in May.","Shaking hands is a common social convention."]},{"word":"conventional","level":"B2","type":"adj.","turkish":"Geleneksel, alışılagelmiş, konvansiyonel.","definition":"Based on or in accordance with what is generally done or believed.","examples":["They opted for a conventional church wedding.","His views on education are quite conventional."]},{"word":"conversion","level":"C1","type":"n.","turkish":"Dönüşüm, dönüştürme (din, para birimi, bina vb.).","definition":"The process of changing or causing something to change from one form to another.","examples":["The conversion of the old warehouse into apartments took two years.","Data conversion is required when switching to a new software system."]},{"word":"convey","level":"B2","type":"v.","turkish":"İletmek, aktarmak (mesaj, duygu vb.); taşımak, nakletmek.","definition":"To make (an idea, impression, or feeling) known or understandable to someone; transport or carry to a place.","examples":["Please convey my apologies to your wife.","Pipes are used to convey water to the city. convict (v."]},{"word":"conviction","level":"C1","type":"n.","turkish":"Mahkumiyet, suçlu bulma; kanı, inanç, kanaat.","definition":"A formal declaration that someone is guilty of a criminal offense; a firmly held belief or opinion.","examples":["He has several previous convictions for theft.","She spoke with great conviction about her political beliefs."]},{"word":"convincing","level":"B2","type":"adj.","turkish":"İkna edici, inandırıcı.","definition":"Capable of causing someone to believe that something is true or real.","examples":["The lawyer presented a convincing argument to the jury.","His explanation didn't sound very convincing. cooperate (v."]},{"word":"cope","level":"B2","type":"v.","turkish":"Başaçıkmak,üstesinden gelmek (zorluk, sorun vb.).","definition":"To deal effectively with something difficult.","examples":["She is finding it hard to cope with the stress of her new job.","He needs to learn healthy ways to cope with anxiety."]},{"word":"copper","level":"C1","type":"n.","turkish":"Bakır (metal).","definition":"A red-brown metal, the chemical element of atomic number 29.","examples":["Electrical wires are usually made of copper.","The pot has a shiny copper bottom."]},{"word":"copyright","level":"C1","type":"n.","turkish":"Telif hakkı.","definition":"The exclusive legal right, given to an originator or an assignee to print, publish, perform, film, or record literary, artistic, or musical material, and to authorize others to do the same.","examples":["This material is protected by copyright.","You need permission to reproduce copyright images."]},{"word":"corporation","level":"B2","type":"n.","turkish":"Şirket, kurum, anonimşirket.","definition":"A large company or group of companies authorized to act as a single entity and recognized as such in law.","examples":["He works for a large multinational corporation.","The corporation announced its quarterly earnings."]},{"word":"correction","level":"C1","type":"n.","turkish":"Düzeltme, tashih; ceza,ıslah.","definition":"The action or process of correcting something; a change that rectifies an error or inaccuracy; punishment intended to reform or improve.","examples":["Please make the necessary corrections to the document.","The newspaper published a correction the next day."]},{"word":"correlate","level":"C1","type":"v.","turkish":"İlişkilendirmek, bağlantı kurmak, korelasyon göstermek.","definition":"To have a mutual relationship or connection, in which one thing affects or depends on another.","examples":["Researchers tried to correlate the findings with data from previous studies.","Obesity often correlates with a higher risk of heart disease."]},{"word":"correlation","level":"C1","type":"n.","turkish":"Korelasyon, ilişki, bağlantı.","definition":"A mutual relationship or connection between two or more things.","examples":["There is a strong correlation between smoking and lung cancer.","Scientists are studying the correlation between diet and health."]},{"word":"correspond","level":"C1","type":"v.","turkish":"Haberleşmek, mektuplaşmak; karşılığı olmak, denk gelmek, uymak.","definition":"To communicate by exchanging letters; have a close similarity; match or agree almost exactly.","examples":["They corresponded regularly for many years.","The results correspond closely to our predictions."]},{"word":"correspondence","level":"C1","type":"n.","turkish":"Yazışma, mektuplaşma, haberleşme; benzerlik, uyum.","definition":"Communication by exchanging letters; letters sent or received; a close similarity, connection, or equivalence.","examples":["Her personal correspondence was published after her death.","There is a clear correspondence between the two sets of data."]},{"word":"correspondent","level":"C1","type":"n.","turkish":"Muhabir; mektup arkadaşı.","definition":"A person who writes letters to a person or a newspaper, especially on a regular basis; a journalist employed to report on a particular subject or from a foreign country.","examples":["He worked as a foreign correspondent in the Middle East.","She kept in touch with her old correspondent from France."]},{"word":"corresponding","level":"C1","type":"adj.","turkish":"Karşılık gelen, denk, benzer, ilgili.","definition":"Analogous or similar in character, form, or function; able to be related or connected.","examples":["Sales were up last year, with a corresponding increase in profits.","For each question, circle the corresponding letter on the answer sheet."]},{"word":"corridor","level":"B2","type":"n.","turkish":"Koridor.","definition":"A long passage in a building from which doors lead into rooms.","examples":["His office is at the end of the corridor.","The hotel corridors were dimly lit."]},{"word":"corrupt","level":"C1","type":"adj.","turkish":"Yolsuz, rüşvetçi, ahlaksız; bozuk, değiştirilmiş (veri vb.).","definition":"Having or showing a willingness to act dishonestly in return for money or personal gain; (of data, etc.) containing errors.","examples":["The investigation revealed a network of corrupt officials.","The file seems to be corrupt and won't open."]},{"word":"corruption","level":"C1","type":"n.","turkish":"Yolsuzluk, rüşvetçilik, ahlaki bozulma.","definition":"Dishonest or fraudulent conduct by those in power, typically involving bribery.","examples":["The government promised to fight corruption at all levels.","Political corruption is a major obstacle to development."]},{"word":"costly","level":"C1","type":"adj.","turkish":"Pahalı, masraflı; (mecazi) ağır (bedel).","definition":"Costing a lot; expensive; involving great loss or sacrifice.","examples":["Renovating the old house proved to be very costly.","The mistake was costly, resulting in lost customers. councilor (n."]},{"word":"counterpart","level":"C1","type":"n.","turkish":"Mevkidaş, akran, karşılık, benzer görevdeki kişi.","definition":"A person or thing holding a position or performing a function that corresponds to that of another person or thing in another place.","examples":["The prime minister met with his Canadian counterpart.","Our sales team is much smaller than its counterpart in the main competitor."]},{"word":"countless","level":"C1","type":"adj.","turkish":"Sayısız, pekçok.","definition":"Too many to be counted; very many.","examples":["There are countless stars visible in the night sky.","She has received countless awards for her work."]},{"word":"coup","level":"C1","type":"n.","turkish":"Darbe (hükümet); başarılı hamle.","definition":"A sudden, violent, and illegal seizure of power from a government; a notable or successful stroke or move.","examples":["The military coup overthrew the democratically elected government.","Signing the famous actor was a major coup for the small film company."]},{"word":"courtesy","level":"C1","type":"n.","turkish":"Nezaket, kibarlık, incelik; ikram, jest.","definition":"The showing of politeness in one's attitude and behavior toward others; a polite remark or action.","examples":["He treated everyone with courtesy and respect.","As a courtesy, please inform us if you cannot attend."]},{"word":"coverage","level":"B2","type":"n.","turkish":"Kapsam (sigorta, haber vb.); (medyada) yer alma, yayınlama.","definition":"The extent to which something deals with or applies to something else; the treatment of an issue by the media.","examples":["Does your insurance policy provide adequate coverage?","The event received extensive media coverage."]},{"word":"cowboy","level":"B2","type":"n.","turkish":"Kovboy.","definition":"(in the western US and Canada) A man, typically one on horseback, who herds and tends cattle.","examples":["The film depicted the life of cowboys in the Old West.","He dreamed of being a cowboy riding across the plains."]},{"word":"crack","level":"B2","type":"v.","turkish":"(v) Çatlatmak,çatlamak; (şifre vb.) kırmak; (şaka) yapmak; (ses)çatallanmak; (n) Çatlak; (ani, keski","definition":"(v) To break or cause to break without complete separation of the parts; find a solution to; decipher or interpret; make (a joke); (of a voice) break and become harsh. (n) A line on the surface of something along which it has split without breaking a","examples":["The vase cracked when I dropped it. (verb) There was a large crack in the wall. (noun)"]},{"word":"craft","level":"B2","type":"n.","turkish":"(n) El sanatı, zanaat; beceri, ustalık; gemi, tekne, hava aracı; (v) Ustalıkla yapmak,özenle hazırla","definition":"(n) An activity involving skill in making things by hand; skill in carrying out one's work; a boat or ship; an aircraft or spacecraft. (v) To exercise skill in making (something).","examples":["She sells traditional handicrafts and crafts at the market. (noun) The table was beautifully crafted from oak. (verb)"]},{"word":"crawl","level":"C1","type":"v.","turkish":"Emeklemek; sürünmek;çok yavaş ilerlemek.","definition":"To move forward on the hands and knees or by dragging the body close to the ground; move slowly.","examples":["The baby is just learning to crawl.","Traffic was crawling along due to the accident."]},{"word":"creativity","level":"B2","type":"n.","turkish":"Yaratıcılık.","definition":"The use of the imagination or original ideas, especially in the production of an artistic work.","examples":["The company encourages creativity and innovation among its employees.","Art classes can help develop children's creativity."]},{"word":"creator","level":"C1","type":"n.","turkish":"Yaratıcı, kurucu, mucit.","definition":"A person or thing that brings something into existence.","examples":["Walt Disney was the creator of Mickey Mouse.","She is the creator and director of the new TV series."]},{"word":"credibility","level":"C1","type":"n.","turkish":"Güvenilirlik, inanılırlık, itibarlılık.","definition":"The quality of being trusted and believed in.","examples":["The scandal damaged the politician's credibility.","Using reliable sources adds credibility to your research."]},{"word":"credible","level":"C1","type":"adj.","turkish":"Güvenilir, inanılır, itibarlı.","definition":"Able to be believed; convincing.","examples":["The police received a credible report of a bomb threat.","We need a credible witness to support the claim. creep (v."]},{"word":"critically","level":"B2","type":"adv.","turkish":"Eleştirel birşekilde; kritik/ciddi bir şekilde; son derece,çok.","definition":"In a way that expresses disapproval; in a way that involves careful judgment of the good and bad points of something; in a way that relates to or denotes a point of transition from one state to another; relating to or denoting a point of crisis; expr","examples":["The report was critically reviewed by experts.","He was critically injured in the accident."]},{"word":"critique","level":"C1","type":"n.","turkish":"Eleştiri, tenkit (genellikle detaylı ve analitik).","definition":"A detailed analysis and assessment of something, especially a literary, philosophical, or political theory.","examples":["She wrote a lengthy critique of the novel.","The professor provided a helpful critique of my essay."]},{"word":"crown","level":"C1","type":"n.","turkish":"Taç; zirve, tepe; (diş) kron.","definition":"A circular ornamental headdress worn by a monarch as a symbol of authority, usually made of or decorated with precious metals and jewels; the top or highest part of something; an artificial covering for a tooth.","examples":["The queen wore a diamond crown.","We reached the crown of the hill."]},{"word":"crude","level":"C1","type":"adj.","turkish":"Ham, işlenmemiş (petrol vb.); kaba, ilkel, basit; (davranış) kaba, nezaketsiz.","definition":"In a natural or raw state; not yet processed or refined; constructed in a rudimentary or makeshift way; offensively coarse or rude.","examples":["Crude oil needs to be refined before it can be used.","He made a crude drawing on the back of the envelope."]},{"word":"cruise","level":"B2","type":"n.","turkish":"(n) Gemi seyahati, gezinti; (v) Gemiyle seyahat etmek; (araçla) sabit hızda gitmek, dolaşmak.","definition":"(n) A voyage on a ship or boat taken for pleasure or as a holiday and usually calling in at several places. (v) Sail about in an area without a precise destination, especially for pleasure; travel smoothly at a moderate or economical speed.","examples":["They went on a Caribbean cruise for their honeymoon. (noun) We were cruising along the motorway at a steady 70 mph. (verb)"]},{"word":"crush","level":"C1","type":"v.","turkish":"Ezmek, ezilmek; (mecazi) yok etmek, bastırmak (isyan, umut vb.).","definition":"To deform, pulverize, or force inwards by compressing forcefully; subdue (opposition or a rebellion) completely.","examples":["Crush the garlic before adding it to the sauce.","The army quickly crushed the rebellion."]},{"word":"crystal","level":"C1","type":"n.","turkish":"Kristal; kesme cam.","definition":"A piece of a homogeneous solid substance having a natural geometrically regular form with symmetrically arranged plane faces; highly transparent glass with a high refractive index.","examples":["Snowflakes are intricate ice crystals.","She served the wine in beautiful crystal glasses."]},{"word":"cue","level":"B2","type":"n.","turkish":"İşaret, replik (tiyatro vb.); (bilardo) isteka.","definition":"A signal for action; the starting signal for a performer to enter or speak; a long tapering rod used to strike a ball in games such as billiards or snooker.","examples":["The actor missed his cue and entered the stage late.","That laugh was my cue to leave the room."]},{"word":"cult","level":"C1","type":"n.","turkish":"(n) Tarikat, kült; (aşırı) hayranlık; (adj) Kült (film, kitap vb.).","definition":"(n) A system of religious veneration and devotion directed toward a particular figure or object; a relatively small group of people having religious beliefs or practices regarded by others as strange or sinister; a misplaced or excessive admiration f","examples":["He was brainwashed into joining a dangerous religious cult. (noun) The movie quickly became a cult classic among sci -fi fans. (adjective)"]},{"word":"cultivate","level":"C1","type":"v.","turkish":"Yetiştirmek (toprak, bitki); geliştirmek (beceri, ilişki vb.).","definition":"To prepare and use (land) for crops or gardening; try to acquire or develop (a quality, sentiment, or skill); try to win the friendship or favor of (someone).","examples":["The villagers cultivate mainly corn and beans.","She has cultivated an image as a tough negotiator."]},{"word":"curiosity","level":"C1","type":"n.","turkish":"Merak; nadir veya ilginç nesne.","definition":"A strong desire to know or learn something; a strange or unusual object or fact.","examples":["Children show great curiosity about the world around them.","Out of curiosity, I opened the old box."]},{"word":"curious","level":"B2","type":"adj.","turkish":"Meraklı; tuhaf, garip.","definition":"Eager to know or learn something; strange; unusual.","examples":["I was curious to find out what would happen next.","We saw a curious object floating in the water. curriculum (n."]},{"word":"custody","level":"C1","type":"n.","turkish":"Gözaltı, tutukluluk; velayet (çocuk).","definition":"The protective care or guardianship of someone or something; imprisonment.","examples":["The suspect was taken into police custody.","The court granted joint custody of the children to both parents. cute (adj."]},{"word":"cutting","level":"C1","type":"n.","turkish":"Kesme, kesim; (bitki)çelik; gazete kupürü; (mecazi) incitici söz.","definition":"A piece cut off from something, especially a stem or shoot cut from a plant for rooting or grafting; an article or picture cut from a newspaper or magazine; the action of cutting something.","examples":["She took a cutting from the rose bush to plant in her own garden.","The article included some hurtful cuttings about his performance."]},{"word":"cynical","level":"C1","type":"adj.","turkish":"Sinik, kuşkucu, herşeyde art niyet arayan.","definition":"Believing that people are motivated purely by self -interest; distrustful of human sincerity or integrity; doubtful as to whether something will happen or whether it is worthwhile.","examples":["He has a very cynical view of politicians.","Why are you so cynical about their motives?"]},{"word":"dairy","level":"B2","type":"n.","turkish":"(n) Mandıra; sütürünleri; (adj) Süt(le ilgili), mandıra(yla ilgili).","definition":"(n) A building, room, or company for the storage, processing, and distribution of milk and milk products; milk and milk products collectively. (adj) Containing or made from milk.","examples":["We buy fresh milk from the local dairy. (noun) Cheese and yogurt are dairy products. (adjective)"]},{"word":"dam","level":"C1","type":"n.","turkish":"Baraj.","definition":"A barrier constructed to hold back water and raise its level, forming a reservoir used to generate electricity or as a water supply.","examples":["The construction of the new dam will take five years.","Hydroelectric power is generated by the dam."]},{"word":"damaging","level":"C1","type":"adj.","turkish":"Zarar verici, hasara yol açan.","definition":"Causing harm or injury.","examples":["The scandal had a damaging effect on his reputation.","Smoking has damaging effects on health."]},{"word":"dare","level":"B2","type":"v.","turkish":"Cesaret etmek, cüret etmek; meydan okumak.","definition":"To have the courage to do something; challenge (someone) to do something risky or audacious.","examples":["I wouldn't dare to ask him for more money.","He dared his friend to jump into the cold water."]},{"word":"darkness","level":"B2","type":"n.","turkish":"Karanlık; (mecazi) kötülük, cehalet.","definition":"The partial or total absence of light; wickedness or evil.","examples":["He switched on the light to dispel the darkness.","The story explores the darkness within human nature."]},{"word":"database","level":"B2","type":"n.","turkish":"Veritabanı.","definition":"A structured set of data held in a computer, especially one that is accessible in various ways.","examples":["The company maintains a large database of customer information.","You can search the online database for relevant articles."]},{"word":"dawn","level":"C1","type":"n.","turkish":"Şafak, tan vakti; (mecazi) başlangıç.","definition":"The first appearance of light in the sky before sunrise; the beginning of a phenomenon or period of time.","examples":["We woke up before dawn to watch the sunrise.","The invention of the printing press marked the dawn of a new era."]},{"word":"deadline","level":"B2","type":"n.","turkish":"Son teslim tarihi, mühlet.","definition":"The latest time or date by which something should be completed.","examples":["The deadline for submitting the application is Friday.","He worked late to meet the project deadline."]},{"word":"deadly","level":"B2","type":"adj.","turkish":"Öldürücü,ölümcül; (mecazi)çok sıkıcı.","definition":"Causing or able to cause death; (informal) extremely boring.","examples":["Some snakes have a deadly bite.","The meeting was absolutely deadly; I almost fell asleep."]},{"word":"dealer","level":"B2","type":"n.","turkish":"Satıcı, bayi (araba, sanat eseri vb.); (iskambil) dağıtan kişi; (uyuşturucu) satıcısı.","definition":"A person or business that buys and sells goods; a person who deals cards in a game; a person who sells illegal drugs.","examples":["We bought our car from a reputable dealer.","He works as an antique dealer. debris (n."]},{"word":"debut","level":"C1","type":"n.","turkish":"İlkçıkış, ilk sahneye/gösterimeçıkma.","definition":"A person's first appearance or performance in a particular capacity or role.","examples":["The young actress made her professional debut in the play.","The band's debut album was a huge success."]},{"word":"decision -making","level":"C1","type":"n.","turkish":"Karar verme (süreci).","definition":"The action or process of making important decisions.","examples":["Good decision-making is crucial for effective leadership.","Employees should be involved in the decision-making process."]},{"word":"decisive","level":"C1","type":"adj.","turkish":"Kararlı, kesin (sonucu belirleyen); azimli.","definition":"Settling an issue; producing a definite result; having or showing the ability to make decisions quickly and effectively.","examples":["The final battle was decisive in ending the war.","She is admired for her decisive leadership style."]},{"word":"deck","level":"B2","type":"n.","turkish":"Güverte (gemi, otobüs); (iskambil) deste; (ahşap) veranda.","definition":"A floor of a ship or bus; a pack of playing cards; a flat, wooden platform built onto a house.","examples":["Passengers gathered on the top deck to enjoy the view.","Can you shuffle the deck of cards?"]},{"word":"declaration","level":"C1","type":"n.","turkish":"Beyan, bildiri, ilan; (gümrük) beyannamesi.","definition":"A formal or explicit statement or announcement; the formal announcement of the beginning of a state or condition.","examples":["The Declaration of Independence was signed in 1776.","You need to make a customs declaration when entering the country."]},{"word":"dedicated","level":"C1","type":"adj.","turkish":"Adanmış, kendini adamış; (belirli bir amaca) ayrılmış.","definition":"(of a person) Devoted to a task or purpose; having single -minded loyalty or integrity; exclusively allocated to or intended for a particular purpose.","examples":["She is a dedicated teacher who works hard for her students.","This computer is dedicated solely to running the security system."]},{"word":"dedication","level":"C1","type":"n.","turkish":"Adama, bağlılık,özveri; ithaf (kitap vb.).","definition":"The quality of being dedicated or committed to a task or purpose; the words with which a book, piece of music, etc. is dedicated.","examples":["Success requires hard work and dedication.","The book's dedication read: \"To my parents.\""]},{"word":"deed","level":"C1","type":"n.","turkish":"Eylem, fiil, iş (genellikleönemli veya dikkatçekici); (hukuk) tapu senedi, resmi belge.","definition":"An action that is performed intentionally or consciously; a legal document that is signed and delivered, especially one regarding the ownership of property or legal rights.","examples":["Helping the elderly woman cross the street was a kind deed.","They signed the deed to the house last week. deem (v."]},{"word":"default","level":"C1","type":"n.","turkish":"Varsayılan (ayar); (borcu)ödememe, yükümlülüğü yerine getirmeme.","definition":"Failure to fulfill an obligation, especially to repay a loan or appear in a court of law; a preselected option adopted by a computer program or other mechanism when no alternative is specified by the user or programmer.","examples":["The company is in default on its loan payments.","The default setting for the font size is 12 points."]},{"word":"defect","level":"C1","type":"n.","turkish":"Kusur, hata, arıza, defo.","definition":"A shortcoming, imperfection, or lack.","examples":["There is a small defect in the fabric.","The car was recalled due to a manufacturing defect."]},{"word":"defender","level":"B2","type":"n.","turkish":"Savunucu, müdafi; (spor) defans oyuncusu.","definition":"A person who defends someone or something; (in sport) a player whose chief role is to prevent the opposing team from scoring.","examples":["He is a passionate defender of human rights.","The team has several strong defenders."]},{"word":"defensive","level":"C1","type":"adj.","turkish":"Savunmacı, savunmaya yönelik; alıngan, hemen savunmaya geçen.","definition":"Used or intended to defend or protect; very anxious to challenge or avoid criticism.","examples":["The army took up defensive positions along the border.","She became very defensive when asked about her mistakes."]},{"word":"deficiency","level":"C1","type":"n.","turkish":"Eksiklik, yetersizlik (vitamin, kanıt vb.).","definition":"A lack or shortage.","examples":["Iron deficiency can lead to anemia.","The report highlighted several deficiencies in the safety procedures."]},{"word":"deficit","level":"C1","type":"n.","turkish":"Açık (bütçe, hesap vb.), eksiklik.","definition":"The amount by which something, especially a sum of money, is too small; an excess of expenditure or liabilities over income or assets in a given period.","examples":["The government is trying to reduce the budget deficit.","The company reported a trade deficit for the last quarter."]},{"word":"defy","level":"C1","type":"v.","turkish":"Karşı gelmek, meydan okumak; (açıklamaya vb.) imkan vermemek.","definition":"To openly resist or refuse to obey; appear to be challenging (someone) to do or prove something; (of a thing) make (an action or quality) almost impossible.","examples":["Some teenagers defy their parents' rules.","The sheer scale of the project defies description."]},{"word":"delegate","level":"C1","type":"n.","turkish":"Delege, temsilci, elçi.","definition":"A person sent or authorized to represent others, in particular an elected representative sent to a conference.","examples":["Each country sent two delegates to the international summit.","The union delegates voted on the proposal."]},{"word":"delegation","level":"C1","type":"n.","turkish":"Delegasyon, heyet, temsilciler kurulu; yetki devri.","definition":"A body of delegates or representatives; the act or process of delegating or being delegated.","examples":["A delegation from Japan visited the factory.","Effective delegation is an important management skill."]},{"word":"delete","level":"B2","type":"v.","turkish":"Silmek (yazı, dosya vb.).","definition":"To remove or obliterate (written or printed matter, especially by drawing a line through it or pressing a delete key).","examples":["Please delete the previous paragraph.","I accidentally deleted the important email."]},{"word":"delicate","level":"C1","type":"adj.","turkish":"Hassas, narin, kırılgan; ince, zarif; (konu) hassas, nazik.","definition":"Very fine in texture or structure; easily broken or damaged; fragile; requiring sensitive or careful handling.","examples":["Be careful with those delicate glass ornaments.","We need to handle this delicate situation with care."]},{"word":"delighted","level":"B2","type":"adj.","turkish":"Memnun, hoşnut, sevinçli.","definition":"Feeling or showing great pleasure.","examples":["We were delighted to hear your good news.","She was delighted with her birthday present."]},{"word":"democracy","level":"B2","type":"n.","turkish":"Demokrasi.","definition":"A system of government by the whole population or all the eligible members of a state, typically through elected representatives.","examples":["Freedom of speech is a fundamental principle of democracy.","The country is transitioning towards democracy."]},{"word":"democratic","level":"B2","type":"adj.","turkish":"Demokratik.","definition":"Relating to or supporting democracy or its principles.","examples":["The organization aims to promote democratic values.","A democratic election was held last year."]},{"word":"demon","level":"C1","type":"n.","turkish":"İblis,şeytan, cin; (mecazi) kötü etki, takıntı.","definition":"An evil spirit or devil, especially one thought to possess a person or act as a tormentor in hell; a cruel, evil, or destructive person or thing.","examples":["Ancient myths often feature gods and demons.","He battled his personal demons of addiction."]},{"word":"demonstration","level":"B2","type":"n.","turkish":"Gösteri, demonstrasyon (ürün, protesto vb.); kanıt, ispat.","definition":"An act of showing that something exists or is true by giving proof or evidence; a practical exhibition and explanation of how something works or is performed; a public meeting or march protesting against something or expressing views on a political i","examples":["The salesperson gave a demonstration of the new vacuum cleaner.","Thousands attended the peaceful demonstration against the war."]},{"word":"denial","level":"C1","type":"n.","turkish":"İnkar, yalanlama, ret.","definition":"The action of declaring something to be untrue; refusal to admit the truth or existence of something.","examples":["He issued a firm denial of the accusations.","She remained in denial about her illness for a long time."]},{"word":"denounce","level":"C1","type":"v.","turkish":"Kınamak, suçlamak, (kamuoyu önünde) itham etmek.","definition":"To publicly declare to be wrong or evil; inform against.","examples":["The government denounced the attack as an act of terrorism.","He was denounced as a traitor by his former colleagues."]},{"word":"dense","level":"C1","type":"adj.","turkish":"Yoğun (sis, nüfus vb.); sıkı, sık (orman vb.); (mecazi, gayriresmi) aptal, kalın kafalı.","definition":"Closely compacted in substance; having the constituent parts crowded closely together; (informal) stupid.","examples":["We couldn't see anything through the dense fog.","The Amazon rainforest is incredibly dense."]},{"word":"density","level":"C1","type":"n.","turkish":"Yoğunluk (nüfus, madde vb.).","definition":"The degree of compactness of a substance; the quantity of people or things in a given area or space.","examples":["Monaco has a very high population density.","The density of the material affects its buoyancy. depart (v."]},{"word":"dependence","level":"C1","type":"n.","turkish":"Bağımlılık, bağlılık.","definition":"The state of relying on or being controlled by someone or something else.","examples":["The country is trying to reduce its dependence on imported oil.","Drug dependence is a serious health issue."]},{"word":"dependent","level":"B2","type":"adj.","turkish":"Bağımlı, bağlı; bakmakla yükümlü olunan kişi.","definition":"Contingent on or determined by; requiring someone or something for financial, emotional, or other support.","examples":["The project's success is dependent on careful planning.","He has two young dependent children."]},{"word":"depict","level":"C1","type":"v.","turkish":"Tasvir etmek, resmetmek, anlatmak.","definition":"To represent by a drawing, painting, or other art form; portray in words; describe.","examples":["The painting depicts a scene from Greek mythology.","The novel depicts the struggles of a poor family during the war."]},{"word":"deploy","level":"C1","type":"v.","turkish":"(Askeri birlik, kaynak vb.) konuşlandırmak, sevk etmek, yaymak.","definition":"To move (troops or equipment) into position for military action; bring resources into effective action.","examples":["The government decided to deploy troops to the border region.","We need to deploy our resources more effectively."]},{"word":"deployment","level":"C1","type":"n.","turkish":"Konuşlandırma, sevk etme, yayma.","definition":"The movement of troops or equipment to a place or position for military action; the action of bringing resources into effective action.","examples":["The deployment of soldiers took several days.","Careful planning is required for successful software deployment."]},{"word":"deposit","level":"B2","type":"v.","turkish":"(n) Depozito, kapora; bankadaki mevduat; tortu, birikinti; (v) Para yatırmak (bankaya); (bir yere) b","definition":"(n) A sum of money paid into a bank or building society account; a sum payable as a first installment on the purchase of something or as a pledge for a contract; a layer or body of accumulated matter. (v) Put or set down (something or someone) in a s","examples":["I need to make a deposit at the bank. (noun) He deposited the keys on the table. (verb) We paid a deposit to reserve the holiday apartment. (noun)"]},{"word":"depression","level":"B2","type":"n.","turkish":"Depresyon, ruhsalçöküntü; ekonomik durgunluk, buhran;çöküntü,çukur alan.","definition":"Feelings of severe despondency and dejection; a long and severe recession in an economy or market; a sunken place or hollow on a surface.","examples":["She sought treatment for her depression.","The Great Depression affected millions of people worldwide."]},{"word":"deprive","level":"C1","type":"v.","turkish":"Mahrum etmek, yoksun bırakmak.","definition":"To deny (a person or place) the possession or use of something.","examples":["The prisoners were deprived of basic necessities.","Working long hours deprived him of sleep."]},{"word":"deputy","level":"C1","type":"n.","turkish":"Vekil, yardımcı (şerif, müdür vb.).","definition":"A person who is appointed to undertake the duties of a superior in the superior's absence; the second-in-command or assistant.","examples":["The deputy manager will handle things while the manager is away.","He served as the deputy sheriff for many years."]},{"word":"derive","level":"B2","type":"v.","turkish":"Türetmek, -den elde etmek; -den kaynaklanmak, -den gelmek.","definition":"To obtain something from (a specified source); base a concept or application on (a source or idea).","examples":["Many English words derive from Latin.","She derives great pleasure from her garden."]},{"word":"descend","level":"C1","type":"v.","turkish":"İnmek, alçalmak; soyundan gelmek.","definition":"To move or fall downwards; be a direct blood relative of (a specified, typically illustrious person or group).","examples":["The plane began to descend as it approached the airport.","They claim to be descended from royalty."]},{"word":"descent","level":"C1","type":"n.","turkish":"İniş, alçalma; soy, köken.","definition":"An action of moving downward, dropping, or falling; the origin or background of a person in terms of family or nationality.","examples":["The steep descent was difficult in the dark.","She is of Irish descent."]},{"word":"designate","level":"C1","type":"v.","turkish":"Belirlemek, atamak, görevlendirmek; göstermek, işaret etmek.","definition":"To appoint (someone) to a specified position; officially assign a specified status or purpose to.","examples":["He was designated as team leader.","This area has been designated a national park."]},{"word":"desirable","level":"C1","type":"adj.","turkish":"Arzu edilir, istenir, cazip.","definition":"Wished for as being attractive, useful, or necessary.","examples":["Good communication skills are highly desirable in this job.","Living close to the city center is desirable for many people."]},{"word":"desktop","level":"C1","type":"n.","turkish":"Masaüstü bilgisayar; (bilgisayar) masaüstü (ekranı).","definition":"A computer suitable for use at an ordinary desk; the working surface of a desk; the main screen display on a personal computer, from which windows may be opened.","examples":["I prefer working on a desktop computer rather than a laptop.","Save the file to your desktop so you can find it easily."]},{"word":"desperately","level":"B2","type":"adv.","turkish":"Umutsuzca,çaresizce; son derece, çok.","definition":"In a way that shows despair; in a way that shows extreme need or desire.","examples":["He looked around desperately for a way to escape.","She desperately wanted to win the competition."]},{"word":"destruction","level":"B2","type":"n.","turkish":"Yıkım, tahribat, imha.","definition":"The action or process of causing so much damage to something that it no longer exists or cannot be repaired.","examples":["The earthquake caused widespread destruction.","War leads to death and destruction."]},{"word":"destructive","level":"C1","type":"adj.","turkish":"Yıkıcı, tahrip edici, zararlı.","definition":"Causing great and irreparable damage.","examples":["Hurricanes can be highly destructive.","Negative criticism can be destructive to someone's confidence."]},{"word":"detain","level":"C1","type":"v.","turkish":"Gözaltına almak, alıkoymak; geciktirmek.","definition":"To keep (someone) from proceeding; hold back; keep (someone) in official custody, typically for questioning about a crime or in politically sensitive situations.","examples":["The police detained two men for questioning.","I'm sorry I'm late; I was detained in a meeting."]},{"word":"detection","level":"C1","type":"n.","turkish":"Tespit etme, bulma, ortayaçıkarma.","definition":"The action or process of identifying the presence of something concealed or subtle.","examples":["Early detection of the disease significantly improves survival rates.","Metal detection systems are used at airports for security."]},{"word":"detention","level":"C1","type":"n.","turkish":"Gözaltı, alıkoyma; (okulda) cezaya kalma.","definition":"The action of detaining someone or the state of being detained in official custody; the punishment of being kept in school after hours.","examples":["The suspects were held in detention overnight.","He got a detention for being late to class."]},{"word":"deteriorate","level":"C1","type":"v.","turkish":"Kötüleşmek, fenalaşmak, bozulmak.","definition":"To become progressively worse.","examples":["Her health began to deteriorate rapidly.","The relationship between the two countries has deteriorated."]},{"word":"determination","level":"B2","type":"n.","turkish":"Kararlılık, azim; belirleme, saptama.","definition":"Firmness of purpose; resoluteness; the process of establishing something exactly, typically by calculation or research.","examples":["She showed great determination to succeed despite the difficulties.","Accurate determination of the launch date is crucial."]},{"word":"devastate","level":"C1","type":"v.","turkish":"Yıkmak, mahvetmek, harap etmek; (mecazi)çoküzmek, perişan etmek.","definition":"To destroy or ruin (something); cause (someone) severe and overwhelming shock or grief.","examples":["The hurricane devastated the coastal town.","She was devastated by the news of her friend's death."]},{"word":"devil","level":"C1","type":"n.","turkish":"Şeytan, iblis.","definition":"(in Christian and Jewish belief) The supreme spirit of evil; Satan.","examples":["Traditional stories often depict the devil as tempting humans. \"Speak of the devil!\" he exclaimed as the person they were discussing arrived. (Idiom)"]},{"word":"devise","level":"C1","type":"v.","turkish":"Tasarlamak, planlamak, icat etmek, bulmak.","definition":"To plan or invent (a complex procedure, system, or mechanism) by careful thought.","examples":["They devised a clever plan to escape.","Scientists are trying to devise new ways to combat the disease."]},{"word":"devote","level":"B2","type":"v.","turkish":"Adamak, vakfetmek (zaman,çaba vb.).","definition":"To give all or a large part of one's time or resources to (a person, activity, or cause).","examples":["She devotes most of her free time to charity work.","He devoted his life to studying ancient history."]},{"word":"diagnose","level":"C1","type":"v.","turkish":"Teşhis etmek, tanı koymak (hastalık, sorun vb.).","definition":"To identify the nature of (an illness or other problem) by examination of the symptoms.","examples":["The doctor diagnosed the illness as pneumonia.","It is difficult to diagnose the problem without more information. diagnosis (n."]},{"word":"dictate","level":"C1","type":"v.","turkish":"Dikte etmek, yazdırmak; emretmek, zorla kabul ettirmek.","definition":"To say or read aloud (words to be typed, written down, or recorded on tape); state or order authoritatively.","examples":["She dictated a letter to her assistant.","We cannot let one person dictate the terms of the agreement."]},{"word":"dictator","level":"C1","type":"n.","turkish":"Diktatör.","definition":"A ruler with total power over a country, typically one who has obtained control by force.","examples":["The country suffered for years under the rule of a brutal dictator.","People lived in fear of the dictator's regime."]},{"word":"differ","level":"B2","type":"v.","turkish":"Farklı olmak, ayrılmak; aynı fikirde olmamak.","definition":"To be unlike or dissimilar; disagree.","examples":["My opinion differs greatly from yours.","The twins look alike but differ in personality."]},{"word":"differentiate","level":"C1","type":"v.","turkish":"Ayırt etmek, farkını görmek/göstermek.","definition":"To recognize or ascertain what makes (someone or something) different; identify differences between (two or more things or people).","examples":["It's important to differentiate between fact and opinion.","What differentiates their product from the competition?"]},{"word":"dignity","level":"C1","type":"n.","turkish":"İtibar, saygınlık, haysiyet, vakar.","definition":"The state or quality of being worthy of honor or respect; a sense of pride in oneself; self-respect.","examples":["He faced the difficult situation with courage and dignity.","Treat everyone with dignity and respect."]},{"word":"dilemma","level":"C1","type":"n.","turkish":"İkilem,çıkmaz, açmaz.","definition":"A situation in which a difficult choice has to be made between two or more alternatives, especially equally undesirable ones.","examples":["She faced the dilemma of choosing between her career and her family.","This placed him in a moral dilemma. dime (n."]},{"word":"dimension","level":"C1","type":"n.","turkish":"Boyut (uzunluk, genişlik, yükseklik); yön, taraf, veçhe.","definition":"A measurable extent of a particular kind, such as length, breadth, depth, or height; an aspect or feature of a situation, problem, or thing.","examples":["Please measure the exact dimensions of the room.","The problem has a social and economic dimension."]},{"word":"diminish","level":"C1","type":"v.","turkish":"Azaltmak, eksiltmek; azalmak, eksilmek.","definition":"To make or become less.","examples":["The government hopes to diminish the influence of T.V. in children's lives.","Our enthusiasm for the project gradually diminished."]},{"word":"dip","level":"C1","type":"v.","turkish":"Batırmak, daldırmak (kısa süreliğine); (seviye, değer) düşmek, azalmak.","definition":"To put or let something down briefly into liquid; sink, drop, or slope downward.","examples":["She dipped her biscuit into her tea.","Temperatures are expected to dip below freezing tonight."]},{"word":"diplomat","level":"C1","type":"n.","turkish":"Diplomat.","definition":"An official representing a country abroad.","examples":["Senior diplomats attended the international negotiations.","He served as a diplomat in several European countries."]},{"word":"diplomatic","level":"C1","type":"adj.","turkish":"Diplomatik; (mecazi) nazik, düşünceli, ince.","definition":"Relating to or involved in diplomacy; having or showing an ability to deal with people in a sensitive and effective way.","examples":["The two countries resolved the issue through diplomatic channels.","It was a diplomatic way of saying he didn't agree."]},{"word":"directory","level":"C1","type":"n.","turkish":"Rehber, fihrist, dizin (telefon, adres vb.); (bilgisayar) dizin.","definition":"A book listing individuals or organizations alphabetically or thematically with details such as names, addresses, and telephone numbers; (computing) a file that consists solely of a list of other files.","examples":["Look up their number in the telephone directory.","Create a new directory to store your project files."]},{"word":"disability","level":"B2","type":"n.","turkish":"Engellilik, sakatlık, maluliyet.","definition":"A physical or mental condition that limits a person's movements, senses, or activities.","examples":["The building has facilities for people with physical disabilities.","She overcame her learning disability to graduate with honors."]},{"word":"disabled","level":"B2","type":"adj.","turkish":"Engelli, sakat, malul.","definition":"Having a physical or mental condition that limits movements, senses, or activities.","examples":["Parking spaces are reserved for disabled drivers.","The charity provides support for disabled veterans."]},{"word":"disagreement","level":"B2","type":"n.","turkish":"Anlaşmazlık, fikir ayrılığı, uyuşmazlık.","definition":"Lack of consensus or approval; a quarrel or argument.","examples":["There was considerable disagreement over the best course of action.","They had a minor disagreement but soon made up."]},{"word":"disappoint","level":"B2","type":"v.","turkish":"Hayal kırıklığına uğratmak, umudunu kırmak.","definition":"To fail to fulfill the hopes or expectations of (someone).","examples":["I hate to disappoint you, but I can't come to the party.","The team's performance disappointed the fans."]},{"word":"disappointment","level":"B2","type":"n.","turkish":"Hayal kırıklığı, hüsran.","definition":"Sadness or displeasure caused by the nonfulfillment of one's hopes or expectations.","examples":["To my great disappointment, the event was cancelled.","Losing the match was a huge disappointment for the players."]},{"word":"disastrous","level":"C1","type":"adj.","turkish":"Feci, korkunç, yıkıcı, felaket getiren.","definition":"Causing great damage; highly unsuccessful.","examples":["The disastrous earthquake left thousands homeless.","Investing all his money in one stock proved to be a disastrous decision."]},{"word":"discard","level":"C1","type":"v.","turkish":"Atmak, kurtulmak, eldençıkarmak; (iskambil) kart atmak.","definition":"To get rid of (someone or something) as no longer useful or desirable.","examples":["Discard any old clothes you no longer wear.","Read the instructions carefully before discarding the packaging."]},{"word":"discharge","level":"C1","type":"v.","turkish":"Taburcu etmek (hastane); terhis etmek (asker); iştençıkarmak; boşaltmak (sıvı, yük vb.); ateşlemek (","definition":"To allow (someone) to leave a hospital, prison, or the armed forces; dismiss from a job; allow (a liquid, gas, or other substance) to flow out from where it has been confined; fire (a gun or missile); fulfill (a duty or role).","examples":["He was discharged from the army after serving two years.","The factory was fined for discharging toxic waste into the river."]},{"word":"disclose","level":"C1","type":"v.","turkish":"Açığa vurmak, ifşa etmek, açıklamak.","definition":"To make (secret or new information) known.","examples":["The company refused to disclose details of the agreement.","He was forced to disclose his financial interests."]},{"word":"disclosure","level":"C1","type":"n.","turkish":"İfşa etme, açığa vurma, açıklama.","definition":"The action of making new or secret information known.","examples":["The full disclosure of the facts revealed a scandal.","Non-disclosure agreements prevent employees from sharing confidential information."]},{"word":"discourage","level":"B2","type":"v.","turkish":"Cesaretini kırmak, hevesini kırmak, vazgeçirmek.","definition":"To cause (someone) to lose confidence or enthusiasm; try to prevent or dissuade someone from doing something.","examples":["Don't let failures discourage you from trying again.","His parents tried to discourage him from becoming an actor."]},{"word":"discourse","level":"C1","type":"n.","turkish":"Söylem, nutuk, konuşma; (yazılı/sözlü) tartışma, ifade.","definition":"Written or spoken communication or debate; a formal discussion of a topic in speech or writing.","examples":["She delivered a fascinating discourse on the history of art.","The book analyzes political discourse in the media."]},{"word":"discretion","level":"C1","type":"n.","turkish":"Takdir yetkisi, serbesti; sağduyu, basiret; ağzı sıkılık, ketumluk.","definition":"The freedom to decide what should be done in a particular situation; the quality of behaving or speaking in such a way as to avoid causing offense or revealing private information.","examples":["The judge used his discretion in sentencing the defendant.","Please be assured of our complete discretion regarding this sensitive matter."]},{"word":"discrimination","level":"C1","type":"n.","turkish":"Ayrımcılık (ırk, cinsiyet vb.); ayırt etme, farkı anlama.","definition":"The unjust or prejudicial treatment of different categories of people or things, especially on the grounds of race, age, or sex; recognition and understanding of the difference between one thing and another.","examples":["Laws prohibit discrimination based on race or gender.","He showed great discrimination in his choice of wines."]},{"word":"dismissal","level":"C1","type":"n.","turkish":"İştençıkarma, kovma; (dava vb.) reddetme; serbest bırakma.","definition":"The act of ordering or allowing someone to leave; the act of dismissing someone from employment; rejection of a legal case by a court.","examples":["He sued the company for unfair dismissal.","The judge ordered the dismissal of the charges due to lack of evidence."]},{"word":"disorder","level":"B2","type":"n.","turkish":"Düzensizlik, kargaşa; rahatsızlık, bozukluk (sağlık).","definition":"A state of confusion; lack of order; an illness that disrupts normal physical or mental functions.","examples":["The room was in a state of complete disorder.","She suffers from a rare genetic disorder."]},{"word":"displace","level":"C1","type":"v.","turkish":"Yerinden etmek, yerini değiştirmek; yerine geçmek.","definition":"To take over the place, position, or role of (someone or something); force (someone) to leave their home, typically because of war, persecution, or natural disaster.","examples":["Thousands of people were displaced by the flood.","Automation may eventually displace many workers."]},{"word":"disposal","level":"C1","type":"n.","turkish":"Eldençıkarma, atma, imha etme; (at sb's disposal) emrine amade olma.","definition":"The action or process of throwing away or getting rid of something; (at someone's disposal) available for someone to use whenever or however they wish.","examples":["Safe disposal of nuclear waste is a major challenge.","I have a car at my disposal for the weekend. dispose (v."]},{"word":"dispute","level":"C1","type":"n.","turkish":"(n) Anlaşmazlık, uyuşmazlık, ihtilaf, tartışma; (v) İtiraz etmek, tartışmak, doğruluğunu sorgulamak.","definition":"(n) A disagreement, argument, or debate. (v) To argue about (something); discuss heatedly; question whether (a statement or alleged fact) is true or valid.","examples":["The border dispute between the two countries remains unresolved. (noun) They disputed the referee's decision. (verb)"]},{"word":"disrupt","level":"C1","type":"v.","turkish":"Aksatmak, sekteye uğratmak, bozmak (düzeni, akışı vb.).","definition":"To interrupt (an event, activity, or process) by causing a disturbance or problem.","examples":["Protesters attempted to disrupt the meeting.","Bad weather could disrupt travel plans."]},{"word":"disruption","level":"C1","type":"n.","turkish":"Aksama, kesinti, bozulma.","definition":"Disturbance or problems which interrupt an event, activity, or process.","examples":["The strike caused major disruption to rail services.","We apologize for any disruption caused by the construction work."]},{"word":"dissolve","level":"C1","type":"v.","turkish":"Çözmek, eritmek (katıyı sıvıda); (meclis, evlilik vb.) feshetmek, sona erdirmek; dağılmak, yok olmak","definition":"(with reference to a solid) Become or cause to become incorporated into a liquid so as to form a solution; close down or dismiss (an assembly or official body); disappear.","examples":["Sugar dissolves easily in hot water.","The parliament was dissolved before the election."]},{"word":"distant","level":"B2","type":"adj.","turkish":"Uzak (mesafe, zaman, akrabalık); soğuk, mesafeli (davranış).","definition":"Far away in space or time; (of a person) not closely related; reserved or uncommunicative.","examples":["We could see the distant mountains from our window.","She seemed cold and distant during the conversation."]},{"word":"distinct","level":"B2","type":"adj.","turkish":"Farklı, ayrı, belirgin.","definition":"Recognizably different in nature from something else of a similar type; readily distinguishable by the senses.","examples":["There are two distinct types of coffee bean.","The smell of smoke was quite distinct."]},{"word":"distinction","level":"C1","type":"n.","turkish":"Ayırt etme, fark; ayrım, farklılık; üstünlük, onur,şeref; (sınav)üstün başarı derecesi.","definition":"A difference or contrast between similar things or people; excellence that sets someone or something apart from others; an award or honor given for excellence.","examples":["It's important to make a distinction between temporary and permanent solutions.","She graduated with distinction in physics."]},{"word":"distinctive","level":"C1","type":"adj.","turkish":"Ayırt edici, kendineözgü, farklı.","definition":"Characteristic of one person or thing, and so serving to distinguish it from others.","examples":["The car has a very distinctive design.","She has a distinctive way of speaking."]},{"word":"distinguish","level":"B2","type":"v.","turkish":"Ayırt etmek, farkını görmek; seçmek, tanımak.","definition":"To recognize or treat (someone or something) as different; perceive or point out a difference.","examples":["It can be difficult to distinguish between identical twins.","He learned to distinguish different types of birdsong."]},{"word":"distort","level":"C1","type":"v.","turkish":"Çarpıtmak (gerçeği, sesi, görüntüyü vb.), tahrif etmek, bozmak.","definition":"To pull or twist out of shape; give a misleading or false account or impression of.","examples":["The media often distorts reality to make stories more sensational.","The curved mirror distorted his reflection."]},{"word":"distract","level":"B2","type":"v.","turkish":"Dikkatini dağıtmak, başka yöne çekmek.","definition":"To prevent (someone) from giving full attention to something.","examples":["Don't distract the driver while he is concentrating.","Loud music distracts me when I'm trying to study."]},{"word":"distress","level":"C1","type":"n.","turkish":"(n) Üzüntü, keder, sıkıntı, acı; tehlike, zor durum; (v) Üzmek, endişelendirmek.","definition":"(n) Extreme anxiety, sorrow, or pain; the state of a ship or aircraft when in danger or difficulty. (v) To cause (someone) anxiety, sorrow, or pain.","examples":["The shipwrecked sailors were in great distress. (noun) She was deeply distressed by the news of the accident. (verb - often used as adjective 'distressed')"]},{"word":"disturb","level":"B2","type":"v.","turkish":"Rahatsız etmek, rahatını bozmak; (düzeni) bozmak.","definition":"To interfere with the normal arrangement or functioning of; interrupt the peace, quiet, or sleep of (someone).","examples":["Please do not disturb the meeting.","I'm sorry to disturb you so late."]},{"word":"disturbing","level":"C1","type":"adj.","turkish":"Rahatsız edici, endişe verici, huzur kaçıran.","definition":"Causing anxiety; worrying; upsetting.","examples":["The news report contained some disturbing images.","There has been a disturbing increase in crime rates."]},{"word":"dive","level":"B2","type":"v.","turkish":"(v) Dalmak (suya, havaya); (n) Dalış.","definition":"(v) To plunge head first into water; (of an aircraft or bird) plunge steeply downward through the air. (n) An act of plunging head first into water; a steep downward plunge by an aircraft or bird.","examples":["He dived into the swimming pool. (verb) Scuba diving allows you to explore the underwater world. (noun)"]},{"word":"diverse","level":"B2","type":"adj.","turkish":"Çeşitli, farklı, değişik.","definition":"Showing a great deal of variety; very different.","examples":["The city has a culturally diverse population.","Our interests are quite diverse."]},{"word":"diversity","level":"B2","type":"n.","turkish":"Çeşitlilik, farklılık.","definition":"The state of being diverse; variety.","examples":["We value the ethnic diversity of our employees.","Biological diversity is essential for a healthy ecosystem."]},{"word":"divert","level":"C1","type":"v.","turkish":"Yönünü değiştirmek, başka yöne çevirmek (trafik, dikkat, kaynak vb.).","definition":"To cause (someone or something) to change course or turn from one direction to another; distract (someone or their attention) from something.","examples":["Traffic was diverted due to the road closure.","The company diverted funds from marketing to research."]},{"word":"divine","level":"C1","type":"adj.","turkish":"İlahi, tanrısal; (mecazi) harika, mükemmel.","definition":"Of, from, or like God or a god; (informal) excellent; delightful.","examples":["Ancient Greeks believed in divine beings living on Mount Olympus.","That chocolate cake looks absolutely divine!"]},{"word":"divorce","level":"B2","type":"n.","turkish":"(n) Boşanma; (v) Boşanmak.","definition":"(n) The legal dissolution of a marriage by a court or other competent body. (v) Legally dissolve one's marriage with (someone).","examples":["They decided to get a divorce after ten years of marriage. (noun) She divorced her husband last year. (verb)"]},{"word":"doctrine","level":"C1","type":"n.","turkish":"Doktrin,öğreti, ilke (dini, siyasi vb.).","definition":"A belief or set of beliefs held and taught by a Church, political party, or other group.","examples":["The Monroe Doctrine influenced US foreign policy for many years.","He questioned the central doctrines of the religion."]},{"word":"documentation","level":"C1","type":"n.","turkish":"Dokümantasyon, belgeleme, belgeler.","definition":"Material that provides official information or evidence or that serves as a record.","examples":["Please provide the necessary documentation to support your application.","Good documentation is essential for software development."]},{"word":"domain","level":"C1","type":"n.","turkish":"Alan, saha (uzmanlık, ilgi vb.); (internet) alan adı; mülk, arazi.","definition":"An area of territory owned or controlled by a ruler or government; a specified sphere of activity or knowledge; a distinct subset of the internet with addresses sharing a common suffix.","examples":["This topic falls outside my domain of expertise.","You need to register a domain name for your website."]},{"word":"dominance","level":"C1","type":"n.","turkish":"Hakimiyet, egemenlik, baskınlık.","definition":"Power and influence over others.","examples":["The company achieved market dominance through aggressive pricing.","The struggle for political dominance continued for years."]},{"word":"dominant","level":"B2","type":"adj.","turkish":"Baskın, hakim, egemen; (genetik) dominant.","definition":"Most important, powerful, or influential; (genetics) relating to or denoting heritable characteristics which are controlled by genes that are expressed in offspring even when inherited from only one parent.","examples":["English is the dominant language in international business.","Brown eyes are a dominant genetic trait."]},{"word":"donation","level":"B2","type":"n.","turkish":"Bağış, iane.","definition":"Something that is given to a charity, especially a sum of money.","examples":["They made a generous donation to the hospital fund.","All donations, large or small, are gratefully received."]},{"word":"donor","level":"C1","type":"n.","turkish":"Bağışçı (para, kan, organ vb.).","definition":"A person who donates something, especially money to a fund or charity; a person who gives blood or a body organ for use by another person.","examples":["The charity relies on generous donors.","They are searching for a suitable kidney donor."]},{"word":"dose","level":"C1","type":"n.","turkish":"Doz,ölçü (ilaç vb.).","definition":"A quantity of a medicine or drug taken or recommended to be taken at a particular time.","examples":["Take one dose of the medicine three times a day.","He accidentally took a double dose of his pills."]},{"word":"dot","level":"B2","type":"n.","turkish":"Nokta (yazı, harita vb.); benek.","definition":"A small round mark or spot.","examples":["Remember to put a dot at the end of the sentence.","Her dress was covered in small white dots."]},{"word":"drain","level":"C1","type":"v.","turkish":"Suyunuçekmek/akıtmak, süzmek; (kaynakları) tüketmek, boşaltmak; (mecazi) yormak, bitkin düşürmek.","definition":"To cause the water or other liquid in (something) to run out, leaving it empty or dry; deplete (resources) or exhaust (someone) emotionally or physically.","examples":["You need to drain the pasta before adding the sauce.","The long illness completely drained her energy."]},{"word":"dramatically","level":"B2","type":"adv.","turkish":"Önemliölçüde,çarpıcı biçimde; dramatik/heyecanlı birşekilde.","definition":"In a way that relates to drama or performance; in a very sudden or noticeable way.","examples":["Prices have fallen dramatically in recent months.","The situation changed dramatically overnight."]},{"word":"drift","level":"C1","type":"v.","turkish":"Sürüklenmek (su, hava akıntısıyla); (amaçsızca) dolaşmak; (konuşma, düşünce) konudan sapmak.","definition":"To be carried slowly by a current of air or water; walk slowly or casually; move passively, aimlessly, or involuntarily into a certain situation or condition.","examples":["The empty boat drifted out to sea.","The conversation drifted from topic to topic."]},{"word":"driving","level":"C1","type":"adj.","turkish":"İtici (güç);şiddetli (yağmur, rüzgar); ana, temel.","definition":"Having a controlling influence; (of rain or snow) falling hard and fast; relating to or denoting the driving force or factor.","examples":["Profit was the main driving force behind the decision.","We struggled to walk against the driving rain."]},{"word":"drought","level":"B2","type":"n.","turkish":"Kuraklık.","definition":"A prolonged period of abnormally low rainfall, leading to a shortage of water.","examples":["The region is suffering from a severe drought.","Water restrictions were imposed due to the drought."]},{"word":"drown","level":"C1","type":"v.","turkish":"Boğulmak (suda); (sesi vb.) bastırmak.","definition":"To die through submersion in and inhalation of water; submerge or flood (an area); overwhelm (a sound).","examples":["Several people drowned when the boat overturned.","Her shouts were drowned out by the noise of the crowd."]},{"word":"dual","level":"C1","type":"adj.","turkish":"Çift, ikili.","definition":"Consisting of two parts, elements, or aspects.","examples":["He has dual citizenship in the UK and Canada.","The car has dual controls for the driving instructor."]},{"word":"dub","level":"C1","type":"v.","turkish":"Dublaj yapmak (film); (isim, lakap) takmak, adlandırmak.","definition":"To provide (a film or television program) with a soundtrack in a different language from the original; give an unofficial name or nickname to (someone or something).","examples":["The foreign film was dubbed into English.","The media dubbed him the \"King of Pop\"."]},{"word":"dull","level":"B2","type":"adj.","turkish":"Sıkıcı, tekdüze; (renk,ışık) donuk, mat; (bıçak) kör; (hava) kapalı; (ağrı) hafif ama sürekli.","definition":"Lacking interest or excitement; lacking brightness, vividness, or sheen; (of an edge or point) not sharp; (of weather) overcast; (of sound) not resonant; (of pain) not intensely felt.","examples":["The lecture was rather dull and uninspiring.","The knife is too dull to cut the bread."]},{"word":"dumb","level":"C1","type":"adj.","turkish":"Dilsiz, konuşamayan (eskimiş ve bazen kaba); (gayriresmi) aptal, salak (kaba).","definition":"(dated and often offensive) Temporarily or permanently unable or unwilling to speak; (informal, offensive) stupid.","examples":["He was struck dumb with amazement. (unable to speak) That was a really dumb thing to do. (stupid - use with caution)"]},{"word":"dump","level":"B2","type":"v.","turkish":"Dökmek, boşaltmak (çöp vb.); (ilişkiyi) bitirmek, terk etmek; (ucuz fiyata) satmak.","definition":"To deposit or dispose of (garbage, waste, or unwanted material), typically in an unauthorized place; (informal) end a romantic relationship with (someone); offload (unwanted assets), especially sell them cheaply.","examples":["It is illegal to dump hazardous waste here.","She decided to dump her boyfriend."]},{"word":"duo","level":"C1","type":"n.","turkish":"İkili, düet (müzik, performans vb.).","definition":"A pair of people or things, especially in music or entertainment.","examples":["The comedy duo had the audience laughing hysterically.","They perform as a singing duo."]},{"word":"duration","level":"B2","type":"n.","turkish":"Süre, müddet.","definition":"The time during which something continues.","examples":["The course is of three months' duration.","Please remain seated for the duration of the flight."]},{"word":"dynamic","level":"B2","type":"adj.","turkish":"(adj) Dinamik, enerjik, değişen; (n) Dinamik, itici güç, işleyiş biçimi.","definition":"(adj) (of a process or system) Characterized by constant change, activity, or progress; (of a person) positive in attitude and full of energy and new ideas. (n) The forces or properties which stimulate growth, development, or change within a system o","examples":["She has a dynamic personality and is always full of energy. (adjective) Understanding the team dynamics is important for the manager. (noun)"]},{"word":"eager","level":"B2","type":"adj.","turkish":"İstekli, hevesli, can atan.","definition":"Strongly wanting to do or have something.","examples":["The children were eager to open their presents.","He is eager to start his new job. earnings (n."]},{"word":"ease","level":"C1","type":"n.","turkish":"(n) Kolaylık, rahatlık; (v) Kolaylaştırmak, rahatlatmak, hafifletmek; yavaşça hareket etmek/ettirmek","definition":"(n) Absence of difficulty or effort; freedom from worry or pain. (v) To make (something) less serious, difficult, or painful; move carefully or gradually.","examples":["He passed the exam with ease. (noun) The medication helped to ease the pain. (verb) She eased the car into the tight parking space. (verb)"]},{"word":"echo","level":"C1","type":"v.","turkish":"(v) Yankılanmak, yankı yapmak; tekrarlamak (fikir vb.); (n) Yankı, akis.","definition":"(v) (of a sound) Be repeated or reverberate after the original sound has stopped; repeat (someone's words or opinions), typically to express agreement. (n) A sound or series of sounds caused by the reflection of sound waves from a surface back to the","examples":["His voice echoed in the large hall. (verb) We could hear the echo of our footsteps in the cave. (noun)"]},{"word":"ecological","level":"C1","type":"adj.","turkish":"Ekolojik,çevreyle ilgili.","definition":"Relating to or concerned with the relation of living organisms to one another and to their physical surroundings.","examples":["The construction project could have serious ecological consequences.","We need to find ecological solutions to waste management."]},{"word":"economics","level":"B2","type":"n.","turkish":"Ekonomi (bilimi), iktisat.","definition":"The branch of knowledge concerned with the production, consumption, and transfer of wealth.","examples":["She studied economics at university.","Understanding basic economics helps in making financial decisions."]},{"word":"economist","level":"B2","type":"n.","turkish":"Ekonomist, iktisatçı.","definition":"An expert in economics.","examples":["Economists predict a slow recovery for the global economy.","He works as a senior economist at the World Bank."]},{"word":"editorial","level":"B2","type":"adj.","turkish":"Editöryal, başyazıyla/yayınla ilgili. (Genellikle isim hali 'başyazı, editoryal yazı' anlamında kull","definition":"Relating to the commissioning or preparing of material for publication; relating to the part of a newspaper or magazine that contains opinions rather than facts.","examples":["The newspaper's editorial stance on the issue was clear.","She is responsible for the editorial content of the magazine."]},{"word":"educator","level":"C1","type":"n.","turkish":"Eğitimci,öğretmen.","definition":"A person who provides instruction or education; a teacher.","examples":["The conference brought together educators from across the country.","He is a respected educator with years of experience."]},{"word":"effectiveness","level":"C1","type":"n.","turkish":"Etkililik, etkinlik, tesirlilik.","definition":"The degree to which something is successful in producing a desired result; success.","examples":["The effectiveness of the new drug is still being tested.","We need to measure the effectiveness of our marketing campaign."]},{"word":"efficiency","level":"C1","type":"n.","turkish":"Verimlilik, etkinlik.","definition":"The state or quality of being efficient (achieving maximum productivity with minimum wasted effort or expense).","examples":["The new system has greatly improved operational efficiency.","Energy efficiency helps reduce costs and protect the environment."]},{"word":"efficiently","level":"B2","type":"adv.","turkish":"Verimli birşekilde, etkili birşekilde.","definition":"In a way that achieves maximum productivity with minimum wasted effort or expense.","examples":["The team worked efficiently to complete the task ahead of schedule.","Resources must be used efficiently."]},{"word":"ego","level":"C1","type":"n.","turkish":"Ego, benlik;özsaygı, kibir.","definition":"A person's sense of self -esteem or self-importance.","examples":["Winning the award boosted his ego.","He has a huge ego and always talks about himself."]},{"word":"elaborate","level":"C1","type":"adj.","turkish":"Detaylı,özenli, karmaşık, incelikli.","definition":"Involving many carefully arranged parts or details; detailed and complicated in design and planning.","examples":["They prepared an elaborate meal for their guests.","The report contained an elaborate analysis of the data."]},{"word":"elbow","level":"B2","type":"n.","turkish":"Dirsek.","definition":"The joint between the forearm and the upper arm.","examples":["He bumped his elbow on the table.","She rested her elbows on the desk."]},{"word":"electoral","level":"C1","type":"adj.","turkish":"Seçim(le ilgili).","definition":"Relating to elections or electors.","examples":["The country is undergoing electoral reform.","The electoral process was monitored by international observers."]},{"word":"electronics","level":"B2","type":"n.","turkish":"Elektronik (bilimi, eşyaları).","definition":"The branch of physics and technology concerned with the design of circuits using transistors and microchips, and with the behavior and movement of electrons; electronic equipment.","examples":["He studied electronics engineering at college.","The store sells a wide range of consumer electronics."]},{"word":"elegant","level":"B2","type":"adj.","turkish":"Zarif,şık, ince.","definition":"Graceful and stylish in appearance or manner; pleasingly ingenious and simple.","examples":["She wore an elegant black dress to the party.","The physicist admired the elegant simplicity of the equation."]},{"word":"elementary","level":"B2","type":"adj.","turkish":"Temel, başlangıç seviyesinde; ilkokul(la ilgili).","definition":"Relating to the basic elements of a subject; relating to or denoting the first stages of education, especially primary school.","examples":["This book provides an elementary introduction to chemistry.","My daughter attends the local elementary school."]},{"word":"elevate","level":"C1","type":"v.","turkish":"Yükseltmek, kaldırmak; (konum, rütbe) yükseltmek; (moral) yükseltmek.","definition":"To raise or lift (something) up to a higher position; raise to a more important or impressive level.","examples":["Use pillows to elevate your injured leg.","His work has been elevated to the status of classic literature."]},{"word":"eligible","level":"C1","type":"adj.","turkish":"Uygun, seçilebilir, hak sahibi (birşeyi yapmaya veya almaya).","definition":"Having the right to do or obtain something; satisfying the appropriate conditions.","examples":["Only people over 18 are eligible to vote.","Are you eligible for financial aid?"]},{"word":"eliminate","level":"B2","type":"v.","turkish":"Elemek, ortadan kaldırmak, yok etmek.","definition":"To completely remove or get rid of (something); exclude (someone or something) from consideration.","examples":["The doctors worked to eliminate the possibility of infection.","Our team was eliminated in the semi-finals."]},{"word":"elite","level":"C1","type":"n.","turkish":"Elit, seçkinler, kaymak tabaka.","definition":"A select group that is superior in terms of ability or qualities to the rest of a group or society.","examples":["The country's political elite controls most of the wealth.","Only the academic elite are invited to join the society."]},{"word":"embark","level":"C1","type":"v.","turkish":"(Gemiye, uçağa) binmek; (yeni bir şeye) başlamak, girişmek.","definition":"To go on board a ship, aircraft, or other vehicle; begin (a course of action, especially one that is important or demanding).","examples":["Passengers prepared to embark the ferry.","She is about to embark on a new career."]},{"word":"embarrassment","level":"C1","type":"n.","turkish":"Utanç, mahcubiyet, sıkılma; utanç verici durum.","definition":"A feeling of self -consciousness, shame, or awkwardness; a person or thing which causes such a feeling.","examples":["He blushed with embarrassment when he realized his mistake.","Forgetting her name was a huge embarrassment."]},{"word":"embassy","level":"C1","type":"n.","turkish":"Büyükelçilik.","definition":"The official residence or offices of an ambassador.","examples":["You need to apply for a visa at the American Embassy.","Protesters gathered outside the French Embassy. embed (v."]},{"word":"embody","level":"C1","type":"v.","turkish":"Somutlaştırmak, cisimleştirmek, temsil etmek, bünyesinde barındırmak.","definition":"To be an expression of or give a tangible or visible form to (an idea, quality, or feeling); include or contain (something) as a constituent part.","examples":["She embodies the principles of honesty and integrity.","The constitution embodies the basic rights of all citizens."]},{"word":"embrace","level":"B2","type":"v.","turkish":"Kucaklamak, sarılmak; benimsemek, kabul etmek (fikir, değişiklik vb.).","definition":"To hold (someone) closely in one's arms, especially as a sign of affection; accept or support (a belief, theory, or change) willingly and enthusiastically.","examples":["They embraced warmly after not seeing each other for years.","The company needs to embrace new technologies to stay competitive."]},{"word":"emergence","level":"C1","type":"n.","turkish":"Ortayaçıkma, belirme, zuhur etme.","definition":"The process of coming into view or becoming exposed after being concealed; the process of coming into being, or of becoming important or prominent.","examples":["The emergence of digital technology has transformed many industries.","We witnessed the slow emergence of the sun from behind the clouds."]},{"word":"emission","level":"B2","type":"n.","turkish":"Salım, yayma, emisyon (gaz,ısı,ışık vb.).","definition":"The production and discharge of something, especially gas or radiation.","examples":["The government aims to reduce carbon emissions.","Stricter controls on vehicle emissions are needed."]},{"word":"emotionally","level":"B2","type":"adv.","turkish":"Duygusal olarak, hissi yönden.","definition":"In a way that relates to a person's emotions.","examples":["He became emotionally involved in her problems.","The film was emotionally draining."]},{"word":"empire","level":"B2","type":"n.","turkish":"İmparatorluk; (mecazi) büyükşirketler grubu.","definition":"An extensive group of states or countries under a single supreme authority, formerly especially an emperor or empress; a large commercial organization owned or controlled by one person or group.","examples":["The Roman Empire stretched across Europe and North Africa.","He built a vast business empire from scratch."]},{"word":"empirical","level":"C1","type":"adj.","turkish":"Deneysel, görgül, tecrübeye dayalı.","definition":"Based on, concerned with, or verifiable by observation or experience rather than theory or pure logic.","examples":["The research is based on empirical evidence collected through surveys.","We need empirical data to support this hypothesis."]},{"word":"empower","level":"C1","type":"v.","turkish":"Yetki vermek, güçlendirmek, olanak sağlamak.","definition":"To give (someone) the authority or power to do something; make (someone) stronger and more confident, especially in controlling their life and claiming their rights.","examples":["The program aims to empower women in rural areas.","Education can empower individuals to improve their lives."]},{"word":"enact","level":"C1","type":"v.","turkish":"Yasalaştırmak, (yasa)çıkarmak; (rol) oynamak, canlandırmak.","definition":"To make (a bill or other proposal) law; act out (a role or play) on stage.","examples":["The government plans to enact new legislation to protect the environment.","The students enacted a scene from Shakespeare's play."]},{"word":"encompass","level":"C1","type":"v.","turkish":"Kapsamak, içermek;çevrelemek, kuşatmak.","definition":"To surround and have or hold within; include comprehensively.","examples":["The course encompasses a wide range of topics.","The national park encompasses mountains, forests, and lakes."]},{"word":"encouragement","level":"C1","type":"n.","turkish":"Teşvik, cesaretlendirme, destek.","definition":"The action of giving someone support, confidence, or hope; persuasion to do or continue something.","examples":["With a little encouragement, she might agree to perform.","His parents gave him constant encouragement throughout his studies."]},{"word":"encouraging","level":"C1","type":"adj.","turkish":"Cesaret verici, teşvik edici, umut verici.","definition":"Giving someone support or confidence; supportive; giving hope or confidence.","examples":["The initial results of the experiment are very encouraging.","Her teacher wrote some encouraging comments on her essay. endeavor (n."]},{"word":"endless","level":"C1","type":"adj.","turkish":"Sonsuz, bitmek bilmeyen, sınırsız.","definition":"Having or seeming to have no end or limit.","examples":["The possibilities seemed endless.","We drove through endless fields of corn."]},{"word":"endorse","level":"C1","type":"v.","turkish":"Onaylamak, desteklemek (birini, bir ürünü vb.); (çek, senet) ciro etmek.","definition":"To declare one's public approval or support of; recommend (a product) in an advertisement; sign (a check or bill of exchange) on the back to make it payable to someone other than the stated payee or to accept responsibility for paying it.","examples":["Many celebrities endorse products for large sums of money.","The committee voted to endorse the proposal."]},{"word":"endorsement","level":"C1","type":"n.","turkish":"Onay, destek, tasdik; ciro (çek, senet).","definition":"An act of giving one's public approval or support to someone or something; the action of endorsing a check or bill of exchange.","examples":["The product received a positive endorsement from a leading expert.","Getting the senator's endorsement was crucial for the campaign."]},{"word":"endure","level":"C1","type":"v.","turkish":"Dayanmak, katlanmak, tahammül etmek; sürmek, devam etmek.","definition":"To suffer (something painful or difficult) patiently; remain in existence; last.","examples":["The refugees had to endure great hardship.","His fame will endure for centuries."]},{"word":"enforce","level":"C1","type":"v.","turkish":"Uygulamak, yürütmek (yasa, kural vb.); zorla kabul ettirmek.","definition":"To compel observance of or compliance with (a law, rule, or obligation).","examples":["It is the job of the police to enforce the law.","The rules will be strictly enforced."]},{"word":"enforcement","level":"C1","type":"n.","turkish":"Uygulama, yürütme (yasa, kural vb.), icra.","definition":"The act of compelling observance of or compliance with a law, rule, or obligation.","examples":["Law enforcement agencies are working to combat crime.","Stricter enforcement of speed limits is needed."]},{"word":"engagement","level":"C1","type":"n.","turkish":"Nişanlanma, nişanlılık; (resmi) randevu, toplantı; angajman, katılım, ilgi; (askeri) çatışma.","definition":"A formal agreement to get married; an arrangement to do something or go somewhere at a fixed time; the process of encouraging people to be interested in something; a fight or battle between armed forces.","examples":["They announced their engagement last week.","The president has several official engagements today."]},{"word":"engaging","level":"C1","type":"adj.","turkish":"Çekici, ilgi uyandıran, hoş.","definition":"Charming and attractive; occupying the attention or efforts of (a person or persons).","examples":["He has an engaging smile and personality.","The speaker gave an engaging presentation."]},{"word":"enjoyable","level":"B2","type":"adj.","turkish":"Keyifli, eğlenceli, hoş.","definition":"Giving delight or pleasure.","examples":["We had a very enjoyable evening at the theater.","Thank you for a most enjoyable meal."]},{"word":"enrich","level":"C1","type":"v.","turkish":"Zenginleştirmek (deneyim, bilgi, toprak vb.).","definition":"To improve or enhance the quality or value of.","examples":["Traveling can greatly enrich your life.","Vitamins and minerals are added to enrich the breakfast cereal. enroll (v."]},{"word":"enterprise","level":"C1","type":"n.","turkish":"Girişim, teşebbüs; işletme,şirket; girişimcilik ruhu.","definition":"A project or undertaking, typically one that is difficult or requires effort; a business or company; initiative and resourcefulness.","examples":["Starting a new business is a risky enterprise.","The government encourages private enterprise."]},{"word":"entertaining","level":"B2","type":"adj.","turkish":"Eğlenceli, keyifli.","definition":"Providing amusement or enjoyment.","examples":["It was a very entertaining film.","He told several entertaining stories about his travels."]},{"word":"enthusiast","level":"C1","type":"n.","turkish":"Meraklısı, düşkünü, heveslisi.","definition":"A person who is very interested in a particular activity or subject.","examples":["He is a keen photography enthusiast.","The festival attracts music enthusiasts from all over the world."]},{"word":"entitle","level":"C1","type":"v.","turkish":"Yetki vermek, hak vermek, isimlendirmek.","definition":"To give (someone) a legal right or a just claim to receive or do something; give (something, especially a text or work of art) a particular title.","examples":["This ticket entitles you to free entry to the museum.","The book is entitled \"A History of the World\"."]},{"word":"entity","level":"C1","type":"n.","turkish":"Varlık, mevcudiyet, kuruluş.","definition":"A thing with distinct and independent existence.","examples":["The company operates as a separate legal entity.","Church and state are considered separate entities."]},{"word":"entrepreneur","level":"B2","type":"n.","turkish":"Girişimci, müteşebbis.","definition":"A person who sets up a business or businesses, taking on financial risks in the hope of profit.","examples":["Many successful entrepreneurs started with very little capital.","She is a talented entrepreneur with innovative ideas."]},{"word":"envelope","level":"B2","type":"n.","turkish":"Zarf.","definition":"A flat paper container with a sealable flap, used to enclose a letter or document.","examples":["Don't forget to put a stamp on the envelope.","He tore open the envelope eagerly."]},{"word":"epidemic","level":"C1","type":"n.","turkish":"Salgın hastalık, salgın.","definition":"A widespread occurrence of an infectious disease in a community at a particular time.","examples":["Health officials warned of a possible flu epidemic.","The city struggled to cope during the cholera epidemic."]},{"word":"equality","level":"C1","type":"n.","turkish":"Eşitlik.","definition":"The state of being equal, especially in status, rights, and opportunities.","examples":["The organization campaigns for racial equality.","Gender equality is essential for a fair society."]},{"word":"equation","level":"C1","type":"n.","turkish":"Eşitlik (matematik); denklem; dengeleme.","definition":"A mathematical statement that the values of two mathematical expressions are equal (indicated by the sign =); a situation or problem in which several factors must be taken into account.","examples":["Can you solve this algebraic equation?","Finding affordable housing is a difficult part of the equation for young families."]},{"word":"equip","level":"B2","type":"v.","turkish":"Donatmak, teçhiz etmek.","definition":"To supply with the necessary items for a particular purpose.","examples":["The laboratory is well equipped with modern instruments.","Make sure you equip yourself properly for the hike."]},{"word":"equivalent","level":"B2","type":"n.","turkish":"(n) Eş değer, karşılık, muadil; (adj) Eş değer, denk, aynı.","definition":"(n) A person or thing that is equal to or corresponds with another in value, amount, function, meaning, etc. (adj) Equal in value, amount, function, meaning, etc.","examples":["Is there a French word that is the exact equivalent of 'home'? (noun) Sending an email is the modern equivalent of writing a letter. (noun) Ten dollars is equivalent to about eight euros. (adjective)"]},{"word":"era","level":"B2","type":"n.","turkish":"Çağ, devir, dönem.","definition":"A long and distinct period of history with a particular feature or characteristic.","examples":["The invention of the computer marked the beginning of a new era.","We are living in the digital era."]},{"word":"erect","level":"C1","type":"v.","turkish":"Dikmek (bina, heykel vb.), inşa etmek; dimdik durmak/tutmak.","definition":"To construct (a building, wall, or other upright structure); set up (a structure) in an upright position.","examples":["The monument was erected in memory of the soldiers.","They plan to erect a new office building on the site."]},{"word":"erupt","level":"B2","type":"v.","turkish":"Püskürmek (yanardağ); (salgın,şiddet vb.) patlak vermek, aniden başlamak.","definition":"(of a volcano) Become active and eject lava, ash, and gases; (of hostility, violence, or emotion) Break out suddenly.","examples":["The volcano could erupt at any time.","Violence erupted during the protests."]},{"word":"escalate","level":"C1","type":"v.","turkish":"Tırmanmak, tırmandırmak, yükselmek/yükseltmek, artmak/artırmak (şiddet, gerginlik vb.).","definition":"To increase rapidly; make or become more intense or serious.","examples":["The conflict could escalate into a full-scale war.","The disagreement escalated into a heated argument."]},{"word":"essence","level":"C1","type":"n.","turkish":"Esas,öz, ana nitelik; esans,özüt.","definition":"The intrinsic nature or indispensable quality of something, especially something abstract, that determines its character; an extract or concentrate obtained from a plant or other matter and used for flavoring or scent.","examples":["The essence of his argument was that change is necessary.","Add a few drops of vanilla essence to the cake mix."]},{"word":"essentially","level":"B2","type":"adv.","turkish":"Esasen, aslında, temelde.","definition":"Used to emphasize the basic, fundamental, or intrinsic nature of a person, thing, or situation.","examples":["The problem is essentially about lack of communication.","Although the technology is complex, it's essentially a simple idea."]},{"word":"establishment","level":"C1","type":"n.","turkish":"Kurma, kuruşuş; kurum, müessese; yerleşik düzen, egemen güçler.","definition":"The action of establishing something or being established; a business organization, public institution, or household; (the Establishment) a group in a society exercising power and influence, and generally resisting change.","examples":["The establishment of the new committee took several weeks.","He works at a well-known research establishment."]},{"word":"eternal","level":"C1","type":"adj.","turkish":"Ebedi, sonsuz,ölümsüz.","definition":"Lasting or existing forever; without end or beginning.","examples":["Many religions promise eternal life after death.","She declared her eternal love for him. ethic (n."]},{"word":"ethnic","level":"B2","type":"adj.","turkish":"Etnik,ırksal.","definition":"Relating to a population subgroup (within a larger or dominant national or cultural group) with a common national or cultural tradition.","examples":["The city has many diverse ethnic communities.","The restaurant serves authentic ethnic cuisine."]},{"word":"evacuate","level":"C1","type":"v.","turkish":"Tahliye etmek, boşaltmak (insanları tehlikeli bir yerden).","definition":"To remove (someone) from a place of danger to a safer place.","examples":["Residents were ordered to evacuate their homes due to the flood.","The building had to be evacuated because of a fire alarm."]},{"word":"evaluation","level":"B2","type":"n.","turkish":"Değerlendirme, değer biçme.","definition":"The making of a judgment about the amount, number, or value of something; assessment.","examples":["A thorough evaluation of the risks is needed.","Employee performance evaluations are conducted annually."]},{"word":"evident","level":"B2","type":"adj.","turkish":"Belli, aşikar, açık, ortada.","definition":"Plain or obvious; clearly seen or understood.","examples":["It was evident from his expression that he was disappointed.","The benefits of the new policy are already evident."]},{"word":"evoke","level":"C1","type":"v.","turkish":"Çağrıştırmak, uyandırmak, hatırlatmak (duygu, anı vb.).","definition":"To bring or recall (a feeling, memory, or image) to the conscious mind.","examples":["The music evoked memories of her childhood.","The smell of the sea often evokes a sense of calm."]},{"word":"evolution","level":"B2","type":"n.","turkish":"Evrim, gelişim, tekamül.","definition":"The process by which different kinds of living organisms are thought to have developed and diversified from earlier forms during the history of the earth; the gradual development of something.","examples":["Darwin's theory of evolution revolutionized biology.","We can trace the evolution of language over centuries."]},{"word":"evolutionary","level":"C1","type":"adj.","turkish":"Evrimsel, evrimle ilgili.","definition":"Relating to or denoting the process of evolution.","examples":["Flight is a major evolutionary advantage for birds.","Scientists study the evolutionary history of species."]},{"word":"evolve","level":"B2","type":"v.","turkish":"Evrim geçirmek, gelişmek, değişmek.","definition":"To develop gradually, especially from a simple to a more complex form.","examples":["Humans evolved from earlier primates.","The company has evolved over the years into a major international corporation."]},{"word":"exaggerate","level":"C1","type":"v.","turkish":"Abartmak, büyütmek.","definition":"To represent (something) as being larger, greater, better, or worse than it really is.","examples":["He tends to exaggerate his achievements.","Don't exaggerate; it wasn't that difficult."]},{"word":"exceed","level":"B2","type":"v.","turkish":"Aşmak, geçmek (limiti, beklentiyi vb.).","definition":"To be greater in number or size than (something); go beyond what is allowed or stipulated by (a set limit).","examples":["The cost must not exceed the allocated budget.","Her performance exceeded all expectations."]},{"word":"excellence","level":"C1","type":"n.","turkish":"Mükemmellik,üstünlük, kusursuzluk.","definition":"The quality of being outstanding or extremely good.","examples":["The company strives for excellence in customer service.","She received an award for academic excellence."]},{"word":"exception","level":"B2","type":"n.","turkish":"İstisna, hariç tutma.","definition":"A person or thing that is excluded from a general statement or does not follow a rule.","examples":["Everyone must attend the meeting; there are no exceptions.","With the exception of John, the whole class passed the exam."]},{"word":"exceptional","level":"C1","type":"adj.","turkish":"Olağanüstü, istisnai, müstesna, harika.","definition":"Unusual; out of the ordinary; outstanding.","examples":["She has an exceptional talent for music.","The student demonstrated exceptional ability in mathematics."]},{"word":"excess","level":"C1","type":"n.","turkish":"(n) Fazlalık, aşırılık; (adj) Fazla, aşırı.","definition":"(n) An amount of something that is more than necessary, permitted, or desirable. (adj) Exceeding what is normal or required.","examples":["Remove any excess fat from the meat. (noun) You may have to pay excess baggage charges. (adjective) An excess of enthusiasm can sometimes be counterproductive. (noun)"]},{"word":"excessive","level":"B2","type":"adj.","turkish":"Aşırı, haddinden fazla.","definition":"More than is necessary, normal, or desirable; immoderate.","examples":["Excessive speed was a factor in the accident.","Avoid excessive consumption of sugary drinks."]},{"word":"exclude","level":"B2","type":"v.","turkish":"Hariç tutmak, dışlamak, dahil etmemek.","definition":"To deny (someone) access to or bar (someone) from a place, group, or privilege; keep (something) out of a place.","examples":["The price excludes taxes and service charges.","He felt excluded from the conversation."]},{"word":"exclusion","level":"C1","type":"n.","turkish":"Dışlama, hariç tutma.","definition":"The process or state of excluding or being excluded.","examples":["Social exclusion is a major problem in some communities.","The exclusion of certain groups from voting was undemocratic."]},{"word":"exclusive","level":"C1","type":"adj.","turkish":"Özel, seçkin; hariç tutan, dahil olmayan; tek, yegane.","definition":"Excluding or not admitting other things; restricted or limited to the person, group, or area concerned; catering for or available to only a few, select people; high class and expensive.","examples":["The hotel offers exclusive access to a private beach.","This offer is exclusive to club members."]},{"word":"exclusively","level":"C1","type":"adv.","turkish":"Sadece, yalnızca,özellikle.","definition":"To the exclusion of others; only; solely.","examples":["The magazine caters exclusively to women.","This parking area is used exclusively by employees."]},{"word":"execute","level":"C1","type":"v.","turkish":"İnfaz etmek, idam etmek; (plan, emir vb.) uygulamak, yerine getirmek, icra etmek.","definition":"To carry out or put into effect (a plan, order, or course of action); carry out a sentence of death on (a legally condemned person).","examples":["The plan was executed perfectly.","The prisoner was executed by firing squad."]},{"word":"execution","level":"C1","type":"n.","turkish":"İnfaz, idam; uygulama, yerine getirme, icra.","definition":"The carrying out or putting into effect of a plan, order, or course of action; the carrying out of a sentence of death.","examples":["The successful execution of the strategy required teamwork.","Public opinion was divided over the execution."]},{"word":"exert","level":"C1","type":"v.","turkish":"Uygulamak (güç, etki vb.), kullanmak; çaba sarf etmek.","definition":"To apply or bring to bear (a force, influence, or quality); make a physical or mental effort.","examples":["He needs to exert more control over the situation.","Don't exert yourself too much if you are feeling unwell."]},{"word":"exile","level":"C1","type":"n.","turkish":"Sürgün; sürgündeki kimse.","definition":"The state of being barred from one's native country, typically for political or punitive reasons; a person who lives away from their native country, either from choice or compulsion.","examples":["The writer lived in exile for many years.","Many political exiles sought refuge in neighboring countries."]},{"word":"exotic","level":"B2","type":"adj.","turkish":"Egzotik, yabancı, uzakülkelerden gelme, sıra dışı.","definition":"Originating in or characteristic of a distant foreign country; attractive or striking because colorful or unusual.","examples":["She grows exotic plants in her greenhouse.","They visited an exotic island in the Pacific."]},{"word":"expansion","level":"B2","type":"n.","turkish":"Genişleme, büyüme, yayılma.","definition":"The action of becoming larger or more extensive.","examples":["The company is planning a major expansion into Asian markets.","Rapid expansion of the city led to housing shortages."]},{"word":"expedition","level":"B2","type":"n.","turkish":"Keşif gezisi, sefer; (bu geziye katılan) heyet.","definition":"A journey undertaken by a group of people with a particular purpose, especially that of exploration, scientific research, or war.","examples":["They organized an expedition to climb Mount Everest.","The scientific expedition collected samples from the rainforest."]},{"word":"expenditure","level":"C1","type":"n.","turkish":"Harcama, masraf, gider.","definition":"The action of spending funds; an amount of money spent.","examples":["Government expenditure on healthcare has increased.","We need to track our monthly expenditures."]},{"word":"experimental","level":"C1","type":"adj.","turkish":"Deneysel.","definition":"Based on untested ideas or techniques and not yet established or finalized; relating to or based on scientific experiments.","examples":["The artist is known for his experimental use of materials.","The drug is still in the experimental stage."]},{"word":"expertise","level":"B2","type":"n.","turkish":"Uzmanlık, ustalık, hüner.","definition":"Expert skill or knowledge in a particular field.","examples":["We need someone with technical expertise for this job.","Her expertise in financial matters is highly valued."]},{"word":"expire","level":"C1","type":"v.","turkish":"Süresi dolmak, sona ermek (belge, anlaşma vb.);ölmek (resmi/edebi).","definition":"(of a document, authorization, or agreement) Cease to be valid, typically after a fixed period of time; (of a person) die.","examples":["My passport expires next month.","The contract will expire at the end of the year."]},{"word":"explicit","level":"C1","type":"adj.","turkish":"Açık, belirgin, aşikar (söz, ifade vb.).","definition":"Stated clearly and in detail, leaving no room for confusion or doubt.","examples":["She gave me explicit instructions on what to do.","The contract contains explicit terms regarding payment."]},{"word":"explicitly","level":"C1","type":"adv.","turkish":"Açıkça, belirgin birşekilde.","definition":"In a clear and detailed manner, leaving no room for confusion or doubt.","examples":["The rules explicitly state that smoking is not allowed.","He explicitly denied any involvement in the incident."]},{"word":"exploit","level":"B2","type":"v.","turkish":"Sömürmek, istismar etmek; faydalanmak, yararlanmak (kaynak vb.).","definition":"To make full use of and derive benefit from (a resource); make use of (a situation) in a way considered unfair or underhand.","examples":["We need to exploit the country's natural resources responsibly.","Some companies exploit workers by paying low wages."]},{"word":"exploitation","level":"C1","type":"n.","turkish":"Sömürü, istismar; faydalanma, işletme.","definition":"The action or fact of treating someone unfairly in order to benefit from their work; the action of making use of and benefiting from resources.","examples":["Child labor is a form of exploitation.","The sustainable exploitation of fisheries is crucial."]},{"word":"explosive","level":"C1","type":"adj.","turkish":"(adj) Patlayıcı; (mecazi) patlamaya hazır,çoköfkeli; (n) Patlayıcı madde.","definition":"(adj) Able or likely to shatter violently or burst apart, as when a bomb explodes; likely to cause anger or controversy. (n) A substance which can be made to explode.","examples":["Bomb disposal experts carefully handled the explosive device. (adjective) The political situation is highly explosive. (adjective) Dynamite is a powerful explosive. (noun)"]},{"word":"exposure","level":"B2","type":"n.","turkish":"Maruz kalma/bırakma (tehlike, hava koşulu vb.); (medyada) yer alma, görünürlük; ifşa etme.","definition":"The state of having no protection from something harmful; the revelation of something secret, especially something embarrassing or damaging; the publicizing of information or an event.","examples":["Prolonged exposure to the sun can be harmful.","The scandal brought negative exposure to the company."]},{"word":"extension","level":"B2","type":"n.","turkish":"Uzatma (süre, bina vb.); ek, ilave; (telefon) dahili hat.","definition":"A part that is added to something to enlarge or prolong it; a continuation; an extra telephone line connected to a central switchboard.","examples":["They applied for an extension of their visa.","We are building an extension onto our house."]},{"word":"extensive","level":"B2","type":"adj.","turkish":"Kapsamlı, geniş, yaygın.","definition":"Covering or affecting a large area; large in amount or scale.","examples":["The storm caused extensive damage to property.","She has extensive knowledge of ancient history."]},{"word":"extensively","level":"B2","type":"adv.","turkish":"Kapsamlı birşekilde, genişölçüde.","definition":"In a way that covers or affects a large area; to a large extent.","examples":["The topic has been extensively researched.","He travelled extensively throughout Asia. extract (n."]},{"word":"extremist","level":"C1","type":"n.","turkish":"Aşırılık yanlısı, radikal, ekstremist.","definition":"A person who holds extreme political or religious views, especially one who advocates illegal, violent, or other extreme action.","examples":["The government is concerned about the rise of political extremists.","He was known for his extremist views."]},{"word":"fabric","level":"B2","type":"n.","turkish":"Kumaş, dokuma; (mecazi) yapı, doku.","definition":"Cloth or other material produced by weaving or knitting fibers; the basic structure of a society, culture, or organization.","examples":["She chose a beautiful silk fabric for her dress.","Social media is changing the fabric of society. fabulous (adj."]},{"word":"facilitate","level":"C1","type":"v.","turkish":"Kolaylaştırmak, rahatlatmak, olanak sağlamak.","definition":"To make (an action or process) easy or easier.","examples":["The use of technology can facilitate learning.","The mediator helped to facilitate communication between the two parties."]},{"word":"faction","level":"C1","type":"n.","turkish":"Hızip, grup, klik (genellikle daha büyük bir grup içinde).","definition":"A small, organized, dissenting group within a larger one, especially in politics.","examples":["The political party was split by internal factions.","Rival factions competed for control of the organization."]},{"word":"faculty","level":"B2","type":"n.","turkish":"Fakülte (üniversite);öğretimüyeleri, akademik kadro; yetenek, yeti (zihinsel, fiziksel).","definition":"An inherent mental or physical power; the teaching staff of a university or college, or of one of its departments or divisions.","examples":["He has a great faculty for learning languages. (ability) The university has a highly respected faculty of law. (staff) She is a member of the history faculty. (staff)"]},{"word":"fade","level":"C1","type":"v.","turkish":"Solmak (renk); (ışık, ses) azalmak, zayıflamak; (umut, anı) silinmek, yok olmak.","definition":"To gradually grow faint and disappear; lose color or brightness.","examples":["The bright colors of the curtains had faded in the sun.","Hopes for a peaceful resolution began to fade."]},{"word":"failed","level":"B2","type":"adj.","turkish":"Başarısız, boşaçıkmış; iflas etmiş.","definition":"Not achieving its aims or goals; unsuccessful; (of an enterprise or institution) unable to continue in existence.","examples":["It was another failed attempt to climb the mountain.","Many businesses failed during the recession."]},{"word":"fairness","level":"C1","type":"n.","turkish":"Adalet, hakkaniyet, dürüstlük; (ten rengi) açıklık.","definition":"Impartial and just treatment or behavior without favoritism or discrimination; the quality of having light-colored hair or skin.","examples":["The referee was praised for his fairness.","A sense of fairness is important in any competition."]},{"word":"fake","level":"B2","type":"adj.","turkish":"Sahte, taklit, yapmacık.","definition":"Not genuine; counterfeit; intended to deceive.","examples":["The police warned about fake banknotes circulating in the area.","She wore a fake fur coat."]},{"word":"fame","level":"B2","type":"n.","turkish":"Şöhret,ün.","definition":"The state of being known or talked about by many people, especially on account of notable achievements.","examples":["He achieved international fame as a singer.","The quest for fame can sometimes be destructive."]},{"word":"fantasy","level":"B2","type":"n.","turkish":"Fantezi, hayal gücüürünü; hayal, düş.","definition":"The faculty or activity of imagining things, especially things that are impossible or improbable; a genre of imaginative fiction involving magic and adventure.","examples":["As a child, he lived in a world of fantasy. \"The Lord of the Rings\" is a classic work of fantasy literature."]},{"word":"fare","level":"B2","type":"n.","turkish":"Ücret, bilet parası (toplu taşıma, taksi vb.).","definition":"The money that a passenger on public transport has to pay.","examples":["What is the bus fare to the city center?","Taxi fares are higher at night."]},{"word":"fatal","level":"C1","type":"adj.","turkish":"Ölümcül,öldürücü; (mecazi) vahim, feci.","definition":"Causing death; leading to failure or disaster.","examples":["The accident resulted in several fatal injuries.","Making that investment proved to be a fatal mistake for the company."]},{"word":"fate","level":"C1","type":"n.","turkish":"Kader, yazgı, alın yazısı; akıbet, son.","definition":"The development of events beyond a person's control, regarded as determined by a supernatural power; the outcome of a situation for someone or something.","examples":["It seemed like fate that they met on that particular day.","The fate of the missing climbers is still unknown. favorable (adj."]},{"word":"feat","level":"C1","type":"n.","turkish":"Başarı, marifet, hüner (özellikle zor veya etkileyici).","definition":"An achievement that requires great courage, skill, or strength.","examples":["Climbing Mount Everest is an incredible feat of human endurance.","Completing the marathon in under three hours was a remarkable feat. felony (n."]},{"word":"feminist","level":"C1","type":"adj.","turkish":"(adj) Feminist; (n) Feminist.","definition":"(adj) Relating to or supporting feminism. (n) A person who supports feminism (the advocacy of women's rights on the basis of the equality of the sexes).","examples":["She holds strong feminist views. (adjective) Gloria Steinem is a well -known feminist writer and activist. (noun) fiber (n.","C1) ( İngiliz İngilizcesi: fibre) Türkçe Anlamı: Lif, iplik, elyaf; (besin) lif."]},{"word":"fierce","level":"C1","type":"adj.","turkish":"Şiddetli, sert, azgın; hiddetli,öfkeli; (rekabet) kıran kırana.","definition":"Having or displaying an intense or ferocious aggressiveness; (of the weather or temperature) powerful and destructive; showing a heartfelt and powerful intensity.","examples":["A fierce storm battered the coast.","There is fierce competition between the two companies."]},{"word":"filmmaker","level":"C1","type":"n.","turkish":"Film yapımcısı, sinemacı (yönetmen, yapımcı vb.).","definition":"A person (such as a director or producer) who makes films.","examples":["Steven Spielberg is a famous Hollywood filmmaker.","Independent filmmakers often work with low budgets."]},{"word":"filter","level":"C1","type":"n.","turkish":"(n) Filtre, süzgeç; (v) Filtrelemek, süzmek; (haber, bilgi) sızmak.","definition":"(n) A porous device for removing impurities or solid particles from a liquid or gas passed through it. (v) Pass (a liquid, gas, light, or sound) through a device to remove unwanted material; (of information etc.) gradually become known or apparent.","examples":["You need to change the air filter in your car regularly. (noun) Filter the coffee before serving. (verb) News of the event slowly filtered through to the public. (verb) fine (n., v.","C1) (Ceza anlamında) Türkçe Anlamı: (n) Para cezası; (v) Para cezası vermek."]},{"word":"firearm","level":"C1","type":"n.","turkish":"Ateşli silah.","definition":"A rifle, pistol, or other portable gun.","examples":["Carrying an unregistered firearm is illegal.","Police found several firearms during the raid."]},{"word":"firefighter","level":"B2","type":"n.","turkish":"İtfaiyeci.","definition":"A person whose job is to extinguish fires.","examples":["Firefighters battled the blaze for several hours.","Being a firefighter requires great courage. firework (n."]},{"word":"firm","level":"B2","type":"adj.","turkish":"Sert, katı; sıkı, sağlam; kararlı, kesin.","definition":"Having a solid, almost unyielding surface or structure; strongly felt and unlikely to change; fixed, steady, or stable.","examples":["Choose a mattress that is comfortably firm.","She has a firm belief in her abilities."]},{"word":"firmly","level":"B2","type":"adv.","turkish":"Sıkıca, sağlamca; kararlılıkla, kesin olarak.","definition":"With little possibility of movement; securely; in a way that is not likely to change.","examples":["Hold the ladder firmly while I climb up.","She firmly believes that she is right."]},{"word":"fiscal","level":"C1","type":"adj.","turkish":"Mali, maliyeyle ilgili (özellikle devlet maliyesi).","definition":"Relating to government revenue, especially taxes.","examples":["The government announced new fiscal policies to stimulate the economy.","The country's fiscal year runs from April to March. fit (n."]},{"word":"flaw","level":"C1","type":"n.","turkish":"Kusur, hata, defo, eksiklik.","definition":"A mark, blemish, or other imperfection which mars a substance or object; a fault or weakness in a person's character or in a system or argument.","examples":["There seems to be a fundamental flaw in their plan.","The diamond had a tiny internal flaw."]},{"word":"flawed","level":"C1","type":"adj.","turkish":"Kusurlu, hatalı, defolu.","definition":"Having or characterized by a fundamental weakness or imperfection.","examples":["The reasoning behind the argument is seriously flawed.","Despite its flawed characters, the novel is compelling. flee (v."]},{"word":"fleet","level":"C1","type":"n.","turkish":"Filo (gemi, uçak, araç vb.).","definition":"A group of ships sailing together, engaged in the same activity, or under the same ownership; a number of vehicles or aircraft operating together or under the same ownership.","examples":["The company operates a large fleet of delivery trucks.","The fishing fleet returned to harbor with a good catch."]},{"word":"flesh","level":"C1","type":"n.","turkish":"Et (insan veya hayvan vücudunun yumuşak kısmı); (meyve) etli kısım.","definition":"The soft substance consisting of muscle and fat that is found between the skin and bones of a human or an animal; the soft part of a fruit or vegetable.","examples":["Lions are flesh-eating animals.","Cut the mango in half and scoop out the sweet flesh."]},{"word":"flexibility","level":"C1","type":"n.","turkish":"Esneklik; uyum sağlama yeteneği.","definition":"The quality of bending easily without breaking; the ability to be easily modified; willingness to change or compromise.","examples":["Yoga improves strength and flexibility.","The job requires flexibility and adaptability."]},{"word":"flourish","level":"C1","type":"v.","turkish":"Gelişmek, büyümek, serpilmek (bitki, iş, sanat vb.); (el, kol) sallamak (gösterişlişekilde).","definition":"(of a person, animal, or other living organism) Grow or develop in a healthy or vigorous way, especially as the result of a particularly favorable environment; (of a person) wave (something) around to attract the attention of others.","examples":["The arts began to flourish during that period.","Plants flourish in fertile soil."]},{"word":"fluid","level":"C1","type":"n.","turkish":"Sıvı, akışkan.","definition":"A substance that has no fixed shape and yields easily to external pressure; a gas or (especially) a liquid.","examples":["Drink plenty of fluids when you are sick.","Brake fluid needed to be topped up in the car. fond (adj."]},{"word":"fool","level":"B2","type":"n.","turkish":"Aptal, budala, enayi; soytarı (eskiden).","definition":"A person who acts unwisely or imprudently; a silly person; (historical) a jester or clown, especially one retained in a royal or noble household.","examples":["Only a fool would believe such an obvious lie.","Stop acting like a fool! footage (n."]},{"word":"forecast","level":"B2","type":"n.","turkish":"(n) Tahmin (hava, ekonomi vb.); (v) Tahmin etmek.","definition":"(n) A prediction or estimate of future events, especially coming weather or a financial trend. (v) Predict or estimate (a future event or trend).","examples":["The weather forecast predicts rain for tomorrow. (noun) Economists forecast continued growth next year. (verb)"]},{"word":"foreigner","level":"C1","type":"n.","turkish":"Yabancı (başkaülkeden).","definition":"A person belonging to or coming from a foreign country.","examples":["Many foreigners visit Turkey during the summer.","She felt like a foreigner in her new school."]},{"word":"forge","level":"C1","type":"v.","turkish":"Sahtesini yapmak, taklit etmek (imza, belge vb.); (metal) döverekşekil vermek; (ilişki, anlaşma) kur","definition":"To make or shape (a metal object) by heating it in a fire or furnace and beating or hammering it; produce a copy or imitation of (a document, signature, banknote, or work or art) for the purposes of deception; create (a relationship or new conditions","examples":["He was arrested for trying to forge passports.","The blacksmith forged the iron into a horseshoe."]},{"word":"format","level":"B2","type":"n.","turkish":"Biçim, format, düzen (kitap, program, veri vb.).","definition":"The way in which something is arranged or set out.","examples":["The report needs to follow a specific format.","The TV show changed its format last season."]},{"word":"formation","level":"B2","type":"n.","turkish":"Oluşum, meydana gelme; biçimlenme, yapı; (askeri, uçuş) düzen.","definition":"The action of forming or process of being formed; a structure or arrangement of something; a particular arrangement of troops, military vehicles, or aircraft.","examples":["We studied rock formations in geology class.","The planes flew in tight formation."]},{"word":"formerly","level":"B2","type":"adv.","turkish":"Eskiden,önceden, vaktiyle.","definition":"In the past; in earlier times.","examples":["The building was formerly a hospital, but is now apartments.","She was formerly known as Mrs."]},{"word":"formulate","level":"C1","type":"v.","turkish":"Formüle etmek, ifade etmek (dikkatlice); oluşturmak, geliştirmek (plan vb.).","definition":"To create or devise methodically (a strategy or proposal); express (an idea) in a concise or systematic way.","examples":["They needed time to formulate a response.","The committee was asked to formulate new safety guidelines. forth (adv."]},{"word":"forthcoming","level":"C1","type":"adj.","turkish":"Yakında olacak/çıkacak; konuşkan, bilgi vermeye istekli.","definition":"About to happen or appear; (of a person) willing to divulge information.","examples":["Details of the forthcoming election will be announced soon.","The company was not very forthcoming about its future plans."]},{"word":"fortunate","level":"B2","type":"adj.","turkish":"Şanslı, talihli, kısmetli.","definition":"Favored by or involving good luck or fortune; lucky.","examples":["We were fortunate to find accommodation so easily.","He felt fortunate to have survived the accident."]},{"word":"forum","level":"B2","type":"n.","turkish":"Forum, tartışma platformu (internet, toplantı vb.); (antik Roma) forum, meydan.","definition":"A place, meeting, or medium where ideas and views on a particular issue can be exchanged; (in ancient Rome) a public square or marketplace used for judicial and other business.","examples":["The website has an online forum for users to share tips.","The conference provided a forum for discussion on climate change."]},{"word":"fossil","level":"B2","type":"n.","turkish":"Fosil.","definition":"The remains or impression of a prehistoric organism preserved in petrified form or as a mold or cast in rock.","examples":["Paleontologists study dinosaur fossils.","They discovered several important fossils at the archaeological site."]},{"word":"foster","level":"C1","type":"v.","turkish":"Geliştirmek, teşvik etmek (beceri, duygu vb.); (koruyucu aile olarak) bakmak, büyütmek.","definition":"To encourage or promote the development of (something, typically something regarded as good); bring up (a child that is not one's own by birth).","examples":["The school aims to foster a love of reading in children.","They decided to foster a child whose parents couldn't care for him."]},{"word":"foundation","level":"B2","type":"n.","turkish":"Temel (bina, fikir vb.); kuruluş, vakıf; fondöten (makyaj).","definition":"The lowest load-bearing part of a building, typically below ground level; an underlying basis or principle; an institution established with an endowment, e.g. a charity; a cosmetic cream applied to the face as a base for other makeup.","examples":["A strong foundation is essential for any tall building.","Trust is the foundation of a good relationship."]},{"word":"founder","level":"B2","type":"n.","turkish":"Kurucu.","definition":"A person who establishes an institution or settlement.","examples":["Bill Gates is the co-founder of Microsoft.","She was the founder and first president of the organization."]},{"word":"fraction","level":"B2","type":"n.","turkish":"Kesir (matematik); küçük parça, kısım.","definition":"A numerical quantity that is not a whole number (e.g., 1/2, 0.5); a small or tiny part, amount, or proportion of something.","examples":["The recipe requires only a small fraction of a teaspoon of salt.","Only a tiny fraction of the population voted in the election."]},{"word":"fragile","level":"C1","type":"adj.","turkish":"Kırılgan, narin, hassas.","definition":"(of an object) Easily broken or damaged; (of a person) not strong or healthy.","examples":["Please handle the fragile glassware with care.","After the illness, she felt weak and fragile."]},{"word":"fragment","level":"B2","type":"n.","turkish":"Parça, kırıntı, fragman.","definition":"A small part broken or separated off something.","examples":["Police found fragments of glass at the scene of the accident.","Archaeologists pieced together fragments of ancient pottery."]},{"word":"framework","level":"B2","type":"n.","turkish":"Çerçeve, yapı, iskelet (bina, plan, sistem vb.).","definition":"A basic structure underlying a system, concept, or text; an essential supporting structure of a building, vehicle, or object.","examples":["The report provides a framework for future research.","We need to establish a legal framework for these activities."]},{"word":"franchise","level":"C1","type":"n.","turkish":"Franchise, bayilik, isim hakkı; oy hakkı.","definition":"An authorization granted by a government or company to an individual or group enabling them to carry out specified commercial activities; the right to vote in public elections.","examples":["He bought a fast-food franchise.","The extension of the voting franchise was a major reform."]},{"word":"frankly","level":"C1","type":"adv.","turkish":"Açıkçası, dürüst olmak gerekirse.","definition":"In an open, honest, and direct manner.","examples":["Frankly, I don't think his plan will work.","She spoke frankly about the challenges she faced."]},{"word":"fraud","level":"B2","type":"n.","turkish":"Dolandırıcılık, sahtekarlık; sahtekar.","definition":"Wrongful or criminal deception intended to result in financial or personal gain; a person or thing intended to deceive others.","examples":["He was charged with credit card fraud.","The investigation uncovered massive accounting fraud."]},{"word":"freely","level":"B2","type":"adv.","turkish":"Serbestçe,özgürce; rahatça, kolayca; bolca, cömertçe.","definition":"Without restraint or restriction; willingly and readily; in abundant quantities.","examples":["You can speak freely; this is a safe space.","Information should flow freely between departments."]},{"word":"frequent","level":"B2","type":"adj.","turkish":"Sık, sık sık olan.","definition":"Occurring or done on many occasions, in many cases, or in quick succession.","examples":["He is a frequent visitor to the library.","There are frequent bus services to the airport. freshman (n."]},{"word":"frustrated","level":"C1","type":"adj.","turkish":"Hayal kırıklığına uğramış, hüsrana uğramış, engellenmiş.","definition":"Feeling or expressing distress and annoyance, especially because of inability to change or achieve something.","examples":["He felt frustrated by the lack of progress.","She became frustrated with the constant delays."]},{"word":"frustrating","level":"C1","type":"adj.","turkish":"Sinir bozucu, can sıkıcı, hayal kırıklığı yaratan.","definition":"Causing annoyance or distress through inability to change or achieve something.","examples":["It's frustrating when the internet connection is slow.","Dealing with bureaucracy can be very frustrating."]},{"word":"frustration","level":"C1","type":"n.","turkish":"Hayal kırıklığı, hüsran, engellenme duygusu.","definition":"The feeling of being upset or annoyed, especially because of inability to change or achieve something.","examples":["He banged his fist on the table in frustration.","Many people experience frustration with the complex tax system. fulfill (v."]},{"word":"full -time","level":"B2","type":"adj.","turkish":"Tam zamanlı, tam gün.","definition":"(adj) Occupying or using the whole of the available working time. (adv) On a full time basis.","examples":["She is looking for a full-time job. (adjective) He works full-time as a software engineer. (adverb)"]},{"word":"functional","level":"C1","type":"adj.","turkish":"İşlevsel, fonksiyonel, kullanışlı;çalışır durumda.","definition":"Of or having a special activity, purpose, or task; relating to the way in which something works or operates; designed to be practical and useful, rather than attractive.","examples":["The machine is old but still fully functional.","The furniture is functional but not very stylish."]},{"word":"fundamentally","level":"B2","type":"adv.","turkish":"Temelde, esasen, kökten.","definition":"In central or primary respects; used to make an emphatic statement about the basic truth of something.","examples":["The two approaches are fundamentally different.","Fundamentally, the problem lies in lack of investment."]},{"word":"fundraising","level":"C1","type":"n.","turkish":"Bağış toplama, kaynak yaratma (hayır işleri vb. için).","definition":"The seeking of financial support for a charity, cause, or other enterprise.","examples":["The school organized a fundraising event for the new library.","They are involved in fundraising for cancer research."]},{"word":"funeral","level":"C1","type":"n.","turkish":"Cenaze töreni.","definition":"A ceremony or service held shortly after a person's death, usually including the person's burial or cremation.","examples":["Hundreds of people attended his funeral.","The funeral service will be held on Friday."]},{"word":"furious","level":"B2","type":"adj.","turkish":"Çoköfkeli, kızgın, hiddetli.","definition":"Extremely angry.","examples":["She was furious when she discovered he had lied.","He gave me a furious look."]},{"word":"gallon","level":"B2","type":"n.","turkish":"Galon (sıvıölçü birimi - yaklaşık 3.8 litre (ABD) veya 4.5 litre ( İngiltere)).","definition":"A unit of liquid or dry capacity equal to four quarts (in the US about 3.79 liters, in the UK about 4.55 liters).","examples":["How many miles per gallon does your car get?","A gallon of milk costs about $3."]},{"word":"gambling","level":"C1","type":"n.","turkish":"Kumar, kumar oynama.","definition":"The activity of playing games of chance for money; betting.","examples":["Gambling addiction can ruin lives.","He lost a lot of money through gambling."]},{"word":"gaming","level":"B2","type":"n.","turkish":"Oyun oynama (özellikle video oyunları); kumar oynama.","definition":"The action or practice of playing video games; the activity of gambling for money.","examples":["The gaming industry is larger than the movie and music industries combined.","Online gaming can be addictive for some people."]},{"word":"gathering","level":"C1","type":"n.","turkish":"Toplanma, toplantı, bir araya gelme.","definition":"An assembly or meeting, especially a social or festive one or one held for a specific purpose.","examples":["We organized a small family gathering for her birthday.","The annual gathering of the association will be held next month."]},{"word":"gay","level":"B2","type":"adj.","turkish":"Gey, eş cinsel (erkek); (eskiden) neşeli, parlak.","definition":"(of a person, especially a man) Homosexual; relating to or used by homosexuals; (dated) lighthearted and carefree.","examples":["He is openly gay and proud of his identity.","The city has a vibrant gay community."]},{"word":"gaze","level":"C1","type":"n.","turkish":"(n) Dik dik bakma, sabit bakış; (v) Gözünü dikip bakmak, seyretmek.","definition":"(n) A long, steady look. (v) To look steadily and intently, especially in admiration, surprise, or thought.","examples":["She met his intense gaze across the room. (noun) He gazed out the window at the falling snow. (verb)"]},{"word":"gear","level":"C1","type":"n.","turkish":"Vites (araç); dişli (makine); ekipman, donanım, malzeme.","definition":"The mechanism in a motor vehicle that adjusts the engine speed to the speed of the wheels; a set of toothed wheels that work together; equipment or apparatus that is used for a particular purpose.","examples":["Change into a lower gear when going uphill.","Make sure you have the right camping gear for the trip."]},{"word":"gender","level":"B2","type":"n.","turkish":"Cinsiyet (toplumsal).","definition":"Either of the two sexes (male and female), especially when considered with reference to social and cultural differences rather than biological ones. Also used more broadly to denote a range of identities that do not correspond to established ideas of","examples":["Discrimination based on gender is illegal.","The survey asked participants about their age, occupation, and gender."]},{"word":"gene","level":"B2","type":"n.","turkish":"Gen.","definition":"A unit of heredity which is transferred from a parent to offspring and is held to determine some characteristic of the offspring.","examples":["Eye color is determined by specific genes.","Scientists are studying the role of genes in disease."]},{"word":"generic","level":"C1","type":"adj.","turkish":"Genel, kapsayıcı; markasız (ürün), jenerik.","definition":"Characteristic of or relating to a class or group of things; not specific; (of goods, especially medicinal drugs) having no brand name; not protected by a registered trademark.","examples":["\"Vegetable\" is a generic term for many different types of plant.","Generic drugs are usually cheaper than brand -name versions."]},{"word":"genetic","level":"B2","type":"adj.","turkish":"Genetik, kalıtsal.","definition":"Relating to genes or heredity.","examples":["Some diseases have a genetic component.","Genetic engineering has many potential applications."]},{"word":"genius","level":"B2","type":"n.","turkish":"Dahi, deha; deha,üstün yetenek.","definition":"Exceptional intellectual or creative power or other natural ability; a person who is exceptionally intelligent or creative.","examples":["Albert Einstein is considered a scientific genius.","She has a genius for organizing complex events."]},{"word":"genocide","level":"C1","type":"n.","turkish":"Soykırım.","definition":"The deliberate killing of a large number of people from a particular nation or ethnic group with the aim of destroying that nation or group.","examples":["The Holocaust is a horrific example of genocide.","International courts prosecute those responsible for genocide."]},{"word":"genuine","level":"B2","type":"adj.","turkish":"Gerçek, hakiki, orijinal; samimi, içten.","definition":"Truly what something is said to be; authentic; (of a person, emotion, or action) sincere.","examples":["Experts confirmed that the painting was a genuine Picasso.","She expressed genuine concern for his well-being."]},{"word":"genuinely","level":"B2","type":"adv.","turkish":"Gerçekten, hakikaten; samimiyetle, içtenlikle.","definition":"Truly; in a way that is authentic or sincere.","examples":["I am genuinely sorry for the mistake.","He seemed genuinely surprised by the news."]},{"word":"gesture","level":"B2","type":"n.","turkish":"Jest, mimik, el kol hareketi; (iyi niyet vb.) göstergesi.","definition":"A movement of part of the body, especially a hand or the head, to express an idea or meaning; an action performed to convey a feeling or intention.","examples":["He made a rude gesture with his hand.","Sending flowers was a kind gesture. gig (n."]},{"word":"glance","level":"C1","type":"n.","turkish":"(n) Kısa bakış, göz atma; (v) Göz atmak, kısa bir an bakmak.","definition":"(n) A brief or hurried look. (v) Take a brief or hurried look.","examples":["She gave a quick glance at her watch. (noun) He glanced nervously around the room. (verb)"]},{"word":"glimpse","level":"C1","type":"n.","turkish":"Anlık görme, kısa bakış.","definition":"A momentary or partial view.","examples":["We caught a brief glimpse of the celebrity as she entered the car.","Through the trees, I got a glimpse of the lake. globalization (n."]},{"word":"globe","level":"B2","type":"n.","turkish":"Küre, dünya modeli; dünya, yerküre.","definition":"The earth; a spherical representation of the earth or the constellations.","examples":["She spun the globe to find Australia.","Tourists come from all corners of the globe to visit this site."]},{"word":"glorious","level":"C1","type":"adj.","turkish":"Görkemli,şanlı, muhteşem, parlak.","definition":"Having, worthy of, or bringing fame or admiration; having a striking beauty or splendor that evokes feelings of delighted admiration.","examples":["It was a glorious victory for the team.","We watched the glorious sunset over the ocean."]},{"word":"glory","level":"C1","type":"n.","turkish":"Şan,şeref, onur, zafer; görkem, ihtişam.","definition":"High renown or honor won by notable achievements; magnificence or great beauty.","examples":["He dreamed of achieving military glory.","The former palace has been restored to its original glory."]},{"word":"golden","level":"B2","type":"adj.","turkish":"Altın renginde, altından yapılmış; (mecazi) parlak, değerli, mutlu (çağ, fırsat vb.).","definition":"Bright, metallic, yellow in color like that of gold; made of gold; very happy and prosperous.","examples":["She wore a beautiful golden necklace.","This is a golden opportunity you shouldn't miss."]},{"word":"goodness","level":"B2","type":"n.","turkish":"İyilik, erdem, doğruluk; (gıdanın) besleyici değeri; ('My goodness!' gibiünlemlerde).","definition":"The quality of being morally good or virtuous; the nutritious, wholesome, or beneficial part of something; used to express surprise or alarm.","examples":["She believed in the inherent goodness of people.","Fruit and vegetables are full of natural goodness."]},{"word":"governance","level":"C1","type":"n.","turkish":"Yönetim, idare, yönetişim.","definition":"The action or manner of governing a state, organization, etc.","examples":["Good corporate governance is essential for business success.","Issues of global governance were discussed at the summit."]},{"word":"grace","level":"C1","type":"n.","turkish":"Zarafet, incelik, lütuf; (Tanrı'nın) inayeti, lütfu; ek süre, mühlet.","definition":"Smoothness and elegance of movement; courteous goodwill; (in Christian belief) the free and unmerited favor of God; a period officially allowed for payment of a sum due or for compliance with a law or condition.","examples":["She moved with the grace of a dancer.","By the grace of God, we survived the storm."]},{"word":"graphic","level":"B2","type":"adj.","turkish":"Grafik,çizimsel; canlı, ayrıntılı (tasvir).","definition":"Relating to visual art, especially involving drawing, engraving, or lettering; giving a vivid picture with explicit detail.","examples":["He works as a graphic designer.","The report gave a graphic account of the accident. graphics (n."]},{"word":"grasp","level":"C1","type":"v.","turkish":"(v) Sıkıca tutmak, kavramak; anlamak, kavramak; (n) Tutma, kavrama; anlama, kavrayış.","definition":"(v) To seize and hold firmly; understand (something) fully. (n) A firm hold or grip; a person's understanding of a subject or situation.","examples":["He grasped her hand tightly. (verb) I couldn't quite grasp what he was trying to say. (verb) She has a good grasp of the basic principles. (noun) grave (n.","C1) (Mezar anlamında) Türkçe Anlamı: Mezar, kabir."]},{"word":"gravity","level":"C1","type":"n.","turkish":"Yerçekimi; ciddiyet, vahamet.","definition":"The force that attracts a body toward the center of the earth, or toward any other physical body having mass; extreme or alarming importance; seriousness.","examples":["Newton discovered the law of universal gravity.","They failed to understand the gravity of the situation."]},{"word":"greatly","level":"B2","type":"adv.","turkish":"Büyükölçüde,çok, oldukça.","definition":"By a considerable amount; very much.","examples":["His health has improved greatly since the operation.","We greatly appreciate your help."]},{"word":"greenhouse","level":"B2","type":"n.","turkish":"Sera.","definition":"A glass building in which plants that need protection from cold weather are grown.","examples":["Tomatoes grow well in a greenhouse.","The greenhouse effect contributes to global warming."]},{"word":"grid","level":"C1","type":"n.","turkish":"Izgara,şebeke (elektrik, harita vb.); (yarış) başlangıççizgisi düzeni.","definition":"A network of lines that cross each other to form a series of squares or rectangles; a network of wires or pipes for distributing power, water, etc.; a pattern of lines marking the starting places on a motor-racing track.","examples":["The map has a grid system to help locate places.","Power was lost due to a failure in the national electricity grid."]},{"word":"grief","level":"C1","type":"n.","turkish":"Keder,üzüntü, yas (özellikleölüm sonrası).","definition":"Intense sorrow, especially caused by someone's death.","examples":["She was overcome with grief after her husband died.","It takes time to work through the stages of grief."]},{"word":"grin","level":"C1","type":"v.","turkish":"(v) Sırıtmak, dişlerini göstererek gülümsemek; (n) Sırıtış.","definition":"(v) To smile broadly, often baring the teeth. (n) A broad smile.","examples":["He grinned at me mischievously. (verb) She accepted the prize with a wide grin. (noun) grind (v.","C1) (grind, ground, ground) Türkçe Anlamı: Öğütmek (kahve, un vb.); (diş) gıcırdatmak; (zorlu/sıkıcı)çokçalışmak."]},{"word":"grip","level":"C1","type":"n.","turkish":"(n) Sıkıca tutma, kavrama; (mecazi) kontrol, etki; (v) Sıkıca tutmak, kavramak; (ilgi)çekmek, sarmak","definition":"(n) A firm hold; grasp; control over someone or something. (v) Take and keep a firm hold of; grasp tightly; deeply affect (someone).","examples":["Maintain a firm grip on the handlebars. (noun) The country was in the grip of a recession. (noun) The story gripped my attention from the first page. (verb)"]},{"word":"gross","level":"C1","type":"adj.","turkish":"Kaba,çirkin, iğrenç; brüt, kesintisiz (gelir, ağırlık vb.); bariz, affedilmez (hata vb.).","definition":"(informal) Very unpleasant; repulsive; (of income, profit, or interest) without deduction of tax or other contributions; total; (of wrongdoing) very obvious and unacceptable.","examples":["\"Eww, that's gross!\" she exclaimed, looking at the rotting food. (unpleasant) The company's gross profit increased by 10%. (total) His actions showed gross negligence. (obvious/unacceptable) guerrilla (n.","C1) ( İngiliz İngilizcesi: guerilla) Türkçe Anlamı: Gerilla,çeteci."]},{"word":"guidance","level":"C1","type":"n.","turkish":"Rehberlik, yol gösterme, tavsiye.","definition":"Advice or information aimed at resolving a problem or difficulty, especially as given by someone in authority.","examples":["Students receive career guidance from counselors.","He looked to his mentor for guidance. guideline (n."]},{"word":"guilt","level":"C1","type":"n.","turkish":"Suçluluk (duygusu); suç, kusur.","definition":"The fact of having committed a specified or implied offense or crime; a feeling of having done wrong or failed in an obligation.","examples":["The evidence proved his guilt beyond doubt.","She suffered from feelings of guilt after the argument. gut (n."]},{"word":"habitat","level":"B2","type":"n.","turkish":"Yaşam alanı, habitat (hayvan, bitki).","definition":"The natural home or environment of an animal, plant, or other organism.","examples":["Deforestation destroys the natural habitat of many species.","The panda's natural habitat is bamboo forest."]},{"word":"hail","level":"C1","type":"v.","turkish":"Seslenmek,çağırmak (taksi vb.); dolu yağmak;övgüyle karşılamak, selamlamak.","definition":"To call out to (someone) to attract attention; (of weather) pellets of ice fall from clouds; acclaim enthusiastically as being record -breaking or wonderful.","examples":["We managed to hail a taxi despite the rain.","It started to hail just as we left the house."]},{"word":"halfway","level":"C1","type":"adv.","turkish":"Yarı yolda, orta noktada; kısmen.","definition":"At or to a point equidistant between two others; to some extent; partly.","examples":["We stopped halfway through the journey for a break.","I'm halfway through reading the book."]},{"word":"halt","level":"C1","type":"v.","turkish":"(v) Durmak, durdurmak; (n) Durma, duraksama.","definition":"(v) Bring or come to an abrupt stop. (n) A suspension of movement or activity, typically a temporary one.","examples":["The train came to a sudden halt. (noun) Production was halted due to a shortage of materials. (verb)"]},{"word":"handful","level":"C1","type":"n.","turkish":"Bir avuç dolusu; az sayıda (kişi/şey); (mecazi) başaçıkması zor kişi/şey.","definition":"A quantity that fills the hand; a small number or amount; (informal) a person who is difficult to deal with or control.","examples":["She picked up a handful of pebbles from the beach.","Only a handful of people attended the meeting."]},{"word":"handling","level":"C1","type":"n.","turkish":"Ele alma, kullanma, idare etme; taşıma, nakliye (ücreti).","definition":"The way that someone deals with a situation or person; the action or process of managing, dealing with, or controlling something or someone; the charge made for packing and sending goods.","examples":["The situation requires careful handling.","The price includes postage and handling."]},{"word":"handy","level":"C1","type":"adj.","turkish":"Kullanışlı, pratik, el altında bulunan; eli yatkın, becerikli.","definition":"Convenient to handle or use; useful; clever at doing practical jobs.","examples":["Keep a first-aid kit handy in case of emergencies.","This little gadget is very handy for opening jars."]},{"word":"harassment","level":"C1","type":"n.","turkish":"Taciz, rahatsız etme.","definition":"Aggressive pressure or intimidation.","examples":["Sexual harassment in the workplace is illegal.","She reported the online harassment to the police. harbor (n."]},{"word":"hardware","level":"C1","type":"n.","turkish":"Donanım (bilgisayar); hırdavat, nalburiye malzemesi; teçhizat.","definition":"Tools, machinery, and other durable equipment; the machines, wiring, and other physical components of a computer or other electronic system.","examples":["You can buy tools and paint at the hardware store.","Upgrading the computer's hardware can improve performance."]},{"word":"harmony","level":"C1","type":"n.","turkish":"Uyum, ahenk; armoni (müzik).","definition":"The combination of simultaneously sounded musical notes to produce chords and chord progressions having a pleasing effect; agreement or concord.","examples":["The singers performed the song in perfect harmony.","We need to live in harmony with nature."]},{"word":"harsh","level":"C1","type":"adj.","turkish":"Sert, kaba, acımasız; (hava koşulu) çetin, zorlu; (ışık, ses) rahatsız edici.","definition":"Unpleasantly rough or jarring to the senses; cruel or severe; (of climate or conditions) difficult to survive in; hostile.","examples":["The prisoners complained about the harsh treatment.","They survived the harsh winter conditions."]},{"word":"harvest","level":"C1","type":"n.","turkish":"(n) Hasat,ürün; (v) Hasat etmek,ürün toplamak.","definition":"(n) The process or period of gathering in crops; the season's yield or crop. (v) Gather (a crop) as a harvest.","examples":["Farmers are busy during the harvest season. (noun) They expect a good harvest this year. (noun) It's time to harvest the potatoes. (verb)"]},{"word":"hatred","level":"C1","type":"n.","turkish":"Nefret, kin.","definition":"Intense dislike or ill will.","examples":["His heart was filled with hatred for his enemies.","Racial hatred is a destructive force in society."]},{"word":"haunt","level":"C1","type":"v.","turkish":"(Hayalet vb.) dadanmak, musallat olmak; (anı, düşünce) peşini bırakmamak, akıldan çıkmamak; sık sık ","definition":"(of a ghost) Manifest itself at (a place) regularly; be persistently and disturbingly present in (the mind); frequent (a place).","examples":["They say the old castle is haunted by a ghost.","Memories of the war continued to haunt him."]},{"word":"hazard","level":"C1","type":"n.","turkish":"Tehlike, risk.","definition":"A danger or risk.","examples":["Smoking is a major health hazard.","Wet floors can be a slipping hazard. headquarters (n."]},{"word":"heal","level":"B2","type":"v.","turkish":"İyileşmek, iyileştirmek (yara, hastalık vb.); (mecazi) acıyı dindirmek.","definition":"(of a wound or a person) Become sound or healthy again; cause (a wound, injury, or person) to become sound or healthy again; alleviate (a person's distress or anguish).","examples":["The cut took several weeks to heal completely.","Time can help to heal emotional wounds."]},{"word":"healthcare","level":"B2","type":"n.","turkish":"Sağlık hizmetleri, sağlık sektörü.","definition":"The maintenance and improvement of physical and mental health, especially through the provision of medical services.","examples":["Access to affordable healthcare is a basic right.","She works in the healthcare industry."]},{"word":"heighten","level":"C1","type":"v.","turkish":"Artırmak, yükseltmek, şiddetlendirmek (gerilim, duygu vb.).","definition":"To make or become more intense.","examples":["The crisis served to heighten tensions between the two countries.","His arrival only heightened her anxiety."]},{"word":"helmet","level":"B2","type":"n.","turkish":"Kask, miğfer.","definition":"A hard or padded protective hat, various types of which are worn by soldiers, police officers, motorcyclists, cyclists, and workers in dangerous jobs.","examples":["Always wear a helmet when riding a motorcycle.","Construction workers must wear hard helmets on site. hence (adv."]},{"word":"heritage","level":"C1","type":"n.","turkish":"Miras (kültürel, tarihi vb.), kalıt.","definition":"Property that is or may be inherited; valued objects and qualities such as cultural traditions, unspoiled countryside, and historic buildings that have been passed down from previous generations.","examples":["It is important to preserve our cultural heritage.","The city is proud of its rich architectural heritage."]},{"word":"hidden","level":"B2","type":"adj.","turkish":"Gizli, saklı.","definition":"Kept out of sight; concealed.","examples":["The treasure was buried in a hidden location.","There may be hidden costs associated with the purchase."]},{"word":"hierarchy","level":"C1","type":"n.","turkish":"Hiyerarşi, aşama sırası.","definition":"A system or organization in which people or groups are ranked one above the other according to status or authority.","examples":["Most large organizations have a formal hierarchy.","He quickly rose through the corporate hierarchy."]},{"word":"high -profile","level":"C1","type":"adj.","turkish":"Çok dikkatçeken, kamuoyunun yakından tanıdığı,önemli.","definition":"Attracting much attention or publicity.","examples":["The trial involved several high-profile witnesses.","She maintains a high-profile presence in the media."]},{"word":"hilarious","level":"B2","type":"adj.","turkish":"Çok komik, gülmekten kırıp geçiren, eğlenceli.","definition":"Extremely amusing.","examples":["He told us some hilarious jokes.","The movie was absolutely hilarious."]},{"word":"hint","level":"C1","type":"n.","turkish":"(n) İpucu, ima, işaret; (v) İma etmek, üstü kapalı söylemek.","definition":"(n) A slight or indirect indication or suggestion. (v) Suggest or indicate something indirectly or covertly.","examples":["Can you give me a hint about where you hid the present? (noun) He hinted that he might be leaving the company soon. (verb)"]},{"word":"hip","level":"B2","type":"n.","turkish":"Kalça.","definition":"A projection of the pelvis and upper thigh bone on each side of the body in human beings and quadrupeds.","examples":["She broke her hip in the fall.","He carried the child on his hip."]},{"word":"historian","level":"B2","type":"n.","turkish":"Tarihçi.","definition":"An expert in or student of history, especially that of a particular period, geographical region, or social phenomenon.","examples":["The historian specializes in medieval Europe.","Several eminent historians contributed to the book."]},{"word":"homeland","level":"C1","type":"n.","turkish":"Anavatan, memleket, yurt.","definition":"A person's native land; the country of one's birth.","examples":["After years abroad, he longed to return to his homeland.","Many immigrants maintain strong ties to their homeland."]},{"word":"homeless","level":"B2","type":"adj.","turkish":"Evsiz, barksız.","definition":"(of a person) Without a home, and therefore typically living on the streets.","examples":["The charity provides shelter for homeless people.","The number of homeless families has increased."]},{"word":"honesty","level":"B2","type":"n.","turkish":"Dürüstlük, namusluluk.","definition":"The quality of being honest (truthful and sincere).","examples":["Honesty is the best policy.","He is respected for his integrity and honesty."]},{"word":"honey","level":"B2","type":"n.","turkish":"Bal; (sevgi sözcüğü) tatlım, canım.","definition":"A sweet, sticky yellowish -brown fluid made by bees and other insects from nectar collected from flowers; used as a term of endearment.","examples":["Bees produce honey from nectar.","Would you like some honey in your tea, dear? (endearment)"]},{"word":"hook","level":"B2","type":"n.","turkish":"(n) Kanca,çengel; (balık) olta iğnesi; (mecazi) ilgiçekenşey; (v) Kancaya takmak,çengele asmak; (bal","definition":"(n) A piece of metal or other material, curved or bent back at an angle, for catching hold of or hanging things on; something designed to catch people's attention. (v) Attach or fasten with a hook or hooks; catch (a fish) with a hook; cause (someone)","examples":["Hang your coat on the hook by the door. (noun) The opening scene really hooks the audience. (verb) He got hooked on video games. (verb - informal)"]},{"word":"hopeful","level":"C1","type":"adj.","turkish":"Umutlu,ümitli; umut verici.","definition":"Feeling or inspiring optimism about a future event; likely to succeed or be fulfilled; promising.","examples":["Despite the setbacks, she remained hopeful.","The early signs are hopeful for a quick recovery."]},{"word":"hopefully","level":"B2","type":"adv.","turkish":"Umarım, inşallah; umutlu birşekilde.","definition":"In a hopeful manner; it is hoped.","examples":["Hopefully, the weather will be good tomorrow.","She looked at him hopefully, waiting for a positive answer."]},{"word":"horizon","level":"C1","type":"n.","turkish":"Ufuk; (mecazi) anlayış, görüş alanı.","definition":"The line at which the earth's surface and the sky appear to meet; the limit of a person's mental perception, experience, or interest.","examples":["We watched the sun sink below the horizon.","Traveling broadens your horizons."]},{"word":"horn","level":"C1","type":"n.","turkish":"Boynuz (hayvan); korna (araç); boru, korno (müzik aleti).","definition":"A hard permanent outgrowth, often curved and pointed, found in pairs on the heads of various animals; a device sounding a warning or other signal; a brass wind instrument.","examples":["The bull lowered its horns and charged.","He honked the car horn impatiently."]},{"word":"hostage","level":"C1","type":"n.","turkish":"Rehine.","definition":"A person seized or held as security for the fulfillment of a condition.","examples":["The terrorists took several passengers hostage.","Negotiations began for the release of the hostages."]},{"word":"hostile","level":"C1","type":"adj.","turkish":"Düşmanca, hasım, muhalif.","definition":"Showing or feeling opposition or dislike; unfriendly; relating to an enemy.","examples":["The crowd became hostile towards the police.","They received a hostile reception upon arrival."]},{"word":"hostility","level":"C1","type":"n.","turkish":"Düşmanlık, husumet; (çoğul: hostilities) savaş hali,çatışmalar.","definition":"Hostile behavior; unfriendliness or opposition; (hostilities) acts of warfare.","examples":["There was open hostility between the two families.","Both sides agreed to a cessation of hostilities. (plural)"]},{"word":"humanitarian","level":"C1","type":"adj.","turkish":"İnsani, insancıl (yardım vb.).","definition":"Concerned with or seeking to promote human welfare.","examples":["Several organizations provided humanitarian aid to the disaster victims.","She dedicated her life to humanitarian work."]},{"word":"humanity","level":"C1","type":"n.","turkish":"İnsanlık, insanoğlu; insanlık, insaniyet (duygusu).","definition":"The human race; human beings collectively; the quality of being human; the condition of being human.","examples":["Climate change poses a threat to all of humanity.","Acts of kindness show the best side of humanity."]},{"word":"humble","level":"C1","type":"adj.","turkish":"Alçakgönüllü, mütevazı; gösterişsiz, basit.","definition":"Having or showing a modest or low estimate of one's own importance; of low social, administrative, or political rank.","examples":["Despite his success, he remained a humble man.","They lived in a humble cottage in the countryside."]},{"word":"hunger","level":"B2","type":"n.","turkish":"Açlık; (mecazi)şiddetli arzu,özlem.","definition":"A feeling of discomfort or weakness caused by lack of food, coupled with the desire to eat; a strong desire or craving.","examples":["Millions of people suffer from hunger and malnutrition.","She had a deep hunger for knowledge."]},{"word":"hydrogen","level":"C1","type":"n.","turkish":"Hidrojen.","definition":"A chemical element with symbol H and atomic number 1, the lightest element, occurring chiefly in combination with oxygen in water.","examples":["Water is composed of hydrogen and oxygen atoms.","Hydrogen is being explored as a clean energy source. hypothesis (n."]},{"word":"icon","level":"B2","type":"n.","turkish":"Simge, ikon; (bilgisayar) ikon, simge; (dini) ikona.","definition":"A person or thing regarded as a representative symbol or as worthy of veneration; a small graphical representation of a program or file on a computer screen; (Eastern Church) a painting of Jesus Christ or another holy figure.","examples":["Marilyn Monroe became a Hollywood icon.","Click on the printer icon to print the document."]},{"word":"identical","level":"B2","type":"adj.","turkish":"Özdeş, tıpatıp aynı, farksız.","definition":"Similar in every detail; exactly alike.","examples":["The two suitcases looked identical.","She bought two identical dresses by mistake."]},{"word":"identification","level":"C1","type":"n.","turkish":"Kimlik tespiti, tanıma; kimlik (belgesi); özdeşleşme.","definition":"The action or process of identifying someone or something or the fact of being identified; an official document providing proof of identity; psychological orientation of the self in regard to something (as a person or group) with a resulting feeling ","examples":["Please provide proof of identification.","Accurate identification of the problem is the first step."]},{"word":"ideological","level":"C1","type":"adj.","turkish":"İdeolojik, fikirsel.","definition":"Relating to or based on a system of ideas and ideals, especially one which forms the basis of economic or political theory and policy.","examples":["The two parties have major ideological differences.","The conflict was fueled by ideological divisions."]},{"word":"ideology","level":"C1","type":"n.","turkish":"İdeoloji, fikir sistemi.","definition":"A system of ideas and ideals, especially one which forms the basis of economic or political theory and policy.","examples":["Capitalism and socialism are competing economic ideologies.","His political ideology changed over time. idiot (n."]},{"word":"ignorance","level":"C1","type":"n.","turkish":"Cehalet, bilgisizlik, habersizlik.","definition":"Lack of knowledge or information.","examples":["His decision was based on ignorance of the facts.","We must fight prejudice born of ignorance."]},{"word":"illusion","level":"B2","type":"n.","turkish":"İllüzyon, yanılsama, aldanma; hayal.","definition":"A deceptive appearance or impression; a false idea or belief.","examples":["The magician created the illusion of making the rabbit disappear.","He has no illusions about how difficult the job will be."]},{"word":"imagery","level":"C1","type":"n.","turkish":"İmgelem, imgeler; betimleme (edebiyatta vb.).","definition":"Visually descriptive or figurative language, especially in a literary work; visual images collectively.","examples":["The poem is full of powerful natural imagery.","Satellite imagery is used for weather forecasting."]},{"word":"immense","level":"C1","type":"adj.","turkish":"Çok büyük, kocaman, muazzam, engin.","definition":"Extremely large or great, especially in scale or degree.","examples":["An immense amount of effort went into organizing the event.","From the mountaintop, the view was immense."]},{"word":"immigration","level":"B2","type":"n.","turkish":"Göç (başkaülkeye yerleşme), göçmenlik.","definition":"The action of coming to live permanently in a foreign country.","examples":["The government introduced stricter immigration controls.","Immigration has contributed to the country's cultural diversity."]},{"word":"imminent","level":"C1","type":"adj.","turkish":"Eli kulağında, pek yakın, olmaküzere (genellikle tehlike).","definition":"About to happen; impending (often refers to something threatening).","examples":["They warned that a storm was imminent.","The announcement of his resignation seems imminent."]},{"word":"immune","level":"B2","type":"adj.","turkish":"Bağışık (hastalığa vb.); muaf, etkilenmez.","definition":"Resistant to a particular infection or toxin owing to the presence of specific antibodies or sensitized white blood cells; protected or exempt from (something, especially an obligation or the effects of something).","examples":["Most people are immune to measles after vaccination.","No one is immune from criticism."]},{"word":"implement","level":"B2","type":"v.","turkish":"Uygulamak, yerine getirmek, hayata geçirmek (plan, karar vb.).","definition":"To put (a decision, plan, agreement, etc.) into effect.","examples":["The company will implement the new policies next month.","It may be difficult to implement these changes."]},{"word":"implementation","level":"C1","type":"n.","turkish":"Uygulama, yerine getirme, yürürlüğe koyma.","definition":"The process of putting a decision or plan into effect; execution.","examples":["The successful implementation of the project requires careful planning.","There were some challenges during the implementation phase."]},{"word":"implication","level":"B2","type":"n.","turkish":"Ima,çıkarım, olası sonuç; (bir işe) karışma, bulaşma.","definition":"The conclusion that can be drawn from something, although it is not explicitly stated; a likely consequence of something; the state of being involved in something.","examples":["What are the implications of this decision for the company?","The implication was that they were not telling the truth."]},{"word":"imprison","level":"C1","type":"v.","turkish":"Hapse atmak, hapsetmek.","definition":"To put or keep in prison or a place like a prison.","examples":["He was imprisoned for ten years for armed robbery.","The regime imprisoned many political opponents."]},{"word":"inability","level":"C1","type":"n.","turkish":"Yeteneksizlik, yapamama, acizlik.","definition":"The state of being unable to do something.","examples":["His inability to make decisions caused problems.","The company cited its inability to compete as the reason for closure."]},{"word":"inadequate","level":"C1","type":"adj.","turkish":"Yetersiz, eksik, kafi olmayan.","definition":"Lacking the quality or quantity required; insufficient for a purpose.","examples":["The food supplies were inadequate for the number of guests.","Training provided to staff was inadequate."]},{"word":"inappropriate","level":"C1","type":"adj.","turkish":"Uygunsuz, yersiz.","definition":"Not suitable or proper in the circumstances.","examples":["His casual clothes were inappropriate for the formal dinner.","Making jokes at a funeral is highly inappropriate. incarcerate (v."]},{"word":"incentive","level":"B2","type":"n.","turkish":"Teşvik,özendiricişey/sebep.","definition":"A thing that motivates or encourages one to do something.","examples":["Financial incentives are offered to employees who exceed their targets.","Tax breaks provide an incentive for businesses to invest."]},{"word":"incidence","level":"C1","type":"n.","turkish":"Görülme sıklığı, oran, vaka sayısı (hastalık, suç vb.).","definition":"The occurrence, rate, or frequency of a disease, crime, or something else undesirable.","examples":["There has been a high incidence of flu cases this winter.","The study examined the incidence of heart disease in different age groups."]},{"word":"inclined","level":"C1","type":"adj.","turkish":"Eğilimli, meyilli; istekli.","definition":"Leaning or turning away from the vertical or horizontal; sloping; tending or willing to do something.","examples":["She is inclined to agree with his proposal.","He is mathematically inclined. (has a natural tendency/ability)"]},{"word":"inclusion","level":"C1","type":"n.","turkish":"Dahil etme, kapsama; içerme.","definition":"The action or state of including or of being included within a group or structure.","examples":["The company promotes diversity and inclusion in the workplace.","Her inclusion in the team was welcomed by everyone."]},{"word":"incorporate","level":"B2","type":"v.","turkish":"Dahil etmek, katmak, bünyesine almak;şirketleşmek.","definition":"To take in or contain (something) as part of a whole; include; constitute (a company, city, or other organization) as a legal corporation.","examples":["We can incorporate your suggestions into the final report.","The company was incorporated in 2010."]},{"word":"incorrect","level":"B2","type":"adj.","turkish":"Yanlış, hatalı, doğru olmayan.","definition":"Not in accordance with fact; wrong; not correct.","examples":["Your answer to question 3 is incorrect.","The information in the article was factually incorrect."]},{"word":"incur","level":"C1","type":"v.","turkish":"(Masrafa, borca) girmek, (zarara) uğramak, (tehlikeye) maruz kalmak.","definition":"To become subject to (something unwelcome or unpleasant) as a result of one's own behavior or actions.","examples":["The company incurred heavy losses last year.","You may incur additional charges for late payment."]},{"word":"independence","level":"B2","type":"n.","turkish":"Bağımsızlık.","definition":"The fact or state of being independent.","examples":["The country gained its independence in 1960.","Financial independence is important for many young adults. index (n."]},{"word":"indication","level":"B2","type":"n.","turkish":"Belirti, işaret, gösterge.","definition":"A sign or piece of information that indicates something.","examples":["Dark clouds are an indication of rain.","There is no indication that the situation will improve soon."]},{"word":"indicator","level":"C1","type":"n.","turkish":"Gösterge, belirti; sinyal lambası (araç).","definition":"A thing, especially a trend or fact, that indicates the state or level of something; a gauge or meter of a specified kind; a flashing light on a vehicle to show that it is about to change lanes or turn.","examples":["Economic indicators suggest a slowing economy.","Remember to use your indicator when turning. indictment (n."]},{"word":"indigenous","level":"C1","type":"adj.","turkish":"Yerli (bir yereözgü).","definition":"Originating or occurring naturally in a particular place; native.","examples":["The museum exhibits artifacts made by indigenous peoples.","Kangaroos are indigenous to Australia."]},{"word":"induce","level":"C1","type":"v.","turkish":"İkna etmek, sebep olmak, teşvik etmek; (doğumu) suni olarak başlatmak.","definition":"To succeed in persuading or influencing (someone) to do something; bring about or give rise to; bring on (the birth of a baby) artificially, typically by the use of drugs.","examples":["Nothing could induce him to change his mind.","Certain medications can induce sleepiness."]},{"word":"indulge","level":"C1","type":"v.","turkish":"Kendini (bir zevke) kaptırmak, zevkine bakmak; (birinin isteğini) yerine getirmek, yüz vermek, şımar","definition":"To allow oneself to enjoy the pleasure of; become involved in (an activity, typically one that is perceived as regrettable or undesirable); allow (someone) to enjoy something desired.","examples":["Occasionally, I indulge in a large bar of chocolate.","Don't indulge the child's every whim."]},{"word":"inequality","level":"C1","type":"n.","turkish":"Eşitsizlik.","definition":"Difference in size, degree, circumstances, etc.; lack of equality.","examples":["Social and economic inequality persists in many countries.","The campaign aims to address gender inequality."]},{"word":"inevitable","level":"B2","type":"adj.","turkish":"Kaçınılmaz,çaresiz.","definition":"Certain to happen; unavoidable.","examples":["Change is inevitable in life.","It was inevitable that they would eventually find out."]},{"word":"inevitably","level":"B2","type":"adv.","turkish":"Kaçınılmaz olarak,çaresizce.","definition":"As is certain to happen; unavoidably.","examples":["Increased demand will inevitably lead to higher prices.","Inevitably, the discussion turned to politics."]},{"word":"infamous","level":"C1","type":"adj.","turkish":"Adı kötüyeçıkmış, kötüşöhretli, rezil.","definition":"Well known for some bad quality or deed.","examples":["He was an infamous gangster in the 1930s.","The town is infamous for its high crime rate."]},{"word":"infant","level":"C1","type":"n.","turkish":"Bebek (genellikle yeni doğmuş veya ilk yıl içinde).","definition":"A very young child or baby.","examples":["The clinic provides care for mothers and infants.","Infant mortality rates have decreased significantly."]},{"word":"infect","level":"C1","type":"v.","turkish":"Bulaştırmak (hastalık), enfekte etmek; (duygu, fikir) etkilemek, yaymak.","definition":"To affect (a person, organism, cell, etc.) with a disease -causing organism; affect with (a feeling or fault).","examples":["Be careful not to infect others if you have the flu.","His enthusiasm infected the whole team."]},{"word":"infer","level":"B2","type":"v.","turkish":"Çıkarım yapmak, sonuççıkarmak, anlamçıkarmak.","definition":"To deduce or conclude (information) from evidence and reasoning rather than from explicit statements.","examples":["From his silence, I inferred that he did not agree.","What can we infer from these statistics?"]},{"word":"inflation","level":"B2","type":"n.","turkish":"Enflasyon (fiyatların genel artışı).","definition":"A general increase in prices and fall in the purchasing value of money.","examples":["High inflation erodes the value of savings.","The central bank raised interest rates to combat inflation."]},{"word":"inflict","level":"C1","type":"v.","turkish":"Vermek (acı, zarar vb.),çektirmek, uygulamak (cezayı).","definition":"To cause (something unpleasant or painful) to be suffered by someone or something; impose something unwelcome on.","examples":["The invaders inflicted heavy casualties on the defending army.","Do not inflict your personal problems on your colleagues."]},{"word":"influential","level":"C1","type":"adj.","turkish":"Etkili, nüfuzlu.","definition":"Having great influence on someone or something.","examples":["He is one of the most influential figures in modern politics.","Her parents were very influential in shaping her career choices. info (n."]},{"word":"infrastructure","level":"B2","type":"n.","turkish":"Altyapı (yol, köprü, enerji vb.).","definition":"The basic physical and organizational structures and facilities (e.g., buildings, roads, power supplies) needed for the operation of a society or enterprise.","examples":["The country needs to invest more in its infrastructure.","Poor transport infrastructure hinders economic growth."]},{"word":"inhabitant","level":"B2","type":"n.","turkish":"Sakin, oturan kişi, yerli.","definition":"A person or animal that lives in or occupies a place.","examples":["The town has about 10,000 inhabitants.","The oldest inhabitant of the village remembers the war."]},{"word":"inherent","level":"C1","type":"adj.","turkish":"Doğasında var olan, doğuştan gelen, içkin.","definition":"Existing in something as a permanent, essential, or characteristic attribute.","examples":["There are inherent risks associated with this type of investment.","A love of learning is inherent in her personality."]},{"word":"inherit","level":"B2","type":"v.","turkish":"Miras almak, miras kalmak; (özellik) kalıtım yoluyla almak.","definition":"To receive (money, property, or a title) as an heir at the death of the previous holder; derive (a quality, characteristic, or predisposition) genetically from one's parents or ancestors.","examples":["She inherited a large fortune from her grandmother.","He inherited his father's blue eyes."]},{"word":"inhibit","level":"C1","type":"v.","turkish":"Engellemek, ket vurmak, yavaşlatmak, kısıtlamak.","definition":"To hinder, restrain, or prevent (an action or process); make (someone) self-conscious and unable to act in a relaxed and natural way.","examples":["Fear of failure can inhibit creativity.","This drug inhibits the growth of cancer cells."]},{"word":"initiate","level":"C1","type":"v.","turkish":"Başlatmak,önayak olmak; (birini gruba/topluluğa) kabul etmek.","definition":"To cause (a process or action) to begin; admit (someone) into a secret or obscure society or group, typically with a ritual.","examples":["The company decided to initiate legal proceedings.","He was initiated into the secret society last year."]},{"word":"inject","level":"C1","type":"v.","turkish":"Enjekte etmek, iğne yapmak,şırınga etmek; (mecazi) katmak, aşılamak.","definition":"To drive or force (a liquid, especially a drug or vaccine) into a person or animal's body with a syringe or similar device; introduce (a new or different element) into something.","examples":["The nurse injected the vaccine into his arm.","We need to inject more creativity into our marketing campaigns."]},{"word":"injection","level":"C1","type":"n.","turkish":"Enjeksiyon, iğne,şırınga; (mecazi) ekleme, katma.","definition":"An instance of injecting or being injected; an introduction of a new or different element.","examples":["He receives regular insulin injections.","The project needed an injection of fresh ideas."]},{"word":"injustice","level":"C1","type":"n.","turkish":"Adaletsizlik, haksızlık.","definition":"Lack of fairness or justice.","examples":["They fought against racial injustice.","Many people felt a sense of injustice over the court's decision."]},{"word":"ink","level":"B2","type":"n.","turkish":"Mürekkep.","definition":"A colored fluid or paste used for writing, drawing, printing, or duplicating.","examples":["The printer has run out of black ink.","Please sign the document in blue or black ink."]},{"word":"inmate","level":"C1","type":"n.","turkish":"Mahkum, tutuklu; (hastane vb.) sakin.","definition":"A person confined to an institution such as a prison or hospital.","examples":["Several inmates escaped from the prison.","The hospital provides care for long -term inmates."]},{"word":"innovation","level":"B2","type":"n.","turkish":"Yenilik, buluş, inovasyon.","definition":"The action or process of innovating; a new method, idea, product, etc.","examples":["The company encourages innovation and creativity.","Technological innovation drives economic growth."]},{"word":"innovative","level":"B2","type":"adj.","turkish":"Yenilikçi, yaratıcı,özgün.","definition":"(of a product, idea, etc.) Featuring new methods; advanced and original.","examples":["She came up with an innovative solution to the problem.","The company is known for its innovative designs."]},{"word":"input","level":"B2","type":"n.","turkish":"Girdi (veri, bilgi, fikir vb.), katkı.","definition":"What is put in, taken in, or operated on by any process or system; contribution of information or ideas.","examples":["We need your input before making a final decision.","Data input can be a time-consuming task. inquire (v."]},{"word":"insert","level":"B2","type":"v.","turkish":"Sokmak, yerleştirmek, araya eklemek.","definition":"To place, fit, or thrust (something) into another thing.","examples":["Insert your card into the machine to withdraw cash.","Please insert a comma here."]},{"word":"insertion","level":"C1","type":"n.","turkish":"Sokma, yerleştirme, ekleme; eklenen şey.","definition":"The action of inserting something; a thing that is inserted.","examples":["The insertion of the key into the lock was difficult.","The editor made several insertions to the text."]},{"word":"insider","level":"C1","type":"n.","turkish":"İçeriden biri, kurum/grup içinden olan kimse.","definition":"A person within a group or organization, especially someone privy to information unavailable to others.","examples":["An insider leaked the confidential information to the press.","Insider trading is illegal."]},{"word":"inspect","level":"C1","type":"v.","turkish":"Denetlemek, teftiş etmek, muayene etmek.","definition":"To look at (someone or something) closely, typically to assess their condition or to discover any shortcomings.","examples":["Health officials inspect restaurants regularly.","Customs officers may inspect your baggage."]},{"word":"inspection","level":"C1","type":"n.","turkish":"Denetleme, teftiş, muayene.","definition":"Careful examination or scrutiny.","examples":["The building failed its safety inspection.","A thorough inspection revealed several defects."]},{"word":"inspector","level":"B2","type":"n.","turkish":"Müfettiş, denetçi; (polis) komiser.","definition":"An official employed to ensure that regulations are obeyed, especially in factories or schools; a police officer ranking below a superintendent.","examples":["The school inspector visited the classes.","Police Inspector Davies led the investigation."]},{"word":"inspiration","level":"C1","type":"n.","turkish":"İlham, esin; ilham veren kişi/şey.","definition":"The process of being mentally stimulated to do or feel something, especially to do something creative; a person or thing that inspires.","examples":["Nature is a great source of inspiration for artists.","Her courage was an inspiration to us all."]},{"word":"installation","level":"B2","type":"n.","turkish":"Kurulum, montaj, tesisat; (sanat) enstalasyon.","definition":"The action or process of installing someone or something, or of being installed; an art exhibit constructed within a gallery.","examples":["The installation of the new software took about an hour.","The gallery features an impressive modern art installation."]},{"word":"instant","level":"B2","type":"adj.","turkish":"Anlık, hemen olan; hazır (kahve vb.).","definition":"Happening or coming immediately; (of food) processed to allow quick preparation.","examples":["The system provides instant access to information.","Would you prefer fresh or instant coffee?"]},{"word":"instantly","level":"B2","type":"adv.","turkish":"Anında, hemen.","definition":"At once; immediately.","examples":["She recognized him instantly.","He fell asleep instantly."]},{"word":"instinct","level":"C1","type":"n.","turkish":"İçgüdü, sezgi.","definition":"An innate, typically fixed pattern of behavior in animals in response to certain stimuli; an intuitive feeling or way of thinking.","examples":["Birds build nests by instinct.","Trust your instincts; they are usually right."]},{"word":"institutional","level":"C1","type":"adj.","turkish":"Kurumsal.","definition":"Relating to or characteristic of an institution (a large important organization such as a university, church, or bank).","examples":["The university received large institutional grants.","Reforms are needed to address institutional weaknesses."]},{"word":"instruct","level":"C1","type":"v.","turkish":"Talimat vermek,öğretmek, eğitmek.","definition":"To direct or command someone to do something; teach (someone) a subject or skill.","examples":["The manager instructed the staff to complete the report by Friday.","He instructs students in computer programming."]},{"word":"instrumental","level":"C1","type":"adj.","turkish":"Etkili, -de rolü olan, yardımcı; enstrümantal (müzik).","definition":"Serving as a means of pursuing an aim; important in causing something to happen; performed on musical instruments.","examples":["She was instrumental in securing the contract.","The album features several instrumental tracks."]},{"word":"insufficient","level":"C1","type":"adj.","turkish":"Yetersiz, eksik, kafi olmayan.","definition":"Not enough; inadequate.","examples":["There was insufficient evidence to prove his guilt.","The funds allocated for the project were insufficient. insult (n., v."]},{"word":"intact","level":"C1","type":"adj.","turkish":"Dokunulmamış, sağlam, bozulmamış, eksiksiz.","definition":"Not damaged or impaired in any way; complete.","examples":["Despite the earthquake, most buildings remained intact.","Luckily, his reputation remained intact after the scandal."]},{"word":"intake","level":"C1","type":"n.","turkish":"Alım (yiyecek, sıvı, hava vb.); alınan miktar; giriş yeri.","definition":"An amount of food, air, or another substance taken into the body; the process of taking something in; a place where fluid or air is drawn into a machine or pipe.","examples":["You should reduce your daily calorie intake.","The college has a large student intake each year."]},{"word":"integral","level":"C1","type":"adj.","turkish":"Tamamlayıcı, bütünleyici, ayrılmaz (parça).","definition":"Necessary to make a whole complete; essential or fundamental.","examples":["Communication is an integral part of any successful team.","Music is integral to the film's atmosphere."]},{"word":"integrate","level":"B2","type":"v.","turkish":"Entegre etmek, bütünleştirmek, birleştirmek; uyum sağlamak, kaynaşmak.","definition":"To combine (one thing) with another so that they become a whole; bring (people or groups with particular characteristics or needs) into equal participation in or membership of a social group or institution.","examples":["The new software allows us to integrate data from different sources.","It can be difficult for immigrants to integrate into a new society."]},{"word":"integrated","level":"C1","type":"adj.","turkish":"Entegre, bütünleşik, birleşik.","definition":"With various parts or aspects linked or coordinated; having different groups (such as races or religions) living or working together.","examples":["The company offers an integrated system for managing finances.","The school promotes an integrated approach to learning."]},{"word":"integration","level":"C1","type":"n.","turkish":"Entegrasyon, bütünleşme, birleşme; uyum.","definition":"The action or process of integrating; the intermixing of people or groups previously segregated.","examples":["The integration of the two companies was a complex process.","Social integration is important for community cohesion."]},{"word":"integrity","level":"C1","type":"n.","turkish":"Dürüstlük, bütünlük, doğruluk; tamlık, bozulmamışlık.","definition":"The quality of being honest and having strong moral principles; moral uprightness; the state of being whole and undivided.","examples":["He is known for his professional integrity.","We must protect the territorial integrity of the country."]},{"word":"intellectual","level":"B2","type":"adj.","turkish":"(adj) Zihinsel, entelektüel; (n) Aydın, entelektüel kişi.","definition":"(adj) Relating to the intellect (the faculty of reasoning and understanding objectively). (n) A person possessing a highly developed intellect.","examples":["Children's intellectual development is crucial in early years. (adjective) She enjoys engaging in intellectual discussions. (adjective) He was regarded as one of the leading intellectuals of his time. (noun)"]},{"word":"intensify","level":"C1","type":"v.","turkish":"Yoğunlaştırmak,şiddetlendirmek, artırmak; yoğunlaşmak,şiddetlenmek.","definition":"To become or make more intense.","examples":["The storm is expected to intensify overnight.","Competition between the rival companies has intensified."]},{"word":"intensity","level":"C1","type":"n.","turkish":"Yoğunluk,şiddet (duygu,ışık, ses vb.).","definition":"The quality of being intense; great energy, strength, concentration, etc.; the measurable amount of a property, such as force, brightness, or a magnetic field.","examples":["The intensity of the heat was unbearable.","He spoke with great intensity about his beliefs."]},{"word":"intensive","level":"C1","type":"adj.","turkish":"Yoğun,şiddetli (çaba, bakım, tarım vb.).","definition":"Concentrated on a single area or subject or into a short time; very thorough or vigorous; involving concentrating a lot of effort or activity in a short period of time.","examples":["He underwent an intensive course of physiotherapy.","The patient required intensive care after the surgery."]},{"word":"intent","level":"C1","type":"n.","turkish":"Niyet, kasıt, maksat.","definition":"Intention or purpose.","examples":["It was not my intent to cause any offense.","The law requires proof of criminal intent."]},{"word":"interact","level":"B2","type":"v.","turkish":"Etkileşmek, etkileşimde bulunmak, birbirini etkilemek.","definition":"To act in such a way as to have an effect on each other; communicate or be involved directly.","examples":["Teachers need to interact well with their students.","Different chemicals can interact in unexpected ways."]},{"word":"interaction","level":"B2","type":"n.","turkish":"Etkileşim, karşılıklı etkilenme.","definition":"Reciprocal action or influence; communication or direct involvement with someone or something.","examples":["Social interaction is important for mental health.","The study examines the interaction between diet and exercise."]},{"word":"interactive","level":"C1","type":"adj.","turkish":"Etkileşimli, interaktif.","definition":"(of two people or things) Influencing each other; allowing a two -way flow of information between a computer and a computer-user; responding to the user's actions.","examples":["The museum has many interactive exhibits for children.","This website offers an interactive learning experience."]},{"word":"interface","level":"C1","type":"n.","turkish":"Arayüz (bilgisayar vb.); etkileşim noktası.","definition":"A point where two systems, subjects, organizations, etc., meet and interact; a device or program enabling a user to communicate with a computer.","examples":["The software has a user -friendly interface.","This cable provides an interface between the printer and the computer."]},{"word":"interfere","level":"C1","type":"v.","turkish":"Karışmak, müdahale etmek; (sinyal vb.) parazit yapmak.","definition":"To intervene in a situation without invitation or necessity; prevent (a process or activity) from continuing or being carried out properly.","examples":["Please don't interfere in matters that don't concern you.","Noise from the construction site interfered with our meeting."]},{"word":"interference","level":"C1","type":"n.","turkish":"Müdahale, karışma; parazit (sinyal).","definition":"The action of interfering or the process of being interfered with; disturbance to radio signals.","examples":["Constant interference from her parents damaged their relationship.","We experienced some radio interference during the storm."]},{"word":"interim","level":"C1","type":"adj.","turkish":"Geçici, ara.","definition":"In or for the intervening period; provisional or temporary.","examples":["An interim manager was appointed while they searched for a permanent replacement.","The company published an interim report halfway through the year."]},{"word":"interior","level":"C1","type":"adj.","turkish":"(adj) İç, dahili; (n) İç kısım, iç taraf; iç mekan (tasarım).","definition":"(adj) Situated within or inside; relating to the inside. (n) The inner or indoor part of something, especially a building; the inside.","examples":["The interior walls need painting. (adjective) She hired a designer to decorate the interior of her house. (noun)"]},{"word":"intermediate","level":"C1","type":"adj.","turkish":"Orta (seviye), ara.","definition":"Coming between two things in time, place, order, character, etc.; relating to or denoting a level of knowledge or skill between basic and advanced.","examples":["This course is suitable for students at an intermediate level.","He speaks intermediate Spanish."]},{"word":"interpretation","level":"B2","type":"n.","turkish":"Yorum, yorumlama, tefsir;çeviri (sözlü).","definition":"The action of explaining the meaning of something; an explanation or way of explaining; a stylistic representation of a creative work or dramatic role.","examples":["The data allows for several different interpretations.","Her interpretation of the character was widely praised."]},{"word":"intersection","level":"C1","type":"n.","turkish":"Kesişim noktası, kavşak.","definition":"A point or line common to lines or surfaces that intersect; a point at which two or more things intersect, especially roads.","examples":["There was an accident at the main intersection.","Turn right at the next intersection."]},{"word":"interval","level":"B2","type":"n.","turkish":"Ara, aralık (zaman, mesafe); perde arası (tiyatro vb.).","definition":"An intervening time or space; a pause; a break in activity; (UK) an intermission in a play or concert.","examples":["Buses run at regular intervals throughout the day.","We bought ice cream during the interval of the play."]},{"word":"intervene","level":"C1","type":"v.","turkish":"Müdahale etmek, araya girmek (anlaşmazlık, durum vb.); (zaman) araya girmek.","definition":"To come between so as to prevent or alter a result or course of events; occur in time between events.","examples":["The police had to intervene to stop the fight.","Several years intervened between their first meeting and their marriage."]},{"word":"intervention","level":"C1","type":"n.","turkish":"Müdahale, araya girme.","definition":"The action or process of intervening.","examples":["Military intervention was necessary to restore order.","Early intervention can help children with learning difficulties."]},{"word":"intimate","level":"C1","type":"adj.","turkish":"Samimi, yakın (arkadaş, ilişki vb.); kişisel,özel; detaylı (bilgi).","definition":"Closely acquainted; familiar; close; private and personal; involving very close connection.","examples":["They shared an intimate conversation over dinner.","She has an intimate knowledge of the local area."]},{"word":"intriguing","level":"C1","type":"adj.","turkish":"İlgiçekici, merak uyandıran.","definition":"Arousing one's curiosity or interest; fascinating.","examples":["The book has an intriguing plot.","That's an intriguing possibility."]},{"word":"invade","level":"B2","type":"v.","turkish":"İstila etmek, işgal etmek; (mecazi) ihlal etmek (mahremiyet vb.).","definition":"(of an armed force) Enter (a country or region) so as to subjugate or occupy it; enter (a place, situation, or sphere of activity) in large numbers, especially intrusively.","examples":["Enemy troops invaded the country at dawn.","Tourists invade the small town every summer."]},{"word":"invasion","level":"B2","type":"n.","turkish":"İstila, işgal; (mecazi) ihlal.","definition":"An instance of invading a country or region with an armed force; an unwelcome intrusion into another's domain.","examples":["The invasion led to a long and bloody war.","She complained about the invasion of her privacy."]},{"word":"inventory","level":"C1","type":"n.","turkish":"Envanter, stok, mal listesi; envanter sayımı.","definition":"A complete list of items such as property, goods in stock, or the contents of a building; the quantity of goods held in stock.","examples":["The store closes once a year to take inventory.","We need to reduce our inventory levels."]},{"word":"investigator","level":"C1","type":"n.","turkish":"Araştırmacı, soruşturmacı, dedektif.","definition":"A person who carries out a formal inquiry or investigation.","examples":["Private investigators were hired to gather evidence.","The lead investigator interviewed all the witnesses."]},{"word":"investor","level":"B2","type":"n.","turkish":"Yatırımcı.","definition":"A person or organization that puts money into financial schemes, property, etc. with the expectation of achieving a profit.","examples":["The company is seeking potential investors.","Foreign investors play a significant role in the economy."]},{"word":"invisible","level":"C1","type":"adj.","turkish":"Görünmez.","definition":"Unable to be seen; not visible to the eye.","examples":["Germs are invisible to the naked eye.","He felt invisible in the large crowd."]},{"word":"invoke","level":"C1","type":"v.","turkish":"Yardım istemek,çağırmak (ruh, tanrı vb.); (yasa, kural) uygulamak, başvurmak; (duygu, anı) uyandırma","definition":"To cite or appeal to (someone or something) as an authority for an action or in support of an argument; call on (a deity or spirit) in prayer, as a witness, or for inspiration; call earnestly for.","examples":["The defendant decided to invoke his right to remain silent.","Ancient priests would invoke the gods for help."]},{"word":"involvement","level":"C1","type":"n.","turkish":"Katılım, ilgi, dahil olma; (suça vb.) karışma, bulaşma.","definition":"The fact or condition of being involved with or participating in something; emotional or personal association with someone.","examples":["Her involvement in the project was crucial to its success.","He denied any involvement in the robbery."]},{"word":"ironic","level":"C1","type":"adj.","turkish":"İronik, alaycı, beklenenin tersi.","definition":"Happening in the opposite way to what is expected, and typically causing wry amusement because of this; using or characterized by irony.","examples":["It's ironic that the firefighter's house burned down.","She gave an ironic smile when he complimented her driving."]},{"word":"ironically","level":"C1","type":"adv.","turkish":"İronik birşekilde, işin garibi, beklenenin tersine olarak.","definition":"In an ironic way; used to denote a paradoxical, unexpected, or coincidental situation.","examples":["Ironically, the safety measures themselves caused the accident.","He spoke ironically about his own failures."]},{"word":"irony","level":"C1","type":"n.","turkish":"İroni, alay, beklenenin tersi olma durumu.","definition":"The expression of one's meaning by using language that normally signifies the opposite, typically for humorous or emphatic effect; a state of affairs or an event that seems deliberately contrary to what one expects and is often wryly amusing as a res","examples":["The irony is that he criticized the very behavior he later exhibited.","There was a touch of irony in her voice."]},{"word":"irrelevant","level":"C1","type":"adj.","turkish":"İlgisiz, alakasız, konu dışı.","definition":"Not connected with or relevant to something.","examples":["His comments were completely irrelevant to the discussion.","Whether he likes the color is irrelevant; we need it to be durable."]},{"word":"isolate","level":"B2","type":"v.","turkish":"İzole etmek, ayırmak, tecrit etmek.","definition":"To cause (a person or place) to be or remain alone or apart from others; identify (something) and examine or deal with it separately.","examples":["Patients with infectious diseases are often isolated.","Scientists managed to isolate the gene responsible for the disorder."]},{"word":"isolated","level":"B2","type":"adj.","turkish":"İzole, ayrı, tek başına, tenha; tecrit edilmiş.","definition":"Far away from other places, buildings, or people; remote; having minimal contact or little in common with others.","examples":["They live in an isolated farmhouse miles from the nearest town.","After the argument, she felt very isolated and alone."]},{"word":"isolation","level":"C1","type":"n.","turkish":"İzolasyon, tecrit, ayrılık, yalnızlık.","definition":"The process or fact of isolating or being isolated.","examples":["Living in a remote area can lead to feelings of isolation.","The country pursued a policy of economic isolation."]},{"word":"jail","level":"B2","type":"n.","turkish":"(n) Hapishane, cezaevi; (v) Hapse atmak.","definition":"(n) A place for the confinement of people accused or convicted of a crime. (v) Put (someone) in jail.","examples":["He spent six months in jail for theft. (noun) The judge jailed him for three years. (verb)"]},{"word":"jet","level":"B2","type":"n.","turkish":"Jet (uçağı); fıskiye, tazyikli su/gaz akışı.","definition":"An aircraft powered by jet engines; a rapid stream of liquid or gas forced out of a small opening.","examples":["We flew to Paris by jet.","A powerful jet of water sprayed from the hose."]},{"word":"joint","level":"B2","type":"adj.","turkish":"(adj) Ortak, müşterek; (n) Eklem (vücut); (gayriresmi) esrarlı sigara.","definition":"(adj) Shared, held, or made by two or more people together. (n) A structure in the human or animal body at which two parts of the skeleton are fitted together; (informal) a marijuana cigarette.","examples":["They opened a joint bank account. (adjective) Arthritis causes pain in the joints. (noun)"]},{"word":"journalism","level":"B2","type":"n.","turkish":"Gazetecilik, habercilik.","definition":"The activity or profession of writing for newspapers, magazines, or news websites or preparing news to be broadcast.","examples":["She studied journalism at university.","Good journalism requires accuracy and impartiality."]},{"word":"judicial","level":"C1","type":"adj.","turkish":"Adli, yargısal, mahkemeyle ilgili.","definition":"Relating to, done by, or appropriate to a court or judge.","examples":["The case is currently under judicial review.","The country has an independent judicial system."]},{"word":"jurisdiction","level":"C1","type":"n.","turkish":"Yargı yetkisi, yetki alanı, görev alanı.","definition":"The official power to make legal decisions and judgments; the territory or sphere of activity over which the legal authority of a court or other institution extends.","examples":["The court has jurisdiction over crimes committed in this state.","This matter falls outside our jurisdiction."]},{"word":"jury","level":"B2","type":"n.","turkish":"Jüri, yargıcılar kurulu.","definition":"A body of people (typically twelve in number) sworn to give a verdict in a legal case on the basis of evidence submitted to them in court.","examples":["The jury found the defendant guilty.","Members of the jury listened intently to the testimony. just (adj."]},{"word":"justification","level":"C1","type":"n.","turkish":"Gerekçe, mazeret, haklı sebep.","definition":"The action of showing something to be right or reasonable; a good reason for something that exists or has been done.","examples":["There is no possible justification for his violent behavior.","What is your justification for taking this action?"]},{"word":"keen","level":"C1","type":"adj.","turkish":"İstekli, hevesli; keskin (zeka, göz, bıçak vb.); düşkün.","definition":"Having or showing eagerness or enthusiasm; (of a sense) highly developed; sharp or penetrating.","examples":["She is very keen to learn Spanish. (eager) Dogs have a keen sense of smell. (sharp) He is a keen photographer. (enthusiastic)"]},{"word":"kidnap","level":"C1","type":"v.","turkish":"Çocuk kaçırmak, (fidye için) adam kaçırmak.","definition":"To abduct (someone) and hold them captive, typically to obtain a ransom.","examples":["The gang attempted to kidnap the wealthy businessman's son.","He was kidnapped and held for three days."]},{"word":"kidney","level":"C1","type":"n.","turkish":"Böbrek.","definition":"Each of a pair of organs in the abdominal cavity of mammals, birds, and reptiles, excreting urine.","examples":["Drinking plenty of water is good for your kidneys.","He needs a kidney transplant."]},{"word":"kindergarten","level":"B2","type":"n.","turkish":"Anaokulu, kreş.","definition":"(in North America) A school or class that prepares children for first grade; (chiefly British) An establishment where children below the age of compulsory education play and learn; a nursery school.","examples":["My daughter starts kindergarten next September.","Children learn through play in kindergarten."]},{"word":"kingdom","level":"C1","type":"n.","turkish":"Krallık; alem (hayvanlar, bitkiler alemi vb.).","definition":"A country, state, or territory ruled by a king or queen; one of the main groups into which natural objects are classified (e.g., animal kingdom).","examples":["The United Kingdom includes England, Scotland, Wales, and Northern Ireland.","Lions are known as the kings of the animal kingdom."]},{"word":"kit","level":"B2","type":"n.","turkish":"Kit, takım, avadanlık, malzemeçantası.","definition":"A set of articles or equipment needed for a specific purpose.","examples":["Make sure you have a well -stocked first-aid kit.","The furniture comes in a kit that you assemble yourself."]},{"word":"ladder","level":"B2","type":"n.","turkish":"Merdiven (taşınabilir).","definition":"A piece of equipment consisting of a series of bars or steps between two upright lengths of wood, metal, or rope, used for climbing up or down something.","examples":["He climbed the ladder to reach the roof.","Be careful when using a ladder."]},{"word":"landing","level":"B2","type":"n.","turkish":"İniş (uçak, gemi vb.); sahanlık (merdiven).","definition":"An act of coming or bringing something to land, either from the air or from the water; a level area at the top or bottom of a staircase or between one flight of stairs and another.","examples":["The plane made a smooth landing.","Leave the boxes on the landing outside my door."]},{"word":"landlord","level":"C1","type":"n.","turkish":"Ev sahibi, mülk sahibi (kiraya veren).","definition":"A man (in legal use also a woman) who rents out land, a building, or part of a building.","examples":["We pay our rent directly to the landlord.","The landlord is responsible for repairs to the property."]},{"word":"landmark","level":"C1","type":"n.","turkish":"Kent simgesi, dikkatçekici yapı/yer; dönüm noktası,önemli olay.","definition":"An object or feature of a landscape or town that is easily seen and recognized from a distance, especially one that enables someone to establish their location; an event, discovery, or change marking an important stage or turning point in something.","examples":["The Eiffel Tower is a famous Parisian landmark.","The invention of the internet was a landmark in communication technology."]},{"word":"lane","level":"B2","type":"n.","turkish":"Şerit (yol); dar yol, patika; kulvar (yüzme, koşu).","definition":"A narrow road, especially in a rural area; a division of a road marked off with painted lines and intended to separate single lines of traffic according to speed or direction; a marked course for competitors in a race.","examples":["Stay in the right-hand lane unless overtaking.","She lives down a quiet country lane."]},{"word":"lap","level":"C1","type":"n.","turkish":"Kucak (otururken dizlerinüst kısmı); tur (pistte).","definition":"The flat area between the waist and knees of a seated person; one circuit of a track or racetrack.","examples":["The cat curled up comfortably on her lap.","The runners completed the final lap of the race."]},{"word":"large -scale","level":"C1","type":"adj.","turkish":"Büyükölçekli, genişçaplı.","definition":"Involving many people or things or covering a wide area.","examples":["The company is undertaking a large-scale restructuring program.","Large-scale farming often involves the use of machinery."]},{"word":"laser","level":"C1","type":"n.","turkish":"Lazer.","definition":"A device that emits light through a process of optical amplification based on the stimulated emission of electromagnetic radiation (acronym for Light Amplification by Stimulated Emission of Radiation).","examples":["Laser technology is used in many medical procedures.","The barcode scanner uses a laser beam."]},{"word":"lately","level":"B2","type":"adv.","turkish":"Son zamanlarda, son günlerde.","definition":"Recently; not long ago.","examples":["Have you seen any good films lately?","I haven't been feeling very well lately."]},{"word":"latter","level":"C1","type":"adj.","turkish":"(adj) Sonraki, ikinci (bahsedilen iki şeyden); (n) İkincisi, sonuncusu.","definition":"(adj) Denoting the second or second mentioned of two people or things. (n) The second or second mentioned of two people or things.","examples":["Between studying and relaxing, I prefer the latter. (noun) Of the two options, the latter seems more practical. (adjective)"]},{"word":"lawmaker","level":"C1","type":"n.","turkish":"Kanun koyucu, yasa yapıcı, milletvekili.","definition":"A person who makes laws; a legislator.","examples":["Lawmakers debated the new bill in parliament.","The proposal was rejected by lawmakers."]},{"word":"lawn","level":"C1","type":"n.","turkish":"Çim alan,çimenlik.","definition":"An area of short, mown grass in a yard, garden, or park.","examples":["He spent Saturday mowing the lawn.","Children were playing on the lawn."]},{"word":"lawsuit","level":"C1","type":"n.","turkish":"Dava, hukuk davası.","definition":"A claim or dispute brought to a court of law for adjudication.","examples":["The company is facing a multimillion -dollar lawsuit.","He filed a lawsuit against his former employer for unfair dismissal."]},{"word":"layout","level":"C1","type":"n.","turkish":"Düzen, plan, mizanpaj (sayfa, bina vb.).","definition":"The way in which the parts of something are arranged or laid out.","examples":["I like the layout of this magazine page.","The architect showed us the proposed layout for the new house."]},{"word":"leak","level":"C1","type":"v.","turkish":"(v) Sızdırmak, akmak (sıvı, gaz); sızdırmak (bilgi); (n) Sızıntı, kaçak (sıvı, gaz, bilgi).","definition":"(v) (of a container or covering) Accidentally lose or admit contents, especially liquid or gas; intentionally disclose (secret information). (n) A hole in a container or covering through which contents may accidentally pass; an intentional disclosure","examples":["The roof is leaking water. (verb) There is a small leak in the pipe. (noun) Confidential documents were leaked to the press. (verb) leap (v., n.","C1) (leap, leaped/leapt, leaped/leapt) Türkçe Anlamı: (v) Sıçramak, atlamak; (mecazi) hızla artmak; (n) Sıçrama, atlama; (mecazi) artış, ilerleme."]},{"word":"legacy","level":"C1","type":"n.","turkish":"Miras (para, mal veya manevi).","definition":"An amount of money or property left to someone in a will; something left or handed down by a predecessor.","examples":["He received a small legacy from his aunt.","The Roman Empire left a lasting legacy of law and engineering."]},{"word":"legend","level":"B2","type":"n.","turkish":"Efsane; efsanevi kişi; (harita vb.) lejant, açıklama.","definition":"A traditional story sometimes popularly regarded as historical but unauthenticated; an extremely famous or notorious person, especially in a particular field; an explanatory list of symbols used in a map or chart.","examples":["Robin Hood is a famous English legend.","Pelé is a football legend."]},{"word":"legendary","level":"C1","type":"adj.","turkish":"Efsanevi, dillere destan.","definition":"Remarkable enough to be famous; very well known; of, described in, or based on legends.","examples":["King Arthur is a legendary figure in British history.","Her generosity was legendary."]},{"word":"legislation","level":"C1","type":"n.","turkish":"Mevzuat, yasama, kanunlar.","definition":"Laws, considered collectively.","examples":["New legislation aims to protect consumer rights.","The government introduced controversial legislation."]},{"word":"legislative","level":"C1","type":"adj.","turkish":"Yasama(yla ilgili), kanun koyucu.","definition":"Having the power to make laws; relating to laws or the making of them.","examples":["The legislative process can be lengthy and complex.","Parliament is the country's main legislative body."]},{"word":"legislature","level":"C1","type":"n.","turkish":"Yasama organı, meclis.","definition":"The legislative body of a country or state.","examples":["The bill must be approved by the legislature.","Members of the legislature are elected by the people."]},{"word":"legitimate","level":"C1","type":"adj.","turkish":"Meşru, yasal, haklı, mantıklı.","definition":"Conforming to the law or to rules; able to be defended with logic or justification; reasonable.","examples":["The government has a legitimate right to tax its citizens.","Employee concerns about safety were quite legitimate."]},{"word":"lengthy","level":"C1","type":"adj.","turkish":"Uzun, uzun süren.","definition":"(especially in reference to time) Of considerable or unusual length, especially so as to be tedious.","examples":["We had a lengthy discussion about the future plans.","The legal process can be lengthy and expensive. lens (n."]},{"word":"lesbian","level":"C1","type":"adj.","turkish":"Lezbiyen, eş cinsel (kadın).","definition":"Relating to homosexual women or to homosexuality in women.","examples":["The film tells the story of a lesbian couple.","She is active in the lesbian rights movement."]},{"word":"lesser","level":"C1","type":"adj.","turkish":"Daha azönemli, daha küçük, ikincil.","definition":"Not so great or important as the other or the rest; smaller in amount or value.","examples":["He chose the lesser of two evils.","These are matters of lesser importance."]},{"word":"lethal","level":"C1","type":"adj.","turkish":"Ölümcül,öldürücü.","definition":"Sufficient to cause death; very harmful or destructive.","examples":["The snake's venom is lethal to humans.","He received a lethal dose of radiation."]},{"word":"liable","level":"C1","type":"adj.","turkish":"Sorumlu (yasal olarak); -e eğilimli, -e yatkın, -mesi muhtemel.","definition":"Responsible by law; legally answerable; likely to do or to be something.","examples":["You will be held liable for any damage caused. (responsible) People who don't exercise are more liable to injury. (likely)"]},{"word":"liberal","level":"C1","type":"adj.","turkish":"(adj) Liberal,özgürlükçü; cömert; (n) Liberal (görüşlü kimse).","definition":"(adj) Willing to respect or accept behavior or opinions different from one's own; open to new ideas; relating to or denoting a political and social philosophy that promotes individual rights, civil liberties, democracy, and free enterprise; given, us","examples":["Her parents have very liberal attitudes towards her choices. (adjective) The party advocates liberal economic policies. (adjective) He considers himself a political liberal. (noun)"]},{"word":"liberation","level":"C1","type":"n.","turkish":"Kurtuluş,özgürlüğe kavuşma/kavuşturma.","definition":"The action of setting someone free from imprisonment, slavery, or oppression; release.","examples":["The movement fought for the liberation of oppressed people.","The city celebrated its liberation after years of occupation."]},{"word":"liberty","level":"C1","type":"n.","turkish":"Özgürlük, hürriyet.","definition":"The state of being free within society from oppressive restrictions imposed by authority on one's way of life, behavior, or political views.","examples":["The Statue of Liberty is a symbol of freedom.","Prisoners long for liberty."]},{"word":"lifelong","level":"C1","type":"adj.","turkish":"Ömür boyu süren, hayat boyu.","definition":"Lasting or remaining in a particular state throughout a person's life.","examples":["They remained lifelong friends.","Learning should be a lifelong pursuit."]},{"word":"lifetime","level":"B2","type":"n.","turkish":"Ömür, yaşam süresi; hayat.","definition":"The duration of a person's life.","examples":["Visiting the pyramids was the experience of a lifetime.","He spent his entire lifetime studying birds."]},{"word":"lighting","level":"B2","type":"n.","turkish":"Aydınlatma,ışıklandırma.","definition":"Equipment in a home, workplace, public place, or vehicle for producing light; the arrangement or effect of lights.","examples":["The room has poor lighting.","Good lighting is essential for reading."]},{"word":"likelihood","level":"C1","type":"n.","turkish":"Olasılık, ihtimal.","definition":"The state or fact of being likely; probability.","examples":["There is a strong likelihood of rain tomorrow.","What is the likelihood of success?"]},{"word":"likewise","level":"B2","type":"adv.","turkish":"Aynışekilde, keza; ayrıca, hem de.","definition":"In the same way; also; used to introduce a point similar or related to one just made.","examples":["Watch him carefully and do likewise. \"It was nice meeting you.\" \" Likewise.\""]},{"word":"limb","level":"C1","type":"n.","turkish":"Kol, bacak, uzuv; (ağacın) ana dalı.","definition":"An arm or leg of a person or fourlegged animal, or a bird's wing; a large branch of a tree.","examples":["He broke a limb in the skiing accident.","The storm broke several large limbs off the old oak tree."]},{"word":"limitation","level":"B2","type":"n.","turkish":"Sınırlama, kısıtlama; eksiklik, kısıtlılık.","definition":"A limiting rule or circumstance; a restriction; a defect or failing.","examples":["Time limitations prevented us from discussing everything.","Despite its limitations, the study provides valuable insights."]},{"word":"linear","level":"C1","type":"adj.","turkish":"Doğrusal,çizgisel.","definition":"Arranged in or extending along a straight or nearly straight line; progressing from one stage to another in a single series of steps; sequential.","examples":["The graph shows a linear relationship between the two variables.","The story follows a linear narrative structure. lineup (n."]},{"word":"linger","level":"C1","type":"v.","turkish":"Oyalanmak, kalmak, ayrılmamak; (duygu, koku vb.) devam etmek, gitmemek.","definition":"To stay in a place longer than necessary, typically because of a reluctance to leave; be slow to disappear or die.","examples":["They lingered over coffee after the meal.","The smell of smoke lingered in the air."]},{"word":"listing","level":"C1","type":"n.","turkish":"Listeleme; liste; (borsa) kotasyon.","definition":"A list or catalogue; an entry in a list or directory; the admission of a company's shares for trading on a stock exchange.","examples":["Please check the listing for today's events.","The company applied for a stock market listing. liter (n."]},{"word":"literacy","level":"C1","type":"n.","turkish":"Okuryazarlık.","definition":"The ability to read and write.","examples":["The government launched a campaign to improve adult literacy.","Basic literacy skills are essential in modern society."]},{"word":"literally","level":"B2","type":"adv.","turkish":"Kelimenin tam anlamıyla, harfi harfine; (gayriresmi) gerçekten, abartısız.","definition":"In a literal manner or sense; exactly; (informal) used for emphasis or to express strong feeling while not being literally true.","examples":["Translate the sentence literally, word for word. (exactly) I was so tired, I literally couldn't move. (informal emphasis)"]},{"word":"literary","level":"B2","type":"adj.","turkish":"Edebi, edebiyatla ilgili.","definition":"Concerning the writing, study, or content of literature, especially of the kind valued for quality of form.","examples":["She won several prestigious literary awards.","He is a well-known literary critic."]},{"word":"liver","level":"C1","type":"n.","turkish":"Karaciğer.","definition":"A large lobed glandular organ in the abdomen of vertebrates, involved in many metabolic processes including filtering blood from the digestive tract.","examples":["The liver plays a vital role in detoxifying the body.","Excessive alcohol consumption can damage the liver."]},{"word":"lobby","level":"C1","type":"n.","turkish":"(n) Lobi, giriş salonu; kulis, baskı grubu; (v) Kulis yapmak, (politikacıları vb.) etkilemeye çalışm","definition":"(n) A room providing a space out of which one or more other rooms or corridors lead, typically one near the entrance of a public building; a group of people seeking to influence politicians or public officials on a particular issue. (v) Seek to influ","examples":["Let's meet in the hotel lobby at 7 PM. (noun - hall) Environmental groups are lobbying the government to reduce emissions. (verb) The oil lobby is very powerful in Washington. (noun - group)"]},{"word":"log","level":"C1","type":"n.","turkish":"(n) Kütük (ağaç); kayıt, seyir defteri; (v) Kaydetmek, günlüğe işlemek; (bilgisayara) giriş yapmak.","definition":"(n) A part of the trunk or a large branch of a tree that has fallen or been cut off; an official record of events during the voyage of a ship or aircraft or during the flight of a spacecraft. (v) Enter (an incident or fact) in the log of a ship or ai","examples":["We threw another log on the fire. (noun - wood) All complaints must be logged in the system. (verb - record) You need a password to log in to your account. (verb - computer)"]},{"word":"logic","level":"C1","type":"n.","turkish":"Mantık.","definition":"Reasoning conducted or assessed according to strict principles of validity; a particular system or codification of the principles of proof and inference.","examples":["There is no logic in his argument.","Studying philosophy helps develop skills in logic and reasoning."]},{"word":"logo","level":"B2","type":"n.","turkish":"Logo, amblem.","definition":"A symbol or other design adopted by an organization to identify its products, uniform, vehicles, etc.","examples":["The company's logo is recognized worldwide.","She designed a new logo for the brand."]},{"word":"long -standing","level":"C1","type":"adj.","turkish":"Uzun süredir devam eden, köklü, eski.","definition":"Having existed or continued for a long time.","examples":["There is a long-standing dispute between the two families.","It is a long-standing tradition in our community."]},{"word":"longtime","level":"C1","type":"adj.","turkish":"Uzun zamandır, eski (arkadaş, ortak vb.).","definition":"Having been such for a long time.","examples":["He is a longtime friend and colleague.","She is a longtime resident of this town."]},{"word":"loom","level":"C1","type":"v.","turkish":"Belirmek, görünmek (heybetli/tehditkarşekilde); (tehlike) yaklaşmak, ufukta görünmek.","definition":"To appear as a shadowy form, especially one that is large or threatening; (of an event regarded as ominous or threatening) seem about to happen.","examples":["Dark clouds loomed on the horizon.","An economic crisis is looming."]},{"word":"loop","level":"C1","type":"n.","turkish":"Döngü, halka, ilmek; (film, müzik) döngü.","definition":"A shape produced by a curve that bends around and crosses itself; a structure, series, or process, the end of which is connected to the beginning; a continuously repeating sequence of film or tape.","examples":["Tie the rope in a loop.","The program got stuck in an infinite loop."]},{"word":"lottery","level":"B2","type":"n.","turkish":"Piyango, loto,şans oyunu.","definition":"A means of raising money by selling numbered tickets and giving prizes to the holders of numbers drawn at random.","examples":["He won a million dollars in the state lottery.","Buying a lottery ticket is a form of gambling."]},{"word":"loyal","level":"B2","type":"adj.","turkish":"Sadık, vefalı.","definition":"Giving or showing firm and constant support or allegiance to a person or institution.","examples":["Dogs are known for being loyal companions.","He remained loyal to the company despite offers from competitors."]},{"word":"loyalty","level":"C1","type":"n.","turkish":"Sadakat, vefa, bağlılık.","definition":"The quality of being loyal to someone or something.","examples":["He values loyalty above all else in his friends.","Customer loyalty is important for business success. lyric (n."]},{"word":"magical","level":"C1","type":"adj.","turkish":"Büyülü, sihirli; (mecazi) harika, büyüleyici.","definition":"Relating to, using, or resembling magic; beautiful or delightful in a way that seems removed from everyday life.","examples":["The story is set in a magical kingdom.","Spending Christmas with the family was a truly magical experience."]},{"word":"magnetic","level":"C1","type":"adj.","turkish":"Manyetik; (mecazi)çekici, mıknatıs gibiçeken.","definition":"Having the property of magnetism; relating to magnetism or magnetic fields; very attractive or alluring.","examples":["Iron is a magnetic metal.","She has a magnetic personality that draws people to her."]},{"word":"magnificent","level":"B2","type":"adj.","turkish":"Muhteşem, görkemli, harika.","definition":"Impressively beautiful, elaborate, or extravagant; striking.","examples":["The palace was filled with magnificent artwork.","From the top of the mountain, the view was magnificent."]},{"word":"magnitude","level":"C1","type":"n.","turkish":"Büyüklük, boyut,önem; (deprem) magnitüd,şiddet; (yıldız) parlaklık derecesi.","definition":"The great size or extent of something; importance; the degree of brightness of a star; the size of an earthquake on the Richter scale.","examples":["We didn't realize the magnitude of the problem until later.","The earthquake had a magnitude of 7.2."]},{"word":"mainland","level":"C1","type":"n.","turkish":"Ana kara.","definition":"A large continuous extent of land that includes the greater part of a country or continent, as opposed to offshore islands and detached territories.","examples":["We took a ferry from the island back to the mainland.","The storm affected the islands more than the mainland."]},{"word":"mainstream","level":"C1","type":"n.","turkish":"(n) Ana akım, genel eğilim; (adj) Ana akım, genel kabul gören, yaygın.","definition":"(n) The ideas, attitudes, or activities that are regarded as normal or conventional; the dominant trend in opinion, fashion, or the arts. (adj) Belonging to or characteristic of the mainstream.","examples":["His radical ideas were outside the political mainstream. (noun) Organic food has become more mainstream in recent years. (adjective)"]},{"word":"maintenance","level":"C1","type":"n.","turkish":"Bakım, onarım; koruma, sürdürme; nafaka.","definition":"The process of preserving a condition or situation or the state of being preserved; the process of keeping something in good condition; financial support paid by a divorced or separated person to their former spouse or partner.","examples":["Regular car maintenance is important for safety.","The old building requires constant maintenance."]},{"word":"mandate","level":"C1","type":"n.","turkish":"Manda, yetki (seçimle verilen vb.); emir, talimat.","definition":"An official order or commission to do something; the authority to carry out a policy or course of action, regarded as given by the electorate to a candidate or party that is victorious.","examples":["The government received a clear mandate from the voters.","The committee was given a mandate to investigate the issue."]},{"word":"mandatory","level":"C1","type":"adj.","turkish":"Zorunlu, mecburi.","definition":"Required by law or rules; compulsory.","examples":["Attendance at the safety meeting is mandatory for all employees.","The judge imposed a mandatory life sentence."]},{"word":"manifest","level":"C1","type":"v.","turkish":"Göstermek, belli etmek, açığa vurmak; ortayaçıkmak.","definition":"To display or show (a quality or feeling) by one's acts or appearance; demonstrate; become apparent through the appearance of symptoms.","examples":["She did not manifest any signs of illness.","His frustration began to manifest itself in his behavior."]},{"word":"manipulate","level":"C1","type":"v.","turkish":"Manipüle etmek, ustaca idare etmek/kullanmak; (bilgi, hesap vb.) tahrif etmek, hile karıştırmak.","definition":"To handle or control (a tool, mechanism, etc.), typically in a skillful manner; control or influence (a person or situation) cleverly, unfairly, or unscrupulously.","examples":["He knows how to manipulate the controls of the machine.","She tried to manipulate him into doing what she wanted."]},{"word":"manipulation","level":"C1","type":"n.","turkish":"Manipülasyon, hileli yönlendirme; ustaca kullanma.","definition":"The action of manipulating something in a skillful manner; the action of manipulating someone in a clever or unscrupulous way.","examples":["Financial manipulation is a serious offense.","She accused him of emotional manipulation."]},{"word":"manufacture","level":"B2","type":"v.","turkish":"İmal etmek,üretmek (fabrikada vb.); uydurmak (hikaye vb.).","definition":"To make (something) on a large scale using machinery; invent or fabricate (evidence or a story).","examples":["The company manufactures electronic components.","He manufactured an excuse for being late."]},{"word":"manufacturing","level":"B2","type":"n.","turkish":"İmalat,üretim (sanayi).","definition":"The making of articles on a large scale using machinery; industrial production.","examples":["The city's economy relies heavily on manufacturing.","Manufacturing jobs have declined in recent years."]},{"word":"manuscript","level":"C1","type":"n.","turkish":"El yazması (kitap, belge vb.); (yayınlanmadanönceki) metin, müsvedde.","definition":"A book, document, or piece of music written by hand rather than typed or printed; an author's text that has not yet been published.","examples":["The library holds several ancient manuscripts.","She submitted the final manuscript to her publisher."]},{"word":"marathon","level":"B2","type":"n.","turkish":"Maraton (koşu); (mecazi) uzun ve zorlu iş.","definition":"A long -distance running race, strictly one of 26 miles 385 yards (42.195 km); a long-lasting or difficult task or activity.","examples":["He is training to run his first marathon.","Getting the project finished felt like a marathon."]},{"word":"march","level":"C1","type":"n.","turkish":"(n) Yürüyüş (askeri, protesto vb.); marş (müzik); (v) (Törenle/askeri adımlarla) yürümek; yürüyüş ya","definition":"(n) An act or instance of marching; a piece of music with a rhythm appropriate for marching. (v) Walk in a military manner with a regular measured tread; walk quickly and purposefully.","examples":["Soldiers took part in the victory march. (noun) Thousands of people marched through the city to protest the war. (verb)"]},{"word":"margin","level":"B2","type":"n.","turkish":"Kenar boşluğu (sayfa); fark (oy, skor vb.); kar payı, marj.","definition":"The edge or border of something; the amount by which something is won or falls short; the difference between the cost price and selling price of goods or services.","examples":["Please write your notes in the margin.","They won the election by a narrow margin."]},{"word":"marginal","level":"C1","type":"adj.","turkish":"Marjinal, küçük,önemsiz; sınırda olan.","definition":"Relating to or situated at the edge or margin of something; of secondary or minor importance; very slight or small.","examples":["There has only been a marginal increase in sales.","The changes had only a marginal effect on the overall result."]},{"word":"marine","level":"C1","type":"adj.","turkish":"Deniz(le ilgili), denize ait.","definition":"Relating to or found in the sea; relating to shipping or naval matters.","examples":["Scientists are studying marine life in the deep ocean.","Pollution poses a threat to marine ecosystems."]},{"word":"marker","level":"B2","type":"n.","turkish":"İşaretleyici kalem, markör; işaret, gösterge.","definition":"A felt-tip pen with a broad tip; an object used to indicate a position, place, or route; something that indicates a certain quality or state.","examples":["Use a permanent marker to label the boxes.","High blood pressure can be a marker for heart disease."]},{"word":"marketplace","level":"C1","type":"n.","turkish":"Pazar yeri, piyasa.","definition":"An open space where a market is or was formerly held; the arena of commercial dealings.","examples":["Farmers sell their produce at the local marketplace.","Companies must adapt to the changing global marketplace."]},{"word":"martial","level":"B2","type":"adj.","turkish":"Savaş(la ilgili), askeri.","definition":"Relating to fighting or war; relating to the armed forces.","examples":["Martial arts originated in East Asia.","The country was placed under martial law during the crisis."]},{"word":"mask","level":"C1","type":"n.","turkish":"Maske.","definition":"A covering for all or part of the face, worn as a disguise, or to amuse or frighten others, or for protection.","examples":["Surgeons wear surgical masks during operations.","He wore a mask to the costume party."]},{"word":"massacre","level":"C1","type":"n.","turkish":"Katliam, kırım.","definition":"An indiscriminate and brutal slaughter of people.","examples":["The event is remembered as a tragic massacre.","Reports of the massacre shocked the world. mate (n., v."]},{"word":"mathematical","level":"C1","type":"adj.","turkish":"Matematiksel.","definition":"Relating to mathematics.","examples":["The problem requires complex mathematical calculations.","He has strong mathematical abilities."]},{"word":"mature","level":"C1","type":"adj.","turkish":"(adj) Olgun, yetişkin; (v) Olgunlaşmak, yetişkinleşmek; (yatırım vb.) vadesi dolmak.","definition":"(adj) Fully developed physically; full-grown; having reached the most advanced stage in a process. (v) Become fully developed; (of an insurance policy, security, etc.) become due for payment.","examples":["She seems very mature for her age. (adjective) The investment will mature in five years. (verb) Wine needs time to mature. (verb) maximize (v.","C1) ( İngiliz İngilizcesi: maximise) Türkçe Anlamı: Enüst düzeyeçıkarmak, maksimize etmek."]},{"word":"meaningful","level":"C1","type":"adj.","turkish":"Anlamlı, manalı,önemli.","definition":"Having meaning; having a serious, important, or useful quality or purpose.","examples":["They had a meaningful conversation about their future.","Volunteering can be a truly meaningful experience. meantime (n."]},{"word":"mechanic","level":"B2","type":"n.","turkish":"Tamirci, makinist (özellikle araba tamircisi).","definition":"A skilled worker who repairs and maintains machinery.","examples":["I need to take my car to the mechanic.","The aircraft mechanics checked the engines."]},{"word":"mechanical","level":"B2","type":"adj.","turkish":"Mekanik; makineyle ilgili; (hareket, davranış) otomatik, düşünmeden yapılan.","definition":"Relating to or operated by machinery; (of a person or action) done without thought or feeling; automatic.","examples":["The device has several moving mechanical parts.","His apology sounded mechanical and insincere."]},{"word":"mechanism","level":"B2","type":"n.","turkish":"Mekanizma, düzenek; işleyiş biçimi, sistem.","definition":"A system of parts working together in a machine; a piece of machinery; a natural or established process by which something takes place or is brought about.","examples":["The locking mechanism is broken.","Scientists are studying the mechanisms of memory."]},{"word":"medal","level":"B2","type":"n.","turkish":"Madalya.","definition":"A metal disc with an inscription or design, made to commemorate an event or awarded as a distinction to someone such as a soldier, athlete, or scholar.","examples":["She won a gold medal at the Olympics.","He was awarded a medal for bravery."]},{"word":"medication","level":"B2","type":"n.","turkish":"İlaç, ilaç tedavisi.","definition":"A drug or other form of medicine that is used to treat or prevent disease.","examples":["Are you currently taking any medication?","The doctor prescribed medication for her high blood pressure. medieval (adj."]},{"word":"meditation","level":"C1","type":"n.","turkish":"Meditasyon, derin düşünme.","definition":"The practice of thinking deeply or focusing one's mind for a period of time, in silence or with the aid of chanting, for religious or spiritual purposes or as a method of relaxation.","examples":["Meditation can help reduce stress and improve focus.","She practices yoga and meditation every morning."]},{"word":"melody","level":"C1","type":"n.","turkish":"Melodi, ezgi.","definition":"A sequence of single notes that is musically satisfying; a tune.","examples":["It's a simple song with a catchy melody.","He could play almost any melody by ear."]},{"word":"membership","level":"B2","type":"n.","turkish":"Üyelik.","definition":"The fact of being a member of a group; the number or body of members in a group.","examples":["You need to renew your gym membership annually.","Membership of the club is open to everyone. memo (n."]},{"word":"memorable","level":"B2","type":"adj.","turkish":"Unutulmaz, hatırlanmaya değer.","definition":"Worth remembering or easily remembered, especially because of being special or unusual.","examples":["Our trip to Italy was a truly memorable experience.","It was a memorable occasion for everyone involved."]},{"word":"memorial","level":"C1","type":"n.","turkish":"Anıt, abide; anma töreni.","definition":"Something, especially a structure, established to remind people of a person or event; an object kept or displayed in memory of a person or event.","examples":["They built a memorial to honour the soldiers who died in the war.","A memorial service was held for the victims of the disaster."]},{"word":"mentor","level":"C1","type":"n.","turkish":"Mentor, akıl hocası, danışman.","definition":"An experienced and trusted adviser.","examples":["She credits her success to her mentor at the company.","Finding a good mentor can be invaluable for career development."]},{"word":"merchant","level":"C1","type":"n.","turkish":"Tüccar, bezirgan.","definition":"A person or company involved in wholesale trade, especially one dealing with foreign countries or supplying goods to a particular trade.","examples":["Venetian merchants dominated trade routes in the Middle Ages.","He worked as a wine merchant."]},{"word":"mercy","level":"C1","type":"n.","turkish":"Merhamet, acıma, insaf;şans, lütuf ('at the mercy of').","definition":"Compassion or forgiveness shown toward someone whom it is within one's power to punish or harm; (at the mercy of) completely in the power or under the control of.","examples":["The prisoner begged for mercy.","They were lost at sea, at the mercy of the wind and waves."]},{"word":"mere","level":"C1","type":"adj.","turkish":"Sadece, sırf, -den ibaret.","definition":"Used to emphasize how small or insignificant someone or something is; that is solely or no more or better than what is specified.","examples":["It was a mere scratch, nothing serious.","She lost the election by a mere 20 votes."]},{"word":"merely","level":"C1","type":"adv.","turkish":"Sadece, yalnızca, sırf.","definition":"Just; only.","examples":["I wasn't criticizing him; I merely made an observation.","This is not merely a suggestion, it's an order."]},{"word":"merge","level":"C1","type":"v.","turkish":"Birleşmek, birleştirmek (şirket, yol vb.); kaynaşmak.","definition":"To combine or cause to combine to form a single entity.","examples":["The two companies decided to merge to form a larger corporation.","Traffic should merge carefully onto the motorway."]},{"word":"merger","level":"C1","type":"n.","turkish":"Birleşme (şirket vb.).","definition":"A combination of two things, especially companies, into one.","examples":["The proposed merger is expected to create hundreds of jobs.","Shareholders voted to approve the merger."]},{"word":"merit","level":"C1","type":"n.","turkish":"Liyakat, değer, erdem, meziyet; hak etme.","definition":"The quality of being particularly good or worthy, especially so as to deserve praise or reward; excellence; worth.","examples":["The proposal has considerable merit.","Promotions should be based on merit, not favoritism."]},{"word":"metaphor","level":"B2","type":"n.","turkish":"Metafor, mecaz, eğretileme.","definition":"A figure of speech in which a word or phrase is applied to an object or action to which it is not literally applicable, without using 'like' or 'as'.","examples":["\"All the world's a stage\" is a famous metaphor.","He used the metaphor of a journey to describe the project."]},{"word":"methodology","level":"C1","type":"n.","turkish":"Metodoloji, yöntem bilimi, yöntemler sistemi.","definition":"A system of methods used in a particular area of study or activity.","examples":["The research methodology is described in the appendix.","They developed a new methodology for data analysis. midst (n."]},{"word":"migration","level":"C1","type":"n.","turkish":"Göç (insan, hayvan).","definition":"Seasonal movement of animals from one region to another; movement of people to a new area or country in order to find work or better living conditions.","examples":["The annual bird migration is a spectacular sight.","Economic factors often drive human migration."]},{"word":"militant","level":"C1","type":"n.","turkish":"(n) Militan, eylemci (savaşçı); (adj) Militan, savaşçı, kavgacı.","definition":"(n) A person who is combative and aggressive in support of a political or social cause, and typically favoring extreme, violent, or confrontational methods. (adj) Combative and aggressive in support of a political or social cause.","examples":["Militants attacked the military checkpoint. (noun) He held militant views on political reform. (adjective)"]},{"word":"militia","level":"C1","type":"n.","turkish":"Milis, sivil askeri güç.","definition":"A military force that is raised from the civil population to supplement a regular army in an emergency; a military force that engages in rebel or terrorist activities, typically in opposition to a regular army.","examples":["Local militia groups helped defend the town.","The government is trying to disarm illegal militias."]},{"word":"mill","level":"C1","type":"n.","turkish":"Değirmen (un, kahve vb.); fabrika (kağıt,çelik vb.).","definition":"A building equipped with machinery for grinding grain into flour; a factory fitted with machinery for a particular manufacturing process.","examples":["The old water mill is now a tourist attraction.","He worked at the local paper mill."]},{"word":"miner","level":"B2","type":"n.","turkish":"Madenci.","definition":"A person who works in a mine.","examples":["Coal miners work in dangerous conditions.","The town's economy depended on the local miners."]},{"word":"minimal","level":"C1","type":"adj.","turkish":"Minimal, asgari, en az,çok az.","definition":"Of a minimum amount, quantity, or degree; negligible.","examples":["The storm caused only minimal damage.","We need to keep costs to a minimal level. minimize (v."]},{"word":"mining","level":"C1","type":"n.","turkish":"Madencilik.","definition":"The process or industry of obtaining coal or other minerals from a mine.","examples":["Coal mining was once a major industry in this region.","Environmental concerns are often raised about mining operations."]},{"word":"ministry","level":"C1","type":"n.","turkish":"Bakanlık; rahiplik mesleği.","definition":"A government department headed by a minister of state; the work or vocation of a minister of religion.","examples":["He works for the Ministry of Education.","She felt called to the ministry. minute² (adj."]},{"word":"miracle","level":"C1","type":"n.","turkish":"Mucize.","definition":"An extraordinary and welcome event that is not explicable by natural or scientific laws and is therefore attributed to a divine agency; a remarkable event or development that brings very welcome consequences.","examples":["It's a miracle that anyone survived the crash.","The invention of antibiotics was a medical miracle."]},{"word":"miserable","level":"B2","type":"adj.","turkish":"Perişan, sefil,çok mutsuz; (hava)çok kötü, kasvetli;çok az (miktar).","definition":"(of a person) Wretchedly unhappy or uncomfortable; (of weather) causing discomfort; pitiably small or inadequate.","examples":["She felt miserable after failing the exam.","What miserable weather we're having!"]},{"word":"misery","level":"C1","type":"n.","turkish":"Sefalet, perişanlık, büyüküzüntü/acı.","definition":"A state or feeling of great distress or discomfort of mind or body.","examples":["The war brought death and misery to millions.","Put the poor animal out of its misery."]},{"word":"misleading","level":"C1","type":"adj.","turkish":"Yanıltıcı, aldatıcı.","definition":"Giving the wrong idea or impression.","examples":["The advertisement was deliberately misleading.","Some of the statistics can be misleading if not interpreted correctly."]},{"word":"missile","level":"C1","type":"n.","turkish":"Füze, mermi.","definition":"An object which is forcibly propelled at a target, either by hand or from a mechanical weapon; a weapon that is self-propelled or directed by remote control, carrying conventional or nuclear explosive.","examples":["Protesters threw bricks and other missiles at the police.","The country test-fired a long-range ballistic missile."]},{"word":"mob","level":"C1","type":"n.","turkish":"Kalabalık (genellikle kontrolsüz, öfkeli), ayaktakımı; (gayriresmi) mafya, organize suç örgütü.","definition":"A large crowd of people, especially one that is disorderly and intent on causing trouble or violence; (the mob) the Mafia or a similar criminal organization.","examples":["An angry mob gathered outside the courthouse.","He was rumored to have connections with the mob."]},{"word":"mobile","level":"C1","type":"adj.","turkish":"Hareketli, taşınabilir, seyyar.","definition":"Able to move or be moved freely or easily.","examples":["Mobile libraries bring books to rural communities.","Patients need to remain mobile after surgery if possible. (Note: 'Mobile phone' is very common, but the C1 adjective emphasizes 'movable' more generally)."]},{"word":"mobility","level":"C1","type":"n.","turkish":"Hareketlilik, hareket kabiliyeti; (sosyal) akışkanlık.","definition":"The ability to move or be moved freely and easily; the ability to move between different levels in society or employment.","examples":["The injury affected his mobility.","Education can increase social mobility. mobilize (v."]},{"word":"mode","level":"B2","type":"n.","turkish":"Tarz, usul,şekil, yöntem; (cihaz) mod, çalışmaşekli; (istatistik) mod.","definition":"A way or manner in which something occurs or is experienced, expressed, or done; a way of operating or using a system; the value that occurs most frequently in a given set of data.","examples":["Walking is his preferred mode of transport.","Please switch your phone to silent mode."]},{"word":"moderate","level":"C1","type":"adj.","turkish":"Ilımlı,ölçülü, orta derecede.","definition":"Average in amount, intensity, quality, or degree.","examples":["The hotel offers comfortable rooms at moderate prices.","He favors a moderate approach to political reform."]},{"word":"modest","level":"B2","type":"adj.","turkish":"Mütevazı, alçakgönüllü; gösterişsiz, sade; az,ölçülü (miktar vb.).","definition":"Unassuming or moderate in the estimation of one's abilities or achievements; (of an amount, rate, or level) relatively moderate, limited, or small; not large, elaborate, or expensive.","examples":["Despite her success, she remains surprisingly modest.","They live in a modest house in the suburbs."]},{"word":"modification","level":"C1","type":"n.","turkish":"Değişiklik yapma, değiştirme; değişiklik.","definition":"The action of modifying something; a change made.","examples":["Several modifications were made to the original design.","The plan requires significant modification."]},{"word":"module","level":"C1","type":"n.","turkish":"Modül, birim (eğitim, yazılım, mobilya vb.).","definition":"Each of a set of standardized parts or independent units that can be used to construct a more complex structure, such as an item of furniture or a building; each of several sections of a course of study.","examples":["The course consists of ten core modules.","This software module handles user authentication."]},{"word":"momentum","level":"C1","type":"n.","turkish":"Momentum, hız, ivme (fiziksel veya mecazi).","definition":"The quantity of motion of a moving body, measured as a product of its mass and velocity; the impetus and driving force gained by the development of a process or course of events.","examples":["The campaign gained momentum in the weeks leading up to the election.","The team lost momentum in the second half of the game."]},{"word":"monk","level":"C1","type":"n.","turkish":"Keşiş, rahip (erkek).","definition":"A member of a religious community of men typically living under vows of poverty, chastity, and obedience.","examples":["Buddhist monks often wear saffron robes.","He lived as a monk in a monastery for many years."]},{"word":"monopoly","level":"C1","type":"n.","turkish":"Tekel, inhisar.","definition":"The exclusive possession or control of the supply of or trade in a commodity or service.","examples":["The company has a virtual monopoly in the software market.","Governments often regulate monopolies to protect consumers."]},{"word":"monster","level":"B2","type":"n.","turkish":"Canavar; (mecazi) devasaşey.","definition":"An imaginary creature that is typically large, ugly, and frightening; an inhumanly cruel or wicked person; a very large example of something.","examples":["Children are sometimes afraid of monsters under the bed.","That truck is an absolute monster!"]},{"word":"monthly","level":"B2","type":"adj.","turkish":"Aylık.","definition":"Done, produced, or occurring once a month.","examples":["We pay the rent on a monthly basis.","The magazine publishes monthly reports."]},{"word":"monument","level":"B2","type":"n.","turkish":"Anıt, abide.","definition":"A statue, building, or other structure erected to commemorate a famous or notable person or event.","examples":["The Lincoln Memorial is a famous monument in Washington D.C.","They visited historical monuments during their trip."]},{"word":"morality","level":"C1","type":"n.","turkish":"Ahlak, ahlaki değerler.","definition":"Principles concerning the distinction between right and wrong or good and bad behavior.","examples":["Different cultures may have different standards of morality.","The debate raised questions about the morality of using animal testing. moreover (adv."]},{"word":"mortgage","level":"B2","type":"n.","turkish":"İpotek, konut kredisi.","definition":"A legal agreement by which a bank or other creditor lends money at interest in exchange for taking title of the debtor's property, with the condition that the conveyance of title becomes void upon the payment of the debt.","examples":["They took out a large mortgage to buy their house.","It will take them 25 years to pay off the mortgage."]},{"word":"mosque","level":"B2","type":"n.","turkish":"Cami.","definition":"A Muslim place of worship.","examples":["The Blue Mosque in Istanbul is famous for its beautiful tiles.","Muslims gather at the mosque for prayer. mosquito (n."]},{"word":"motion","level":"B2","type":"n.","turkish":"Hareket;önerge, teklif (toplantı, mahkeme).","definition":"The action or process of moving or being moved; a formal proposal put to a legislature or committee, to be voted on.","examples":["The slow motion of the clouds was mesmerizing.","The lawyer filed a motion to dismiss the case."]},{"word":"motivate","level":"B2","type":"v.","turkish":"Motive etmek, teşvik etmek, isteklendirmek.","definition":"To provide (someone) with a motive for doing something; stimulate (someone's) interest in or enthusiasm for doing something.","examples":["What motivates people to work hard?","The coach's speech motivated the team to play better."]},{"word":"motivation","level":"B2","type":"n.","turkish":"Motivasyon, güdü, istek.","definition":"The reason or reasons one has for acting or behaving in a particular way; the general desire or willingness of someone to do something.","examples":["Money was his main motivation for taking the job.","She seems to lack the motivation to study."]},{"word":"motive","level":"C1","type":"n.","turkish":"Neden, sebep, güdü, kasıt (bir eylem için).","definition":"A reason for doing something, especially one that is hidden or not obvious.","examples":["Police are trying to establish the motive for the crime.","Profit was the primary motive behind the decision."]},{"word":"moving","level":"B2","type":"adj.","turkish":"Dokunaklı, duygulandırıcı, etkileyici; hareketli.","definition":"Producing strong emotions, especially sadness or sympathy; involving movement.","examples":["It was a deeply moving film about loss and resilience. (emotional) Keep clear of the moving parts of the machinery. (in motion)"]},{"word":"municipal","level":"C1","type":"adj.","turkish":"Belediye(ye ait), kentsel.","definition":"Relating to a city or town or its governing body.","examples":["Municipal elections will be held next year.","The municipal council approved the new budget."]},{"word":"mutual","level":"C1","type":"adj.","turkish":"Karşılıklı, ortak, müşterek.","definition":"(of a feeling or action) Experienced or done by each of two or more parties toward the other or others; held in common by two or more parties.","examples":["The decision was based on mutual agreement.","Their relationship was built on mutual respect and trust."]},{"word":"myth","level":"B2","type":"n.","turkish":"Mit, efsane; asılsız inanış, hurafe.","definition":"A traditional story concerning the early history of a people or explaining some natural or social phenomenon, and typically involving supernatural beings or events; a widely held but false belief or idea.","examples":["Greek myths tell stories of gods and heroes.","It's a popular myth that cracking your knuckles causes arthritis."]},{"word":"naked","level":"B2","type":"adj.","turkish":"Çıplak, yalın; (göz)çıplak gözle görünen; (gerçek) apaçık.","definition":"(of a person or part of the body) Unclothed; without coverings; (of the eye or vision) unassisted by an optical instrument; expressed openly; undisguised.","examples":["The children ran around naked on the beach.","The bacteria are too small to be seen with the naked eye."]},{"word":"namely","level":"C1","type":"adv.","turkish":"Yani,şöyle ki, başka bir deyişle (açıklama yaparken).","definition":"That is to say; to be specific (used to introduce detailed information or examples).","examples":["Only one student passed the exam, namely John.","There are three main factors involved, namely cost, quality, and time."]},{"word":"nasty","level":"B2","type":"adj.","turkish":"Pis, kötü, iğrenç; (davranış) kaba, çirkin; (hava, durum) fena.","definition":"Very bad or unpleasant; (of a person or animal) behaving in an unpleasant or spiteful way.","examples":["There's a nasty smell coming from the kitchen.","Don't be so nasty to your little brother."]},{"word":"nationwide","level":"C1","type":"adj.","turkish":"Ülkeçapında, yurt geneli.","definition":"Extending or reaching throughout a whole nation.","examples":["The company launched a nationwide advertising campaign.","There will be a nationwide strike next Tuesday."]},{"word":"naval","level":"C1","type":"adj.","turkish":"Deniz kuvvetleri(ne ait), donanma(ya ait).","definition":"Relating to a nation's navy.","examples":["He served as a naval officer for twenty years.","The museum has exhibits on naval history."]},{"word":"navigation","level":"B2","type":"n.","turkish":"Navigasyon, seyir, yol bulma; (web sitesinde) gezinme.","definition":"The process or activity of accurately ascertaining one's position and planning and following a route; the movement of ships or aircraft; the process of navigating a website.","examples":["Sailors used the stars for navigation.","The website has clear navigation menus."]},{"word":"nearby","level":"B2","type":"adj.","turkish":"(adj) Yakındaki, civardaki; (adv) Yakında, yakınlarda.","definition":"(adj) Not far away; close. (adv) Not far away; close at hand.","examples":["We went for a walk in a nearby park. (adjective) Is there a post office nearby? (adverb)"]},{"word":"necessity","level":"B2","type":"n.","turkish":"Gereklilik, zorunluluk; ihtiyaç, zaruri şey.","definition":"The fact of being required or indispensable; an indispensable thing.","examples":["Water is a basic necessity of life.","There is no necessity to shout."]},{"word":"neglect","level":"C1","type":"v.","turkish":"(v) İhmal etmek, savsaklamak, boşlamak; (n) İhmal, savsaklama.","definition":"(v) Fail to care for properly; not pay proper attention to; disregard. (n) The state of being uncared for; failure to give proper attention to something.","examples":["He neglected his duties and was fired. (verb) The old house suffered from years of neglect. (noun)"]},{"word":"negotiate","level":"B2","type":"v.","turkish":"Müzakere etmek, görüşmek, pazarlık etmek; (engeli) aşmak.","definition":"To obtain or bring about by discussion; try to reach an agreement or compromise by discussion with others; find a way over or through (an obstacle or difficult path).","examples":["The unions are negotiating a new contract with the employers.","It was difficult to negotiate the crowded streets."]},{"word":"negotiation","level":"B2","type":"n.","turkish":"Müzakere, görüşme, pazarlık.","definition":"Discussion aimed at reaching an agreement.","examples":["Contract negotiations are scheduled to resume next week.","After lengthy negotiations, they finally reached a deal. neighboring (adj."]},{"word":"nest","level":"C1","type":"n.","turkish":"Yuva (kuş, böcek vb.); (mecazi) sıcak yuva, sığınak.","definition":"A structure or place made or chosen by a bird for laying eggs and sheltering its young; a place where insects, spiders, fish, turtles, or rabbits breed or live; a comfortable or secluded retreat.","examples":["We watched the birds building their nest.","The house became an empty nest when the children left home. net (adj."]},{"word":"neutral","level":"B2","type":"adj.","turkish":"Tarafsız, yansız; nötr (renk, kimya vb.).","definition":"Not helping or supporting either side in a conflict, disagreement, etc.; impartial; having no strongly marked or positive characteristics or features.","examples":["Switzerland remained neutral during World War II.","She chose neutral colors like beige and grey for the living room."]},{"word":"newly","level":"B2","type":"adv.","turkish":"Yeni, son zamanlarda, kısa süreönce.","definition":"Recently; lately.","examples":["They are a newly married couple.","The newly appointed manager introduced herself."]},{"word":"newsletter","level":"C1","type":"n.","turkish":"Bülten, haber mektubu.","definition":"A bulletin issued periodically to the members of a society, business, or organization.","examples":["Sign up to receive our monthly email newsletter.","The club newsletter keeps members informed about upcoming events."]},{"word":"niche","level":"C1","type":"n.","turkish":"Niş, (pazarda)özel bir alan/konum; (duvarda) oyuk; (ekoloji) ekolojik niş.","definition":"A specialized segment of the market for a particular kind of product or service; a comfortable or suitable position in life or employment; a shallow recess, especially one in a wall to display a statue or other ornament.","examples":["The company found a profitable niche in the organic food market.","He finally found his niche working as a wildlife photographer."]},{"word":"nickel","level":"B2","type":"n.","turkish":"Nikel (metal); beş sentlik madeni para (ABD).","definition":"A silvery-white metallic element; a five-cent coin used in the US and Canada.","examples":["Stainless steel often contains chromium and nickel. (metal) Can you give me change for a quarter?","I need two dimes and a nickel. (coin)"]},{"word":"noble","level":"C1","type":"adj.","turkish":"Soylu, asil; yüce, onurlu.","definition":"Belonging to a hereditary class with high social or political status; aristocratic; having or showing fine personal qualities or high moral principles and ideals.","examples":["He came from a noble family.","Helping others is a noble cause."]},{"word":"nod","level":"C1","type":"v.","turkish":"Kafa sallamak (onaylamak/selamlamak için); (uyuklarken) başıöne düşmek.","definition":"To lower and raise one's head slightly and briefly, especially in greeting, assent, or understanding, or to give someone a signal; let one's head fall forward when drowsy or asleep.","examples":["She nodded in agreement.","He nodded off during the boring lecture."]},{"word":"nominate","level":"C1","type":"v.","turkish":"Aday göstermek (ödül, görev vb.).","definition":"To propose or formally enter as a candidate for election or for an honor or award.","examples":["She was nominated for the Best Actress award.","The committee will nominate candidates for the position."]},{"word":"nomination","level":"C1","type":"n.","turkish":"Aday gösterme, adaylık.","definition":"The action of nominating or state of being nominated.","examples":["Her nomination for the award was well -deserved.","The party announced its nominations for the election."]},{"word":"nominee","level":"C1","type":"n.","turkish":"Aday (gösterilen).","definition":"A person who is proposed or formally entered as a candidate for an office or as the recipient of a grant or award.","examples":["The Oscar nominees were announced yesterday.","He was the party's presidential nominee. nonetheless (adv."]},{"word":"nonsense","level":"C1","type":"n.","turkish":"Saçmalık, anlamsızşey/söz.","definition":"Spoken or written words that have no meaning or make no sense; foolish or unacceptable behavior.","examples":["Stop talking nonsense and tell me what really happened.","Most of the rumors turned out to be complete nonsense."]},{"word":"noon","level":"C1","type":"n.","turkish":"Öğle vakti (tam 12:00).","definition":"Twelve o'clock in the day; midday.","examples":["The meeting is scheduled for 12 noon.","We stopped for lunch around noon."]},{"word":"norm","level":"B2","type":"n.","turkish":"Norm, kural, standart, alışılagelmiş durum.","definition":"Something that is usual, typical, or standard.","examples":["Working from home has become the new norm for many people.","Social norms vary from culture to culture."]},{"word":"notable","level":"C1","type":"adj.","turkish":"Dikkate değer,önemli, tanınmış.","definition":"Worthy of attention or notice; remarkable.","examples":["The town is notable for its beautiful architecture.","Several notable figures attended the event."]},{"word":"notably","level":"C1","type":"adv.","turkish":"Özellikle, bilhassa, dikkate değer bir şekilde.","definition":"Especially; in particular; in a way that is worthy of attention or notice.","examples":["Several factors contributed to the success, notably the strong leadership.","The weather was bad all week, but notably worse on Tuesday."]},{"word":"notebook","level":"B2","type":"n.","turkish":"Not defteri; dizüstü bilgisayar (laptop).","definition":"A small book with blank or ruled pages for writing notes in; a portable computer typically having a screen that closes down onto the keyboard.","examples":["He jotted down some ideas in his notebook. (paper) She bought a new notebook for work. (computer)"]},{"word":"notify","level":"C1","type":"v.","turkish":"Bildirmek, haber vermek, haberdar etmek (resmi olarak).","definition":"To inform (someone) of something, typically in a formal or official way.","examples":["Please notify us of any change of address.","Applicants will be notified of the decision by email."]},{"word":"notorious","level":"C1","type":"adj.","turkish":"Kötüşöhretli, adıçıkmış.","definition":"Famous for something bad.","examples":["He was a notorious criminal in the city.","The area is notorious for its high crime rate. novel (adj."]},{"word":"novelist","level":"B2","type":"n.","turkish":"Romancı, roman yazarı.","definition":"A writer of novels.","examples":["Jane Austen is a famous English novelist.","The young novelist published her first book last year."]},{"word":"nowadays","level":"B2","type":"adv.","turkish":"Bugünlerde, günümüzde.","definition":"At the present time, in contrast with the past.","examples":["Nowadays, most people communicate via email or messaging apps.","Life seems much faster nowadays."]},{"word":"nursery","level":"C1","type":"n.","turkish":"Kreş,çocuk yuvası; fidanlık (bitki).","definition":"A room in a house for the special use of young children; a place where young children are cared for during the working day; a place where young plants and trees are grown for sale or for planting elsewhere.","examples":["She takes her son to the nursery while she works. (childcare) We bought some rose bushes at the local garden nursery. (plants)"]},{"word":"nursing","level":"B2","type":"adj.","turkish":"Hemşirelik(le ilgili); bakımevi(yle ilgili).","definition":"Relating to the profession or practice of a nurse; relating to a nursing home.","examples":["She works as nursing staff at the hospital.","Her grandmother lives in a nursing home."]},{"word":"nutrition","level":"B2","type":"n.","turkish":"Beslenme, gıda.","definition":"The process of providing or obtaining the food necessary for health and growth.","examples":["Good nutrition is essential for children's development.","The course covers topics related to health and nutrition."]},{"word":"obesity","level":"B2","type":"n.","turkish":"Obezite, aşırışişmanlık.","definition":"The state of being grossly fat or overweight.","examples":["Obesity is a growing health problem in many countries.","Diet and lack of exercise contribute to obesity."]},{"word":"objection","level":"C1","type":"n.","turkish":"İtiraz, karşıçıkma.","definition":"An expression or feeling of disapproval or opposition; a reason for disagreeing.","examples":["Does anyone have any objections to the proposal?","Her main objection was that the plan was too expensive."]},{"word":"oblige","level":"C1","type":"v.","turkish":"Zorunda bırakmak, mecbur etmek; (birine) iyilik etmek, memnun etmek.","definition":"To make (someone) legally or morally bound to an action or course of action; do as (someone) asks or desires in order to help or please them.","examples":["The law obliges drivers to have insurance.","Could you oblige me by closing the window?"]},{"word":"observer","level":"B2","type":"n.","turkish":"Gözlemci, gözlemleyen kişi.","definition":"A person who watches or notices something; a person who attends a meeting or discussion without taking part, in order to assess or report on it.","examples":["International observers monitored the election process.","He is a keen observer of human behavior."]},{"word":"obsess","level":"C1","type":"v.","turkish":"Takıntı haline getirmek, aklına takılmak, saplantılı olmak.","definition":"To preoccupy or fill the mind of (someone) continually, intrusively, and to a troubling extent. (Often used in passive: be obsessed with).","examples":["Don't obsess over small details.","He became obsessed with collecting rare stamps. (passive form common)"]},{"word":"obsession","level":"C1","type":"n.","turkish":"Takıntı, saplantı, sabit fikir.","definition":"The state of being obsessed with someone or something; an idea or thought that continually preoccupies or intrudes on a person's mind.","examples":["Her obsession with cleanliness drove everyone crazy.","He developed an unhealthy obsession with his work."]},{"word":"obstacle","level":"B2","type":"n.","turkish":"Engel, mani.","definition":"A thing that blocks one's way or prevents or hinders progress.","examples":["Lack of funding is a major obstacle to the project's success.","She overcame many obstacles to achieve her goals."]},{"word":"occasional","level":"C1","type":"adj.","turkish":"Ara sıra olan, zaman zaman olan.","definition":"Occurring, appearing, or done infrequently and irregularly.","examples":["We have occasional meetings, perhaps once a month.","Apart from the occasional headache, she felt fine."]},{"word":"occupation","level":"B2","type":"n.","turkish":"Meslek, iş; işgal (askeri).","definition":"A job or profession; the action, state, or period of occupying or being occupied by military force.","examples":["Please state your name, address, and occupation. (job) The country lived under foreign occupation for many years. (military)"]},{"word":"occupy","level":"B2","type":"v.","turkish":"İşgal etmek (yer, zaman, zihin); oturmak, ikamet etmek; (askeri) işgal etmek.","definition":"To reside or have one's place of business in (a building); fill or take up (a space or time); take control of (a place, especially a country) by military conquest or settlement.","examples":["The bathroom is currently occupied.","These thoughts occupy my mind constantly."]},{"word":"occurrence","level":"C1","type":"n.","turkish":"Olma, meydana gelme, vuku bulma; olay, hadise.","definition":"An incident or event; the fact or frequency of something happening.","examples":["Flooding is a common occurrence in this area during spring.","The police are investigating the strange occurrence. odds (n."]},{"word":"offender","level":"B2","type":"n.","turkish":"Suçlu, fail; (kural) ihlal eden kişi.","definition":"A person who commits an illegal act; a person or thing that does something wrong or causes problems.","examples":["Repeat offenders face harsher penalties.","The police are trying to catch the offender."]},{"word":"offering","level":"C1","type":"n.","turkish":"Sunma, arz etme; sunulanşey, teklif; adak.","definition":"A thing offered, especially as a gift or contribution; a product or service made available by a particular company; something offered as a religious sacrifice or token of devotion.","examples":["The company expanded its product offerings.","They made an offering at the temple. offspring (n."]},{"word":"ongoing","level":"B2","type":"adj.","turkish":"Devam eden, süregelen.","definition":"Continuing; still in progress.","examples":["There is an ongoing investigation into the incident.","Negotiations are still ongoing."]},{"word":"openly","level":"B2","type":"adv.","turkish":"Açıkça, alenen,çekinmeden.","definition":"Without concealment, secrecy, or prevarication; frankly or honestly.","examples":["She spoke openly about her experiences.","He is openly critical of the government's policies."]},{"word":"opera","level":"B2","type":"n.","turkish":"Opera.","definition":"A dramatic work in one or more acts, set to music for singers and instrumentalists.","examples":["We went to see an opera at Covent Garden.","Mozart composed several famous operas."]},{"word":"operational","level":"C1","type":"adj.","turkish":"Operasyonel, faal,çalışır durumda, kullanıma hazır.","definition":"Relating to the routine functioning or execution of an activity; in or ready for use.","examples":["The new system will become fully operational next week.","There were some operational difficulties during the launch."]},{"word":"operator","level":"B2","type":"n.","turkish":"Operatör (telefon, makine vb.).","definition":"A person who operates equipment or a machine; a person who works at the switchboard of a telephone exchange.","examples":["A trained machine operator is required for this job.","Please hold the line, I'll connect you to the operator."]},{"word":"opt","level":"C1","type":"v.","turkish":"Seçmek, tercih etmek (...için: 'opt for'; ...yapmayı: 'opt to').","definition":"To make a choice from a range of possibilities.","examples":["Instead of a big wedding, they opted for a quiet ceremony.","Many students opt to study abroad for a semester."]},{"word":"optical","level":"C1","type":"adj.","turkish":"Optik, görme(yle ilgili),ışık(la ilgili).","definition":"Relating to sight, especially in relation to the physical action of light.","examples":["Telescopes and microscopes are optical instruments.","An optical illusion can trick your eyes."]},{"word":"optimism","level":"C1","type":"n.","turkish":"İyimserlik.","definition":"Hopefulness and confidence about the future or the successful outcome of something.","examples":["Despite the challenges, she maintained her optimism.","There is cautious optimism about the economic recovery."]},{"word":"optimistic","level":"B2","type":"adj.","turkish":"İyimser.","definition":"Hopeful and confident about the future.","examples":["He is always optimistic, even when things go wrong.","She has an optimistic outlook on life."]},{"word":"oral","level":"C1","type":"adj.","turkish":"Sözlü; ağız(la ilgili).","definition":"Spoken rather than written; verbal; relating to the mouth.","examples":["The exam includes both written and oral components.","Good oral hygiene involves brushing and flossing regularly."]},{"word":"orchestra","level":"B2","type":"n.","turkish":"Orkestra.","definition":"A large group of instrumentalists playing together, typically including string, woodwind, brass, and percussion sections.","examples":["The symphony orchestra performed Beethoven's Fifth.","She plays the violin in the school orchestra."]},{"word":"organic","level":"B2","type":"adj.","turkish":"Organik (tarım, kimya vb.); yapısal, sistemsel.","definition":"Relating to or derived from living matter; (of food or farming methods) produced or involving production without the use of chemical fertilizers, pesticides, or other artificial agents; relating to or affecting body organs.","examples":["We try to buy organic fruits and vegetables whenever possible.","The disease caused organic damage to the brain. organizational (adj."]},{"word":"orientation","level":"C1","type":"n.","turkish":"Oryantasyon, yönlendirme, uyum sağlama; yönelim, eğilim; konumlandırma.","definition":"The determination of the relative position of something or someone; a person's basic attitude, beliefs, or feelings in relation to a particular subject or issue; introductory instruction concerning a new situation.","examples":["New employees attend an orientation session on their first day.","The building has a north -south orientation."]},{"word":"originate","level":"C1","type":"v.","turkish":"Kaynaklanmak, -dençıkmak, başlamak; yaratmak, başlatmak.","definition":"To have a specified beginning; create or initiate (something).","examples":["The tradition originated in the Middle Ages.","Many Chtistmas customs originated from pagan festivals."]},{"word":"outbreak","level":"C1","type":"n.","turkish":"Salgın (hastalık); patlak verme (şiddet, savaş vb.).","definition":"The sudden or violent start of something unwelcome, such as war, disease, etc.","examples":["Health officials are monitoring the flu outbreak.","The outbreak of war changed everything."]},{"word":"outfit","level":"B2","type":"n.","turkish":"Kıyafet, takım (giysi); ekipman.","definition":"A set of clothes worn together, typically for a particular occasion or purpose; a set of equipment needed for a particular activity.","examples":["She wore a stylish new outfit to the party.","You'll need a waterproof outfit for hiking in the rain."]},{"word":"outing","level":"C1","type":"n.","turkish":"Gezi, kısa seyahat (genellikle grup halinde).","definition":"A trip taken for pleasure, typically one lasting a day or less.","examples":["The school organized an outing to the museum.","We went on a family outing to the beach."]},{"word":"outlet","level":"C1","type":"n.","turkish":"Çıkış noktası,çıkış yeri; (duygusal) boşalma yolu; priz; indirimli satış mağazası (outlet mağaza).","definition":"A pipe or hole through which water or gas may escape; a point from which goods are sold or distributed; a way of expressing or releasing strong emotion, energy, etc.; an electrical socket.","examples":["Painting is a creative outlet for her stress.","We bought some discounted clothes at the factory outlet."]},{"word":"outlook","level":"C1","type":"n.","turkish":"Bakış açısı, görüş; beklenti, görünüm (gelecek için); manzara.","definition":"A person's point of view or general attitude to life; a view; the prospect for the future.","examples":["He has a positive outlook on life.","The economic outlook remains uncertain."]},{"word":"output","level":"B2","type":"n.","turkish":"Üretim,çıktı, verim;ürün.","definition":"The amount of something produced by a person, machine, or industry; the power, energy, or information produced by a system.","examples":["Factory output has increased by 10%.","The computer's output is displayed on the screen."]},{"word":"outrage","level":"C1","type":"n.","turkish":"(n) Öfke, kızgınlık, infial; rezalet, skandal; (v) Çok kızdırmak,öfkelendirmek.","definition":"(n) An extremely strong reaction of anger, shock, or indignation; an action or event causing such a reaction. (v) Arouse fierce anger, shock, or indignation in (someone).","examples":["The decision caused public outrage. (noun) She was outraged by the injustice of the situation. (verb - often passive)"]},{"word":"outsider","level":"C1","type":"n.","turkish":"Dışarıdan biri, yabancı (gruba ait olmayan).","definition":"A person who does not belong to a particular group.","examples":["As a newcomer, she felt like an outsider in the village.","Sometimes an outsider's perspective can be valuable."]},{"word":"outstanding","level":"B2","type":"adj.","turkish":"Olağanüstü, mükemmel, gözeçarpan; ödenmemiş, halledilmemiş (borç, sorun vb.).","definition":"Exceptionally good; clearly noticeable; (of payment, work, problems, etc.) not yet paid, done, or dealt with.","examples":["She gave an outstanding performance in the play. (excellent) There are still some outstanding issues to resolve. (not resolved) Please pay the outstanding balance as soon as possible. (not paid) overcome (v.","B2) (overcome, overcame, overcome) Türkçe Anlamı: Üstesinden gelmek, yenmek, aşmak (zorluk, duygu vb.)."]},{"word":"overlook","level":"C1","type":"v.","turkish":"Gözden kaçırmak, fark etmemek; görmezden gelmek, affetmek; (-e) bakmak, nazır olmak (manzara).","definition":"To fail to notice (something); ignore or disregard (something, especially a fault or offense); have or afford a view of from above.","examples":["I think you may have overlooked a crucial detail. (fail to notice) We decided to overlook his lateness this time. (ignore) Our hotel room overlooked the sea. (have a view)"]},{"word":"overly","level":"C1","type":"adv.","turkish":"Aşırı derecede, fazlasıyla.","definition":"Excessively.","examples":["Don't be overly critical of her work.","He wasn't overly enthusiastic about the idea."]},{"word":"overnight","level":"B2","type":"adv.","turkish":"Bir gecede, geceleyin; aniden.","definition":"For the duration of a night; happening in the course of a night; very quickly or suddenly.","examples":["Can I stay overnight at your place?","The situation changed overnight. oversee (v."]},{"word":"overturn","level":"C1","type":"v.","turkish":"Devirmek, devrilmek; (kararı vb.) bozmak, iptal etmek.","definition":"To tip (something) over so that it is on its side or upside down; abolish, invalidate, or reverse (a previous system, decision, situation, etc.).","examples":["The strong winds overturned several boats.","The appeal court overturned the original verdict."]},{"word":"overwhelm","level":"C1","type":"v.","turkish":"Bunal(t)mak, boğmak, alt etmek (duygu, iş yükü vb.); istila etmek.","definition":"To bury or drown beneath a huge mass; defeat completely; give too much of something to (someone); inundate.","examples":["She felt overwhelmed by the amount of work she had to do.","Do not let negative emotions overwhelm you."]},{"word":"overwhelming","level":"C1","type":"adj.","turkish":"Ezici, ağır basan, karşı konulmaz (çoğunluk, duygu vb.).","definition":"Very great in amount; (especially of an emotion) very strong.","examples":["There was overwhelming support for the proposal.","She felt an overwhelming sense of relief."]},{"word":"ownership","level":"B2","type":"n.","turkish":"Sahiplik, mülkiyet.","definition":"The act, state, or right of possessing something.","examples":["The documents prove his ownership of the land.","Home ownership is becoming increasingly difficult for young people."]},{"word":"oxygen","level":"B2","type":"n.","turkish":"Oksijen.","definition":"A chemical element with symbol O and atomic number 8, a colorless, odorless reactive gas, the chemical element of atomic number 8 and the life-supporting component of the air.","examples":["Plants release oxygen into the atmosphere.","The patient needed an oxygen mask to help him breathe."]},{"word":"packet","level":"B2","type":"n.","turkish":"Paket, ambalaj (küçük).","definition":"A small paper or cardboard container in which goods are packed for selling.","examples":["Could you get me a packet of biscuits?","The price is printed on the packet."]},{"word":"pad","level":"C1","type":"n.","turkish":"Ped, tampon, altlık (koruyucu/yumuşak); not defteri/bloğu; (parmak ucu) yastıkçık; (helikopter) pist","definition":"A thick piece of soft material, typically used to protect or shape something, or to absorb liquid; a number of sheets of blank paper fastened together at one edge, used for writing or drawing; the fleshy underpart of an animal's foot or of a human fi","examples":["Use protective knee pads when skateboarding. (soft material) She scribbled a note on a writing pad. (paper) The cat licked its paw pads. (animal foot)"]},{"word":"palm","level":"B2","type":"n.","turkish":"Avuç içi; palmiye ağacı.","definition":"The inner surface of the hand between the wrist and fingers; an unbranched evergreen tree of tropical and warm regions, with a crown of very large pinnate or fan -shaped leaves.","examples":["He held the small bird gently in the palm of his hand. (hand) Coconuts grow on palm trees. (tree)"]},{"word":"panic","level":"B2","type":"n.","turkish":"Panik, korku, telaş.","definition":"Sudden uncontrollable fear or anxiety, often causing wildly unthinking behavior.","examples":["There was mass panic when the fire alarm sounded.","Try to stay calm and don't panic. (Verb form often used)"]},{"word":"parade","level":"B2","type":"n.","turkish":"Geçit töreni, resmi geçit; (mecazi) gösteriş, sergileme.","definition":"A public procession, especially one celebrating a special day or event and including marching bands and floats; a succession of people or things.","examples":["We watched the military parade on Independence Day.","The fashion show featured a parade of stunning designs."]},{"word":"parallel","level":"B2","type":"adj.","turkish":"(adj) Paralel, koşut; benzer; (n) Paralel (çizgi, enlem); benzerlik, koşutluk.","definition":"(adj) (of lines, planes, surfaces, or objects) Side by side and having the same distance continuously between them; having comparable aspects. (n) Each of the imaginary parallel circles of constant latitude on the earth's surface; a person or thing t","examples":["Railway tracks run parallel to each other. (adjective) There are interesting parallels between the two novels. (noun) The road runs parallel with the river. (adjective)"]},{"word":"parameter","level":"C1","type":"n.","turkish":"Parametre, değişken; sınır,ölçüt.","definition":"A numerical or other measurable factor forming one of a set that defines a system or sets the conditions of its operation; a limit or boundary which defines the scope of a particular process or activity.","examples":["We need to define the key parameters of the study.","The investigation must stay within the parameters set by the committee."]},{"word":"parental","level":"C1","type":"adj.","turkish":"Ebeveyne ait, anne babayla ilgili.","definition":"Relating to or characteristic of a parent or parents.","examples":["Parental consent is required for minors to participate.","She received strong parental support throughout her education."]},{"word":"parliament","level":"C1","type":"n.","turkish":"Parlamento, meclis.","definition":"(in the UK and some other countries) The highest legislature, consisting of the sovereign, the House of Lords, and the House of Commons.","examples":["The new law was debated in Parliament.","Members of Parliament (MPs) are elected representatives."]},{"word":"partial","level":"C1","type":"adj.","turkish":"Kısmi, taraf tutan, taraflı; birşeye düşkün ('partial to').","definition":"Existing only in part; incomplete; favoring one side in a dispute above the other; biased; having a liking for.","examples":["The project was only a partial success.","The referee was accused of being partial to the home team."]},{"word":"partially","level":"C1","type":"adv.","turkish":"Kısmen.","definition":"Only in part; to a limited extent.","examples":["The road was partially blocked by a fallen tree.","He only partially understood the instructions."]},{"word":"participation","level":"B2","type":"n.","turkish":"Katılım, iştirak.","definition":"The action of taking part in something.","examples":["Class participation is encouraged.","We appreciate your active participation in the event."]},{"word":"partnership","level":"B2","type":"n.","turkish":"Ortaklık, işbirliği.","definition":"An association of two or more people as partners; the state of being a partner or partners.","examples":["They formed a business partnership last year.","The project is a partnership between the university and local industry."]},{"word":"part -time","level":"B2","type":"adj.","turkish":"Yarı zamanlı, kısmi süreli.","definition":"(adj) For only part of the usual working day or week. (adv) On a part -time basis.","examples":["She has a part-time job while studying. (adjective) He works part-time at the bookstore. (adverb)"]},{"word":"passing","level":"C1","type":"n.","turkish":"Geçme, geçiş; (zamanın) geçmesi; ölüm, vefat; (sınavdan) geçme.","definition":"The act or an instance of going past or across something; the passage or lapse of time; death; the achievement of the required standard in an examination or test.","examples":["The passing of time seems quicker as you get older.","We were saddened to hear of his passing. (death) Her passing grade in the exam was a relief."]},{"word":"passionate","level":"B2","type":"adj.","turkish":"Tutkulu, ihtiraslı, ateşli.","definition":"Showing or caused by strong feelings or strong belief.","examples":["He delivered a passionate speech about social justice.","She is passionate about environmental protection."]},{"word":"passive","level":"C1","type":"adj.","turkish":"Pasif, edilgen; etkisiz, eylemsiz.","definition":"Accepting or allowing what happens or what others do, without active response or resistance; (grammar) denoting a voice of verbs in which the subject undergoes the action of the verb (e.g. they were killed as opposed to he killed them).","examples":["He played a passive role in the discussion, preferring to listen. \"The ball was thrown\" is an example of the passive voice."]},{"word":"password","level":"B2","type":"n.","turkish":"Şifre, parola.","definition":"A secret word or phrase that must be used to gain admission to something.","examples":["Choose a strong password for your online accounts.","I forgot my password and couldn't log in."]},{"word":"pastor","level":"C1","type":"n.","turkish":"Papaz, pastör (bazı Protestan kiliselerinde).","definition":"A minister in charge of a Christian church or congregation, especially in some non episcopal churches.","examples":["The pastor delivered an inspiring sermon on Sunday.","They sought counseling from their church pastor."]},{"word":"patch","level":"B2","type":"n.","turkish":"Yama (kumaş, yol vb.); küçük arazi parçası, bölüm; (göz) bandı.","definition":"A piece of cloth or other material used to mend or strengthen a torn or weak point; a small piece of ground, especially one used for gardening; a pad or shield worn over an injured eye.","examples":["She sewed a patch onto the knee of his jeans.","We grew vegetables in a small patch of the garden."]},{"word":"patent","level":"C1","type":"n.","turkish":"Patent, buluş hakkı belgesi.","definition":"A government authority or license conferring a right or title for a set period, especially the sole right to exclude others from making, using, or selling an invention.","examples":["The company holds several patents for its technology.","He applied for a patent for his new invention."]},{"word":"pathway","level":"C1","type":"n.","turkish":"Patika, yol; (mecazi) izlenecek yol, yöntem.","definition":"A path or track; a way of achieving a specified result; a course of action.","examples":["Follow the pathway through the woods.","There are several different pathways to a career in medicine."]},{"word":"patience","level":"B2","type":"n.","turkish":"Sabır.","definition":"The capacity to accept or tolerate delay, trouble, or suffering without getting angry or upset.","examples":["Learning a new language requires time and patience.","He finally lost his patience and shouted."]},{"word":"patrol","level":"C1","type":"n.","turkish":"(n) Devriye; (v) Devriye gezmek.","definition":"(n) An expedition to keep watch over an area, especially by guards or police walking or driving around at intervals. (v) Keep watch over (an area) by regularly walking or traveling around it.","examples":["A police car on patrol stopped the speeding vehicle. (noun) Soldiers patrol the border region constantly. (verb)"]},{"word":"patron","level":"C1","type":"n.","turkish":"Müşteri (düzenli); hami, koruyucu, destekçi (sanatçı vb.).","definition":"A customer of a shop, restaurant, etc., especially a regular one; a person who gives financial or other support to a person, organization, cause, or activity.","examples":["The restaurant relies on its loyal patrons. (customer) He was a generous patron of the arts. (supporter)"]},{"word":"pause","level":"B2","type":"v.","turkish":"(v) Duraklamak, ara vermek; (n) Duraklama, ara, mola.","definition":"(v) Interrupt action or speech briefly. (n) A temporary stop in action or speech.","examples":["Let's pause for a moment and think about this. (verb) There was a long pause before she answered. (noun)"]},{"word":"peak","level":"C1","type":"n.","turkish":"Zirve, doruk (dağ, kariyer, seviye vb.).","definition":"The pointed top of a mountain; the point of highest activity, quality, or achievement.","examples":["We reached the peak of the mountain just before sunset.","Traffic reaches its peak during rush hour."]},{"word":"peasant","level":"C1","type":"n.","turkish":"Köylü (genellikle fakir, topraksız veya küçük toprak sahibi).","definition":"A poor smallholder or agricultural laborer of low social status (chiefly in historical use or referring to subsistence farming in poorer countries).","examples":["Peasants worked the land owned by the feudal lord.","The revolution was supported by the peasants."]},{"word":"peculiar","level":"C1","type":"adj.","turkish":"Tuhaf, garip, acayip;özgü, has.","definition":"Strange or odd; unusual; particular; special.","examples":["There was a peculiar smell in the room.","This type of bird has peculiar nesting habits."]},{"word":"peer","level":"B2","type":"n.","turkish":"Akran, yaşıt, mevkidaş.","definition":"A person of the same age, status, or ability as another specified person.","examples":["Children are often influenced by their peers.","He is highly respected by his peers in the scientific community."]},{"word":"penalty","level":"B2","type":"n.","turkish":"Ceza (kural ihlali, suç vb.); penaltı (spor).","definition":"A punishment imposed for breaking a law, rule, or contract; (in sport) a disadvantage or handicap imposed on a player or team, typically for infringement of the rules.","examples":["There is a financial penalty for late payment.","The referee awarded a penalty kick. pension¹ (n."]},{"word":"perceive","level":"B2","type":"v.","turkish":"Algılamak, sezmek, farkına varmak; ... olarak görmek/anlamak.","definition":"To become aware or conscious of (something); come to realize or understand; interpret or look on (someone or something) in a particular way.","examples":["I perceived a change in his attitude towards me.","How do you perceive the current situation?"]},{"word":"perception","level":"B2","type":"n.","turkish":"Algı, algılama, idrak; sezgi.","definition":"The ability to see, hear, or become aware of something through the senses; the way in which something is regarded, understood, or interpreted.","examples":["Our perception of reality is shaped by our experiences.","There is a public perception that crime is increasing."]},{"word":"permanently","level":"B2","type":"adv.","turkish":"Kalıcı olarak, sürekli, daimi.","definition":"In a way that lasts or remains unchanged indefinitely; forever.","examples":["The accident left him permanently disabled.","They decided to settle permanently in Australia."]},{"word":"persist","level":"C1","type":"v.","turkish":"Israr etmek, direnmek; sürüp gitmek, devam etmek.","definition":"To continue firmly or obstinately in an opinion or course of action in spite of difficulty, opposition, or failure; continue to exist; be prolonged.","examples":["If the symptoms persist, consult your doctor.","She persisted in asking difficult questions."]},{"word":"persistent","level":"C1","type":"adj.","turkish":"Israrcı, inatçı, direnen; sürekli, devamlı.","definition":"Continuing firmly or obstinately in a course of action in spite of difficulty or opposition; continuing to exist or occur over a prolonged period.","examples":["He is a persistent salesman who doesn't take no for an answer.","She suffered from a persistent cough. personnel (n."]},{"word":"petition","level":"C1","type":"n.","turkish":"Dilekçe, istirham; (hukuk) dava dilekçesi.","definition":"A formal written request, typically one signed by many people, appealing to authority with respect to a particular cause.","examples":["They presented a petition to the council demanding better public transport.","Thousands of people signed the online petition. pharmacy (n."]},{"word":"philosopher","level":"C1","type":"n.","turkish":"Filozof, felsefeci.","definition":"A person engaged or learned in philosophy, especially as an academic discipline.","examples":["Plato and Aristotle were ancient Greek philosophers.","The philosopher discussed the nature of existence."]},{"word":"philosophical","level":"C1","type":"adj.","turkish":"Felsefi; filozofça, bilgece, metanetli.","definition":"Relating or devoted to the study of the fundamental nature of knowledge, reality, and existence; having or showing a calm attitude toward disappointments or difficulties.","examples":["The book raises deep philosophical questions.","He tried to be philosophical about losing his job. physician (n."]},{"word":"pill","level":"B2","type":"n.","turkish":"Hap, tablet (ilaç); doğum kontrol hapı ('the pill').","definition":"A small round mass of solid medicine for swallowing whole; (the pill) a contraceptive pill.","examples":["Take one pill twice a day after meals.","She forgot to take her allergy pills."]},{"word":"pioneer","level":"C1","type":"n.","turkish":"(n) Öncü,çığır açan kimse; (v) Öncülük etmek,çığır açmak.","definition":"(n) A person who is among the first to explore or settle a new country or area; a person who is among the first to research and develop a new area of knowledge or activity. (v) Develop or be the first to use or apply (a new method, area of knowledge,","examples":["Marie Curie was a pioneer in the field of radioactivity. (noun) The company pioneered the use of sustainable materials. (verb)"]},{"word":"pipeline","level":"C1","type":"n.","turkish":"Boru hattı; (mecazi) geliştirme/hazırlık aşaması ('in the pipeline').","definition":"A long pipe, typically underground, for conveying oil, gas, etc., over long distances; a channel supplying goods or information; (in the pipeline) in the process of being planned or developed.","examples":["A new gas pipeline is being built across the region.","Several new projects are in the pipeline."]},{"word":"pirate","level":"C1","type":"n.","turkish":"Korsan (deniz); (mecazi) korsan (yayın vb.).","definition":"A person who attacks and robs ships at sea; a person who appropriates or reproduces the work of another for profit without permission.","examples":["Stories of treasure hidden by pirates are popular.","Software pirates illegally copy and sell programs."]},{"word":"pit","level":"C1","type":"n.","turkish":"Çukur, oyuk; maden ocağı; (meyve) çekirdek; (orkestra)çukuru; (yarış) pit alanı.","definition":"A large hole in the ground; a mine shaft or excavation; the stone of a fruit such as a cherry, plum, or peach; the area in front of and below the stage in a theater; an area at the side of a track where racing cars are serviced.","examples":["Be careful not to fall into the pit.","He worked down the coal pit for years."]},{"word":"pity","level":"B2","type":"n.","turkish":"Acıma, merhamet;üzücü/talihsiz durum ('a pity').","definition":"The feeling of sorrow and compassion caused by the suffering and misfortunes of others; (a pity) something that causes regret or disappointment.","examples":["She looked at the homeless man with pity.","It's a pity you can't come to the party."]},{"word":"placement","level":"B2","type":"n.","turkish":"Yerleştirme (iş, staj vb.); yerleştirilme; konumlandırma.","definition":"The action of finding someone a suitable job or place to live; a temporary position or job in an organization, often unpaid, taken by a student to get work experience; the action or process of placing someone or something somewhere.","examples":["The university helps students find work placements.","Careful placement of furniture can make a room feel larger."]},{"word":"plea","level":"C1","type":"n.","turkish":"Rica, yalvarma, istirham; (hukuk) savunma, iddia.","definition":"A request made in an urgent and emotional manner; (law) a formal statement by or on behalf of a defendant or prisoner, stating guilt or innocence in response to a charge.","examples":["He made a desperate plea for help.","The defendant entered a plea of not guilty."]},{"word":"plead","level":"C1","type":"v.","turkish":"Yalvarmak, rica etmek; (hukuk) savunma yapmak, iddia etmek.","definition":"To make an emotional appeal; (law) state formally in court whether one is guilty or not guilty of the offense with which one is charged.","examples":["She pleaded with him not to leave.","He decided to plead guilty to the charges."]},{"word":"pledge","level":"C1","type":"v.","turkish":"(v) Söz vermek, taahhüt etmek, vaat etmek; (n) Söz, taahhüt, vaat, rehin.","definition":"(v) Solemnly promise or undertake to do something. (n) A solemn promise or undertaking.","examples":["He pledged his support to the campaign. (verb) They made a pledge to donate money every month. (noun)"]},{"word":"plug","level":"C1","type":"v.","turkish":"(v) Tıkamak (delik vb.); (elektrikli cihazı) fişe takmak; (mecazi, gayriresmi) reklamını yapmak; (n)","definition":"(v) Block or fill in (a hole or cavity); connect (an electrical appliance) to an electricity supply by inserting a plug into a socket; (informal) mention (a product, event, or establishment) publicly in order to promote it. (n) A piece of solid mater","examples":["Plug the hole to stop the leak. (verb) Don't forget to plug in the TV. (verb) The author gave a brief plug for his new book during the interview. (noun) Put the plug in the sink before filling it. (noun)"]},{"word":"plunge","level":"C1","type":"v.","turkish":"Dalmak, hızla düşmek/atılmak; (değer, sıcaklık) aniden düşmek.","definition":"To jump or dive quickly and energetically; fall suddenly and uncontrollably; push or thrust quickly.","examples":["He plunged into the icy water.","Share prices plunged after the bad news."]},{"word":"pole","level":"C1","type":"n.","turkish":"Direk, sırık; kutup (Coğrafi/Manyetik Kuzey/Güney Kutbu).","definition":"A long, slender, rounded piece of wood or metal, typically used with one end placed in the ground as a support for something; either of the two locations (North Pole or South Pole) on the surface of the earth (or of a celestial object) which are the ","examples":["The flag was flying from a tall pole.","Explorers reached the South Pole in 1911."]},{"word":"poll","level":"C1","type":"n.","turkish":"Anket, kamuoyu yoklaması; seçim, oylama; (çoğul: polls) sandık, seçim yeri.","definition":"The process of voting in an election; the place where votes are cast in an election; a survey of public opinion.","examples":["According to a recent opinion poll, the ruling party is losing support.","Millions of people went to the polls to vote. (plural) A poll conducted last week showed mixed results."]},{"word":"pond","level":"C1","type":"n.","turkish":"Gölet, küçük havuz.","definition":"A small body of still water formed naturally or by hollowing or embanking.","examples":["Ducks were swimming in the village pond.","Frogs lay their eggs in ponds. pop (v."]},{"word":"portfolio","level":"C1","type":"n.","turkish":"Portföy (sanatçı, model vb. için iş örnekleri); portföy (yatırım); (bakanlık) görev alanı.","definition":"A large, thin, flat case for loose sheets of paper such as drawings or maps; a range of investments held by a person or organization; the range of products or services offered by a company; the position and duties of a minister or secretary of state.","examples":["The artist showed us her portfolio of drawings.","It's wise to have a diverse investment portfolio."]},{"word":"portion","level":"B2","type":"n.","turkish":"Porsiyon, kısım, pay, bölüm.","definition":"A part of a whole; an amount, share, or serving of something.","examples":["Divide the cake into equal portions.","A significant portion of the budget is allocated to education."]},{"word":"portray","level":"C1","type":"v.","turkish":"Tasvir etmek, betimlemek; (rol) canlandırmak.","definition":"To depict (someone or something) in a work of art or literature; represent or describe (someone or something) in a particular way; play the role of.","examples":["The painting portrays a scene from the French Revolution.","The actor portrayed the king with great dignity."]},{"word":"postpone","level":"C1","type":"v.","turkish":"Ertelemek.","definition":"To cause or arrange for (something) to take place at a time later than that first scheduled.","examples":["They decided to postpone the wedding until next year.","The meeting has been postponed due to bad weather."]},{"word":"postwar","level":"C1","type":"adj.","turkish":"Savaş sonrası.","definition":"Occurring or existing in the period after a war, especially the Second World War.","examples":["The country experienced rapid economic growth in the postwar era.","Postwar reconstruction took many years."]},{"word":"potentially","level":"B2","type":"adv.","turkish":"Potansiyel olarak, muhtemelen.","definition":"With the capacity to develop or happen in the future; possibly.","examples":["This is a potentially dangerous situation.","The new drug is potentially life-saving."]},{"word":"practitioner","level":"C1","type":"n.","turkish":"Pratisyen, uygulayıcı (özellikle tıp veya hukuk alanında).","definition":"A person actively engaged in an art, discipline, or profession, especially medicine or law.","examples":["She is a licensed medical practitioner.","Legal practitioners must adhere to a strict code of ethics."]},{"word":"preach","level":"C1","type":"v.","turkish":"Vaaz vermek; (mecazi)öğüt vermek, ahlak dersi vermek.","definition":"To deliver a sermon or religious address to an assembled group of people, typically in church; publicly proclaim or teach (a religious message or belief); earnestly advocate (a belief or course of action).","examples":["The vicar preached a sermon on forgiveness.","Stop preaching at me; I know what I did wrong."]},{"word":"precede","level":"B2","type":"v.","turkish":"-denönce gelmek, -inönünde gitmek.","definition":"To come before (something) in time; come before in order or position.","examples":["A warning message preceded the main announcement.","Lunch will be preceded by a short presentation."]},{"word":"precedent","level":"C1","type":"n.","turkish":"Emsal,örnek olay/karar,öncekiörnek.","definition":"An earlier event or action that is regarded as an example or guide to be considered in subsequent similar circumstances; (law) a previous case or legal decision that may be or must be followed in subsequent similar cases.","examples":["There is no precedent for such a decision.","The ruling set a precedent for future cases."]},{"word":"precious","level":"B2","type":"adj.","turkish":"Değerli, kıymetli; (mecazi) sevgili, canım.","definition":"Of great value; not to be wasted or treated carelessly; greatly loved or treasured by someone.","examples":["Gold and diamonds are precious metals and stones.","Time is precious, so don't waste it."]},{"word":"precise","level":"B2","type":"adj.","turkish":"Kesin, tam, doğru, hassas.","definition":"Marked by exactness and accuracy of expression or detail.","examples":["Can you give me a precise location?","We need precise measurements for this experiment."]},{"word":"precisely","level":"B2","type":"adv.","turkish":"Tam olarak, kesinlikle.","definition":"In exact terms; without vagueness; exactly.","examples":["The meeting starts at 2 PM precisely.","That's precisely what I meant."]},{"word":"precision","level":"C1","type":"n.","turkish":"Kesinlik, doğruluk, hassasiyet.","definition":"The quality, condition, or fact of being exact and accurate.","examples":["The work requires skill and precision.","Scientific instruments measure with great precision."]},{"word":"predator","level":"C1","type":"n.","turkish":"Yırtıcı hayvan, avcı; (mecazi) yırtıcı kimse, sömüren kimse.","definition":"An animal that naturally preys on others; a person or group that ruthlessly exploits others.","examples":["Lions are natural predators of zebras.","Financial predators often target vulnerable people."]},{"word":"predecessor","level":"C1","type":"n.","turkish":"Selef,önceki kişi/şey.","definition":"A person who held a job or office before the current holder; a thing that has been followed or replaced by another.","examples":["The new manager is very different from his predecessor.","This computer model is much faster than its predecessor."]},{"word":"predictable","level":"B2","type":"adj.","turkish":"Tahmin edilebilir, beklendik.","definition":"Able to be predicted; behaving or occurring in a way that is expected.","examples":["The ending of the film was completely predictable.","His reaction was entirely predictable."]},{"word":"predominantly","level":"C1","type":"adv.","turkish":"Ağırlıklı olarak,çoğunlukla, baskın bir şekilde.","definition":"Mainly; for the most part.","examples":["The audience was predominantly young people.","The workforce in this industry is predominantly male."]},{"word":"preference","level":"B2","type":"n.","turkish":"Tercih, yeğleme.","definition":"A greater liking for one alternative over another or others.","examples":["Do you have a color preference for the car?","Personal preference plays a large role in choosing a career."]},{"word":"pregnancy","level":"C1","type":"n.","turkish":"Hamilelik, gebelik.","definition":"The condition or period of being pregnant.","examples":["She announced her pregnancy to her family.","Nausea is common during early pregnancy."]},{"word":"prejudice","level":"C1","type":"n.","turkish":"Ön yargı, peşin hüküm.","definition":"Preconceived opinion that is not based on reason or actual experience; dislike, hostility, or unjust behavior deriving from preconceived and unfounded opinions.","examples":["We must challenge racial prejudice wherever we find it.","Her opinions are based on prejudice, not facts."]},{"word":"preliminary","level":"C1","type":"adj.","turkish":"Ön, hazırlık niteliğinde, başlangıç.","definition":"Preceding or done in preparation for something fuller or more important.","examples":["The preliminary results of the study are promising.","After some preliminary discussions, they decided to proceed."]},{"word":"premier","level":"C1","type":"n.","turkish":"Başbakan (bazıülkelerde/bölgelerde); önde gelen, birinci sınıf.","definition":"A prime minister or other head of government; first in importance, order, or rank; leading. (Can also be an adjective).","examples":["The premier of the province attended the meeting.","This is one of the premier research universities in the country."]},{"word":"premise","level":"C1","type":"n.","turkish":"Öncül (mantıkta); (çoğul: premises) bina ve arazisi, mülk.","definition":"A previous statement or proposition from which another is inferred or follows as a conclusion; (premises) a house or building, together with its land and outbuildings, occupied by a business or considered in an official context.","examples":["The argument is based on a false premise. (idea) Smoking is not allowed on the company premises. (building/land)"]},{"word":"premium","level":"C1","type":"n.","turkish":"Prim (sigorta vb.); ekücret, fazlalık; (adj gibi) birinci sınıf, yüksek kaliteli.","definition":"An amount to be paid for a contract of insurance; a sum added to an ordinary price or charge; something given as a reward, prize, or incentive; of exceptional quality or greater value than others of its kind.","examples":["How much is your monthly insurance premium? (insurance payment) Organic products often sell at a premium. (extra charge) They offer premium quality coffee beans. (high quality)"]},{"word":"prescribe","level":"C1","type":"v.","turkish":"Reçete yazmak (ilaç); (kural, görev vb.) buyurmak, emretmek.","definition":"(of a medical practitioner) Advise and authorize the use of (a medicine or treatment) for someone, especially in writing; state authoritatively or as a rule that (an action or procedure) should be carried out.","examples":["The doctor prescribed antibiotics for the infection.","The regulations prescribe the safety measures that must be taken."]},{"word":"prescription","level":"C1","type":"n.","turkish":"Reçete (ilaç); (mecazi) talimat, kural.","definition":"An instruction written by a medical practitioner that authorizes a patient to be provided a medicine or treatment; a recommendation.","examples":["You need a doctor's prescription to buy this medication.","There's no easy prescription for happiness."]},{"word":"presently","level":"C1","type":"adv.","turkish":"Şu anda,şimdi (özellikle Amerikan İngilizcesinde); birazdan, yakında (özellikle İngiliz İngilizcesin","definition":"At the present time; now (chiefly North American); soon; after a short time (chiefly British).","examples":["He is presently working on a new novel. (now - US usage) The manager will be with you presently. (soon - UK usage)"]},{"word":"preservation","level":"C1","type":"n.","turkish":"Koruma, muhafaza etme (tarihi eser, doğa vb.).","definition":"The action of preserving something; the state of being preserved, especially to a specified degree.","examples":["The preservation of ancient monuments is important for future generations.","Efforts are underway for the preservation of endangered species' habitats."]},{"word":"preside","level":"C1","type":"v.","turkish":"Başkanlık etmek, yönetmek (toplantı, tören vb.).","definition":"To be in the position of authority in a meeting or other gathering.","examples":["The judge will preside over the trial.","Who will preside at the next committee meeting?"]},{"word":"presidency","level":"C1","type":"n.","turkish":"Başkanlık (makamı, dönemi).","definition":"The office, function, or term of office of a president.","examples":["He announced his candidacy for the presidency.","During his presidency, the economy grew steadily."]},{"word":"presidential","level":"B2","type":"adj.","turkish":"Başkanlık(la ilgili).","definition":"Relating to a president or presidency.","examples":["A presidential election will be held next year.","The White House is the presidential residence."]},{"word":"prestigious","level":"C1","type":"adj.","turkish":"Prestijli, saygın, itibarlı.","definition":"Inspiring respect and admiration; having high status.","examples":["She won a prestigious award for her research.","He graduated from a prestigious university."]},{"word":"presumably","level":"C1","type":"adv.","turkish":"Muhtemelen, tahminen, galiba.","definition":"Used to say what you think is the likely situation, reason, or outcome.","examples":["Presumably, they have received the message by now.","He isn't here yet; presumably, he's stuck in traffic."]},{"word":"presume","level":"C1","type":"v.","turkish":"Varsaymak, farz etmek; cüret etmek, haddini aşmak.","definition":"To suppose that something is the case on the basis of probability; take for granted that something exists or is the case; be audacious enough to do something.","examples":["I presume you know why you are here.","Don't presume to tell me what to do."]},{"word":"prevail","level":"C1","type":"v.","turkish":"Hakim olmak, hüküm sürmek, yaygın olmak; galip gelmek,üstün gelmek.","definition":"To prove more powerful than opposing forces; be victorious; be widespread in a particular area at a particular time; be current.","examples":["Justice will ultimately prevail.","A sense of optimism prevailed despite the difficulties."]},{"word":"prevalence","level":"C1","type":"n.","turkish":"Yaygınlık, sıklık.","definition":"The fact or condition of being prevalent; commonness.","examples":["The prevalence of smoking has decreased in recent years.","The study investigated the prevalence of the disease in different populations."]},{"word":"prevention","level":"C1","type":"n.","turkish":"Önleme, engelleme, koruma.","definition":"The action of stopping something from happening or arising.","examples":["Disease prevention is better than cure.","The police focus on crime prevention. prey (n."]},{"word":"pride","level":"B2","type":"n.","turkish":"Gurur, iftihar; kibir, kendini beğenmişlik; (aslan) sürüsü.","definition":"A feeling of deep pleasure or satisfaction derived from one's own achievements, qualities, or possessions or those of someone with whom one is closely associated; consciousness of one's own dignity; excessive self -esteem; a group of lions forming a ","examples":["She takes great pride in her work.","His pride wouldn't allow him to ask for help."]},{"word":"primarily","level":"B2","type":"adv.","turkish":"Öncelikle, esasen, başlıca.","definition":"For the most part; mainly.","examples":["The course is primarily aimed at beginners.","He is known primarily for his novels."]},{"word":"principal","level":"B2","type":"adj.","turkish":"(adj) Başlıca, ana, temel, enönemli; (n) Okul müdürü; ana para (borç/yatırım).","definition":"(adj) Most important, consequential, or influential; main. (n) The person with the highest authority or most important position in an organization, institution, or group; the head of a school; a sum of money lent or invested, on which interest is pai","examples":["Lack of funding was the principal reason for the project's failure. (adjective) The school principal addressed the students. (noun - head of school) You only pay interest, not the principal, during the first year of the loan. (noun - money)"]},{"word":"prior","level":"B2","type":"adj.","turkish":"Önceki,öncelikli.","definition":"Existing or coming before in time, order, or importance.","examples":["Please cancel any prior arrangements you have made.","You need prior approval from the manager. privatization (n."]},{"word":"privilege","level":"C1","type":"n.","turkish":"Ayrıcalık, imtiyaz.","definition":"A special right, advantage, or immunity granted or available only to a particular person or group.","examples":["Access to clean water should be a right, not a privilege.","Education is a privilege that not everyone enjoys."]},{"word":"probability","level":"B2","type":"n.","turkish":"Olasılık, ihtimal.","definition":"The extent to which something is probable; the likelihood of something happening or being the case.","examples":["There is a high probability of success.","The probability of being struck by lightning is extremely low."]},{"word":"probable","level":"B2","type":"adj.","turkish":"Olası, muhtemel.","definition":"Likely to happen or be the case.","examples":["Rain is probable later today.","The probable cause of the fire was faulty wiring."]},{"word":"probe","level":"C1","type":"n.","turkish":"(n) Sonda (tıbbi, uzay vb.); soruşturma, araştırma; (v) Sonda ile yoklamak; araştırmak, soruşturmak,","definition":"(n) A blunt -ended surgical instrument used for exploring a wound or part of the body; a small spacecraft, containing scientific instruments, sent to explore outer space; an investigation into a crime or other matter. (v) Physically explore or examin","examples":["The doctor used a probe to examine the wound. (noun - tool) The committee launched a probe into the allegations. (noun - investigation) Detectives are probing the circumstances surrounding his death. (verb)"]},{"word":"problematic","level":"C1","type":"adj.","turkish":"Problemli, sorunlu,şüpheli.","definition":"Constituting or presenting a problem or difficulty; doubtful or questionable.","examples":["The relationship between the two countries remains problematic.","His interpretation of the data is highly problematic."]},{"word":"proceed","level":"B2","type":"v.","turkish":"Devam etmek, ilerlemek; (bir yöne) gitmek; (yasal) işlem başlatmak.","definition":"To begin or continue a course of action; move forward, especially after reaching a certain point; start a legal action against someone.","examples":["Please proceed with caution.","After the interruption, the speaker proceeded with her presentation."]},{"word":"processing","level":"C1","type":"n.","turkish":"İşleme, işlemden geçirme (veri, gıda vb.).","definition":"The action of performing a series of mechanical or chemical operations on (something) in order to change or preserve it; the manipulation of data by a computer.","examples":["Food processing can remove some nutrients.","Data processing is done by powerful computers."]},{"word":"processor","level":"C1","type":"n.","turkish":"İşlemci (bilgisayar); işleyici (gıda vb.).","definition":"A machine that processes something; a central processing unit (CPU).","examples":["This computer has a faster processor than my old one.","A food processor makes chopping vegetables much easier."]},{"word":"proclaim","level":"C1","type":"v.","turkish":"İlan etmek, duyurmak, bildirmek (resmen).","definition":"To announce officially or publicly.","examples":["The government proclaimed a state of emergency.","He proclaimed his love for her in front of everyone."]},{"word":"productive","level":"C1","type":"adj.","turkish":"Üretken, verimli.","definition":"Producing or able to produce large amounts of goods, crops, or other commodities; achieving or producing a significant amount or result.","examples":["We had a very productive meeting this morning.","Fertile land is essential for productive farming."]},{"word":"productivity","level":"C1","type":"n.","turkish":"Üretkenlik, verimlilik.","definition":"The state or quality of being productive; the effectiveness of productive effort, especially in industry, as measured in terms of the rate of output per unit of input.","examples":["The company is looking for ways to increase worker productivity.","Lack of sleep can negatively affect productivity."]},{"word":"profitable","level":"C1","type":"adj.","turkish":"Karlı, kazançlı; yararlı, faydalı.","definition":"(of a business or activity) Yielding profit or financial gain; beneficial; useful.","examples":["It was a highly profitable business venture.","Investing in education is always profitable in the long run."]},{"word":"profound","level":"C1","type":"adj.","turkish":"Derin (anlam, duygu, etki vb.); büyük, yoğun.","definition":"(of a state, quality, or emotion) Very great or intense; (of a person or statement) having or showing great knowledge or insight.","examples":["The book had a profound impact on my thinking.","She expressed profound sadness over the tragedy."]},{"word":"programming","level":"B2","type":"n.","turkish":"Programlama (bilgisayar); program yapımı (TV, radyo).","definition":"The process or activity of writing computer programs; the process of scheduling or providing programs for broadcast on radio or television.","examples":["He is learning computer programming.","The channel changed its evening programming schedule."]},{"word":"progressive","level":"B2","type":"adj.","turkish":"İlerici, gelişmeci; artan, giderek ilerleyen.","definition":"Happening or developing gradually or in stages; proceeding step by step; favoring or implementing social reform or new, liberal ideas.","examples":["The government implemented progressive tax policies.","The disease causes progressive muscle weakness."]},{"word":"prohibit","level":"B2","type":"v.","turkish":"Yasaklamak, men etmek.","definition":"To formally forbid (something) by law, rule, or other authority.","examples":["Smoking is strictly prohibited in this area.","The law prohibits discrimination based on race."]},{"word":"projection","level":"C1","type":"n.","turkish":"Projeksiyon, yansıtma; tahmin,öngörü (gelecekle ilgili);çıkıntı.","definition":"An estimate or forecast of a future situation or trend based on a study of present ones; the presentation of an image on a surface; something that extends outward from something else.","examples":["Sales projections for next year are optimistic.","The image projection on the screen was clear."]},{"word":"prominent","level":"C1","type":"adj.","turkish":"Öneçıkan, gözeçarpan, seçkin, önemli;çıkıntılı.","definition":"Important; famous; projecting from something; protuberant.","examples":["She played a prominent role in the negotiations.","The hotel occupies a prominent position on the seafront."]},{"word":"promising","level":"B2","type":"adj.","turkish":"Umut verici, gelecek vadeden.","definition":"Showing signs of future success.","examples":["He is a promising young athlete.","The initial results of the research look promising."]},{"word":"promotion","level":"B2","type":"n.","turkish":"Terfi, yükselme (işte); tanıtım, promosyon (ürün vb.).","definition":"Activity that supports or provides active encouragement for the furtherance of a cause, venture, or aim; the publicizing of a product, organization, or venture so as to increase sales or public awareness; advancement in rank or position.","examples":["Congratulations on your promotion to manager! (job advancement) The company launched a special promotion for the new product. (advertising)"]},{"word":"prompt","level":"B2","type":"v.","turkish":"Teşvik etmek, -e yol açmak, sebep olmak; (aktöre vb.) repliği hatırlatmak.","definition":"(of an event or fact) Cause or bring about (an action or feeling); assist or encourage (a hesitating speaker) to say something.","examples":["His comments prompted a heated debate.","What prompted you to make that decision? pronounced (adj."]},{"word":"propaganda","level":"C1","type":"n.","turkish":"Propaganda.","definition":"Information, especially of a biased or misleading nature, used to promote or publicize a particular political cause or point of view.","examples":["Wartime propaganda often demonizes the enemy.","Be critical of information that might be political propaganda."]},{"word":"proportion","level":"B2","type":"n.","turkish":"Oran, orantı; kısım, pay; boyutlar.","definition":"A part, share, or number considered in comparative relation to a whole; the relationship of one thing to another in terms of quantity, size, or number; relative size or extent.","examples":["A large proportion of the students live off-campus.","The room's proportions make it feel spacious."]},{"word":"proposition","level":"C1","type":"n.","turkish":"Önerme, teklif,öneri; (matematik) teorem.","definition":"A statement or assertion that expresses a judgment or opinion; a suggested scheme or plan of action, especially in a business context.","examples":["He made an attractive business proposition.","The central proposition of his theory is that..."]},{"word":"prosecute","level":"C1","type":"v.","turkish":"Dava açmak, (hukuken) takip etmek, kovuşturmak.","definition":"To institute legal proceedings against (a person or organization); continue (a course of action) with determination to its completion.","examples":["The state decided to prosecute him for theft.","Shoplifters will be prosecuted."]},{"word":"prosecution","level":"C1","type":"n.","turkish":"Kovuşturma, dava açma; iddia makamı, savcılık.","definition":"The institution and conducting of legal proceedings against someone in respect of a criminal charge; the party instituting or conducting legal proceedings against someone in a lawsuit.","examples":["The prosecution presented strong evidence against the defendant.","He faces prosecution for tax evasion."]},{"word":"prosecutor","level":"C1","type":"n.","turkish":"Savcı, iddia makamı temsilcisi.","definition":"A person, especially a public official, who institutes legal proceedings against someone.","examples":["The prosecutor cross-examined the witness.","She worked as a federal prosecutor."]},{"word":"prospective","level":"C1","type":"adj.","turkish":"Müstakbel, olası, potansiyel (müşteri, aday vb.).","definition":"Expected or expecting to be something particular in the future; likely to happen at a future date.","examples":["The company sent information packs to prospective students.","We met with several prospective buyers for our house."]},{"word":"prosperity","level":"C1","type":"n.","turkish":"Refah, zenginlik, bolluk.","definition":"The state of being prosperous (successful in material terms; flourishing financially).","examples":["The country enjoyed a period of peace and prosperity.","Economic policies aimed at increasing national prosperity."]},{"word":"protective","level":"C1","type":"adj.","turkish":"Koruyucu.","definition":"Intended to protect someone or something; having or showing a strong wish to protect someone from harm or injury.","examples":["Wear protective clothing when handling chemicals.","He felt very protective towards his younger sister."]},{"word":"protein","level":"B2","type":"n.","turkish":"Protein.","definition":"Any of a class of nitrogenous organic compounds that consist of large molecules composed of one or more long chains of amino acids and are an essential part of all living organisms, especially as structural components of body tissues such as muscle, ","examples":["Meat, eggs, and beans are good sources of protein.","Protein is essential for building muscle."]},{"word":"protester","level":"B2","type":"n.","turkish":"Protestocu, gösterici.","definition":"A person who publicly demonstrates strong objection to something; a demonstrator.","examples":["Police clashed with protesters during the demonstration.","Environmental protesters blocked the road."]},{"word":"protocol","level":"C1","type":"n.","turkish":"Protokol (resmi kurallar, diplomatik usuller, bilimsel/teknik kurallar).","definition":"The official procedure or system of rules governing affairs of state or diplomatic occasions; the accepted or established code of procedure or behavior in any group, organization, or situation; a set of rules governing the exchange or transmission of","examples":["Strict protocol must be observed during royal visits.","Follow the safety protocols carefully."]},{"word":"province","level":"C1","type":"n.","turkish":"İl, eyalet, vilayet; (mecazi) uzmanlık alanı.","definition":"A principal administrative division of certain countries or empires; (the provinces) the whole of a country outside the capital, especially when regarded as lacking sophistication or culture; an area of special knowledge, interest, or responsibility.","examples":["Quebec is the largest province in Canada.","That sort of decision is outside my province. (area of responsibility)"]},{"word":"provincial","level":"C1","type":"adj.","turkish":"İl(e ait), eyalet(le ilgili); taşra(ya ait), dar görüşlü.","definition":"Relating to or characteristic of a province; (derogatory) having or showing the manners, viewpoints, etc., considered characteristic of unsophisticated inhabitants of a province; rustic; narrow or illiberal.","examples":["She grew up in a small provincial town.","He found their attitudes rather provincial."]},{"word":"provision","level":"C1","type":"n.","turkish":"Sağlama, temin etme; (çoğul: provisions) erzak, tedarik; koşul, hüküm (anlaşma, yasa vb.).","definition":"The action of providing or supplying something for use; (provisions) supplies of food, drink, or equipment, especially for a journey; a condition or requirement in a legal document.","examples":["The government is responsible for the provision of healthcare. (supplying) We need to buy adequate provisions for the camping trip. (supplies) The contract includes a provision for early termination. (condition)"]},{"word":"provoke","level":"C1","type":"v.","turkish":"Kışkırtmak, -e neden olmak, -e yol açmak (öfke, tartışma vb.); uyandırmak (duygu).","definition":"To stimulate or give rise to (a reaction or emotion, typically a strong or unwelcome one) in someone; deliberately make (someone) annoyed or angry.","examples":["His comments provoked outrage among the audience.","Don't try to provoke an argument."]},{"word":"psychiatric","level":"C1","type":"adj.","turkish":"Psikiyatrik, ruh sağlığı ile ilgili.","definition":"Relating to mental illness or its treatment.","examples":["He was admitted to a psychiatric hospital.","The patient underwent a psychiatric evaluation."]},{"word":"psychological","level":"B2","type":"adj.","turkish":"Psikolojik, ruhsal.","definition":"Relating to, or arising from the mind or emotions.","examples":["Stress can have both physical and psychological effects.","The study explores the psychological impact of trauma."]},{"word":"publicity","level":"B2","type":"n.","turkish":"Tanıtım, reklam, kamuoyu ilgisi.","definition":"Notice or attention given to someone or something by the media.","examples":["The event generated a lot of positive publicity.","Celebrities sometimes hire agents to handle their publicity."]},{"word":"publishing","level":"B2","type":"n.","turkish":"Yayıncılık.","definition":"The occupation, business, or activity of preparing and issuing books, journals, and other material for sale.","examples":["She works in the publishing industry.","Digital technology has transformed the publishing world."]},{"word":"pulse","level":"C1","type":"n.","turkish":"Nabız, vuruş (kalp); (mecazi) eğilim, kamuoyu.","definition":"The regular throbbing of the arteries as blood is propelled through them, typically as felt in the wrists or neck; a single vibration or short burst of sound, electric current, light, or energy; the general feeling or opinion in a group or society.","examples":["The nurse checked the patient's pulse.","He could feel the steady pulse of the music."]},{"word":"pump","level":"C1","type":"v.","turkish":"(v) Pompalamak; (n) Pompa; (kadın ayakkabısı) babet.","definition":"(v) Force (liquid, gas, etc.) to move in a particular direction by means of a pump; move vigorously up and down. (n) A mechanical device using suction or pressure to raise or move liquids, compress gases, or force air into inflatable objects such as ","examples":["Your heart pumps blood around your body. (verb) We need a pump to inflate the tires. (noun) She wore elegant black pumps to the event. (noun - shoe)"]},{"word":"punch","level":"C1","type":"n.","turkish":"(n) Yumruk; zımba (delgeç); (içecek) punç; (mecazi) etki, güç; (v) Yumruklamak; (delgeçle) delmek.","definition":"(n) A blow with the fist; a tool or machine for impressing a design or stamping a mark on a surface or for piercing holes in paper, leather, metal, etc.; a drink made from wine or spirits mixed with fruit juice or water, spices, etc.; forcefulness or","examples":["He received a punch on the nose. (noun - blow) Use the hole punch to make holes in the paper. (noun - tool) She punched him playfully on the arm. (verb) The story lacked emotional punch. (noun - impact)"]},{"word":"punk","level":"B2","type":"n.","turkish":"Punk (müzik türü/altkültür); (argo) serseri, değersiz kimse.","definition":"A loud, fast -moving, and aggressive form of rock music, popular in the late 1970s; a young person who belongs to a subculture characterized by punk music, outrageous clothes, and shocking behavior; (informal, derogatory) a worthless person.","examples":["The Sex Pistols were a famous punk band.","He dressed like a punk with ripped jeans and safety pins."]},{"word":"purely","level":"B2","type":"adv.","turkish":"Sadece, tamamen, sırf.","definition":"Entirely; only; exclusively.","examples":["The decision was based purely on financial considerations.","My motive was purely selfish."]},{"word":"pursuit","level":"B2","type":"n.","turkish":"Takip, kovalama; uğraş, meşgale, hobi; peşinde koşma (amaç vb.).","definition":"The action of following or pursuing someone or something; an activity that you spend time doing, usually when you are not working; the action of trying to achieve something.","examples":["The police car was in hot pursuit of the stolen vehicle.","Reading and gardening are among her favorite pursuits."]},{"word":"puzzle","level":"B2","type":"n.","turkish":"Bulmaca, yapboz; kafa karıştıranşey, muamma.","definition":"A game, toy, or problem designed to test ingenuity or knowledge; something that is difficult to understand or explain.","examples":["Completing a jigsaw puzzle can be relaxing.","Her sudden disappearance remains a puzzle."]},{"word":"query","level":"C1","type":"n.","turkish":"Soru, sorgu, sorgulama.","definition":"A question, especially one addressed to an official or organization.","examples":["If you have any queries about your order, please contact customer service.","The database allows users to run complex queries."]},{"word":"quest","level":"C1","type":"n.","turkish":"Arayış, araştırma (uzun ve zorlu).","definition":"A long or arduous search for something.","examples":["The knights embarked on a quest for the Holy Grail.","Her lifelong quest was for knowledge and truth."]},{"word":"questionnaire","level":"B2","type":"n.","turkish":"Anket, soru kağıdı.","definition":"A set of printed or written questions with a choice of answers, devised for the purposes of a survey or statistical study.","examples":["Please fill out the questionnaire about your shopping habits.","The results of the questionnaire will be analyzed next week."]},{"word":"quota","level":"C1","type":"n.","turkish":"Kota, kontenjan, pay.","definition":"A fixed share of something that a person or group is entitled to receive or is bound to contribute; a limited quantity of a particular product which under official controls can be produced, exported, or imported.","examples":["The company has failed to meet its sales quota for the quarter.","There is a strict quota on immigration into the country."]},{"word":"racial","level":"B2","type":"adj.","turkish":"Irksal,ırkla ilgili.","definition":"Relating to race or differences between races.","examples":["Racial discrimination is unacceptable.","The city is known for its racial diversity."]},{"word":"racism","level":"B2","type":"n.","turkish":"Irkçılık.","definition":"Prejudice, discrimination, or antagonism directed against someone of a different race based on the belief that one's own race is superior.","examples":["We must fight against racism in all its forms.","The incident sparked protests against systemic racism."]},{"word":"racist","level":"B2","type":"adj.","turkish":"(adj) Irkçı; (n) Irkçı (kimse).","definition":"(adj) Showing or feeling discrimination or prejudice against people of other races, or believing that a particular race is superior to another. (n) A person who shows or feels discrimination or prejudice against people of other races.","examples":["He was fired for making racist comments. (adjective) There is no place for racists in our society. (noun)"]},{"word":"radar","level":"C1","type":"n.","turkish":"Radar.","definition":"A system for detecting the presence, direction, distance, and speed of aircraft, ships, and other objects, by sending out pulses of high-frequency electromagnetic waves that are reflected off the object back to the source.","examples":["Air traffic controllers use radar to monitor planes.","The ship disappeared from the radar screen."]},{"word":"radiation","level":"B2","type":"n.","turkish":"Radyasyon,ışınım.","definition":"The emission of energy as electromagnetic waves or as moving subatomic particles, especially high -energy particles which cause ionization.","examples":["Exposure to high levels of radiation can be harmful.","Microwave ovens use electromagnetic radiation to heat food."]},{"word":"radical","level":"C1","type":"adj.","turkish":"Radikal, köklü (değişim vb.); köktenci, aşırı (görüş).","definition":"(especially of change or action) Relating to or affecting the fundamental nature of something; far -reaching or thorough; advocating thorough or complete political or social reform; representing or supporting an extreme section of a political party.","examples":["The situation requires radical changes.","He holds radical political views."]},{"word":"rage","level":"C1","type":"n.","turkish":"Öfke, hiddet, gazap (şiddetli).","definition":"Violent, uncontrollable anger.","examples":["He flew into a rage when he heard the news.","Her eyes were filled with rage and frustration."]},{"word":"raid","level":"C1","type":"n.","turkish":"(n) Baskın (polis, askeri vb.), ani saldırı; (v) Baskın yapmak, ani saldırıda bulunmak.","definition":"(n) A rapid surprise attack on an enemy by troops, aircraft, or other armed forces; a surprise visit by police to arrest suspected criminals or seize illicit goods. (v) Conduct a raid on.","examples":["Police conducted a raid on the suspected drug house. (noun) Enemy planes raided the city during the night. (verb)"]},{"word":"rail","level":"B2","type":"n.","turkish":"Ray (tren); parmaklık, korkuluk, tırabzan; demiryolu.","definition":"A bar or series of bars fixed on upright supports or attached to a wall or ceiling, serving as part of a fence or barrier or used to hang things on; railroad tracks.","examples":["The train went off the rails. (track) Hold onto the hand rail when going down the stairs. (bar) Traveling by rail is often more relaxing than driving. (railway)"]},{"word":"rally","level":"C1","type":"n.","turkish":"(n) Miting, toplantı; ralli (otomobil yarışı); (borsa, sağlık vb.) toparlanma, iyileşme; (v) Toplanm","definition":"(n) A mass meeting of people making a political protest or showing support for a cause; a long -distance race for motor vehicles over public roads or rough terrain; a recovery in price or strength after a decline. (v) (of troops) Come together again ","examples":["Thousands attended the political rally in the city square. (noun - meeting) The team rallied in the second half to win the game. (verb - recover) Stock prices rallied after the announcement. (verb - recover price) Supporters rallied around the candidate. (verb - assemble)"]},{"word":"random","level":"B2","type":"adj.","turkish":"Rastgele, gelişigüzel, tesadüfi.","definition":"Made, done, or happening without method or conscious decision.","examples":["The winners were chosen by random selection.","He tends to make random comments that have nothing to do with the topic."]},{"word":"ranking","level":"C1","type":"n.","turkish":"Sıralama, dereceleme; rütbe, mevki.","definition":"A position in a hierarchy or scale; the action or process of giving something a rank.","examples":["The university improved its ranking this year.","What is his official ranking within the company?"]},{"word":"rape","level":"C1","type":"n.","turkish":"(n) Tecavüz; (v) Tecavüz etmek.","definition":"(n) The crime, typically committed by a man, of forcing another person to have sexual intercourse with the offender against their will. (v) Force (another person) to have sexual intercourse with the offender against their will.","examples":["Rape is a horrific crime with devastating consequences for the victim. (noun) He was convicted of raping multiple women. (verb)"]},{"word":"rat","level":"B2","type":"n.","turkish":"Sıçan, fare; (mecazi, argo) hain, ispiyoncu.","definition":"A rodent that resembles a large mouse, typically having a pointed snout and a long, sparsely haired tail; (informal) an unpleasant person, especially one who betrays or informs on others.","examples":["We saw a large rat run across the alley.","He felt betrayed when his friend acted like a rat. (informal)"]},{"word":"rating","level":"B2","type":"n.","turkish":"Derecelendirme, puanlama, değerlendirme; (TV, radyo) izlenme/dinlenme oranı.","definition":"A classification or ranking of someone or something based on a comparative assessment of their quality, standard, or performance; (ratings) the estimated audience size of a particular television or radio program.","examples":["The hotel received excellent ratings from guests.","The show's TV ratings have declined recently."]},{"word":"ratio","level":"C1","type":"n.","turkish":"Oran, orantı, nispet.","definition":"The quantitative relation between two amounts showing the number of times one value contains or is contained within the other.","examples":["The ratio of men to women in the class is two to one.","Maintain the correct ratio of water to cement when mixing concrete."]},{"word":"rational","level":"C1","type":"adj.","turkish":"Rasyonel, mantıklı, akılcı.","definition":"Based on or in accordance with reason or logic.","examples":["We need to make a rational decision based on the facts.","There must be a rational explanation for what happened."]},{"word":"ray","level":"C1","type":"n.","turkish":"Işın (ışık,ısı vb.); (mecazi) umutışığı.","definition":"Each of the lines in which light (and heat) may seem to stream from the sun or any luminous body, or pass through a small opening; a small amount of a quality or feeling.","examples":["A single ray of sunlight shone through the clouds.","X-rays are used in medical imaging."]},{"word":"readily","level":"C1","type":"adv.","turkish":"Kolayca, rahatlıkla; istekli birşekilde, seve seve.","definition":"Without difficulty or delay; willingly.","examples":["Information is readily available on the internet.","She readily agreed to help us. realization (n."]},{"word":"realm","level":"C1","type":"n.","turkish":"Alan, saha, diyar; krallık.","definition":"A kingdom; a field or domain of activity or interest.","examples":["This issue falls outside the realm of possibility.","He was banished from the realm. (kingdom)"]},{"word":"rear","level":"C1","type":"adj.","turkish":"(adj) Arka; (n) Arka kısım, art.","definition":"(adj) At the back. (n) The back part of something, especially a building or vehicle.","examples":["Please use the rear entrance of the building. (adjective) He loaded the luggage into the rear of the car. (noun)"]},{"word":"reasonably","level":"B2","type":"adv.","turkish":"Makul birşekilde, oldukça; mantıklı olarak.","definition":"In a sensible and fair way; to a moderately good standard; fairly.","examples":["The hotel was reasonably priced.","She performed reasonably well in the exam."]},{"word":"reasoning","level":"C1","type":"n.","turkish":"Akıl yürütme, mantık yürütme, muhakeme.","definition":"The action of thinking about something in a logical, sensible way.","examples":["His reasoning was sound, but his conclusions were wrong.","Explain the reasoning behind your decision."]},{"word":"reassure","level":"C1","type":"v.","turkish":"Güvence vermek, içini rahatlatmak, teskin etmek.","definition":"To say or do something to remove the doubts or fears of (someone).","examples":["The doctor reassured the patient that the operation was routine.","I tried to reassure her that everything would be okay."]},{"word":"rebel","level":"C1","type":"n.","turkish":"Asi, isyancı.","definition":"A person who rises in opposition or armed resistance against an established government or ruler; a person who resists authority, control, or convention.","examples":["Government forces fought against the rebels.","As a teenager, he was something of a rebel."]},{"word":"rebellion","level":"C1","type":"n.","turkish":"İsyan, başkaldırı.","definition":"An act of violent or open resistance to an established government or ruler.","examples":["The army quickly crushed the rebellion.","High taxes led to a popular rebellion."]},{"word":"rebui ld","level":"B2","type":"v.","turkish":"Yeniden inşa etmek, yeniden yapmak.","definition":"To build (something) again after it has been damaged or destroyed.","examples":["It took years to rebuild the city after the war.","They plan to rebuild the engine."]},{"word":"receiver","level":"B2","type":"n.","turkish":"Ahize (telefon); alıcı (cihaz); alan kimse.","definition":"The part of a telephone apparatus contained in the earpiece, which converts electrical signals into sound; a person who receives something; equipment that receives broadcast signals.","examples":["She picked up the phone receiver.","The package requires the signature of the receiver."]},{"word":"recession","level":"B2","type":"n.","turkish":"Ekonomik durgunluk, gerileme.","definition":"A period of temporary economic decline during which trade and industrial activity are reduced, generally identified by a fall in GDP in two successive quarters.","examples":["Many businesses struggled during the last recession.","The country is slowly recovering from the recession."]},{"word":"recipient","level":"C1","type":"n.","turkish":"Alan kimse, alıcı (ödül, hediye, e-posta vb.).","definition":"A person or thing that receives or is awarded something.","examples":["She was the proud recipient of the employee of the month award.","Please enter the email address of the recipient. reckon (v."]},{"word":"recognition","level":"B2","type":"n.","turkish":"Tanıma, tanınma; takdir, onaylama; (devlet vb.) tanıma.","definition":"Identification of someone or something or person from previous encounters or knowledge; appreciation or acknowledgment of the existence, validity, or legality of something.","examples":["He received an award in recognition of his achievements.","Facial recognition technology is becoming more advanced."]},{"word":"reconstruction","level":"C1","type":"n.","turkish":"Yeniden inşa, yeniden yapılandırma, imar.","definition":"The process of rebuilding something after it has been damaged or destroyed; the process of recreating or retelling (a past event).","examples":["The reconstruction of the city took decades after the earthquake.","Police carried out a reconstruction of the crime. recount¹ (v."]},{"word":"recovery","level":"B2","type":"n.","turkish":"İyileşme (hastalık, ekonomi vb.); geri kazanma.","definition":"A return to a normal state of health, mind, or strength; the action or process of regaining possession or control of something stolen or lost.","examples":["We wish you a speedy recovery from your illness.","The economy is showing signs of recovery."]},{"word":"recruit","level":"B2","type":"v.","turkish":"(v) İşe almak, askere almak; (n) Yeni üye, acemi (asker,çalışan vb.).","definition":"(v) Enlist (someone) in the armed forces; enroll (someone) as a member or worker in an organization or company. (n) A person newly enlisted in the armed forces and not yet fully trained; a new member of a group or organization.","examples":["The company is planning to recruit more staff next year. (verb) Army recruits undergo basic training. (noun)"]},{"word":"recruitment","level":"C1","type":"n.","turkish":"İşe alma, personel alma; askere alma.","definition":"The action of finding new people to join an organization or support a cause.","examples":["The company handles its own recruitment.","Graduate recruitment fairs are held at universities."]},{"word":"referee","level":"B2","type":"n.","turkish":"Hakem (spor); (iş/akademik) referans veren kimse.","definition":"An official who watches a game or match closely to ensure that the rules are adhered to and (in some sports) to arbitrate on matters arising from the play; a person willing to testify in writing about the character or ability of someone, especially a","examples":["The referee blew the whistle for full time.","You need to provide the names of two referees on your job application. referendum (n."]},{"word":"reflection","level":"C1","type":"n.","turkish":"Yansıma (ışık, görüntü); derin düşünme; yansıması, göstergesi.","definition":"The throwing back by a body or surface of light, heat, or sound without absorbing it; an image seen in a mirror or shiny surface; serious thought or consideration; something that brings discredit on sb/sth or shows the state of sth.","examples":["He saw his reflection in the window. (image) After careful reflection, she decided to accept the offer. (thought) The dirty streets are a sad reflection on the city council. (indicator)"]},{"word":"reform","level":"C1","type":"n.","turkish":"(n) Reform,ıslahat, iyileştirme; (v) Reform yapmak,ıslah etmek, iyileştirmek.","definition":"(n) The improvement or amendment of what is wrong, corrupt, unsatisfactory, etc. (v) Make changes in (something, typically a social, political, or economic institution or practice) in order to improve it.","examples":["The government introduced major economic reforms. (noun) They are trying to reform the education system. (verb)"]},{"word":"refuge","level":"C1","type":"n.","turkish":"Sığınak, barınak; sığınma.","definition":"The state of being safe or sheltered from pursuit, danger, or trouble; something providing shelter.","examples":["They sought refuge from the storm in an old barn.","The embassy granted political refuge to the dissidents."]},{"word":"refugee","level":"B2","type":"n.","turkish":"Mülteci, sığınmacı.","definition":"A person who has been forced to leave their country in order to escape war, persecution, or natural disaster.","examples":["Camps were set up to house the refugees.","Many refugees fled the war-torn country."]},{"word":"refusal","level":"C1","type":"n.","turkish":"Red, geriçevirme, kabul etmeme.","definition":"An act or an instance of refusing to do something.","examples":["His refusal to cooperate angered the police.","Her visa application met with refusal."]},{"word":"regain","level":"C1","type":"v.","turkish":"Geri kazanmak, yeniden elde etmek.","definition":"To obtain possession or use of (something) again after losing it; reach (a place, position, or state) again.","examples":["He slowly regained consciousness after the accident.","The team fought hard to regain the lead. regardless (adv."]},{"word":"regime","level":"C1","type":"n.","turkish":"Rejim, yönetim biçimi (genellikle otoriter); (diyet, egzersiz) rejimi.","definition":"A government, especially an authoritarian one; a system or planned way of doing things, especially one imposed from above.","examples":["The military regime ruled the country for decades.","She follows a strict fitness regime."]},{"word":"registration","level":"B2","type":"n.","turkish":"Kayıt, tescil.","definition":"The action or process of registering or of being registered.","examples":["Registration for the conference closes next week.","Vehicle registration documents must be kept in the car."]},{"word":"regulate","level":"B2","type":"v.","turkish":"Düzenlemek, ayarlamak; kurallara bağlamak, denetlemek.","definition":"To control or maintain the rate or speed of (a machine or process) so that it operates properly; control or supervise (something, especially a business activity) by means of rules and regulations.","examples":["A thermostat regulates the temperature.","The government needs to regulate the financial industry more closely."]},{"word":"regulator","level":"C1","type":"n.","turkish":"Düzenleyici (kurum, cihaz vb.).","definition":"A person or body that supervises a particular industry or business activity; a device for controlling the rate of working of machinery or the rate of flow of gas or fluid.","examples":["The energy regulator announced new price caps.","A pressure regulator controls the flow of gas."]},{"word":"regulatory","level":"C1","type":"adj.","turkish":"Düzenleyici (kurallarla ilgili).","definition":"Serving or intended to regulate something.","examples":["Companies must comply with strict regulatory requirements.","The regulatory body oversees the banking sector."]},{"word":"rehabilitat ion","level":"C1","type":"n.","turkish":"Rehabilitasyon, iyileştirme,ıslah etme (hasta, suçlu vb.); eski haline getirme.","definition":"The action of restoring someone to health or normal life through training and therapy after imprisonment, addiction, or illness; the action of restoring something that has been damaged to its former condition.","examples":["He is undergoing rehabilitation after his knee surgery.","The program focuses on the rehabilitation of young offenders."]},{"word":"reign","level":"C1","type":"n.","turkish":"(n) Hükümranlık, saltanat, egemenlik dönemi; (v) Hüküm sürmek, saltanat sürmek; hakim olmak.","definition":"(n) The period during which a sovereign rules. (v) Hold royal office; rule as king or queen; prevail.","examples":["Queen Victoria's reign lasted for over 60 years. (noun) Chaos reigned after the government collapsed. (verb)"]},{"word":"reinforce","level":"B2","type":"v.","turkish":"Güçlendirmek, pekiştirmek, takviye etmek.","definition":"To strengthen or support, especially with additional personnel or material; strengthen (an existing feeling, idea, or habit).","examples":["The bridge needs to be reinforced with steel beams.","Positive feedback helps to reinforce good behavior."]},{"word":"rejection","level":"C1","type":"n.","turkish":"Reddetme, geriçevirme; kabul etmeme.","definition":"The dismissing or refusing of a proposal, idea, etc.","examples":["She was disappointed by the rejection of her application.","Fear of rejection can prevent people from taking risks."]},{"word":"relevance","level":"C1","type":"n.","turkish":"İlgi, alaka, ilişki (konuyla).","definition":"The quality or state of being closely connected or appropriate.","examples":["I don't see the relevance of his comments to the current discussion.","The course content has direct relevance to the job market."]},{"word":"reliability","level":"C1","type":"n.","turkish":"Güvenilirlik, sağlamlık.","definition":"The quality of being trustworthy or of performing consistently well.","examples":["This brand is known for its reliability.","Data reliability is crucial for accurate research."]},{"word":"relieve","level":"B2","type":"v.","turkish":"Rahatlatmak, hafifletmek, dindirmek (acı, endişe vb.); (görevden) almak, yerine geçmek.","definition":"To cause (pain, distress, or difficulty) to become less severe or serious; release (someone) from a duty or task by taking their place.","examples":["Take some painkillers to relieve the headache.","The guard was relieved after his four-hour shift."]},{"word":"relieved","level":"B2","type":"adj.","turkish":"Rahatlamış, içi ferahlamış.","definition":"No longer feeling distressed or anxious; reassured.","examples":["She was relieved to hear that everyone was safe.","I felt greatly relieved after the exam was over."]},{"word":"reluctant","level":"C1","type":"adj.","turkish":"İsteksiz, gönülsüz, tereddütlü.","definition":"Unwilling and hesitant; disinclined.","examples":["He was reluctant to talk about his past.","She seemed reluctant to accept the invitation."]},{"word":"remainder","level":"C1","type":"n.","turkish":"Geri kalan kısım, artan, bakiye; kalan (matematik).","definition":"A part of something that is left over when other parts have been completed, used, or dealt with; the number which is left over in a division calculation.","examples":["You can keep the remainder of the money. 10 divided by 3 leaves a remainder of 1. remains (n.","C1) (Her zamançoğul) Türkçe Anlamı: Kalıntılar, artıklar; naaş, ceset."]},{"word":"remarkable","level":"B2","type":"adj.","turkish":"Dikkate değer, olağanüstü, dikkat çekici.","definition":"Worthy of attention; striking.","examples":["She has made remarkable progress in a short time.","It's remarkable how much he has changed."]},{"word":"remarkably","level":"B2","type":"adv.","turkish":"Dikkate değer birşekilde, oldukça, şaşırtıcı derecede.","definition":"In a way that is worthy of attention; used for emphasizing how surprising or unusual something is.","examples":["The two paintings are remarkably similar.","She remained remarkably calm throughout the crisis."]},{"word":"remedy","level":"C1","type":"n.","turkish":"Çare, deva, ilaç;çözüm.","definition":"A medicine or treatment for a disease or injury; a means of counteracting or eliminating something undesirable.","examples":["There is no simple remedy for loneliness.","Herbal remedies are popular for minor ailments."]},{"word":"reminder","level":"C1","type":"n.","turkish":"Hatırlatıcı (not, mesaj vb.).","definition":"A thing that causes someone to remember something.","examples":["I set a reminder on my phone for the meeting.","Let this be a reminder to always double -check your work."]},{"word":"removal","level":"C1","type":"n.","turkish":"Kaldırma,çıkarma, ortadan kaldırma; taşınma (ev, ofis).","definition":"The action of taking away or abolishing something unwanted; the action of moving house or business premises.","examples":["The removal of the blockage cleared the pipe.","They hired a removal company to help them move house."]},{"word":"render","level":"C1","type":"v.","turkish":"Hale getirmek, ...duruma sokmak; (hizmet, yardım) sunmak, vermek; (karar) vermek; çevirmek, tercüme ","definition":"Cause to be or become; make; provide or give (a service, help, etc.); formally announce (a verdict or judgment); translate; perform (a piece of music); represent or depict artistically.","examples":["The accident rendered him unable to walk. (make) The organization renders assistance to disaster victims. (provide) The jury rendered a verdict of not guilty. (give judgment)"]},{"word":"renew","level":"C1","type":"v.","turkish":"Yenilemek (sözleşme, abonelik vb.); tazelemek, yeniden başlamak.","definition":"Resume (an activity) after an interruption; extend the period of validity of (a license, subscription, or contract).","examples":["Don't forget to renew your library books.","We need to renew our efforts to find a solution."]},{"word":"renowned","level":"C1","type":"adj.","turkish":"Ünlü, meşhur, tanınmış (genellikle iyi bir nedenle).","definition":"Known or talked about by many people; famous.","examples":["He is a renowned expert in his field.","The restaurant is renowned for its excellent seafood."]},{"word":"rental","level":"C1","type":"n.","turkish":"Kiralama; kiralık eşya/yer; kira bedeli.","definition":"The action of renting something; an amount paid or received as rent; a rented property.","examples":["Car rental can be expensive during peak season.","We found a nice short -term rental near the beach."]},{"word":"replacement","level":"C1","type":"n.","turkish":"Yerine geçme/geçirme; yerine geçen kişi/şey, yedek.","definition":"The action or process of replacing someone or something; a person or thing that takes the place of another.","examples":["We need to find a replacement for the broken part.","The teacher is off sick, so a replacement will take the class."]},{"word":"reportedly","level":"C1","type":"adv.","turkish":"Söylendiğine göre, bildirildiğine göre.","definition":"According to what some say or believe; allegedly.","examples":["The company is reportedly planning to lay off workers.","He reportedly fled the country with a large amount of money."]},{"word":"reporting","level":"B2","type":"n.","turkish":"Habercilik, muhabirlik; raporlama, bildirme.","definition":"The activity or profession of reporting news or events for broadcast or publication; the presentation of prepared information.","examples":["She won an award for her investigative reporting.","Financial reporting needs to be accurate and transparent."]},{"word":"representation","level":"C1","type":"n.","turkish":"Temsil, temsil etme; tasvir, betimleme; beyan, iddia.","definition":"The action of speaking or acting on behalf of someone or the state of being so represented; the description or portrayal of someone or something in a particular way or as being of a certain nature.","examples":["The committee ensures fair representation for all members.","The film's representation of historical events was criticized."]},{"word":"repr oduce","level":"C1","type":"v.","turkish":"Çoğaltmak, kopyasını yapmak; üremek,çoğalmak (canlılar).","definition":"To produce a copy or representation of; (of an organism) produce offspring by a sexual or asexual process.","examples":["It is illegal to reproduce copyrighted material without permission.","Bacteria reproduce rapidly in warm conditions."]},{"word":"reproduction","level":"C1","type":"n.","turkish":"Çoğaltma, kopya;üreme,çoğalma.","definition":"The action or process of making a copy of something; the production of offspring by a sexual or asexual process.","examples":["This is a high -quality reproduction of the original painting.","The course covers human reproduction."]},{"word":"republic","level":"C1","type":"n.","turkish":"Cumhuriyet.","definition":"A state in which supreme power is held by the people and their elected representatives, and which has an elected or nominated president rather than a monarch.","examples":["France is a republic.","The country voted to become a republic."]},{"word":"resemble","level":"C1","type":"v.","turkish":"Benzemek, andırmak.","definition":"To have a similar appearance to or qualities in common with (someone or something); look or seem like.","examples":["She closely resembles her older sister.","The building resembles a medieval castle. reside (v."]},{"word":"residential","level":"C1","type":"adj.","turkish":"Konut(larla ilgili), yerleşim(le ilgili).","definition":"Designed for people to live in; relating to or denoting where people live.","examples":["They live in a quiet residential neighborhood.","The building is zoned for residential use only."]},{"word":"residue","level":"C1","type":"n.","turkish":"Kalıntı, tortu, artık.","definition":"A small amount of something that remains after the main part has gone or been taken or used.","examples":["Wipe away any sticky residue from the surface.","Pesticide residue was found on the fruit."]},{"word":"resign","level":"B2","type":"v.","turkish":"İstifa etmek.","definition":"To voluntarily leave a job or other position.","examples":["The minister was forced to resign after the scandal.","She decided to resign from her position as CEO."]},{"word":"resignation","level":"C1","type":"n.","turkish":"İstifa; (kaderine) boyun eğme, kabullenme.","definition":"An act of retiring or giving up a position; the acceptance of something undesirable but inevitable.","examples":["He tendered his resignation yesterday.","She faced her illness with quiet resignation."]},{"word":"resistance","level":"C1","type":"n.","turkish":"Direniş, mukavemet; rezistans, direnç (elektrik vb.).","definition":"The refusal to accept or comply with something; the attempt to prevent something by action or argument; the impeding effect exerted by one material object on another; the degree to which a substance or device opposes the passage of an electric curren","examples":["The French Resistance fought against the Nazi occupation.","There was strong resistance to the proposed changes."]},{"word":"resolution","level":"B2","type":"n.","turkish":"Karar, azim; (sorun)çözme,çözüm; çözünürlük (ekran, görüntü).","definition":"A firm decision to do or not to do something; the action of solving a problem, dispute, or contentious matter; the quality of being determined or resolute; the smallest interval measurable by a scientific (especially optical) instrument; the resolvin","examples":["My New Year's resolution is to exercise more. (decision) We are working towards a peaceful resolution of the conflict. (solving) The image has a high resolution. (screen quality)"]},{"word":"respective","level":"C1","type":"adj.","turkish":"Kendi,şahsi, ilgili (sırayla bahsedilenlere ait).","definition":"Belonging or relating separately to each of two or more people or things.","examples":["The winners returned to their respective countries.","John and Mary collected their respective prizes."]},{"word":"respectively","level":"C1","type":"adv.","turkish":"Sırasıyla, belirtilen sırayla.","definition":"Separately or individually and in the order already mentioned.","examples":["John, Mary, and Peter scored 10, 15, and 20 points, respectively.","The first and second prizes went to Ann and Ben, respectively."]},{"word":"restoration","level":"C1","type":"n.","turkish":"Restorasyon, onarma, eski haline getirme; iade etme.","definition":"The action of returning something to a former owner, place, or condition.","examples":["The restoration of the old painting took several years.","They are working on the restoration of the historic building."]},{"word":"restore","level":"B2","type":"v.","turkish":"Restore etmek, onarmak, eski haline getirmek; iade etmek.","definition":"To bring back (a previous right, practice, custom, or situation); reinstate; repair or renovate (a building, work of art, vehicle, etc.) so as to return it to its original condition.","examples":["Efforts are being made to restore the damaged ecosystem.","The goal is to restore the building to its former glory."]},{"word":"restraint","level":"C1","type":"n.","turkish":"Kısıtlama, sınırlama; (duygusal) kontrol,ölçülülük, itidal.","definition":"A measure or condition that keeps someone or something under control or within limits; unemotional, dispassionate, or moderate behavior; self-control.","examples":["Budget restraints mean we cannot hire more staff.","She showed great restraint in not reacting angrily."]},{"word":"restrict","level":"B2","type":"v.","turkish":"Kısıtlamak, sınırlamak.","definition":"To put a limit on; keep under control.","examples":["Access to the area is restricted to authorized personnel.","The new law aims to restrict the sale of alcohol."]},{"word":"restriction","level":"B2","type":"n.","turkish":"Kısıtlama, sınırlama.","definition":"A limiting condition or measure, especially a legal one.","examples":["Travel restrictions were imposed during the pandemic.","There are parking restrictions on this street. resume (v."]},{"word":"retail","level":"B2","type":"n.","turkish":"Perakende satış.","definition":"The sale of goods to the public in relatively small quantities for use or consumption rather than for resale.","examples":["She works in the retail sector.","The retail price is usually higher than the wholesale price."]},{"word":"retirement","level":"B2","type":"n.","turkish":"Emeklilik.","definition":"The action or fact of leaving one's job and ceasing to work.","examples":["He is looking forward to his retirement next year.","Many people travel more after retirement."]},{"word":"retreat","level":"C1","type":"n.","turkish":"(n) Geriçekilme; (sessiz/huzurlu) sığınak, inziva yeri; (v) Geriçekilmek; inzivayaçekilmek.","definition":"(n) An act of moving back or withdrawing; a quiet or secluded place in which one can rest and relax. (v) Move back or withdraw; withdraw to a quiet or secluded place.","examples":["The army was forced to retreat. (verb) They spent the weekend at a quiet country retreat. (noun) Faced with strong opposition, the government had to retreat on its plans. (verb)"]},{"word":"retrieve","level":"C1","type":"v.","turkish":"Geri almak, kurtarmak; (bilgiyi) bulup getirmek.","definition":"To get or bring (something) back; regain possession of; find or extract (information stored in a computer or other electronic device).","examples":["The dog was trained to retrieve birds.","It took a long time to retrieve the data from the damaged hard drive."]},{"word":"revelation","level":"C1","type":"n.","turkish":"Vahiy, ilham; ifşa etme, açığaçıkarma; açığaçıkanşaşırtıcışey.","definition":"A surprising and previously unknown fact, especially one that is made known in a dramatic way; the divine or supernatural disclosure to humans of something relating to human existence or the world.","examples":["The book contained shocking revelations about his personal life.","Her confession came as a revelation to her family."]},{"word":"revenge","level":"C1","type":"n.","turkish":"İntikam,öç.","definition":"The action of inflicting hurt or harm on someone for an injury or wrong suffered at their hands.","examples":["He swore to take revenge for his brother's murder.","Seeking revenge often leads to more violence."]},{"word":"revenue","level":"B2","type":"n.","turkish":"Gelir, hasılat (şirket, devlet vb.).","definition":"Income, especially when of a company or organization and of a substantial nature; a state's annual income from which public expenses are met.","examples":["The company's annual revenue exceeded $1 billion.","Government revenues come primarily from taxes."]},{"word":"rev erse","level":"C1","type":"v.","turkish":"(v) Tersineçevirmek, geriçevirmek; geri geri gitmek (araç); (n) Ters, arka taraf; geri vites; (adj) ","definition":"(v) Move backward; make (something) the opposite of what it was; turn (something) the other way around or up or inside out. (n) The opposite or contrary of a previous situation or condition; reverse gear in a vehicle. (adj) Going in or turned toward ","examples":["You need to reverse the car into the parking space. (verb) The decision was later reversed by the appeal court. (verb) Please write your name on the reverse side of the paper. (noun/adj)"]},{"word":"revi sion","level":"B2","type":"n.","turkish":"Revizyon, gözden geçirme, düzeltme; (sınava) tekrarçalışma ( İngiltere).","definition":"The action of revising; a revised edition or form of something; (UK) the action of rereading work done previously to improve one's knowledge of a subject, typically in preparation for an examination.","examples":["The draft requires substantial revision.","He spent the weekend doing revision for his exams. (UK study)"]},{"word":"revival","level":"C1","type":"n.","turkish":"Canlanma, diriliş, yeniden popülerleşme; (tiyatro) yeniden sahneleme.","definition":"An improvement in the condition or strength of something; an instance of something becoming popular, active, or important again; a new production of an old play or similar work.","examples":["There has been a revival of interest in traditional crafts.","The theater is staging a revival of a classic musical."]},{"word":"revive","level":"C1","type":"v.","turkish":"Canlandırmak, diriltmek, hayata döndürmek; yeniden popülerleştirmek.","definition":"To restore to life or consciousness; give new strength or energy to; restore interest in or the popularity of.","examples":["The paramedics managed to revive the unconscious man.","The government hopes to revive the struggling economy."]},{"word":"revolutionary","level":"C1","type":"adj.","turkish":"Devrimci, devrimle ilgili; kökten değişiklik getiren,çığır açan.","definition":"Involving or causing a complete or dramatic change; engaged in or promoting political revolution.","examples":["The invention of the printing press was revolutionary.","He was a key figure in the revolutionary movement."]},{"word":"rhetoric","level":"C1","type":"n.","turkish":"Retorik, hitabet sanatı; etkileyici ama samimiyetsiz/boş söz.","definition":"The art of effective or persuasive speaking or writing, especially the use of figures of speech and other compositional techniques; language designed to have a persuasive or impressive effect on its audience, but often regarded as lacking in sincerit","examples":["His speech was full of powerful rhetoric.","Voters grew tired of the politician's empty rhetoric."]},{"word":"ridiculous","level":"B2","type":"adj.","turkish":"Gülünç, saçma, komik.","definition":"Deserving or inviting derision or mockery; absurd.","examples":["You look ridiculous in that hat!","It's ridiculous to expect one person to do all that work."]},{"word":"rifle","level":"C1","type":"n.","turkish":"Tüfek.","definition":"A gun, especially one fired from shoulder level, having a long spirally grooved barrel intended to make a bullet spin and thereby have greater accuracy over a long distance.","examples":["Hunters often use high-powered rifles.","Soldiers are trained in the use of rifles."]},{"word":"riot","level":"C1","type":"n.","turkish":"İsyan, ayaklanma, kargaşa.","definition":"A violent disturbance of the peace by a crowd.","examples":["The police were called in to control the riot.","Food shortages sparked riots in several cities."]},{"word":"rip","level":"C1","type":"v.","turkish":"Yırtmak, yırtılmak; (hızla) sökmek, koparmak.","definition":"To tear or pull (something) quickly or forcibly away from something or someone; move forcefully and rapidly.","examples":["Be careful not to rip the paper.","He ripped the poster off the wall."]},{"word":"risky","level":"B2","type":"adj.","turkish":"Riskli, tehlikeli.","definition":"Full of the possibility of danger, failure, or loss.","examples":["Investing in startup companies can be risky.","It's risky to drive so fast on icy roads."]},{"word":"ritual","level":"C1","type":"n.","turkish":"Ritüel, ayin, tören; adet, alışkanlık.","definition":"A religious or solemn ceremony consisting of a series of actions performed according to a prescribed order; a series of actions or type of behavior regularly and invariably followed by someone.","examples":["Weddings and funerals often involve traditional rituals.","His morning coffee had become a daily ritual."]},{"word":"rival","level":"B2","type":"n.","turkish":"(n) Rakip; (adj) Rakip.","definition":"(n) A person or thing competing with another for the same objective or for superiority in the same field of activity. (adj) Competing.","examples":["The two companies are fierce rivals. (noun) They played against their main rival team. (adjective)"]},{"word":"rob","level":"B2","type":"v.","turkish":"Soymak (bir yeri/kişiyi).","definition":"To take property unlawfully from (a person or place) by force or threat of force.","examples":["Masked men attempted to rob the bank.","He was robbed at gunpoint."]},{"word":"robbery","level":"B2","type":"n.","turkish":"Soygun, soygunculuk.","definition":"The action of robbing a person or place.","examples":["There was an armed robbery at the jewelry store.","He was arrested for attempted robbery."]},{"word":"robust","level":"C1","type":"adj.","turkish":"Sağlam, güçlü, gürbüz; (sistem, ekonomi vb.) dayanıklı.","definition":"Strong and healthy; vigorous; (of a system, organization, etc.) strong and unlikely to fail or be weakened.","examples":["Despite his age, he remains robust and active.","The company has shown robust growth this year."]},{"word":"rock","level":"C1","type":"v.","turkish":"Sallamak, sallanmak (ileri geri/yanlara); sarsmak,şok etmek.","definition":"To move gently to and fro or from side to side; shake or cause to shake or vibrate violently; shock or distress (someone) greatly.","examples":["She gently rocked the baby to sleep. (move gently) The explosion rocked buildings miles away. (shake violently) News of the scandal rocked the nation. (shock)"]},{"word":"rocket","level":"B2","type":"n.","turkish":"Roket; havai fişek roketi.","definition":"A spacecraft, missile, or aircraft propelled by a rocket engine; a firework that propels itself high into the air before exploding.","examples":["The rocket launched successfully carrying the satellite into orbit.","Children love watching rockets explode on Bonfire Night."]},{"word":"rod","level":"C1","type":"n.","turkish":"Çubuk, değnek, sopa; olta.","definition":"A thin straight bar, typically of wood or metal; a fishing rod.","examples":["He used a metal rod to prop open the window.","She sat by the river with her fishing rod."]},{"word":"romance","level":"B2","type":"n.","turkish":"Romans, aşk ilişkisi; aşk hikayesi/filmi; romantizm, macera havası.","definition":"A feeling of excitement and mystery associated with love; a quality or feeling of mystery, excitement, and remoteness from everyday life; a genre of fiction dealing with love in a sentimental or idealized way.","examples":["Their holiday romance didn't last long.","She enjoys reading historical romances."]},{"word":"rose","level":"B2","type":"n.","turkish":"Gül (çiçek); gül rengi, pembe.","definition":"A prickly bush or shrub that typically bears red, pink, yellow, or white fragrant flowers, native to north temperate regions; a fragrant flower of a rose bush; a pink color.","examples":["He gave her a single red rose.","The garden is full of beautiful roses."]},{"word":"roster","level":"C1","type":"n.","turkish":"Kadro, liste (isim, görev vb.).","definition":"A list or plan showing turns of duty or leave for individuals or groups in an organization.","examples":["Check the duty roster to see when you are working next week.","The team roster includes several new players this season."]},{"word":"rotate","level":"C1","type":"v.","turkish":"Döndürmek, dönmek (kendi ekseninde); (görevi vb.) dönüşümlü yapmak.","definition":"To move or cause to move in a circle around an axis or center; pass (a responsibility or turn) to members of a group in a regularly recurring sequence.","examples":["The Earth rotates on its axis once every 24 hours.","We rotate the tires on the car every 10,000 miles."]},{"word":"rotation","level":"C1","type":"n.","turkish":"Dönme, dönüş (kendi ekseninde); rotasyon, nöbetleşe görev yapma; (tarım) münavebe.","definition":"The action of rotating around an axis or center; the regular alternation of people in a job or task; the practice of growing different crops in succession on the same land.","examples":["The Earth's rotation causes day and night.","Job rotation allows employees to gain experience in different areas."]},{"word":"roughly","level":"B2","type":"adv.","turkish":"Yaklaşık olarak, kabaca; kabaca, sertçe.","definition":"Approximately; not exactly; in a way that is not gentle or careful.","examples":["The journey took roughly two hours.","He pushed roughly past her."]},{"word":"ruin","level":"B2","type":"v.","turkish":"(v) Mahvetmek, harap etmek, yıkmak; iflas ettirmek; (n) Harabe, yıkıntı; mahvolma, yıkım.","definition":"(v) Reduce (a building or place) to a state of decay, collapse, or disintegration; destroy or severely damage; cause to lose all or most of one's money. (n) The physical destruction or disintegration of something or the state of being destroyed; (rui","examples":["The bad weather completely ruined our picnic. (verb) Gambling led to his financial ruin. (noun) We explored the ancient ruins of the castle. (noun)"]},{"word":"ruling","level":"C1","type":"n.","turkish":"Karar, hüküm (mahkeme, yetkili merci vb.).","definition":"An authoritative decision or pronouncement, especially one made by a judge.","examples":["The court issued a ruling in favor of the plaintiff.","The ruling established an important legal precedent. rumor (n."]},{"word":"sacred","level":"C1","type":"adj.","turkish":"Kutsal, mukaddes.","definition":"Connected with God (or the gods) or dedicated to a religious purpose and so deserving veneration; regarded with great respect and reverence by a particular religion, group, or individual.","examples":["The Ganges River is sacred to Hindus.","Certain traditions are held sacred within the community."]},{"word":"sacrifice","level":"C1","type":"n.","turkish":"(n) Kurban, fedakarlık; (v) Kurban etmek, feda etmek.","definition":"(n) An act of slaughtering an animal or person or surrendering a possession as an offering to God or to a divine or supernatural figure; an act of giving up something valued for the sake of something else regarded as more important or worthy. (v) Off","examples":["Parents often make huge sacrifices for their children. (noun) He sacrificed his career to care for his sick mother. (verb)"]},{"word":"saint","level":"C1","type":"n.","turkish":"Aziz, azize, evliya.","definition":"A person acknowledged as holy or virtuous and typically regarded as being in heaven after death; a very virtuous, kind, or patient person.","examples":["Saint Patrick is the patron saint of Ireland.","My grandmother was a real saint; she was always helping others. sake (n."]},{"word":"sanction","level":"C1","type":"n.","turkish":"Yaptırım, müeyyide (genellikle ekonomik/politik); onay, izin.","definition":"A threatened penalty for disobeying a law or rule; official permission or approval for an action.","examples":["The United Nations imposed economic sanctions on the country. (penalty) The project received official sanction from the committee. (approval)"]},{"word":"satisfaction","level":"B2","type":"n.","turkish":"Memnuniyet, tatmin, hoşnutluk.","definition":"Fulfillment of one's wishes, expectations, or needs, or the pleasure derived from this.","examples":["Finishing the project gave him a great sense of satisfaction.","Customer satisfaction is our top priority. say (n."]},{"word":"scandal","level":"B2","type":"n.","turkish":"Skandal, rezalet.","definition":"An action or event regarded as morally or legally wrong and causing general public outrage.","examples":["The politician was involved in a financial scandal.","The scandal forced the company's CEO to resign."]},{"word":"scare","level":"B2","type":"v.","turkish":"(v) Korkutmak; (n) Korku,ürkme.","definition":"(v) Cause great fear or nervousness in; frighten. (n) A sudden attack of fright.","examples":["The loud noise scared the baby. (verb) You gave me a scare creeping up like that! (noun)"]},{"word":"scattered","level":"C1","type":"adj.","turkish":"Dağınık, serpilmiş, seyrek.","definition":"Occurring or found at intervals or various locations rather than all together.","examples":["Clothes were scattered all over the floor.","There were a few scattered houses in the valley."]},{"word":"scenario","level":"B2","type":"n.","turkish":"Senaryo (olasılık, durum); senaryo (film, oyun).","definition":"A postulated sequence or development of events; a written outline of a movie, novel, or stage work giving details of the plot and individual scenes.","examples":["Let's consider a worst -case scenario.","The most likely scenario is that the project will be delayed."]},{"word":"scholar","level":"B2","type":"n.","turkish":"Bilgin, alim (özellikle beşeri bilimlerde); bursiyer.","definition":"A specialist in a particular branch of study, especially the humanities; a distinguished academic; a student who holds a scholarship.","examples":["He is a respected scholar of ancient Greek literature.","The conference attracted scholars from around the world."]},{"word":"scholarship","level":"B2","type":"n.","turkish":"Burs (eğitim); bilgelik, ilim.","definition":"A grant or payment made to support a student's education, awarded on the basis of academic or other achievement; academic study or achievement; learning of a high level.","examples":["She won a scholarship to study at Oxford.","His book demonstrates impressive scholarship."]},{"word":"scope","level":"C1","type":"n.","turkish":"Kapsam, alan; fırsat, olanak.","definition":"The extent of the area or subject matter that something deals with or to which it is relevant; the opportunity or possibility to do or deal with something.","examples":["This issue falls outside the scope of our investigation.","There is limited scope for creativity in this job."]},{"word":"scratch","level":"B2","type":"v.","turkish":"(v) Kaşımak; tırmalamak,çizmek; karalamak; (plan vb.) iptal etmek; (n) Çizik, tırmık; kaşıma sesi.","definition":"(v) Score or mark the surface of (something) with a sharp or pointed object; rub (a part of one's body) with one's fingernails to relieve itching; cancel or strike out (writing); withdraw from a competition. (n) A mark made by scratching; an act of s","examples":["The cat scratched the furniture. (verb) Be careful not to scratch the car door. (verb) There's a deep scratch on the table. (noun)"]},{"word":"screening","level":"B2","type":"n.","turkish":"Gösterim (film); tarama (sağlık); eleme (işe alım vb.).","definition":"Showing a film or television program; testing people for the presence of disease or injury; examining people or things to see if they are suitable for a particular purpose.","examples":["There will be a special screening of the director's new film. (film) Regular health screenings can detect cancer early. (medical) Candidate screening involves checking qualifications and references. (job)"]},{"word":"screw","level":"C1","type":"v.","turkish":"(v) Vidalamak; (argo) aldatmak, kazıklamak; (n) Vida; (argo) gardiyan.","definition":"(v) Fasten or tighten with a screw or screws; (slang) cheat or swindle (someone). (n) A short, slender, sharp -pointed metal pin with a raised helical thread running around it and a slotted head, used to join things together by being rotated; (slang)","examples":["Use a screwdriver to screw the pieces together. (verb) Make sure the lid is screwed on tightly. (verb) You need a longer screw for this hole. (noun)"]},{"word":"scrutiny","level":"C1","type":"n.","turkish":"Dikkatli inceleme, detaylı kontrol, tetkik.","definition":"Critical observation or examination.","examples":["The proposal came under close scrutiny from the committee.","Her performance was subjected to intense public scrutiny. seal (v., n."]},{"word":"secondly","level":"C1","type":"adv.","turkish":"İkinci olarak, ikincisi.","definition":"Used to introduce the second point or reason.","examples":["Firstly, we need more time.","Secondly, we need more money."]},{"word":"secular","level":"C1","type":"adj.","turkish":"Seküler, laik, dünyevi (dini olmayan).","definition":"Not connected with religious or spiritual matters.","examples":["Turkey is officially a secular republic.","He attended a secular school, not a religious one."]},{"word":"seeker","level":"B2","type":"n.","turkish":"Arayan kimse (iş, sığınma vb.).","definition":"A person who is attempting to find or obtain something.","examples":["The careers service provides help for job seekers.","Asylum seekers often face long waits for decisions."]},{"word":"seemingly","level":"C1","type":"adv.","turkish":"Görünüşe göre, görünüşte.","definition":"So as to give the impression of having a certain quality; apparently.","examples":["He remains seemingly unaffected by the criticism.","It was a seemingly harmless question, but it caused a lot of trouble."]},{"word":"segment","level":"C1","type":"n.","turkish":"Bölüm, parça, segment (pazar, portakal dilimi vb.).","definition":"Each of the parts into which something is or may be divided.","examples":["The company targets a specific segment of the market.","Cut the orange into segments."]},{"word":"seize","level":"C1","type":"v.","turkish":"Yakalamak, ele geçirmek; (zorla) el koymak; (fırsatı) yakalamak, kapmak.","definition":"To take hold of suddenly and forcibly; take (an opportunity or initiative) eagerly and decisively; take possession of (something) by legal process.","examples":["The police seized a large quantity of illegal drugs.","You must seize the opportunity while it lasts."]},{"word":"seldom","level":"C1","type":"adv.","turkish":"Nadiren, seyrek olarak.","definition":"Not often; rarely.","examples":["We seldom see our cousins who live abroad.","Such opportunities arise very seldom."]},{"word":"selective","level":"C1","type":"adj.","turkish":"Seçici, seçerek.","definition":"Relating to or involving selection of a particular kind; tending to choose carefully.","examples":["The university has a highly selective admissions process.","She is very selective about the books she reads."]},{"word":"seminar","level":"B2","type":"n.","turkish":"Seminer.","definition":"A conference or other meeting for discussion or training; a class at a college or university in which a topic is discussed by a teacher and a small group of students.","examples":["I attended a seminar on project management.","The professor leads a weekly graduate seminar."]},{"word":"sensation","level":"C1","type":"n.","turkish":"His, duygu, duyum; sansasyon, heyecan yaratan olay/kişi.","definition":"A physical feeling or perception resulting from something that happens to or comes into contact with the body; a widespread reaction of interest and excitement.","examples":["She felt a tingling sensation in her fingers.","The new singer became an overnight sensation."]},{"word":"sensitivity","level":"C1","type":"n.","turkish":"Hassasiyet, duyarlılık; alınganlık.","definition":"The quality or condition of being sensitive; the quality of being easily hurt or offended.","examples":["Handle the situation with care and sensitivity.","Some people have a high sensitivity to caffeine."]},{"word":"sentiment","level":"C1","type":"n.","turkish":"Duygu, his; düşünce, görüş (duygusal); aşırı duygusallık.","definition":"A view or opinion that is held or expressed; a feeling or emotion; exaggerated and selfindulgent feelings of tenderness, sadness, or nostalgia.","examples":["I agree with your sentiments entirely.","Public sentiment is turning against the war."]},{"word":"separation","level":"C1","type":"n.","turkish":"Ayrılma, ayrılık (evlilik vb.); ayırma.","definition":"The action or state of moving or being moved apart; the state in which a husband and wife remain married but live apart.","examples":["The separation of powers is a key principle of democracy.","They decided on a trial separation before getting divorced."]},{"word":"serial","level":"C1","type":"adj.","turkish":"Seri (katil, yayın vb.), dizi halinde.","definition":"Consisting of, forming part of, or taking place in a series; repeatedly committing the same offense and typically following a characteristic pattern.","examples":["The police are hunting a serial killer.","The story was published in serial form in the magazine."]},{"word":"settlemen t","level":"C1","type":"n.","turkish":"Yerleşim yeri, köy; anlaşma, uzlaşma; ödeme, kapatma (hesap).","definition":"An official agreement intended to resolve a dispute or conflict; a place, typically one which has previously been uninhabited, where people establish a community; the action or process of settling an account.","examples":["Archaeologists discovered an ancient Roman settlement. (place) They reached a financial settlement out of court. (agreement)"]},{"word":"settler","level":"B2","type":"n.","turkish":"Yerleşimci, göçmen (yeni bir yere yerleşen).","definition":"A person who settles in an area, typically one with no or few previous inhabitants.","examples":["Early European settlers faced many hardships in America.","Conflicts arose between the settlers and the indigenous population. setup (n."]},{"word":"severely","level":"B2","type":"adv.","turkish":"Şiddetle, ciddişekilde, ağır biçimde.","definition":"To a severe or serious degree; very badly or strictly.","examples":["He was severely injured in the car crash.","The company's profits were severely affected by the recession."]},{"word":"sexuality","level":"C1","type":"n.","turkish":"Cinsellik.","definition":"A person's sexual identity in relation to the gender to which they are attracted; the fact of being heterosexual, homosexual, or bisexual; capacity for sexual feelings.","examples":["Attitudes towards sexuality have changed over time.","The book explores themes of identity and sexuality. sexy (adj."]},{"word":"shaped","level":"B2","type":"adj.","turkish":"Şekilli, ...şeklinde/biçiminde.","definition":"Having a particular shape. Often used in compounds (e.g., L -shaped, heart-shaped).","examples":["The table is L-shaped.","She cut the sandwiches into heart -shaped pieces."]},{"word":"shareholder","level":"C1","type":"n.","turkish":"Hissedar, pay sahibi.","definition":"An owner of shares in a company.","examples":["The company's annual report was sent to all shareholders.","Shareholders voted on the proposal at the meeting."]},{"word":"shatter","level":"C1","type":"v.","turkish":"Parçalamak, paramparça etmek/olmak; (mecazi) sarsmak, yıkmak (umut, inanç vb.).","definition":"To break or cause to break suddenly and violently into pieces; upset (someone) greatly; damage or destroy (something abstract).","examples":["The vase fell and shattered into a thousand pieces.","The news shattered her hopes of recovery. shed (v."]},{"word":"sheer","level":"C1","type":"adj.","turkish":"Tam, katıksız, sırf; (kumaş)çok ince, tül gibi; (uçurum vb.) dimdik, sarp.","definition":"Nothing other than; unmitigated (used for emphasis); (of fabric) very thin; diaphanous; (especially of a cliff or wall) perpendicular or nearly so.","examples":["It was sheer luck that we found the place. (complete) The curtains were made of sheer silk. (thin fabric) Be careful near the sheer drop at the cliff edge. (steep)"]},{"word":"shipping","level":"C1","type":"n.","turkish":"Nakliye, taşımacılık (gemiyle); gemiler.","definition":"Ships considered collectively, especially those in a particular area or belonging to a particular country; the transport of goods by sea or other means.","examples":["The port is busy with international shipping.","The price includes shipping and handling charges."]},{"word":"shocking","level":"B2","type":"adj.","turkish":"Şok edici, sarsıcı, korkunç.","definition":"Causing indignation or disgust; offensive; causing surprise and distress.","examples":["The news of the accident was truly shocking.","His behavior at the party was shocking."]},{"word":"shoot","level":"C1","type":"n.","turkish":"Sürgün, filiz (bitki); fotoğraf/film çekimi.","definition":"A young branch or sucker springing from the main stock of a tree or other plant; an occasion when a professional photographer takes photographs or when a film or video is being made.","examples":["New shoots appeared on the plant in spring. (plant) The fashion magazine organized a photo shoot in Paris. (photography)"]},{"word":"shore","level":"B2","type":"n.","turkish":"Kıyı, sahil (deniz, göl).","definition":"The land along the edge of a sea, lake, or wide river.","examples":["We walked along the sandy shore.","The waves crashed against the rocky shore."]},{"word":"shortage","level":"B2","type":"n.","turkish":"Kıtlık, eksiklik, sıkıntı.","definition":"A state or situation in which something needed cannot be obtained in sufficient amounts.","examples":["There is a severe shortage of housing in the city.","Water shortages are common during the dry season."]},{"word":"shortly","level":"B2","type":"adv.","turkish":"Kısa süre sonra, birazdan; kısaca, ters birşekilde.","definition":"Soon; in a short time; in a concise or abrupt way.","examples":["The train will arrive shortly.","She answered rather shortly, clearly annoyed."]},{"word":"short -term","level":"B2","type":"adj.","turkish":"Kısa vadeli, kısa süreli.","definition":"Occurring over or relating to a short period of time.","examples":["We are looking for a short-term solution to the problem.","What are your short-term career goals? shrink (v."]},{"word":"shrug","level":"C1","type":"v.","turkish":"Omuz silkmek (bilmemezlik, umursamazlık vb. belirtisi).","definition":"To raise (one's shoulders) slightly and momentarily to express doubt, ignorance, or indifference.","examples":["When I asked him where she was, he just shrugged.","She shrugged her shoulders as if to say it didn't matter."]},{"word":"sibling","level":"B2","type":"n.","turkish":"Kardeş (erkek veya kız).","definition":"Each of two or more children or offspring having one or both parents in common; a brother or sister.","examples":["Do you have any siblings?","There was often rivalry between the siblings. sidewalk (n."]},{"word":"sigh","level":"C1","type":"v.","turkish":"(v) İççekmek, oflamak; (n) İççekiş, oflama.","definition":"(v) Emit a long, deep, audible breath expressing sadness, relief, tiredness, or similar. (n) A long, deep, audible breath expressing sadness, relief, tiredness, or similar.","examples":["He sighed deeply when he heard the bad news. (verb) She let out a sigh of relief. (noun)"]},{"word":"signature","level":"B2","type":"n.","turkish":"İmza; (mecazi) ayırt ediciözellik.","definition":"A person's name written in a distinctive way as a form of identification in authorizing a check or document or concluding a letter; a distinctive pattern, product, or characteristic by which someone or something can be identified.","examples":["Please put your signature at the bottom of the form.","That dish is the chef's signature creation."]},{"word":"significance","level":"B2","type":"n.","turkish":"Önem, mana, anlam.","definition":"The quality of being worthy of attention; importance; the meaning to be found in words or events.","examples":["The discovery is of great historical significance.","He didn't grasp the full significance of her remarks."]},{"word":"simulate","level":"C1","type":"v.","turkish":"Simüle etmek, benzetimini yapmak, taklit etmek.","definition":"To imitate the appearance or character of; produce a computer model of (something, especially for the purpose of study).","examples":["Pilots use flight simulators to simulate emergency situations.","The program simulates the effects of climate change."]},{"word":"simulation","level":"C1","type":"n.","turkish":"Simülasyon, benzetim, taklit.","definition":"Imitation of a situation or process; the production of a computer model of something, especially for the purpose of study.","examples":["Computer simulations are used in scientific research.","The training included a simulation of a rescue operation."]},{"word":"simultaneously","level":"C1","type":"adv.","turkish":"Eş zamanlı olarak, aynı anda.","definition":"At the same time.","examples":["The two events happened simultaneously.","It's difficult to listen and take notes simultaneously."]},{"word":"sin","level":"C1","type":"n.","turkish":"Günah.","definition":"An immoral act considered to be a transgression against divine law.","examples":["In many religions, killing is considered a grave sin.","He confessed his sins to the priest. situated (adj."]},{"word":"sketch","level":"C1","type":"n.","turkish":"Eskiz, taslakçizim; kısa oyun/yazı, skeç.","definition":"A rough or unfinished drawing or painting, often made to assist in making a more finished picture; a short humorous play or performance, consisting typically of one scene in a comedy program.","examples":["The artist made several quick sketches of the model.","The comedy show featured several hilarious sketches."]},{"word":"skilled","level":"B2","type":"adj.","turkish":"Yetenekli, becerikli, usta.","definition":"Having or showing the knowledge, ability, or training to perform a certain activity or task well.","examples":["He is a highly skilled craftsman.","The job requires skilled workers."]},{"word":"skip","level":"C1","type":"v","turkish":"Atlamak, sektirmek (ip vb.); atlamak, es geçmek (bir bölümü vb.).","definition":"Move along lightly, stepping from one foot to the other with a hop or bounce; omit (part of a book, sequence, etc.) or fail to attend (something).","examples":["Children love to skip rope in the playground.","You can skip the introduction and go straight to chapter one."]},{"word":"skull","level":"B2","type":"n.","turkish":"Kafatası.","definition":"A bone framework enclosing the brain of a vertebrate; the human head.","examples":["The archaeologist found a human skull at the site.","Helmets protect the skull from injury."]},{"word":"slam","level":"C1","type":"v.","turkish":"Çarparak kapatmak (kapı vb.); sertçe vurmak/koymak; (mecazi) sertçe eleştirmek.","definition":"Shut (a door, window, or lid) forcefully and loudly; put (something) down forcefully; criticize severely.","examples":["He slammed the door shut in anger.","She slammed her books down on the table."]},{"word":"slap","level":"C1","type":"v.","turkish":"Tokat atmak,şaplak atmak.","definition":"Hit or strike with the palm of the hand or a flat object.","examples":["She threatened to slap his face.","He playfully slapped his friend on the back."]},{"word":"slash","level":"C1","type":"v.","turkish":"Kesmek (uzun, derin birşekilde); (fiyat vb.) büyükölçüde azaltmak.","definition":"Cut (something) with a violent sweeping movement, typically with a knife or sword; reduce (a price, quantity, etc.) greatly.","examples":["Someone had slashed the tires on his car.","The company decided to slash prices to boost sales."]},{"word":"slavery","level":"C1","type":"n.","turkish":"Kölelik.","definition":"The state of being a slave; the practice or system of owning slaves.","examples":["Millions of Africans were forced into slavery.","The abolition of slavery was a major historical event."]},{"word":"slogan","level":"B2","type":"n.","turkish":"Slogan, parola.","definition":"A short and striking or memorable phrase used in advertising, or associated with a political party or other group.","examples":["\"Just Do It\" is Nike's famous slogan.","The demonstrators chanted political slogans."]},{"word":"slot","level":"C1","type":"n.","turkish":"Yarık, delik (jeton, mektup vb. için); (program, zamançizelgesi) yer, zaman dilimi.","definition":"A long, narrow aperture or slit in a machine for something to be inserted; a position in a schedule or sequence.","examples":["Insert the coin into the slot.","We managed to get a delivery slot for tomorrow morning."]},{"word":"smash","level":"C1","type":"v.","turkish":"Paramparça etmek/olmak, kırmak; çarpmak (şiddetle); (rekor) kırmak.","definition":"Violently break (something) into pieces; move so as to hit or collide with something with great force; comprehensively defeat or surpass (an existing record).","examples":["He accidentally smashed the window with a ball.","The car smashed into a tree."]},{"word":"snap","level":"C1","type":"v.","turkish":"Kırmak, kırılmak (ani, keskin sesle); şipşak fotoğrafçekmek; (hayvan) kapmak,ısırmaya çalışmak; ters","definition":"Break or cause to break suddenly and completely, typically with a sharp cracking sound; take a snapshot; (of an animal) make a sudden audible bite; speak or say something quickly and irritably.","examples":["The dry twig snapped under his foot.","She snapped a photo of the sunset."]},{"word":"soak","level":"C1","type":"v.","turkish":"Islatmak, suya bastırmak; (sıvıyı) emmek; (güneşte vb.) kalmak.","definition":"Make or allow (something) to become thoroughly wet by immersing it in liquid; (of a liquid) penetrate or permeate completely; bask or luxuriate in (something pleasant, e.g., sunshine).","examples":["You need to soak the beans overnight before cooking.","Use a cloth to soak up the spilled milk."]},{"word":"soar","level":"C1","type":"v","turkish":"Hızla yükselmek, fırlamak (fiyat, duygu vb.); süzülmek (kuş vb.).","definition":"Fly or rise high in the air; increase rapidly above the usual level.","examples":["The eagle soared high above the mountains.","Prices are expected to soar due to increased demand."]},{"word":"so-called","level":"B2","type":"adj.","turkish":"Sözde, güya (genellikle inanılmadığını veya doğruluğununşüpheli olduğunu belirtir).","definition":"Used to show that something or someone is commonly designated by the name or term specified, often implying that the name or term is inappropriate or inaccurate.","examples":["This so-called expert doesn't know what he's talking about.","Be wary of these so-called miracle cures."]},{"word":"socialist","level":"C1","type":"adj.","turkish":"Sosyalist.","definition":"Relating to or adhering to the principles of socialism (a political and economic theory of social organization which advocates that the means of production, distribution, and exchange should be owned or regulated by the community as a whole).","examples":["Several European countries have strong socialist parties.","The government implemented socialist policies aimed at reducing inequality."]},{"word":"sole","level":"C1","type":"adj.","turkish":"Tek, yegane.","definition":"One and only; single.","examples":["He was the sole survivor of the plane crash.","My sole reason for coming here is to see you."]},{"word":"solely","level":"C1","type":"adv.","turkish":"Sadece, yalnızca, sırf.","definition":"Not involving anyone or anything else; only.","examples":["The decision was based solely on financial factors.","He is solely responsible for the error."]},{"word":"solidarity","level":"C1","type":"n.","turkish":"Dayanışma, birlik.","definition":"Unity or agreement of feeling or action, especially among individuals with a common interest; mutual support within a group.","examples":["Workers showed solidarity with the strikers.","The event was organized to express solidarity with the victims."]},{"word":"solo","level":"C1","type":"adj.","turkish":"(adj) Solo, tek başına; (n) Solo (performans).","definition":"(adj) For or done by one person alone. (n) A piece or passage of music for one voice or instrument; something done by one person unaccompanied.","examples":["She embarked on a solo trip around the world. (adjective) The guitarist played an amazing solo. (noun)"]},{"word":"somehow","level":"B2","type":"adv.","turkish":"Birşekilde, her nasılsa.","definition":"In some way; by some means.","examples":["Don't worry, we'll get the money back somehow.","Somehow, I managed to pass the exam even though I hadn't studied much."]},{"word":"sometime","level":"B2","type":"adv.","turkish":"Bir ara, bir zamanlar, belirsiz bir zamanda.","definition":"At some unspecified or unknown time.","examples":["Let's meet up for coffee sometime next week.","This house was built sometime in the 18th century."]},{"word":"sophisticated","level":"B2","type":"adj.","turkish":"Sofistike, gelişmiş, karmaşık; görmüş geçirmiş, kültürlü.","definition":"Having, revealing, or involving a great deal of worldly experience and knowledge of fashion and culture; (of a machine, system, or technique) developed to a high degree of complexity.","examples":["The company uses sophisticated technology in its manufacturing process.","She has a very sophisticated taste in art. sophomore (n."]},{"word":"sovereignty","level":"C1","type":"n.","turkish":"Egemenlik, hükümranlık.","definition":"Supreme power or authority; the authority of a state to govern itself or another state.","examples":["The country fought to defend its national sovereignty.","The treaty recognized the sovereignty of the newly independent nation."]},{"word":"spam","level":"C1","type":"n.","turkish":"Spam, istenmeyen e-posta/mesaj.","definition":"Irrelevant or unsolicited messages sent over the Internet, typically to a large number of users, for the purposes of advertising, phishing, spreading malware, etc.","examples":["My inbox is full of spam.","Use a good filter to block spam emails."]},{"word":"span","level":"C1","type":"v.","turkish":"(v) Kapsamak, sürmek (zaman/mesafe olarak); uzanmak (köprü vb.); (n) Süre, zaman aralığı; açıklık, m","definition":"(v) Extend from side to side of or across; extend over (a long period). (n) The full extent of something from end to end; the amount of space that something covers; the length of time for which something lasts.","examples":["His career spanned more than fifty years. (verb) The bridge spans the river. (verb) The project was completed within a short time span. (noun)"]},{"word":"spare","level":"B2","type":"a","turkish":"(adj) Yedek; boş (zaman); (v) Ayırmak (zaman, para vb.); esirgemek, canını bağışlamak; kıymamak.","definition":"(adj) Additional to what is required for ordinary use; available to be used or drawn upon as needed; not currently in use or occupied. (v) Afford to give (time, money, or space); refrain from killing, injuring, or distressing.","examples":["Do you have a spare pen I could borrow? (adjective) What do you do in your spare time? (adjective) Could you spare a few minutes to help me? (verb - give) They begged the king to spare the prisoner's life. (verb - refrain from killing)"]},{"word":"spark","level":"C1","type":"v.","turkish":"Kıvılcımçıkarmak; (mecazi) başlatmak, ateşlemek, tetiklemek.","definition":"Emit sparks of fire or electricity; ignite; set off (a process or event).","examples":["Faulty wiring can spark a fire.","The incident sparked widespread protests. specialize (v."]},{"word":"specify","level":"B2","type":"v.","turkish":"Belirtmek, açıkça tanımlamak.","definition":"Identify clearly and definitely.","examples":["Please specify your requirements in detail.","The contract specifies the delivery date."]},{"word":"specimen","level":"C1","type":"n.","turkish":"Numune,örnek (test, inceleme vb. için).","definition":"An individual animal, plant, piece of a mineral, etc., used as an example of its species or type for scientific study or display; a sample for medical testing, especially of urine.","examples":["The museum has a large collection of insect specimens.","The doctor asked for a urine specimen."]},{"word":"spectacle","level":"C1","type":"n.","turkish":"Görünüm, manzara (etkileyici, görülmeye değer); (çoğul: spectacles) gözlük; rezalet, seyirlik olay.","definition":"A visually striking performance or display; an event or scene regarded in terms of its visual impact; (spectacles) dated term for eyeglasses.","examples":["The opening ceremony of the Olympics was a magnificent spectacle.","He made a spectacle of himself by shouting in public."]},{"word":"spectacular","level":"B2","type":"adj.","turkish":"Görkemli, muhteşem, olağanüstü, çarpıcı.","definition":"Beautiful in a dramatic and eye catching way.","examples":["The view from the top of the mountain was spectacular.","The fireworks display was absolutely spectacular."]},{"word":"spectator","level":"B2","type":"n.","turkish":"Seyirci, izleyici (spor, etkinlik vb.).","definition":"A person who watches at a show, game, or other event.","examples":["Thousands of spectators filled the stadium.","The match attracted a large number of spectators."]},{"word":"spectrum","level":"C1","type":"n.","turkish":"Spektrum, tayf; (mecazi)çeşitlilik, yelpaze.","definition":"A band of colors, as seen in a rainbow, produced by separation of the components of light by their different degrees of refraction according to wavelength; used to classify something, or suggest that it can be classified, in terms of its position on ","examples":["The research covers a wide spectrum of opinions.","Visible light is just a small part of the electromagnetic spectrum."]},{"word":"speculate","level":"B2","type":"v.","turkish":"Spekülasyon yapmak, tahminde bulunmak; (borsada vb.) oynamak.","definition":"To form a theory or conjecture about a subject without firm evidence; invest in stocks, property, or other ventures in the hope of gain but with the risk of loss.","examples":["It's useless to speculate about what might have happened.","He lost a lot of money speculating on the stock market."]},{"word":"speculation","level":"B2","type":"n.","turkish":"Spekülasyon, tahmin, kuram; (borsa) vurgunculuk.","definition":"The forming of a theory or conjecture without firm evidence; investment in stocks, property, or other ventures in the hope of gain but with the risk of loss.","examples":["There has been much speculation about the company's future.","Financial speculation can be very risky."]},{"word":"spel l","level":"C1","type":"n.","turkish":"Büyü, tılsım; (kısa) süre, nöbet (hava durumu, hastalık vb.).","definition":"A form of words used as a magical charm or incantation; a short period.","examples":["The witch cast a spell on the prince. (magic) We had a brief spell of warm weather in February. (period of time) He suffered a dizzy spell. (period of illness)"]},{"word":"sphere","level":"C1","type":"n.","turkish":"Küre; alan, saha,çevre (etki, ilgi vb.).","definition":"A round solid figure, or its surface, with every point on its surface equidistant from its center; an area of activity, interest, or expertise; a section of society or an aspect of life distinguished and separated from others.","examples":["The Earth is not a perfect sphere.","This issue falls outside my sphere of influence."]},{"word":"spice","level":"B2","type":"n.","turkish":"Baharat; (mecazi)çeşni, heyecan.","definition":"An aromatic or pungent vegetable substance used to flavor food, e.g., cloves, pepper, or cumin; an element providing interest or excitement.","examples":["Indian curries use a variety of spices.","Variety is the spice of life. (idiom) spill (v."]},{"word":"spine","level":"C1","type":"n.","turkish":"Omurga; (kitap) sırt; diken (bitki, hayvan).","definition":"A series of vertebrae extending from the skull to the pelvis; the backbone; the part of a book's jacket or cover that encloses the inner edges of the pages; a hard pointed defensive projection or structure.","examples":["He injured his spine in the accident.","The title of the book is printed on the spine."]},{"word":"spokesman","level":"B2","type":"n.","turkish":"Sözcü (erkek).","definition":"A man who makes statements on behalf of a group or individual.","examples":["A police spokesman confirmed the details of the incident.","He acted as the spokesman for the committee."]},{"word":"spokesperson","level":"B2","type":"n.","turkish":"Sözcü (cinsiyet belirtmez).","definition":"A person who makes statements on behalf of a group or individual (gender -neutral term).","examples":["The official spokesperson addressed the media.","A spokesperson for the company refused to comment."]},{"word":"spokeswoman","level":"B2","type":"n.","turkish":"Sözcü (kadın).","definition":"A woman who makes statements on behalf of a group or individual.","examples":["The spokeswoman outlined the organization's position.","She served as the campaign's chief spokeswoman."]},{"word":"sponsorship","level":"B2","type":"n.","turkish":"Sponsorluk, hamilik.","definition":"Financial support received from a sponsor (a person or organization that pays for or contributes to the costs involved in staging a sporting or artistic event in return for advertising).","examples":["The event relies heavily on corporate sponsorship.","They are seeking sponsorship for their charity walk."]},{"word":"spotlight","level":"C1","type":"n.","turkish":"Spotışığı, projektör; (mecazi) ilgi odağı, dikkat merkezi.","definition":"A lamp projecting a narrow, intense beam of light directly onto a place or person, especially a performer on stage; intense public attention or scrutiny.","examples":["The actor stood alone in the spotlight.","The issue was brought into the spotlight by the media coverage."]},{"word":"spouse","level":"C1","type":"n.","turkish":"Eş (karı veya koca).","definition":"A husband or wife, considered in relation to their partner.","examples":["Employees and their spouses are invited to the company party.","Please state your spouse's occupation on the form."]},{"word":"spy","level":"C1","type":"n.","turkish":"(n) Casus; (v) Casusluk yapmak; gizlice gözetlemek.","definition":"(n) A person employed by a government or other organization to secretly obtain information on an enemy or competitor. (v) Work for a government or other organization by secretly obtaining information about enemies or competitors; observe (someone) fu","examples":["James Bond is a famous fictional spy. (noun) He was accused of spying for a foreign government. (verb) I thought I saw someone spying on us through the window. (verb)"]},{"word":"squad","level":"C1","type":"n.","turkish":"Manga, takım (askeri, polis, spor vb.).","definition":"A small group of people having a particular task; a small group of soldiers assembled for drill or assigned to some special task; a group of players from which a team is chosen.","examples":["The bomb disposal squad arrived at the scene.","He is a member of the national football squad."]},{"word":"squeeze","level":"C1","type":"v.","turkish":"Sıkmak, sıkıştırmak; suyunu sıkmak; (zorla) sığmak/sığdırmak.","definition":"Firmly press (something soft or yielding), typically with one's fingers; extract (liquid or a soft substance) from something by compressing or twisting it firmly; manage to get into or through a narrow or restricted space.","examples":["Squeeze the lemon to get the juice.","Can we all squeeze into the car?"]},{"word":"stab","level":"C1","type":"v.","turkish":"Bıçaklamak, saplamak.","definition":"Thrust a knife or other pointed weapon into (someone) so as to wound or kill.","examples":["He was stabbed during a fight outside the bar.","The victim was stabbed multiple times."]},{"word":"stability","level":"C1","type":"n.","turkish":"İstikrara kavuşturmak/kavuşmak, dengelemek/dengeye gelmek, sabitlemek.","definition":"The state of being stable (not likely to give way or overturn; firmly fixed; not likely to change or fail; firmly established).","examples":["Political stability is essential for economic growth.","The structure lacks stability. stabilize (v."]},{"word":"stake","level":"C1","type":"n.","turkish":"Kazık (yereçakılan); (kumar, bahis) ortaya konan para; (mecazi) pay, hisse,çıkar ('at stake' = tehli","definition":"A strong wooden or metal post with a point at one end, driven into the ground to support a tree, form part of a fence, act as a boundary mark, etc.; a sum of money gambled on the outcome of a race, game, or other event; a share or interest in a busin","examples":["Tie the young tree to a stake for support. (post) He has a large financial stake in the company's success. (interest) Thousands of lives are at stake if the war continues. (at risk)"]},{"word":"stall","level":"B2","type":"n.","turkish":"Tezgah, stand (pazar, sergi vb.); bölme (ahır vb.).","definition":"A stand, booth, or compartment for the sale of goods in a market or large covered area; an individual compartment for an animal in a stable or barn.","examples":["She bought fresh vegetables from a market stall.","Each horse had its own stall in the stable. (Note: Verb 'stall' means delay or engine stop)"]},{"word":"stance","level":"B2","type":"n.","turkish":"Duruş (hem fiziksel hem mecazi), tavır, tutum.","definition":"The way in which someone stands, especially when deliberately adopted (as in cricket, golf, and other sports); stance; a person's attitude or standpoint on a matter.","examples":["What is the government's stance on this issue?","He adopted a defensive stance."]},{"word":"standing","level":"C1","type":"adj.","turkish":"Ayakta duran; daimi, kalıcı (komite, emir vb.); itibar, konum.","definition":"Remaining in force or use; permanent; existing indefinitely; position, status, or reputation. (Can also be a noun).","examples":["We have a standing invitation to visit them anytime. (permanent) He has a high standing in the community. (reputation - noun usage) The committee has standing authority to make decisions. (permanent)"]},{"word":"stark","level":"C1","type":"adj.","turkish":"Sert, katı (gerçeklik vb.);çıplak, boş; tam, katıksız.","definition":"Severe or bare in appearance or outline; unpleasantly or sharply clear; impossible to avoid; complete; sheer.","examples":["The room was decorated in stark black and white. (bare) The report painted a stark picture of poverty in the region. (harshly clear) There is a stark contrast between the two candidates. (complete)"]},{"word":"starve","level":"B2","type":"v.","turkish":"Açlıktanölmek, aç bırakmak,çok aç olmak.","definition":"Suffer or die or cause to suffer or die from hunger.","examples":["Millions of people starved during the famine.","What's for dinner?"]},{"word":"statistical","level":"C1","type":"adj.","turkish":"İstatistiksel.","definition":"Relating to or based on statistics (the practice or science of collecting and analyzing numerical data in large quantities).","examples":["The report includes detailed statistical analysis.","There is a statistical correlation between smoking and cancer."]},{"word":"steadily","level":"B2","type":"adv.","turkish":"İstikrarlı birşekilde, durmadan, sabit birşekilde.","definition":"In a regular and unwavering manner; gradually.","examples":["Prices have been rising steadily.","He looked steadily into her eyes."]},{"word":"steam","level":"B2","type":"n.","turkish":"Buhar, istim.","definition":"The vapor into which water is converted when heated, forming a white mist of minute water droplets in the air.","examples":["Be careful of the hot steam coming from the kettle.","Steam engines powered the industrial revolution."]},{"word":"steer","level":"C1","type":"v.","turkish":"Yönlendirmek, dümen kullanmak (araç, gemi vb.); (mecazi) yönlendirmek, idare etmek.","definition":"Guide or control the movement of (a vehicle, vessel, or aircraft); guide the movement or course of.","examples":["He carefully steered the boat through the narrow channel.","She tried to steer the conversation away from controversial topics."]},{"word":"stem","level":"C1","type":"n.","turkish":"(n) Sap (bitki), gövde; (kadeh vb.) sap; (v) -den kaynaklanmak, -den gelmek ('stem from'); durdurmak","definition":"(n) The main body or stalk of a plant or shrub, typically rising above ground but occasionally subterranean; the slender part of a wine glass, goblet, or similar vessel, connecting the bowl to the base. (v) Originate in or be caused by ('stem from');","examples":["She broke the stem of the wine glass. (noun) Many health problems stem from a poor diet. (verb - originate) Doctors tried to stem the bleeding. (verb - stop flow) The flower has a long stem. (noun - plant)"]},{"word":"stereotype","level":"C1","type":"n.","turkish":"Stereotip, basmakalıp düşünce/tip.","definition":"A widely held but fixed and oversimplified image or idea of a particular type of person or thing.","examples":["It's important to challenge gender stereotypes.","Not all teenagers fit the stereotype of being lazy and rebellious."]},{"word":"stimulate","level":"B2","type":"v.","turkish":"Uyarmak, teşvik etmek, canlandırmak.","definition":"Raise levels of physiological or nervous activity in (the body or any biological system); encourage interest or enthusiasm in.","examples":["Caffeine can stimulate the nervous system.","The teacher uses games to stimulate the children's interest. stimulus (n."]},{"word":"stir","level":"C1","type":"v.","turkish":"Karıştırmak (sıvı vb.); (hafifçe) kımıldatmak/kımıldamak; (duygu) uyandırmak, harekete geçirmek.","definition":"Move a spoon or other implement round and round in (a liquid or other substance) in order to mix it thoroughly; move or cause to move slightly; arouse strong feeling in (someone); prompt or provoke.","examples":["Stir the soup occasionally while it's cooking.","A slight breeze stirred the leaves on the trees."]},{"word":"storage","level":"C1","type":"n.","turkish":"Depolama, saklama; depo alanı.","definition":"The action or method of storing something for future use; space available for storing something.","examples":["We need more storage space for our files.","Cloud storage allows you to access your data from anywhere."]},{"word":"straightforward","level":"C1","type":"adj.","turkish":"Basit, anlaşılır, karmaşık olmayan; dürüst, açık sözlü.","definition":"Uncomplicated and easy to do or understand; (of a person) honest and frank.","examples":["The instructions were surprisingly straightforward.","She gave a straightforward account of what happened."]},{"word":"strain","level":"C1","type":"n.","turkish":"Gerginlik, zorlanma, baskı; incinme, burkulma; tür, soy, nesil (bakteri, bitki vb.).","definition":"A force tending to pull or stretch something to an extreme or damaging degree; an injury to a part of the body caused by overexertion; a severe or excessive demand on strength, resources, or abilities; a particular breed, stock, or variety of an anim","examples":["Working long hours puts a strain on family life. (pressure) He suffered a muscle strain while playing football. (injury) Scientists developed a new strain of disease-resistant rice. (variety)"]},{"word":"strand","level":"C1","type":"n.","turkish":"Tel, iplikçik (saç, ip vb.); (bir hikayenin/durumun) bölümü, unsuru.","definition":"A single thin length of something such as thread, fiber, or wire, especially as twisted together with others; an element that forms part of a complex whole.","examples":["She tucked a loose strand of hair behind her ear.","The novel weaves together several different plot strands."]},{"word":"strategic","level":"C1","type":"adj.","turkish":"Stratejik.","definition":"Relating to the identification of long-term or overall aims and interests and the means of achieving them; relating to the gaining of overall or long-term military advantage.","examples":["The company made a strategic decision to enter the Asian market.","The bridge is of great strategic importance."]},{"word":"strengthen","level":"B2","type":"v.","turkish":"Güçlendirmek, kuvvetlendirmek; güçlenmek.","definition":"Make or become stronger.","examples":["Exercise helps to strengthen muscles.","The government aims to strengthen ties with neighboring countries."]},{"word":"strictly","level":"B2","type":"adv.","turkish":"Kesinlikle, harfiyen, sıkı birşekilde; sadece, yalnızca.","definition":"In a way that involves rigid enforcement of rules or principles; exactly; only; solely.","examples":["Smoking is strictly forbidden here.","This information is strictly confidential."]},{"word":"striking","level":"B2","type":"adj.","turkish":"Çarpıcı, dikkatçekici, gözeçarpan.","definition":"Attracting attention by reason of being unusual, extreme, or prominent.","examples":["She bears a striking resemblance to her mother.","The most striking feature of the building is its tall tower. strip (n."]},{"word":"stroke","level":"B2","type":"n.","turkish":"İnme, felç; okşama, sıvazlama; vuruş (tenis, golf vb.); kulaç (yüzme).","definition":"A sudden disabling attack or loss of consciousness caused by an interruption in the flow of blood to the brain; an act of moving one's hand or an object across a surface, applying gentle pressure; a style of moving the arms and legs in swimming or ro","examples":["He suffered a severe stroke last year. (medical) She gave the cat a gentle stroke. (touch) His tennis serve has a powerful backhand stroke. (hit)"]},{"word":"structural","level":"C1","type":"adj.","turkish":"Yapısal.","definition":"Relating to or forming part of the structure of a building or other object; relating to the arrangement of and relations between the parts or elements of a complex whole.","examples":["The earthquake caused significant structural damage to the bridge.","The company needs to make major structural changes."]},{"word":"stun","level":"C1","type":"v.","turkish":"Sersemletmek, afallatmak,şoke etmek; bayıltmak.","definition":"Knock unconscious or into a dazed or semiconscious state; astonish or shock (someone) so that they are temporarily unable to react.","examples":["The blow stunned him for a moment.","We were stunned by the news of his sudden death."]},{"word":"stunning","level":"B2","type":"adj.","turkish":"Çok güzel,çarpıcı, nefes kesici; şaşırtıcı.","definition":"Extremely impressive or attractive; surprisingly impressive or shocking.","examples":["She looked absolutely stunning in her wedding dress.","The view from the mountaintop was stunning."]},{"word":"submission","level":"C1","type":"n.","turkish":"Teslim etme, sunma (belge, teklif vb.); boyun eğme, itaat; teslim olma.","definition":"The action or fact of accepting or yielding to a superior force or to the will or authority of another person; the action of presenting a proposal, application, or other document for consideration or judgment.","examples":["The deadline for the submission of essays is next Friday. (presenting document) He demanded complete submission from his followers. (yielding)"]},{"word":"subscriber","level":"C1","type":"n.","turkish":"Abone.","definition":"A person who receives a publication regularly by paying in advance; a person who pays to receive or access a service.","examples":["The magazine has thousands of loyal subscribers.","YouTube channels rely on subscribers."]},{"word":"subscription","level":"C1","type":"n.","turkish":"Abonelik.","definition":"An agreement to receive something regularly by paying in advance.","examples":["I have an annual subscription to the streaming service.","You can cancel your subscription at any time."]},{"word":"subsequent","level":"B2","type":"adj.","turkish":"Sonraki, ardından gelen, müteakip.","definition":"Coming after something in time; following.","examples":["The first meeting was successful, and subsequent meetings built on that progress.","Subsequent events proved him right."]},{"word":"subsequently","level":"B2","type":"adv.","turkish":"Sonradan, akabinde, ardından.","definition":"After a particular thing has happened; afterward.","examples":["He was injured in the accident and subsequently died.","The plan was initially rejected but was subsequently approved."]},{"word":"subsidy","level":"C1","type":"n.","turkish":"Sübvansiyon, devlet desteği, mali yardım.","definition":"A sum of money granted by the state or a public body to help an industry or business keep the price of a commodity or service low.","examples":["Farmers receive government subsidies.","The company relies on state subsidies to operate."]},{"word":"substantial","level":"C1","type":"adj.","turkish":"Önemli (miktarda), büyük, hatırı sayılır; sağlam, dayanıklı.","definition":"Of considerable importance, size, or worth; real and tangible; strongly built or made.","examples":["The company made a substantial profit last year.","We have gathered a substantial amount of evidence."]},{"word":"substantially","level":"C1","type":"adv.","turkish":"Büyükölçüde,önemli derecede; esasen.","definition":"To a great or significant extent; for the most part; essentially.","examples":["Prices have increased substantially.","The new model is substantially the same as the old one."]},{"word":"substitute","level":"C1","type":"n.","turkish":"(n) Yedek (oyuncu vb.), vekil; yerine geçenşey; (v) Yerine geçmek/koymak, vekalet etmek.","definition":"(n) A person or thing acting or serving in place of another. (v) Use or add in place of; act or serve as a substitute for.","examples":["The coach brought on a substitute in the second half. (noun) You can substitute honey for sugar in this recipe. (verb)"]},{"word":"substitution","level":"C1","type":"n.","turkish":"Yerine geçirme/koyma, değiştirme; oyuncu değişikliği.","definition":"The action of replacing someone or something with another person or thing.","examples":["The coach made a tactical substitution.","Substitution of margarine for butter is possible in this recipe."]},{"word":"subtle","level":"C1","type":"adj.","turkish":"İnce, zarif, hemen gözeçarpmayan; zekice, ustaca.","definition":"(especially of a change or distinction) So delicate or precise as to be difficult to analyze or describe; making use of clever and indirect methods to achieve something.","examples":["There is a subtle difference between the two colors.","He used subtle hints to convey his meaning."]},{"word":"suburb","level":"B2","type":"n.","turkish":"Banliyö, kenar mahalle, varoş.","definition":"An outlying district of a city, especially a residential one.","examples":["They live in a quiet suburb just outside London.","Many people commute from the suburbs to work in the city."]},{"word":"suburban","level":"C1","type":"adj.","turkish":"Banliyö(ye ait), kenar mahalle(ye ait).","definition":"Relating to or characteristic of a suburb.","examples":["They lead a typical suburban lifestyle.","The house is located in a peaceful suburban area."]},{"word":"success ion","level":"C1","type":"n.","turkish":"Ardışıklık, birbirini izleme, silsile; veraset, yerine geçme (taht, makam vb.).","definition":"A number of people or things sharing a specified characteristic and following one after the other; the action or process of inheriting a title, office, property, etc.","examples":["A succession of visitors came to the door.","The line of succession to the throne was clear."]},{"word":"successive","level":"C1","type":"adj.","turkish":"Ardışık, art arda gelen, birbirini izleyen.","definition":"Following one another or following others.","examples":["The team won the championship for three successive years.","He missed successive meetings without explanation."]},{"word":"successor","level":"C1","type":"n.","turkish":"Halef, varis, yerine geçen kişi/şey.","definition":"A person or thing that succeeds another.","examples":["The CEO announced his retirement and named his successor.","Who will be the likely successor to the party leader?"]},{"word":"suck","level":"C1","type":"v.","turkish":"Emmek; içineçekmek; (argo) berbat olmak,çok kötü olmak.","definition":"Draw into the mouth by contracting the muscles of the lips and mouth to make a partial vacuum; draw in a specified direction by creating a vacuum; (informal) be very bad, unpleasant, or unsatisfactory.","examples":["The baby was sucking its thumb.","The vacuum cleaner sucked up all the dirt."]},{"word":"sue","level":"C1","type":"v.","turkish":"Dava etmek, dava açmak.","definition":"Institute legal proceedings against (a person or institution), typically for redress.","examples":["She decided to sue the company for damages.","He threatened to sue them for breach of contract."]},{"word":"suffering","level":"B2","type":"n.","turkish":"Acı,ıstırap, cefa.","definition":"The state of undergoing pain, distress, or hardship.","examples":["The war caused immense human suffering.","The organization works to alleviate poverty and suffering."]},{"word":"sufficient","level":"B2","type":"adj.","turkish":"Yeterli, kafi.","definition":"Enough; adequate.","examples":["Do we have sufficient food for everyone?","One hour should be sufficient time to complete the task."]},{"word":"sufficiently","level":"B2","type":"adv.","turkish":"Yeterince, yeteri kadar.","definition":"To an adequate degree; enough.","examples":["Make sure the meat is sufficiently cooked.","Are you sufficiently prepared for the exam?"]},{"word":"suicide","level":"C1","type":"n.","turkish":"İntihar.","definition":"The action of killing oneself intentionally.","examples":["Suicide rates have sadly increased among young people.","Anyone feeling desperate should seek help rather than considering suicide. suite (n."]},{"word":"summit","level":"C1","type":"n.","turkish":"Zirve (dağ); zirve toplantısı (liderler vb.).","definition":"The highest point of a hill or mountain; a meeting between heads of government.","examples":["They reached the summit after a long climb.","The world leaders gathered for an economic summit. super (adj."]},{"word":"superb","level":"C1","type":"adj.","turkish":"Harika, mükemmel, muhteşem.","definition":"Excellent; impressively splendid.","examples":["The meal was absolutely superb.","She gave a superb performance as Juliet."]},{"word":"superinte ndent","level":"C1","type":"n.","turkish":"Yönetici, müdür; (polis) komiser/emniyet müdürü; bina görevlisi (ABD).","definition":"A person who manages or supervises an organization or activity; a high -ranking police officer; (North American) a person who is responsible for the maintenance of a large building.","examples":["The school superintendent addressed the board members.","He reported the crime to the police superintendent."]},{"word":"superior","level":"C1","type":"adj.","turkish":"Üstün, daha iyi;üst (makam).","definition":"Higher in rank, status, or quality; better than average or than others of the same type.","examples":["This model is superior to the previous version in every way.","You need to get approval from your superior officer."]},{"word":"supervise","level":"C1","type":"v.","turkish":"Denetlemek, gözetmek, nezaret etmek.","definition":"Observe and direct the execution of (a task, project, or activity) or the work of (a person).","examples":["She was hired to supervise the construction project.","Teachers need to supervise children closely in the playground."]},{"word":"supervision","level":"C1","type":"n.","turkish":"Denetim, gözetim, nezaret.","definition":"The action of supervising someone or something.","examples":["Young children require constant supervision.","The project was completed under the supervision of experienced engineers."]},{"word":"supervisor","level":"C1","type":"n.","turkish":"Süpervizör, denetçi, gözetmen,şef.","definition":"A person who supervises a person or activity.","examples":["If you have a problem, please speak to your supervisor.","He works as a shift supervisor at the factory."]},{"word":"supplement","level":"C1","type":"n.","turkish":"(n) Ek, ilave, takviye (gıda, vitamin vb.); (v) Takviye etmek, eklemek, tamamlamak.","definition":"(n) Something that completes or enhances something else when added to it. (v) Add an extra element or amount to.","examples":["Many people take vitamin supplements. (noun) He works part-time to supplement his income. (verb)"]},{"word":"supportive","level":"C1","type":"adj.","turkish":"Destekleyici, yardımcı.","definition":"Providing encouragement or emotional help.","examples":["Her family was very supportive of her decision.","Creating a supportive work environment benefits everyone."]},{"word":"supposedly","level":"C1","type":"adv.","turkish":"Sözde, güya, iddiaya göre.","definition":"According to what is generally assumed or believed (often used to indicate that the speaker doubts the truth of the statement).","examples":["The repairs are supposedly guaranteed for a year.","He was supposedly seen leaving the country last night."]},{"word":"suppress","level":"C1","type":"v.","turkish":"Bastırmak, دبفش etmek (isyan, duygu, kanıt vb.); (gelişmeyi) engellemek.","definition":"Forcibly put an end to; prevent the development, action, or expression of (a feeling, impulse, idea, etc.); restrain.","examples":["The government tried to suppress news of the protest.","She struggled to suppress a giggle."]},{"word":"supreme","level":"C1","type":"adj.","turkish":"Yüce, ulu, en yüksek,üstün.","definition":"Strongest, most important, or most powerful; highest in rank or authority.","examples":["The Supreme Court is the highest court in the land.","He died making the supreme sacrifice for his country."]},{"word":"surge","level":"C1","type":"n.","turkish":"(n) Ani artış, dalgalanma, hücum (enerji, duygu, kalabalık vb.); (v) Dalgalanmak, aniden artmak, hüc","definition":"(n) A sudden powerful forward or upward movement, especially by a crowd or by a natural force such as the waves or tide; a sudden large increase, typically a temporary one. (v) Move suddenly and powerfully forward or upward; increase suddenly and dra","examples":["There has been a recent surge in demand for electric cars. (noun) The crowd surged towards the stage. (verb) Oil prices surged after the announcement. (verb)"]},{"word":"surgeon","level":"B2","type":"n.","turkish":"Cerrah.","definition":"A medical practitioner qualified to practice surgery.","examples":["The surgeon performed a complex operation.","She is training to become a heart surgeon."]},{"word":"surgical","level":"C1","type":"adj.","turkish":"Cerrahi, ameliyatla ilgili.","definition":"Relating to or used in surgery.","examples":["The patient requires surgical intervention.","Doctors wear surgical masks and gloves."]},{"word":"surplus","level":"C1","type":"n.","turkish":"Fazla, fazlalık (üretim, bütçe vb.).","definition":"An amount of something left over when requirements have been met; an excess of production or supply over demand.","examples":["The country has a large budget surplus.","Farmers sold their surplus produce at the market."]},{"word":"surrender","level":"C1","type":"v.","turkish":"Teslim olmak; teslim etmek, vazgeçmek.","definition":"Stop resisting to an enemy or opponent and submit to their authority; give up or hand over (a person, right, or possession), typically on compulsion or demand.","examples":["The defeated army was forced to surrender.","He refused to surrender his principles."]},{"word":"surveillance","level":"C1","type":"n.","turkish":"Gözetim, gözetleme, izleme (polis vb.).","definition":"Close observation, especially of a suspected spy or criminal.","examples":["The police kept the suspect under constant surveillance.","Increased use of CCTV cameras has led to greater public surveillance."]},{"word":"survival","level":"B2","type":"n.","turkish":"Hayatta kalma, sağ kalma.","definition":"The state or fact of continuing to live or exist, typically in spite of an accident, ordeal, or difficult circumstances.","examples":["Their chances of survival were slim.","Basic survival skills include finding food and water."]},{"word":"survivor","level":"B2","type":"n.","turkish":"Hayatta kalan kimse, sağ kalan kimse.","definition":"A person who survives, especially a person remaining alive after an event in which others have died.","examples":["He was the sole survivor of the plane crash.","Rescue teams searched for survivors in the rubble."]},{"word":"suspend","level":"B2","type":"v.","turkish":"Askıya almak, geçici olarak durdurmak; (okuldan/işten) uzaklaştırmak; asmak.","definition":"Temporarily prevent from continuing or being in force or effect; officially debar (someone) from a job, school, or privilege for a time; hang (something) from somewhere.","examples":["Train services were suspended due to heavy snow.","The student was suspended from school for fighting."]},{"word":"susp ension","level":"C1","type":"n.","turkish":"Askıya alma, durdurma; (okuldan/işten) uzaklaştırma; süspansiyon (araç); asma, askı.","definition":"The action of suspending someone or something or the condition of being suspended; temporary removal from a job or position; the system of springs and shock absorbers by which a vehicle is supported on its wheels.","examples":["The player received a two -game suspension for misconduct.","The car has excellent suspension, making the ride very smooth."]},{"word":"suspicion","level":"C1","type":"n.","turkish":"Şüphe, kuşku.","definition":"A feeling or thought that something is possible, likely, or true; a feeling or belief that someone is guilty of an illegal, dishonest, or unpleasant action.","examples":["His strange behavior aroused suspicion.","She had a nagging suspicion that he was lying."]},{"word":"suspicious","level":"C1","type":"adj.","turkish":"Şüpheli, kuşkulu;şüpheci.","definition":"Having or showing a cautious distrust of someone or something; causing one to have the idea or impression that someone or something is questionable, dishonest, or dangerous.","examples":["The police are treating the fire as suspicious.","She gave him a suspicious glance."]},{"word":"sustain","level":"C1","type":"v.","turkish":"Sürdürmek, devam ettirmek; (zarar, kayıp) görmek, -e uğramak; desteklemek, ayakta tutmak.","definition":"To strengthen or support physically or mentally; undergo or suffer (something unpleasant, especially an injury); cause to continue or be prolonged for an extended period or without interruption.","examples":["It's difficult to sustain enthusiasm for a long project.","He sustained serious injuries in the accident."]},{"word":"sustainable","level":"B2","type":"adj.","turkish":"Sürdürülebilir (çevre, ekonomi vb.), devam ettirilebilir.","definition":"Able to be maintained at a certain rate or level; conserving an ecological balance by avoiding depletion of natural resources.","examples":["We need to find sustainable sources of energy.","The company is committed to sustainable business practices."]},{"word":"swallow","level":"B2","type":"v.","turkish":"Yutmak, yutkunmak; (mecazi) inanmak, kanmak; bastırmak (duygu).","definition":"Cause or allow (something, especially food or drink) to pass down the throat; accept or believe (something) without question or suspicion; resist expressing (a feeling) or reacting to (an emotion).","examples":["Chew your food properly before you swallow.","He found her story difficult to swallow."]},{"word":"sword","level":"C1","type":"n.","turkish":"Kılıç.","definition":"A weapon with a long metal blade and a hilt with a hand guard, used for thrusting or striking and now typically worn as part of ceremonial dress.","examples":["Knights used swords and shields in battle.","The museum displayed ancient Japanese swords."]},{"word":"symbolic","level":"C1","type":"adj.","turkish":"Sembolik, simgesel.","definition":"Serving as a symbol; involving the use of symbols or symbolism.","examples":["The dove is symbolic of peace.","The ceremony held great symbolic importance."]},{"word":"sympathetic","level":"B2","type":"adj.","turkish":"Sempatik, cana yakın; anlayışlı, halden anlayan, duygudaş.","definition":"Feeling, showing, or expressing sympathy (feelings of pity and sorrow for someone else's misfortune); showing approval of or favor toward an idea or action.","examples":["She was very sympathetic when I told her about my problem.","The manager was sympathetic to her request for time off."]},{"word":"syndrome","level":"C1","type":"n.","turkish":"Sendrom (belirtiler bütünü).","definition":"A group of symptoms which consistently occur together, or a condition characterized by a set of associated symptoms.","examples":["Down syndrome is a genetic condition.","Chronic fatigue syndrome affects many people. synthesis (n."]},{"word":"systematic","level":"C1","type":"adj.","turkish":"Sistematik, düzenli.","definition":"Done or acting according to a fixed plan or system; methodical.","examples":["We need a systematic approach to solve this problem.","A systematic search of the area was conducted."]},{"word":"tackle","level":"B2","type":"v.","turkish":"(v) Ele almak,çözmeyeçalışmak (sorun vb.); (sporda) topu kapmayaçalışmak, müdahale etmek; (n) (Spord","definition":"(v) Make determined efforts to deal with (a difficult problem or task); (in sport) try to take the ball from (an opponent); engage in discussion or argument with. (n) An act of tackling someone, especially in football or rugby; the equipment required","examples":["The government must tackle the issue of unemployment. (verb - deal with) He was penalized for a dangerous tackle. (noun - sports) The defender tackled the striker just outside the box. (verb - sports)"]},{"word":"tactic","level":"C1","type":"n.","turkish":"Taktik, manevra.","definition":"An action or strategy carefully planned to achieve a specific end.","examples":["Delaying the decision was just a clever tactic.","The team changed their tactics in the second half."]},{"word":"tactical","level":"C1","type":"adj.","turkish":"Taktiksel, taktik(le ilgili).","definition":"Relating to or constituting actions carefully planned to gain a specific end; relating to actions planned to gain a military advantage in a battle or engagement.","examples":["The commander made a brilliant tactical decision.","They engaged in tactical voting to defeat the main candidate."]},{"word":"tag","level":"B2","type":"n.","turkish":"(n) Etiket; (v) Etiketlemek; (sosyal medyada) etiketlemek; (oyun) ebelemek.","definition":"(n) A label attached to someone or something for the purpose of identification or to give other information. (v) Attach a label to; add to something, especially as an afterthought or with no real connection; link to someone's profile in a social medi","examples":["Check the price tag before you buy it. (noun) Please tag me in the photos on Facebook. (verb) All items must be tagged with a security device. (verb)"]},{"word":"tap","level":"B2","type":"v.","turkish":"(v) Hafifçe vurmak; (kaynaktan) yararlanmak, kullanmak; (telefon vb.) dinlemek; (n) Musluk (İngilter","definition":"(v) Strike (someone or something) with a quick light blow or blows; exploit or make use of (a source of power, energy, etc.); connect a device to (a telephone line) so that conversations can be listened to secretly. (n) (chiefly British) A faucet; a ","examples":["She tapped him on the shoulder. (verb - hit lightly) Turn off the tap properly. (noun - faucet, UK) We need to tap into new markets to grow the business. (verb - make use of)"]},{"word":"taxpayer","level":"C1","type":"n.","turkish":"Vergi mükellefi.","definition":"A person who pays taxes.","examples":["Government spending is funded by taxpayers.","The new project will cost taxpayers millions."]},{"word":"technological","level":"B2","type":"adj.","turkish":"Teknolojik.","definition":"Relating to or using technology.","examples":["We live in an era of rapid technological change.","Technological advances have transformed communication. teen (n., adj."]},{"word":"temple","level":"B2","type":"n.","turkish":"Tapınak, mabet;şakak (başın yan tarafı).","definition":"A building devoted to the worship, or regarded as the dwelling place, of a god or gods or other objects of religious reverence; the flat part of the side of the head between the forehead and the ear.","examples":["Ancient Greeks built magnificent temples to their gods. (building) He had a throbbing pain in his right temple. (head)"]},{"word":"temporarily","level":"B2","type":"adv.","turkish":"Geçici olarak.","definition":"For a limited period of time; not permanently.","examples":["The office will be temporarily closed for renovations.","She is temporarily staying with her parents."]},{"word":"tempt","level":"C1","type":"v.","turkish":"Ayartmak, baştançıkarmak, özendirmek; (şeytana) uymak.","definition":"Entice or attempt to entice (someone) to do or acquire something that they find attractive but know to be wrong or unwise.","examples":["Don't tempt me with that delicious cake; I'm on a diet!","He was tempted to take the easy way out."]},{"word":"tenant","level":"C1","type":"n.","turkish":"Kiracı.","definition":"A person who occupies land or property rented from a landlord.","examples":["The tenants complained to the landlord about the leaky roof.","New tenants moved into the apartment next door."]},{"word":"tendency","level":"B2","type":"n.","turkish":"Eğilim, meyil.","definition":"An inclination toward a particular characteristic or type of behavior.","examples":["He has a tendency to exaggerate.","There is a growing tendency for people to work from home."]},{"word":"tender","level":"C1","type":"adj.","turkish":"Yumuşak (et vb.); hassas, narin; şefkatli, sevecen; (vücut kısmı) ağrıyan, hassas.","definition":"Showing gentleness and concern or sympathy; (of food) easy to cut or chew; soft; (of a part of the body) sensitive to pain.","examples":["The steak was beautifully cooked and very tender. (food) She gave him a tender kiss on the cheek. (gentle) My bruised arm is still tender. (sensitive to pain)"]},{"word":"tension","level":"B2","type":"n.","turkish":"Gerginlik, gerilim (duygusal, politik, fiziksel).","definition":"Mental or emotional strain; a strained political or social state or relationship; the state of being stretched tight.","examples":["You could feel the tension in the room before the exam.","Rising political tension led to protests."]},{"word":"tenure","level":"C1","type":"n.","turkish":"Görev süresi; (akademik) kadro güvencesi; (mülk) kullanma hakkı.","definition":"The holding of an office; the conditions under which land or buildings are held or occupied; guaranteed permanent employment, especially as a teacher or professor, after a probationary period.","examples":["During his tenure as CEO, the company grew significantly.","She was granted tenure after seven years at the university."]},{"word":"terminal","level":"C1","type":"n.","turkish":"(n) Terminal (havaalanı, otogar vb.); uç, kutup (elektrik); (adj) Ölümcül, son (hastalık); son, niha","definition":"(n) The end of a railway or other transport route, or a station at such a point; a point of connection for closing an electric circuit. (adj) (of a disease) Predicted to lead to death, especially slowly; incurable; situated at or forming the end or e","examples":["We waited at the bus terminal. (noun) He was diagnosed with terminal cancer. (adjective - disease) Connect the wire to the positive terminal. (noun - electric)"]},{"word":"ter minate","level":"C1","type":"v.","turkish":"Son vermek, bitirmek, feshetmek (sözleşme, gebelik vb.).","definition":"Bring to an end.","examples":["The company decided to terminate the contract.","His employment was terminated due to misconduct. terms (n."]},{"word":"terrain","level":"C1","type":"n.","turkish":"Arazi, bölge (özellikle fiziksel yapısı).","definition":"A stretch of land, especially with regard to its physical features.","examples":["The mountainous terrain made hiking difficult.","They navigated the rough terrain in a four-wheel-drive vehicle."]},{"word":"terribly","level":"B2","type":"adv.","turkish":"Çok, son derece; korkunç birşekilde, feci.","definition":"Very; extremely; very badly or unpleasantly.","examples":["I'm terribly sorry for being late.","He played terribly and lost the match easily. terrific (adj."]},{"word":"terrify","level":"B2","type":"v.","turkish":"Çok korkutmak, dehşete düşürmek.","definition":"Cause to feel extreme fear.","examples":["The thought of speaking in public terrifies me.","The horror film terrified the children."]},{"word":"territory","level":"B2","type":"n.","turkish":"Bölge, arazi; (ülkeye ait) toprak; (hayvan) bölgesi; (mecazi) alan, saha.","definition":"An area of land under the jurisdiction of a ruler or state; an area defended by an animal or group of animals against others of the same sex or species; an area of knowledge or experience.","examples":["The company is expanding into new territories.","Lions mark their territory to warn off rivals."]},{"word":"terror","level":"B2","type":"n.","turkish":"Terör, dehşet, korku; terör eylemi.","definition":"Extreme fear; the use of extreme fear to intimidate people; a person or thing that causes extreme fear.","examples":["She screamed in terror as the building collapsed.","The bombing campaign spread terror throughout the city."]},{"word":"terrorism","level":"B2","type":"n.","turkish":"Terörizm, terör.","definition":"The unlawful use of violence and intimidation, especially against civilians, in the pursuit of political aims.","examples":["Governments worldwide are working to combat terrorism.","The attack was condemned as an act of terrorism."]},{"word":"terrorist","level":"B2","type":"n.","turkish":"Terörist.","definition":"A person who uses unlawful violence and intimidation, especially against civilians, in the pursuit of political aims.","examples":["The police arrested several suspected terrorists.","Terrorist groups pose a threat to global security."]},{"word":"testify","level":"C1","type":"v.","turkish":"Tanık olarak ifade vermek (mahkemede); tanıklık etmek, göstermek.","definition":"Give evidence as a witness in a law court; serve as evidence or proof of something's existing or being the case.","examples":["She agreed to testify against her former boss.","The results testify to the effectiveness of the treatment."]},{"word":"testimony","level":"C1","type":"n.","turkish":"Tanıklık,şahitlik, ifade (mahkemede); kanıt.","definition":"A formal written or spoken statement, especially one given in a court of law; evidence or proof provided by the existence or appearance of something.","examples":["The witness gave powerful testimony in court.","His changed behavior is testimony to the therapy's success."]},{"word":"testing","level":"B2","type":"n.","turkish":"Test etme, deneme, sınama.","definition":"The process of using or trying something to see if it works, is suitable, or is true.","examples":["Extensive testing is required before launching a new product.","Drug testing is mandatory for athletes."]},{"word":"textbook","level":"B2","type":"n.","turkish":"Ders kitabı; (mecazi) tipikörnek.","definition":"A book used as a standard work for the study of a particular subject; a book used by students; something providing a typical example of a principle or situation.","examples":["Please bring your history textbooks to the next class.","His handling of the situation was a textbook example of good leadership."]},{"word":"texture","level":"C1","type":"n.","turkish":"Doku, yapı (kumaş, yiyecek, yüzey vb.).","definition":"The feel, appearance, or consistency of a surface or substance.","examples":["The fabric has a soft, smooth texture.","I love the creamy texture of this dessert."]},{"word":"thankfully","level":"C1","type":"adv.","turkish":"Şükürler olsun ki, neyse ki; minnetle.","definition":"Used to express relief or gratitude about something; in a relieved or grateful manner.","examples":["Thankfully, no one was seriously injured in the accident.","She accepted the gift thankfully."]},{"word":"theatrical","level":"C1","type":"adj.","turkish":"Tiyatro(yla ilgili); (davranış) yapmacık, abartılı, teatral.","definition":"Relating to acting, actors, or the theater; behaving in an exaggerated way to attract attention.","examples":["She is studying theatrical design.","He made a grand, theatrical entrance."]},{"word":"theft","level":"B2","type":"n.","turkish":"Hırsızlık.","definition":"The action or crime of stealing.","examples":["Car theft is a common problem in this area.","He was arrested for identity theft."]},{"word":"theology","level":"C1","type":"n.","turkish":"Teoloji, ilahiyat, din bilimi.","definition":"The study of the nature of God and religious belief.","examples":["He studied theology at seminary.","Christian theology has evolved over centuries."]},{"word":"theoretical","level":"C1","type":"adj.","turkish":"Teorik, kuramsal.","definition":"Concerned with or involving the theory of a subject or area of study rather than its practical application; based on or calculated through theory rather than experience or practice.","examples":["The course covers both theoretical and practical aspects of engineering.","His argument is purely theoretical and lacks evidence."]},{"word":"therapist","level":"B2","type":"n.","turkish":"Terapist.","definition":"A person skilled in a particular kind of therapy (e.g., psychotherapist, physical therapist).","examples":["She sees a therapist regularly to discuss her anxiety.","A physical therapist helped him recover after the injury. thereafter (adv."]},{"word":"thorough","level":"B2","type":"adj.","turkish":"Kapsamlı, detaylı, eksiksiz; dikkatli, titiz.","definition":"Complete with regard to every detail; not superficial or partial; performed or written with great care and completeness.","examples":["The police conducted a thorough investigation.","Please do a thorough review of the document before signing."]},{"word":"thoroughly","level":"B2","type":"adv.","turkish":"Tamamen, baştan sona, etraflıca;çok, son derece.","definition":"In a thorough manner; completely; very much; greatly.","examples":["Read the instructions thoroughly before starting.","We thoroughly enjoyed our vacation."]},{"word":"thoughtful","level":"C1","type":"adj.","turkish":"Düşünceli, nazik; dalgın, düşünceli.","definition":"Showing consideration for the needs of other people; absorbed in or involving thought.","examples":["It was very thoughtful of you to bring flowers.","He had a thoughtful expression on his face."]},{"word":"thought -provoking","level":"C1","type":"adj.","turkish":"Düşündürücü.","definition":"Stimulating careful consideration or attention.","examples":["The film raises some thought-provoking questions about society.","It was a thought-provoking article."]},{"word":"thread","level":"C1","type":"n.","turkish":"İplik; (mecazi) konu, bağlantı; (vida) diş.","definition":"A long, thin strand of cotton, nylon, or other fibers used in sewing or weaving; a theme or characteristic running throughout a situation or piece of writing; the helical ridge on the outside of a screw or bolt or on the inside of a nut.","examples":["Can you pass me the needle and thread?","I lost the thread of the conversation."]},{"word":"threshold","level":"C1","type":"n.","turkish":"Eşik (kapı); eşik, sınır (başlangıç noktası).","definition":"A strip of wood, metal, or stone forming the bottom of a doorway and crossed in entering a house or room; the magnitude or intensity that must be exceeded for a certain reaction, phenomenon, result, or condition to occur or be manifested.","examples":["He carried his bride across the threshold. (doorway) She is on the threshold of a brilliant career. (starting point) My pain threshold is quite high. (limit)"]},{"word":"thrilled","level":"C1","type":"adj.","turkish":"Çok heyecanlı, sevinçten havalara uçan.","definition":"Feeling intense excitement and pleasure.","examples":["She was thrilled to win the competition.","We were absolutely thrilled with the results."]},{"word":"thrive","level":"C1","type":"v.","turkish":"Gelişmek, serpilmek, başarılı olmak, (işleri) yolunda gitmek.","definition":"(of a child, animal, or plant) Grow or develop well or vigorously; prosper; flourish.","examples":["The business continues to thrive despite the recession.","Children thrive in a supportive environment."]},{"word":"thumb","level":"B2","type":"n.","turkish":"Başparmak.","definition":"The short, thick first digit of the human hand, set lower and apart from the other four and opposable to them.","examples":["He hit his thumb with the hammer.","She gave me a thumbs -up gesture (using her thumb)."]},{"word":"tide","level":"C1","type":"n.","turkish":"Gelgit, medcezir; (mecazi) akım, gidişat.","definition":"The alternate rising and falling of the sea, usually twice in each lunar day at a particular place, due to the attraction of the moon and sun; a powerful surge of feeling or trend of events.","examples":["We walked along the beach at low tide.","The tide of public opinion is turning against the government."]},{"word":"tighten","level":"C1","type":"v.","turkish":"Sıkmak, sıkılaştırmak; (kontrolü vb.) sıkılaştırmak.","definition":"Make or become tight or tighter.","examples":["Tighten the screws firmly.","The government plans to tighten border controls."]},{"word":"timber","level":"C1","type":"n.","turkish":"Kereste, tomruk; orman (ağaçlık alan).","definition":"Wood prepared for use in building and carpentry; trees grown for timber.","examples":["The house was built using local timber.","Large areas of forest are cut down for timber."]},{"word":"timely","level":"C1","type":"adj.","turkish":"Zamanında yapılan/olan, tam zamanında, uygun zamanda.","definition":"Done or occurring at a favorable or useful time; opportune.","examples":["His intervention was timely and prevented a crisis.","Thank you for the timely reminder."]},{"word":"timing","level":"B2","type":"n.","turkish":"Zamanlama.","definition":"The choice, judgment, or control of when something should be done.","examples":["The timing of the announcement was perfect.","His comic timing is impeccable."]},{"word":"tissue","level":"B2","type":"n.","turkish":"Doku (biyolojik); kağıt mendil; ince kağıt.","definition":"Any of the distinct types of material of which animals or plants are made, consisting of specialized cells and their products; soft absorbent paper used as a handkerchief or towel; thin, soft paper used for wrapping or packing.","examples":["Muscle tissue requires protein to grow. (body) Could you pass me a tissue? (paper handkerchief) The gift was wrapped in delicate tissue paper. (wrapping)"]},{"word":"tobacco","level":"C1","type":"n.","turkish":"Tütün.","definition":"A preparation of the nicotine-rich leaves of an American plant, which are cured by a process of drying and fermentation for smoking or chewing.","examples":["Smoking tobacco is harmful to health.","The state imposed higher taxes on tobacco products."]},{"word":"tolerance","level":"C1","type":"n.","turkish":"Hoşgörü, tolerans; dayanıklılık, tolerans (ilaç vb.).","definition":"The ability or willingness to tolerate something, in particular the existence of opinions or behavior that one does not necessarily agree with; the capacity to endure continued subjection to something, especially a drug, transplant, antigen, or envir","examples":["Religious tolerance is important in a diverse society.","Some bacteria develop tolerance to antibiotics."]},{"word":"tolerate","level":"C1","type":"v.","turkish":"Hoş görmek, tahammül etmek, katlanmak, tolere etmek.","definition":"Allow the existence, occurrence, or practice of (something that one does not necessarily like or agree with) without interference; accept or endure (someone or something unpleasant or disliked) with forbearance.","examples":["We do not tolerate racism in our school.","I cannot tolerate his constant complaining."]},{"word":"top","level":"C1","type":"v.","turkish":"Geçmek, aşmak; zirvede olmak/bitirmek;üstünü kaplamak.","definition":"Exceed (an amount, level, or number); be higher than; be at the highest place or rank in; provide with a top or topping.","examples":["Sales are expected to top $10 million this year. (exceed) She topped the class in the final exams. (be the best) Top the pizza with cheese before baking. (cover the top)"]},{"word":"torture","level":"C1","type":"n.","turkish":"(n) İşkence; (mecazi) büyük acı, eziyet; (v) İşkence etmek.","definition":"(n) The action or practice of inflicting severe pain on someone as a punishment or to force them to do or say something; great physical or mental suffering. (v) Inflict severe pain on (someone).","examples":["Torture is prohibited under international law. (noun) Waiting for the results was absolute torture. (noun - suffering) The prisoners were allegedly tortured by their captors. (verb)"]},{"word":"toss","level":"C1","type":"v.","turkish":"Atmak, fırlatmak (hafifçe, gelişigüzel); (salata vb.) karıştırmak; yazı tura atmak.","definition":"Throw (something) somewhere lightly, easily, or casually; mix (food, especially salad) lightly; throw (a coin) up into the air in order to make a decision between two alternatives.","examples":["He tossed the keys onto the table.","Toss the salad with the dressing just before serving."]},{"word":"total","level":"C1","type":"v.","turkish":"Toplam ... etmek, ... tutmak; (araba vb.) hurdayaçıkarmak.","definition":"Amount in number to (a specified figure or quantity); add up to; (informal) damage (something, typically a vehicle) beyond repair; wreck.","examples":["The repair costs totaled over $500.","He totaled his car in the accident. (informal)"]},{"word":"tournament","level":"B2","type":"n.","turkish":"Turnuva (spor vb.).","definition":"(in sport and games) A series of contests between a number of competitors, competing for an overall prize.","examples":["Our team reached the semi -finals of the tournament.","She won the chess tournament."]},{"word":"toxic","level":"C1","type":"adj.","turkish":"Toksik, zehirli.","definition":"Poisonous; relating to or caused by poison.","examples":["Some mushrooms are highly toxic.","Industrial waste can release toxic chemicals into the environment."]},{"word":"trace","level":"B2","type":"v.","turkish":"(v) İzini sürmek, takip etmek; kökenini bulmak; (resim vb.) kopyasınıçizmek; (n) İz, belirti;çok az ","definition":"(v) Find or discover by investigation; find the origin or development of; copy (a drawing, map, or design) by drawing over its lines on a superimposed piece of transparent paper. (n) A mark, object, or other indication of the existence or passing of ","examples":["Police are trying to trace the owner of the car. (verb) The origins of the custom can be traced back to the Middle Ages. (verb) There was no trace of anyone having been there. (noun - sign) The water contained traces of lead. (noun - small amount)"]},{"word":"trademark","level":"C1","type":"n.","turkish":"Ticari marka, marka; ayırt ediciözellik.","definition":"A symbol, word, or words legally registered or established by use as representing a company or product; a distinctive characteristic or object.","examples":["Coca-Cola is a registered trademark.","His distinctive hat became his trademark."]},{"word":"trading","level":"B2","type":"n.","turkish":"Ticaret, alım satım (özellikle borsa).","definition":"The action or activity of buying and selling goods and services; the buying and selling of shares or currency.","examples":["International trading boosts the economy.","Stock market trading was halted due to technical issues."]},{"word":"tragedy","level":"B2","type":"n.","turkish":"Trajedi, facia,çoküzücü olay; trajedi (tiyatro türü).","definition":"An event causing great suffering, destruction, and distress, such as a serious accident, crime, or natural catastrophe; a play dealing with tragic events and having an unhappy ending, especially one concerning the downfall of the main character.","examples":["The earthquake was a terrible tragedy.","Shakespeare wrote several famous tragedies, including Hamlet and Macbeth."]},{"word":"tragic","level":"B2","type":"adj.","turkish":"Trajik, feci,çoküzücü.","definition":"Causing or characterized by extreme distress or sorrow; relating to tragedy in a literary work.","examples":["He died in a tragic accident at a young age.","The play tells the tragic story of doomed lovers."]},{"word":"trail","level":"C1","type":"n.","turkish":"(n) Patika, iz, yol; iz (arkada bırakılan); (v) İzini sürmek, takip etmek; sürüklenmek, geride kalma","definition":"(n) A mark or a series of signs or objects left behind by the passage of someone or something; a path or track worn by usage or deliberately made. (v) Draw or be drawn along behind someone or something; follow (a person or animal) by using marks or s","examples":["We followed the hiking trail through the forest. (noun - path) The police followed the trail of footprints. (noun - marks) The little boy trailed behind his parents. (verb - lag behind)"]},{"word":"trailer","level":"C1","type":"n.","turkish":"Römork, treyler; karavan (ABD); fragman (film).","definition":"An unpowered vehicle towed by another; (North American) a mobile home; an extract from a film or programme used for advance publicity.","examples":["The truck was pulling a large trailer. (vehicle) Have you seen the trailer for the new superhero movie? (film preview)"]},{"word":"trait","level":"B2","type":"n.","turkish":"Özellik, nitelik (kişilik vb.).","definition":"A distinguishing quality or characteristic, typically one belonging to a person.","examples":["Honesty is one of his best traits.","Certain personality traits are inherited."]},{"word":"transaction","level":"C1","type":"n.","turkish":"İşlem (ticari, bankacılık vb.).","definition":"An instance of buying or selling something; a business deal; an exchange or interaction between people.","examples":["All bank transactions are recorded.","The real estate transaction was completed last week."]},{"word":"transcript","level":"C1","type":"n.","turkish":"Transkript, kopya (yazılı); not dökümü (akademik).","definition":"A written or printed version of material originally presented in another medium; an official record of a student's work, showing courses taken and grades achieved.","examples":["The court reporter provided a transcript of the trial.","You will need to submit your academic transcript with your university application."]},{"word":"transformation","level":"C1","type":"n.","turkish":"Dönüşüm, değişme/değiştirme.","definition":"A thorough or dramatic change in form or appearance.","examples":["The city has undergone a complete transformation in the last decade.","Caterpillars undergo a remarkable transformation into butterflies."]},{"word":"transit","level":"C1","type":"n.","turkish":"Geçiş, transit; taşıma, nakliye.","definition":"The carrying of people, goods, or materials from one place to another; the action of passing through or across a place.","examples":["The goods were damaged in transit.","Passengers arriving from international flights must go through the transit lounge if connecting."]},{"word":"transmission","level":"C1","type":"n.","turkish":"İletim, aktarma (sinyal, hastalık, bilgi vb.);şanzıman, vites kutusu (araç).","definition":"The action or process of transmitting something or the state of being transmitted; the mechanism by which power is transmitted from an engine to the axle in a motor vehicle.","examples":["Measures were taken to prevent the transmission of the disease.","The broadcast experienced signal transmission problems."]},{"word":"trans mit","level":"B2","type":"v.","turkish":"İletmek, aktarmak, göndermek (sinyal, hastalık, bilgi vb.).","definition":"Cause (something) to pass on from one place or person to another.","examples":["Mosquitoes can transmit diseases like malaria.","The radio station transmits on FM frequency."]},{"word":"transparency","level":"C1","type":"n.","turkish":"Şeffaflık, saydamlık.","definition":"The condition of being transparent (allowing light to pass through; easy to perceive or detect); the quality of being open to public scrutiny.","examples":["The company prides itself on its transparency in business dealings.","Lack of transparency can lead to mistrust."]},{"word":"transparent","level":"C1","type":"adj.","turkish":"Şeffaf, saydam; (mecazi) açık, anlaşılır, gizlisi saklısı olmayan.","definition":"(of a material or article) Allowing light to pass through so that objects behind can be distinctly seen; easy to perceive or detect; open to public scrutiny.","examples":["Glass is a transparent material.","We need a more transparent decision-making process."]},{"word":"trap","level":"B2","type":"v.","turkish":"(v) Tuzağa düşürmek, yakalamak; sıkıştırmak; (n) Tuzak, kapan; (argo) ağız.","definition":"(v) Catch (an animal) in a trap; prevent (someone) from escaping from a place or situation. (n) A device or enclosure designed to catch and retain animals; an unpleasant situation from which it is hard to escape.","examples":["They set a trap to catch the mouse. (noun) He felt trapped in a dead-end job. (verb)"]},{"word":"trauma","level":"C1","type":"n.","turkish":"Travma, sarsıntı (ruhsal veya fiziksel).","definition":"A deeply distressing or disturbing experience; emotional shock following a stressful event or a physical injury, which may lead to long-term neurosis; physical injury.","examples":["She is still dealing with the trauma of the accident.","Childhood trauma can have long-lasting effects."]},{"word":"treasure","level":"B2","type":"n.","turkish":"Hazine, define;çok değerlişey/kimse.","definition":"A quantity of precious metals, gems, or other valuable objects; a very valuable object; a person esteemed as rare or precious.","examples":["Pirates supposedly buried treasure on the island.","These old photographs are family treasures."]},{"word":"treaty","level":"C1","type":"n.","turkish":"Antlaşma, pakt (uluslararası).","definition":"A formally concluded and ratified agreement between countries.","examples":["The two nations signed a peace treaty.","The treaty aimed to limit nuclear weapons."]},{"word":"tremendous","level":"C1","type":"adj.","turkish":"Muazzam,çok büyük, olağanüstü, harika.","definition":"Very great in amount, scale, or intensity; (informal) extremely good or impressive.","examples":["She has made a tremendous effort to improve her grades.","The concert was a tremendous success."]},{"word":"tribal","level":"C1","type":"adj.","turkish":"Kabile(ye ait), aşiret(le ilgili).","definition":"Relating to or characteristic of a tribe or tribes.","examples":["The museum displays tribal art from Africa.","Conflicts arose over tribal lands."]},{"word":"tribe","level":"B2","type":"n.","turkish":"Kabile, aşiret; (mecazi) grup, topluluk.","definition":"A social division in a traditional society consisting of families or communities linked by social, economic, religious, or blood ties, with a common culture and dialect, typically having a recognized leader.","examples":["Several indigenous tribes live in the Amazon rainforest.","He felt like he had found his tribe among fellow musicians."]},{"word":"tribute","level":"C1","type":"n.","turkish":"Haraç, vergi (tarihsel);övgü, saygı göstergesi, takdir.","definition":"An act, statement, or gift that is intended to show gratitude, respect, or admiration; (historical) payment made periodically by one state or ruler to another, especially as a sign of dependence.","examples":["The concert was a tribute to the late singer. (respect) Conquered nations often had to pay tribute to the empire. (payment)"]},{"word":"trigger","level":"B2","type":"v.","turkish":"(v) Tetiklemek, -e yol açmak, başlatmak; (n) Tetik (silah); tetikleyicişey/sebep.","definition":"(v) Cause (an event or situation) to happen or exist; (n) A small device that releases a spring or catch and so sets off a mechanism, especially in order to fire a gun; an event or situation, etc. that is the cause of a particular action, process, or","examples":["The announcement triggered a wave of protests. (verb) Stress can be a trigger for anxiety attacks. (noun - cause) He pulled the trigger of the gun. (noun - gun part)"]},{"word":"trillion","level":"B2","type":"number","turkish":"Trilyon (1,000,000,000,000).","definition":"A million million (10¹² or 1,000,000,000,000).","examples":["The national debt exceeds several trillion dollars.","There are trillions of stars in the observable universe."]},{"word":"trio","level":"C1","type":"n.","turkish":"Üçlü (müzik grubu, kişi grubu vb.).","definition":"A set or group of three people or things; a musical composition for three voices or instruments.","examples":["A trio of musicians played jazz in the corner.","The three friends formed an inseparable trio."]},{"word":"triumph","level":"C1","type":"n.","turkish":"Zafer, büyük başarı, galibiyet.","definition":"A great victory or achievement; the state of being victorious.","examples":["Winning the championship was a personal triumph for the coach.","The discovery was hailed as a scientific triumph. troop (n."]},{"word":"trophy","level":"C1","type":"n.","turkish":"Kupa,ödül; ganimet.","definition":"A cup or other decorative object awarded as a prize for a victory or success; something taken in war or hunting, or seized or won from an enemy; spoil; memento.","examples":["The winning team held the trophy high.","His study was filled with hunting trophies."]},{"word":"troubled","level":"C1","type":"adj.","turkish":"Sorunlu, sıkıntılı, endişeli.","definition":"Experiencing problems or difficulties; showing distress or anxiety.","examples":["She comes from a troubled family background.","He looked troubled when he heard the news."]},{"word":"trustee","level":"C1","type":"n.","turkish":"Mütevelli, yediemin, vasi.","definition":"An individual person or member of a board given control or powers of administration of property in trust with a legal obligation to administer it solely for the purposes specified.","examples":["The charity is managed by a board of trustees.","He acts as a trustee for his nephew's inheritance."]},{"word":"tsunami","level":"B2","type":"n.","turkish":"Tsunami, dev dalga.","definition":"A long high sea wave caused by an earthquake, submarine landslide, or other disturbance.","examples":["The earthquake triggered a massive tsunami.","Coastal areas are vulnerable to tsunamis."]},{"word":"tuition","level":"C1","type":"n.","turkish":"Öğretim, ders verme; okulücreti, öğrenim harcı.","definition":"Teaching or instruction, especially of individual pupils or small groups; a sum of money charged for teaching or instruction by a school, college, or university.","examples":["She gives private tuition in mathematics. (teaching) University tuition fees have increased significantly. (fee) tumor (n.","C1) ( İngiliz İngilizcesi: tumour) Türkçe Anlamı: Tümör, ur."]},{"word":"turnout","level":"C1","type":"n.","turkish":"Katılım (oranı - seçim, etkinlik vb.); üretim miktarı.","definition":"The number of people attending or taking part in an event, especially the number of people voting in an election; the amount of something produced by a person, machine, or industry.","examples":["There was a high voter turnout in the last election.","The concert had a disappointing turnout."]},{"word":"turnover","level":"C1","type":"n.","turkish":"Ciro, iş hacmi; personel devir hızı, (çalışan) değişme oranı.","definition":"The amount of money taken by a business in a particular period; the rate at which employees leave a workforce and are replaced.","examples":["The company's annual turnover is over £5 million. (revenue) High staff turnover can be costly for businesses. (employee replacement)"]},{"word":"twist","level":"C1","type":"v.","turkish":"(v) Bükmek, burmak, kıvırmak; (bilek vb.) burkmak; (anlamı)çarpıtmak; (n) Bükme, burma; (yol vb.) vi","definition":"(v) Form into a bent, curling, or distorted shape; injure (a part of the body) by wrenching it; alter the meaning or implication of (something) by distortion. (n) An act of turning something; a thing with a spiral shape; an unexpected change or devel","examples":["Twist the wire to secure it. (verb) The plot had an unexpected twist at the end. (noun) She twisted her ankle playing tennis. (verb - injure)"]},{"word":"ultimate","level":"B2","type":"adj.","turkish":"Nihai, son, en son; en iyi, enüstün.","definition":"Being or happening at the end of a process; final; being the best or most extreme example of its kind.","examples":["Our ultimate goal is to achieve world peace.","This car represents the ultimate in luxury travel."]},{"word":"unacceptable","level":"B2","type":"adj.","turkish":"Kabul edilemez, uygunsuz.","definition":"Not satisfactory or allowable.","examples":["Such behavior is completely unacceptable.","The level of pollution is unacceptable."]},{"word":"uncertainty","level":"B2","type":"n.","turkish":"Belirsizlik, kararsızlık,şüphe.","definition":"The state of being uncertain; doubt.","examples":["There is considerable uncertainty about the future of the economy.","She felt a sense of uncertainty about her decision."]},{"word":"unconstitutional","level":"C1","type":"adj.","turkish":"Anayasaya aykırı.","definition":"Not in accordance with a political constitution, especially the US Constitution, or with procedural rules.","examples":["The Supreme Court declared the law unconstitutional.","Critics argued that the president's actions were unconstitutional. undergo (v."]},{"word":"undergraduate","level":"C1","type":"n.","turkish":"Lisansöğrencisi (henüz ilk diplomasını almamış).","definition":"A student at a college or university who has not yet earned a bachelor's or equivalent degree.","examples":["The course is open to both undergraduates and graduates.","He is currently an undergraduate studying history."]},{"word":"underlying","level":"C1","type":"adj.","turkish":"Altında yatan, temelindeki, esas.","definition":"Being the cause or basis of something; fundamental; situated below or beneath.","examples":["We need to address the underlying causes of the problem.","The underlying message of the film is about hope."]},{"word":"undermine","level":"C1","type":"v.","turkish":"Zayıflatmak, baltalamak, temeline zarar vermek.","definition":"Lessen the effectiveness, power, or ability of, especially gradually or insidiously; erode the base or foundation of (a rock formation).","examples":["Constant criticism can undermine a person's confidence.","Attempts were made to undermine the authority of the committee. undertake (v."]},{"word":"undoubtedly","level":"C1","type":"adv.","turkish":"Şüphesiz, kuşkusuz.","definition":"Without doubt; certainly.","examples":["She is undoubtedly the best candidate for the job.","This is undoubtedly a challenging time for the industry."]},{"word":"unfold","level":"B2","type":"v.","turkish":"Açmak, sermek (katlanmışşeyi); (olaylar) gelişmek, ortayaçıkmak.","definition":"Open or spread out from a folded position; (of events or information) gradually develop or be revealed.","examples":["He carefully unfolded the map.","Let's see how events unfold."]},{"word":"unfortunate","level":"B2","type":"adj.","turkish":"Talihsiz,şanssız,üzücü.","definition":"Having or marked by bad fortune; unlucky; regrettable or inappropriate.","examples":["It was unfortunate that we couldn't meet.","He suffered an unfortunate accident."]},{"word":"unify","level":"C1","type":"v.","turkish":"Birleştirmek, tekçatı altında toplamak.","definition":"Make or become united, uniform, or whole.","examples":["The leader tried to unify the different factions within the party.","The goal is to unify the two separate systems into one."]},{"word":"unite","level":"B2","type":"v.","turkish":"Birleşmek, birleştirmek.","definition":"Come or bring together for a common purpose or action.","examples":["The various groups decided to unite to form a coalition.","We must unite against the common enemy."]},{"word":"unity","level":"B2","type":"n.","turkish":"Birlik, bütünlük, teklik.","definition":"The state of being united or joined as a whole.","examples":["The crisis brought a sense of national unity.","Team unity is crucial for success."]},{"word":"universal","level":"B2","type":"adj.","turkish":"Evrensel, genel,üniversal.","definition":"Relating to or done by all people or things in the world or in a particular group; applicable to all cases.","examples":["Music is often considered a universal language.","Access to education should be universal."]},{"word":"unprecedented","level":"C1","type":"adj.","turkish":"Eşi benzeri görülmemiş, emsalsiz.","definition":"Never done or known before.","examples":["The company achieved unprecedented growth last year.","The pandemic caused disruption on an unprecedented scale."]},{"word":"unveil","level":"C1","type":"v.","turkish":"Açığaçıkarmak, gözlerönüne sermek; (heykel, anıt vb.) açılışını yapmak.","definition":"Remove a veil or covering from, in particular uncover (a new monument or work of art) as part of a public ceremony; show or announce publicly for the first time.","examples":["The company will unveil its new car model next month.","The mayor unveiled the statue in the town square."]},{"word":"upcoming","level":"C1","type":"adj.","turkish":"Yaklaşan, yakında olacak/gelecek.","definition":"Forthcoming; about to happen.","examples":["Are you prepared for the upcoming exams?","Details of the upcoming event will be posted online."]},{"word":"upgrade","level":"C1","type":"v.","turkish":"(v) Yükseltmek (versiyon, sınıf vb.), iyileştirmek; (n) Yükseltme, iyileştirme.","definition":"(v) Raise (something) to a higher standard, in particular improve (equipment or machinery) by adding or replacing components; raise (an employee) to a higher grade or rank. (n) An act of upgrading something.","examples":["You need to upgrade your software to the latest version. (verb) We received a free upgrade to business class on the flight. (noun) uphold (v.","C1) (uphold, upheld, upheld) Türkçe Anlamı: Desteklemek, onaylamak, sürdürmek (karar, prensip vb.)."]},{"word":"urgent","level":"B2","type":"adj.","turkish":"Acil, ivedi.","definition":"Requiring immediate action or attention.","examples":["There is an urgent need for blood donors.","Please reply to this email as soon as possible; it's urgent."]},{"word":"usage","level":"B2","type":"n.","turkish":"Kullanım, kullanma biçimi; (dil) kullanım.","definition":"The action of using something or the fact of being used; the way in which a word or phrase is normally and correctly used.","examples":["Water usage increases during hot weather.","This dictionary provides examples of common English usage."]},{"word":"useless","level":"B2","type":"adj.","turkish":"İşe yaramaz, faydasız, boşuna.","definition":"Not fulfilling or not expected to achieve the intended purpose or desired outcome; having no ability or skill in a specified activity or area.","examples":["This old phone is completely useless.","It's useless trying to argue with him."]},{"word":"utility","level":"C1","type":"n.","turkish":"Fayda, yarar; kamu hizmeti (elektrik, su, gaz vb.).","definition":"The state of being useful, profitable, or beneficial; an organization supplying the community with electricity, gas, water, or sewerage.","examples":["We need to consider the utility of this approach. (usefulness) Remember to pay the monthly utility bills. (public service) utilize (v.","C1) ( İngiliz İngilizcesi: utilise) (Resmi) Türkçe Anlamı: Kullanmak, yararlanmak, faydalanmak."]},{"word":"utterly","level":"C1","type":"adv.","turkish":"Tamamen, bütünüyle, kesinlikle.","definition":"Completely and without qualification; absolutely.","examples":["I was utterly exhausted after the long journey.","His explanation was utterly unbelievable."]},{"word":"vacuum","level":"C1","type":"n.","turkish":"Vakum, boşluk (hava vb. olmayan); elektrikli süpürge.","definition":"A space entirely devoid of matter; a space or container from which the air has been completely or partly removed; a vacuum cleaner.","examples":["Sound cannot travel in a vacuum.","I need to buy a new bag for the vacuum cleaner."]},{"word":"vague","level":"C1","type":"adj.","turkish":"Belirsiz, net olmayan, muğlak,üstü kapalı.","definition":"Of uncertain, indefinite, or unclear character or meaning; thinking or communicating in an unfocused or imprecise way.","examples":["He gave only a vague description of the attacker.","I have a vague memory of meeting her before."]},{"word":"valid","level":"B2","type":"adj.","turkish":"Geçerli (belge, argüman vb.); mantıklı, makul.","definition":"(of an argument or point) Having a sound basis in logic or fact; reasonable or cogent; legally binding due to having been executed in compliance with the law.","examples":["Your passport is no longer valid.","She made several valid points during the discussion."]},{"word":"validity","level":"C1","type":"n.","turkish":"Geçerlilik; mantıklılık, doğruluk.","definition":"The quality of being logically or factually sound; the state of being legally or officially binding or acceptable.","examples":["The validity of the contract was questioned.","Researchers need to ensure the validity of their data."]},{"word":"vanish","level":"C1","type":"v.","turkish":"Ortadan kaybolmak, yok olmak, sırra kadem basmak.","definition":"Disappear suddenly and completely.","examples":["The magician made the rabbit vanish into thin air.","All hopes of finding survivors vanished."]},{"word":"variable","level":"C1","type":"n.","turkish":"(n) Değişken; (adj) Değişken, kararsız.","definition":"(n) An element, feature, or factor that is liable to vary or change. (adj) Not consistent or having a fixed pattern; liable to change.","examples":["Temperature is an important variable in this experiment. (noun) The weather in the mountains is highly variable. (adjective)"]},{"word":"variation","level":"B2","type":"n.","turkish":"Varyasyon,çeşitlilik, farklılık, değişiklik.","definition":"A change or difference in condition, amount, or level, typically with certain limits.","examples":["The survey showed wide variation in students' opinions.","There are regional variations in pronunciation."]},{"word":"varied","level":"C1","type":"adj.","turkish":"Çeşitli, değişik, farklılık gösteren.","definition":"Incorporating a number of different types or elements; showing variation or variety.","examples":["She has had a rich and varied career.","The restaurant offers a varied menu."]},{"word":"vein","level":"C1","type":"n.","turkish":"Damar (toplardamar); (yaprak, kanat) damar; (maden) damarı; (mecazi) tarz,üslup.","definition":"Any of the tubes forming part of the blood circulation system of the body, carrying in most cases oxygen -depleted blood toward the heart; a distinct layer or streak of mineral or ore embedded in rock; a particular quality or style.","examples":["The nurse had trouble finding a suitable vein for the injection. (blood) They discovered a rich vein of gold in the mine. (mineral) He continued speaking in a humorous vein. (style)"]},{"word":"venture","level":"C1","type":"n.","turkish":"(n) Riskli girişim, macera; (v) Tehlikeye atılmak, cesaret etmek; (fikir)öne sürmeye cesaret etmek.","definition":"(n) A risky or daring journey or undertaking. (v) Dare to do something or go somewhere that may be dangerous or unpleasant; dare to say something that might be considered audacious.","examples":["Starting a new business is always a risky venture. (noun) They ventured deep into the unexplored jungle. (verb) He nervously ventured an opinion. (verb - say)"]},{"word":"verbal","level":"C1","type":"adj.","turkish":"Sözlü, sözel.","definition":"Relating to or in the form of words; spoken rather than written.","examples":["We have a verbal agreement, but nothing in writing yet.","Good verbal communication skills are essential."]},{"word":"verdict","level":"C1","type":"n.","turkish":"Karar, hüküm (mahkeme jürisi); (mecazi) görüş, kanı.","definition":"A decision on an issue of fact in a civil or criminal case or an inquest; an opinion or judgment.","examples":["The jury reached a guilty verdict.","What's your verdict on the new restaurant?"]},{"word":"verify","level":"C1","type":"v.","turkish":"Doğrulamak, teyit etmek.","definition":"Make sure or demonstrate that (something) is true, accurate, or justified.","examples":["Please verify your email address by clicking the link.","We need to verify his identity before allowing him access."]},{"word":"verse","level":"C1","type":"n.","turkish":"Mısra, dize; kıta, dörtlük; ayet (kutsal kitap).","definition":"Writing arranged with a metrical rhythm, typically having a rhyme; a group of lines that form a unit in a poem or song; stanza; each of the short numbered divisions of a chapter in the Bible or other scripture.","examples":["Can you recite the first verse of the poem?","He quoted a verse from the Bible. versus (conj."]},{"word":"vertical","level":"B2","type":"adj.","turkish":"Dikey, düşey.","definition":"At right angles to a horizontal plane; in a direction, or having an alignment, such that the top is directly above the bottom.","examples":["Draw a vertical line down the page.","The cliffs rose vertical from the sea."]},{"word":"vessel","level":"C1","type":"n.","turkish":"Gemi, tekne; kap, hazne; damar (kan).","definition":"A ship or large boat; a hollow container, especially one used to hold liquid, such as a bowl or cask; a duct or canal holding or conveying blood or other fluid.","examples":["The fishing vessel returned to port. (ship) Clay vessels were used for storing water. (container) Damaged blood vessels can restrict blood flow. (body)"]},{"word":"veteran","level":"C1","type":"n.","turkish":"Gazi, eski muharip; kıdemli, deneyimli kimse.","definition":"A person who has had long experience in a particular field; a person who has served in the armed forces.","examples":["He is a veteran of the Vietnam War. (military) The team includes several veteran players. (experienced)"]},{"word":"viable","level":"C1","type":"adj.","turkish":"Uygulanabilir, yaşayabilir, geçerli.","definition":"Capable of working successfully; feasible.","examples":["Is solar power a viable alternative to fossil fuels?","We need to find a commercially viable solution."]},{"word":"vibrant","level":"C1","type":"adj.","turkish":"Canlı, enerjik, hareketli; (renk) parlak, canlı.","definition":"Full of energy and enthusiasm; (of color) bright and striking.","examples":["New York is a vibrant, exciting city.","She wore a dress in vibrant shades of red and orange."]},{"word":"vice","level":"C1","type":"n.","turkish":"Kötü alışkanlık, kusur, ahlaksızlık; yardımcılık, vekillik ('vice president' vb.).","definition":"Immoral or wicked behavior; an immoral or wicked personal characteristic; (in titles) acting as deputy or substitute for.","examples":["Gambling can become a destructive vice. (bad habit) Patience is a virtue, impatience a vice. (characteristic) He holds the position of Vice Chairman. (deputy)"]},{"word":"vicious","level":"C1","type":"adj.","turkish":"Kötü niyetli, gaddar, acımasız;şiddetli, tehlikeli.","definition":"Deliberately cruel or violent; (of an animal) wild and dangerous to people.","examples":["He was subjected to a vicious attack.","Beware of the dog; it can be vicious."]},{"word":"viewpoint","level":"B2","type":"n.","turkish":"Bakış açısı, görüş noktası.","definition":"A person's opinion or point of view; a position giving a good view.","examples":["From an economic viewpoint, the project is not feasible.","Try to understand the situation from her viewpoint."]},{"word":"violate","level":"C1","type":"v.","turkish":"İhlal etmek (kural, yasa, anlaşma vb.), çiğnemek.","definition":"Break or fail to comply with (a rule or formal agreement); treat (something sacred) with irreverence or disrespect.","examples":["Driving over the speed limit violates the law.","The company was accused of violating human rights."]},{"word":"violation","level":"C1","type":"n.","turkish":"İhlal,çiğneme.","definition":"The action of violating someone or something.","examples":["Speeding is a common traffic violation.","This action is a clear violation of the terms of the contract."]},{"word":"virtue","level":"C1","type":"n.","turkish":"Erdem, fazilet, iyi ahlak; avantaj, meziyet.","definition":"Behavior showing high moral standards; a quality considered morally good or desirable in a person; a good or useful quality of a thing.","examples":["Patience is a virtue.","One of the virtues of this system is its simplicity."]},{"word":"visa","level":"B2","type":"n.","turkish":"Vize.","definition":"An endorsement on a passport indicating that the holder is allowed to enter, leave, or stay for a specified period of time in a country.","examples":["You need a visa to travel to some countries.","He applied for a student visa."]},{"word":"visible","level":"B2","type":"adj.","turkish":"Görünür, görülebilir.","definition":"Able to be seen.","examples":["The mountains were barely visible through the mist.","The scar is still visible on his arm."]},{"word":"vocal","level":"C1","type":"adj.","turkish":"Vokal, ses(le ilgili); sesini yükselten, görüşleriniçekinmeden belirten.","definition":"Relating to the human voice; expressing opinions or feelings freely or loudly.","examples":["The song features beautiful vocal harmonies. (voice) He has been a vocal critic of the government's policies. (outspoken)"]},{"word":"voluntary","level":"B2","type":"adj.","turkish":"Gönüllü, isteğe bağlı.","definition":"Done, given, or acting of one's own free will.","examples":["She does voluntary work at the local hospital.","Attendance at the meeting is purely voluntary."]},{"word":"voting","level":"B2","type":"n.","turkish":"Oy verme, oylama.","definition":"The process of casting a vote.","examples":["Voting is an important civic duty.","The result will be announced after the voting closes."]},{"word":"vow","level":"C1","type":"v.","turkish":"Yemin etmek, ant içmek.","definition":"Solemnly promise to do a specified thing.","examples":["He vowed to take revenge.","They vowed to love each other forever."]},{"word":"vulnerability","level":"C1","type":"n.","turkish":"Kırılganlık, hassasiyet, savunmasızlık.","definition":"The quality or state of being exposed to the possibility of being attacked or harmed, either physically or emotionally.","examples":["The system's vulnerability to cyberattacks is a major concern.","His vulnerability made her want to protect him."]},{"word":"vulnerable","level":"C1","type":"adj.","turkish":"Savunmasız, korunmasız, hassas, kırılgan (saldırıya, eleştiriye vb. açık).","definition":"Exposed to the possibility of being attacked or harmed, either physically or emotionally.","examples":["Young birds are very vulnerable to predators.","Elderly people are often more vulnerable to illness."]},{"word":"wander","level":"B2","type":"v.","turkish":"Dolaşmak, gezinmek (amaçsızca); (konudan) sapmak.","definition":"Walk or move in a leisurely, casual, or aimless way; move slowly away from a fixed point or course.","examples":["We spent the afternoon wandering around the old town.","His mind began to wander during the long lecture."]},{"word":"ward","level":"C1","type":"n.","turkish":"Koğuş (hastane); vesayet altındaki kimse; (şehirde) seçim bölgesi.","definition":"A separate room in a hospital, typically one allocated to a particular type of patient; a person, usually a child, who is under the legal protection of a guardian or court; an administrative division of a city or borough that typically elects and is ","examples":["He is recovering on the surgical ward. (hospital) The orphan became a ward of the state. (person under protection) She represents the central ward on the city council. (district)"]},{"word":"warehouse","level":"C1","type":"n.","turkish":"Depo, ambar.","definition":"A large building where raw materials or manufactured goods may be stored before their export or distribution for sale.","examples":["The company stores its products in a large warehouse.","Online retailers often operate from huge warehouses."]},{"word":"warfare","level":"C1","type":"n.","turkish":"Savaş, harp, savaş hali.","definition":"Engagement in or the activities involved in war or conflict.","examples":["Modern warfare involves advanced technology.","Guerrilla warfare tactics were used by the rebels."]},{"word":"warming","level":"B2","type":"n.","turkish":"Isınma (özellikle küreselısınma).","definition":"An increase in the temperature of the earth's atmosphere generally attributed to the greenhouse effect (often in 'global warming').","examples":["Global warming is causing sea levels to rise.","Scientists are studying the effects of global warming."]},{"word":"warr ant","level":"C1","type":"n.","turkish":"(n) Yetki belgesi, izin, ruhsat (arama, tutuklama vb.); gerekçe, sebep; (v) Gerektirmek, haklı kılma","definition":"(n) A document issued by a legal or government official authorizing the police or some other body to make an arrest, search premises, or carry out some other action relating to the administration of justice; justification or authority for an action, ","examples":["The police obtained a search warrant. (noun - document) His behavior does not warrant such a severe punishment. (verb - justify) Further investigation is warranted. (verb - justify)"]},{"word":"warrior","level":"C1","type":"n.","turkish":"Savaşçı.","definition":"(especially in former times) A brave or experienced soldier or fighter.","examples":["Samurai were legendary Japanese warriors.","The museum displayed the armor of ancient warriors."]},{"word":"weaken","level":"C1","type":"v.","turkish":"Zayıflatmak, güçsüzleştirmek; zayıflamak.","definition":"Make or become weaker in power, resolve, or physical strength.","examples":["The illness had weakened him considerably.","Economic sanctions aim to weaken the regime. weave (v."]},{"word":"weed","level":"C1","type":"n.","turkish":"Yabani ot; (argo) esrar.","definition":"A wild plant growing where it is not wanted and in competition with cultivated plants; (informal) cannabis.","examples":["The garden was overgrown with weeds.","It's important to remove weeds regularly."]},{"word":"weekly","level":"B2","type":"adj.","turkish":"Haftalık.","definition":"Done, produced, or occurring once a week.","examples":["We have a weekly team meeting every Monday.","She receives a weekly allowance from her parents. weird (adj."]},{"word":"welfare","level":"B2","type":"n.","turkish":"Refah, esenlik, iyilik hali; sosyal yardım.","definition":"The health, happiness, and fortunes of a person or group; statutory procedure or social effort designed to promote the basic physical and material well-being of people in need.","examples":["The company prioritizes employee welfare. (well being) Many families rely on state welfare benefits. (assistance) well (n.","C1) (Su kuyusu anlamında) Türkçe Anlamı: Kuyu (su)."]},{"word":"well -being","level":"C1","type":"n.","turkish":"Esenlik, iyilik hali, refah.","definition":"The state of being comfortable, healthy, or happy.","examples":["Exercise is important for both physical and mental well-being.","The company promotes employee well-being initiatives. whatsoever (adv."]},{"word":"wheat","level":"B2","type":"n.","turkish":"Buğday.","definition":"A cereal plant that is the most important kind grown in temperate countries, the grain of which is ground to make flour for bread, pasta, pastry, etc.","examples":["Vast fields of wheat stretched to the horizon.","Bread is made from wheat flour. whereby (adv."]},{"word":"whip","level":"C1","type":"v.","turkish":"Kırbaçlamak, kamçılamak; (krema, yumurta)çırpmak; (hızla)çıkarmak/hareket ettirmek.","definition":"Beat (a person or animal) with a whip or similar instrument; beat (cream, eggs, or other food) into a froth; move quickly and suddenly.","examples":["Whip the cream until it forms stiff peaks.","He whipped out his phone to take a picture. (Historical context: The cruel master would whip the slaves.)"]},{"word":"whoever","level":"B2","type":"pron.","turkish":"Her kimse, kim olursa olsun.","definition":"Anyone who; the person or people who.","examples":["Whoever finishes first wins the prize.","Give this message to whoever answers the phone."]},{"word":"wholly","level":"C1","type":"adv.","turkish":"Tamamen, bütünüyle.","definition":"Entirely; fully.","examples":["The success was wholly due to her efforts.","I am not wholly convinced by his argument."]},{"word":"widen","level":"C1","type":"v.","turkish":"Genişletmek, genişlemek.","definition":"Make or become wider.","examples":["They plan to widen the road to reduce traffic congestion.","His eyes widened in surprise."]},{"word":"widespread","level":"B2","type":"adj.","turkish":"Yaygın, genişçapta.","definition":"Found or distributed over a large area or number of people.","examples":["There is widespread support for the new policy.","The disease became widespread across the country."]},{"word":"widow","level":"C1","type":"n.","turkish":"Dul kadın.","definition":"A woman who has lost her spouse by death and has not remarried.","examples":["She became a young widow when her husband died in the war.","The charity provides support for widows and orphans."]},{"word":"width","level":"C1","type":"n.","turkish":"Genişlik, en.","definition":"The measurement or extent of something from side to side.","examples":["Measure the length and width of the room.","The river varies in width along its course."]},{"word":"willingness","level":"C1","type":"n.","turkish":"İsteklilik, gönüllülük.","definition":"The quality or state of being prepared to do something; readiness.","examples":["She showed a great willingness to learn.","Success depends on your willingness to work hard."]},{"word":"wisdom","level":"B2","type":"n.","turkish":"Bilgelik, akıl, irfan.","definition":"The quality of having experience, knowledge, and good judgment; the quality of being wise.","examples":["He shared his words of wisdom with the younger generation.","With age comes wisdom."]},{"word":"wit","level":"C1","type":"n.","turkish":"Nükte, ince espri yeteneği; hazırcevaplık, akıl.","definition":"The capacity for inventive thought and quick understanding; keen intelligence; a natural aptitude for using words and ideas in a quick and inventive way to create humor.","examples":["She impressed everyone with her sharp wit and intelligence.","His speeches were full of wit and charm. withdraw (v."]},{"word":"withdrawal","level":"C1","type":"n.","turkish":"Geriçekme/çekilme (para, asker, iddia vb.); (bağımlılık) yoksunluk belirtileri.","definition":"The action of withdrawing something; the process of ceasing to take an addictive drug; the process of removing money from a bank account.","examples":["The sudden withdrawal of funding caused problems.","He suffered severe withdrawal symptoms when he stopped smoking."]},{"word":"workforce","level":"B2","type":"n.","turkish":"İş gücü,çalışanlar.","definition":"The people engaged in or available for work, either in a country or area or in a particular company or industry.","examples":["The company plans to reduce its workforce.","Women make up a large percentage of the workforce."]},{"word":"workout","level":"C1","type":"n.","turkish":"Antrenman, egzersiz.","definition":"A session of vigorous physical exercise or training.","examples":["She does a 30-minute workout every morning.","Going to the gym for a workout helps relieve stress."]},{"word":"workplace","level":"B2","type":"n.","turkish":"İş yeri.","definition":"A place where people work, such as an office or factory.","examples":["Safety regulations must be followed in the workplace.","Creating a positive workplace environment is important."]},{"word":"workshop","level":"B2","type":"n.","turkish":"Atölye (tamir,üretim vb.); atölye çalışması, seminer (eğitim).","definition":"A room or building in which goods are manufactured or repaired; a meeting at which a group of people engage in intensive discussion and activity on a particular subject or project.","examples":["He fixed the chair in his woodworking workshop. (place) I attended a workshop on creative writing. (training session)"]},{"word":"worm","level":"B2","type":"n.","turkish":"Solucan, kurtçuk.","definition":"Any of a number of creeping or burrowing invertebrate animals with long, slender soft bodies and no limbs.","examples":["Birds often eat worms.","Fishermen use worms as bait."]},{"word":"worship","level":"C1","type":"n.","turkish":"(n) İbadet, tapınma; (v) İbadet etmek, tapmak, tapınmak.","definition":"(n) The feeling or expression of reverence and adoration for a deity; acts of religious praise, honor, or devotion. (v) Show reverence and adoration for (a deity); honor with religious rites.","examples":["Freedom of worship is a fundamental right. (noun) They gather every Sunday to worship. (verb)"]},{"word":"worthwhile","level":"C1","type":"adj.","turkish":"Değerli, zahmete değer, faydalı.","definition":"Worth the time, money, or effort spent; of value or importance.","examples":["Volunteering for a good cause is a worthwhile activity.","It wasn't worthwhile continuing the project."]},{"word":"worthy","level":"C1","type":"adj.","turkish":"Değer, layık (...of); saygıdeğer.","definition":"Having or showing the qualities or abilities that merit recognition in a specified way; deserving effort, attention, or respect.","examples":["His actions are worthy of praise.","She is a worthy successor to the previous manager."]},{"word":"wrist","level":"B2","type":"n.","turkish":"Bilek (el).","definition":"The joint connecting the hand with the forearm.","examples":["She wore a bracelet on her wrist.","He sprained his wrist playing tennis."]},{"word":"yell","level":"C1","type":"v.","turkish":"Bağırmak, haykırmak.","definition":"Shout loudly, typically in pain, anger, or excitement.","examples":["Don't yell at me!","He yelled for help when he fell into the water."]},{"word":"yield","level":"C1","type":"n.","turkish":"(n) Verim,ürün, hasılat; getiri (yatırım); (v) Ürün vermek, verim sağlamak; teslim olmak, boyun eğme","definition":"(n) An amount produced of an agricultural or industrial product; the total income, profit or result produced. (v) Produce or provide (a natural, agricultural, or industrial product); give way to arguments, demands, or pressure; (of traffic) allow oth","examples":["The farm had a high crop yield this year. (noun) This investment should yield a good return. (verb - produce) Drivers must yield to pedestrians in crosswalks. (verb - give way) He refused to yield to their demands. (verb - surrender)"]}];